    public function user_login($user,$pwd){
        $query=$this->db->query("SELECT * FROM user_details WHERE username='$user' AND password='$pwd' AND status = 'active'");
        return $query->result();
    }


     public function user_login_check($user, $pwd)
    {
        $query = $this->db
            ->select('id,name,zone_id,email,photo,type_id,user_id,admin_id,password')
            ->from('user_details')
            ->where('username', $user)
            ->where('status', 'active')
            ->limit(1)
            ->get();

        $row = $query->row();

        // If user found
        if(!empty($row))
        {
           if ((string)$pwd == (string)$row->password) 
            {
                return $row;
            }
        }

        return false;
    }



