    public function add_bdHandover($sname,$saddress,$scity,$sstate,$scontact,$sdegignation,$snumber,$bdid, $client_name,$client_id, $mediator, $noofschool, $location, $city, $state, $spd_identify_by, $infrastructure, $filname,$count, $contact_person, $cp_mno, $acontact_person, $acp_mno, $language, $expected_installation_date, $project_tenure,$project_type, $comments,$sid,$remark,$fttptype){
                if($count>0){
                    $flink="";
                for($i = 0; $i < $count; $i++){
                    $fn = $_FILES['file']['name']     = $_FILES['filname']['name'][$i];
                    $_FILES['file']['type']     = $_FILES['filname']['type'][$i];
                    $_FILES['file']['tmp_name'] = $_FILES['filname']['tmp_name'][$i];
                    $_FILES['file']['error']     = $_FILES['filname']['error'][$i];
                    $_FILES['file']['size'] = $_FILES['filname']['size'][$i];
                    $uploadPath = 'uploads/logo/';
                    $config['upload_path'] = $uploadPath;
                    $config['allowed_types'] = '*';
                    $config['file_name'] = $fn;
                    $this->load->library('upload', $config);
                    $this->upload->initialize($config);
                    if($this->upload->do_upload('file')){
                        $uploadData = $this->upload->data();
                        $filename = $uploadData['file_name'];
                        if($i==0){$flink = $uploadPath.$filename;}
                        else{$flink = $flink.','.$uploadPath.$filename;}
                    }}}
                    $currentMonth = date('n');
                    $currentYear = date('Y');
                    if ($currentMonth < 4) {
                        $financialYearStart = ($currentYear - 1);
                        $financialYearEnd = $currentYear;
                    } else {
                        $financialYearStart = $currentYear;
                        $financialYearEnd = ($currentYear + 1);
                    }
                    $financialYear = $financialYearStart . '-' . $financialYearEnd;
        $db3 = $this->load->database('db3', TRUE);
        $db3->query("INSERT INTO `client_handover` (bd_id,client_name,client_id, mediator, noofschool, location, city, state, spd_identify_by, infrastructure, logo, contact_person, cp_mno, acontact_person, acp_mno, language, expected_installation_date, project_tenure,project_type,comments,remark,fttptype,project_year) VALUES ('$bdid','$client_name','$client_id', '$mediator', '$noofschool', '$location', '$city', '$state', '$spd_identify_by', '$infrastructure', '$flink', '$contact_person', '$cp_mno', '$acontact_person', '$acp_mno', '$language', '$expected_installation_date', '$project_tenure', '$project_type', '$comments','$remark','$fttptype','$financialYear')");
        $cid= $db3->insert_id();
        $l=sizeof($sid);
        for($i=0;$i<$l;$i++){
            $db3->query("Update spd set idebypi=pi_id, cid='$cid', pi_id=null where id='$sid[$i]'");
        }
        if($sname!=0){
            $l=sizeof($sname);
            for($i=0;$i<$l;$i++){
                $db3->query("INSERT INTO spd (sname,saddress,scity,sstate,cid) VALUES ('$sname[$i]','$saddress[$i]','$scity[$i]','$sstate[$i]','$cid')");
                $ssid = $db3->insert_id();
                $db3->query("INSERT INTO spd_contact (contact_name,designation,contact_no,main,sid) VALUES ('$scontact[$i]','$sdegignation[$i]','$snumber[$i]','1','$ssid')");
            }
        }
        $db3->query("INSERT INTO handoverlog (cid, taskby, remark) VALUES ('$cid','1','Handover From BD to Program Manager')");
        return $cid;
    }
