public function get_cbdtf($fopst, $topst, $cid, $this_financial_year, $select_cluster) {
    $user   = $this->session->userdata('user');
    $by_uid = $user['user_id'];
    $cfYear = $this->Menu_model->FindCurrentFinancialYear();

    $l = count($cid);  // sizeof is an alias, count is clearer
    $text_error_message   = '';
    $text_success_message = '';

    for ($i = 0; $i < $l; $i++) {
        $cmpid                      = $cid[$i];
        $this_financial_year_column = $this_financial_year[$i];
        $travel_cluster_id          = $select_cluster[$i];

        // --- Get init_call record for this company ---
        $query = $this->db->query("SELECT * FROM init_call WHERE cmpid_id = ?", [$cmpid]);
        $data  = $query->result();

        if (empty($data)) {
            $text_error_message .= "$i - No init_call record found for CID $cmpid.<br/>";
            continue;
        }

        $inid                = $data[0]->id;
        $cinit_call_cstatus  = $data[0]->cstatus;
        $cur_date            = date("Y-m-d");

        // --- Check if there is a future follow-up for the user ($fopst) on ANY other company ---
        $sql_nfhd = "
            SELECT
                next_folloup_have_date.*,
                company_master.id as cid,
                company_master.compname,
                init_call.id as init_call_id,
                init_call.cstatus as init_call_cstatus
            FROM next_folloup_have_date
            LEFT JOIN tblcallevents ON tblcallevents.id = next_folloup_have_date.tid
            LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            WHERE tblcallevents.cid_id != ?
                AND followup_new_task_id IS NOT NULL
                AND CAST(next_folloup_date AS DATE) > ?
                AND next_folloup_have_date.user_id = ?
        ";
        $query_nfhd = $this->db->query($sql_nfhd, [$inid, $cur_date, $fopst]);
        $datanfhd   = $query_nfhd->result();
        $datanfhdcnt = count($datanfhd);

        if ($datanfhdcnt > 0) {
            // There is a future follow-up → cannot transfer
            $next_folloup_have_date = $datanfhd[0]->next_folloup_date;
            $next_folloup_cid       = $datanfhd[0]->cid;
            $next_folloup_compname  = $datanfhd[0]->compname;

            $text_error_message .= "$i - CID $next_folloup_cid - $next_folloup_compname has a follow-up plan by the user on $next_folloup_have_date. This is the reason the lead was not transferred.<br/>";
            continue;
        }

        // --- No future follow-up → proceed with transfer ---

        // Update financial year column (dynamic column name – ensure it's safe)
        if (!empty($this_financial_year_column)) {
            $this->db->query("UPDATE init_call SET `$this_financial_year_column` = ? WHERE cmpid_id = ?", [$cfYear, $cmpid]);
        }

        // Update cluster & main BD
        $this->db->query("UPDATE init_call SET cluster_id = ? WHERE cmpid_id = ?", [$travel_cluster_id, $cmpid]);
        $this->db->query("UPDATE init_call SET mainbd = ? WHERE cmpid_id = ?", [$topst, $cmpid]);

        // Reset all role flags – FIXED missing comma after insidebd='0'
        $reset_sql = "
            UPDATE init_call SET
                apst = '0',
                insidebd = '0',
                ash_nae_co_id = '0',
                ash_w_co_id = '0',
                ash_s_co_id = '0',
                rm_east_co_id = '0',
                bpst = '0',
                rm_north_co_id = '0',
                acm_co_id = '0',
                clm_id = '0',
                assign_support = '0'
            WHERE cmpid_id = ?
        ";
        $this->db->query($reset_sql, [$cmpid]);

        if ($this->db->affected_rows() > 0) {
            // Determine new status based on RP meetings in the current financial year
            $meet_sql = "
                SELECT * FROM tblcallevents
                WHERE cid_id = ?
                    AND nextCFID != 0
                    AND (mtype = 'RP' OR mtype = 'RPClose' OR mtype = 'Change RP')
                    AND YEAR(appointmentdatetime) = ?
            ";
            $meetQuery = $this->db->query($meet_sql, [$inid, $cfYear]);
            $meetQueryDatas = $meetQuery->result();

            if (count($meetQueryDatas) > 0) {
                $new_updated_status = 8;  // RP Meetings exist
                $becauseof = "because of RP Meetings on Find Current Financial Year";
            } else {
                $new_updated_status = 1;  // No RP Meetings
                $becauseof = "because of No Meetings on Find Current Financial Year";
            }

            $new_updated_status_name = $this->Menu_model->get_statusbyid($new_updated_status)[0]->name;
            // Update status (preserve previous status in lstatus)
            $this->db->query("UPDATE init_call SET lstatus = cstatus, cstatus = ? WHERE cmpid_id = ?", [$new_updated_status, $cmpid]);

            // Delete related tasks that have no nextCFID (old tasks)
            $task_sql = "SELECT * FROM tblcallevents WHERE cid_id = ? AND user_id = ? AND assignedto_id = ? AND nextCFID = 0";
            $taskQuery = $this->db->query($task_sql, [$inid, $fopst, $fopst]);
            $taskQueryDatas = $taskQuery->result();

            foreach ($taskQueryDatas as $taskQueryData) {
                $task_id            = $taskQueryData->id;
                $task_actiontype_id = $taskQueryData->actiontype_id;
                $task_nextCFID      = $taskQueryData->nextCFID;

                if ($task_nextCFID == 0) {
                    if ($task_actiontype_id == 3 || $task_actiontype_id == 4 || $task_actiontype_id == 17) {
                        // Delete meeting
                        $this->db->query("DELETE FROM barginmeeting WHERE tid = ?", [$task_id]);
                        $this->db->query("DELETE FROM tblcallevents WHERE id = ?", [$task_id]);
                    } else {
                        $this->db->query("DELETE FROM tblcallevents WHERE id = ?", [$task_id]);
                    }
                }
            }

            // Log the transfer
            $init_call_cstatus_name = $this->Menu_model->get_statusbyid($cinit_call_cstatus)[0]->name;
            $log_data = [
                'cid'        => $cmpid,
                'from_uid'   => $fopst,
                'to_uid'     => $topst,
                'by_uid'     => $by_uid,
                'remarks'    => "Lead Transfer Successfully and status change - $init_call_cstatus_name to $new_updated_status_name. $becauseof",
                'old_status' => $cinit_call_cstatus,
                'new_status' => $new_updated_status
            ];
            $this->db->insert('funnel_transfer_log', $log_data);
        }
    }

    $this->session->set_flashdata('error_message', $text_error_message);
    // redirect('Menu/BDTOBDCTF');
}








    public function FindCurrentFinancialYear() {
                $currentMonth = date('n'); // Numeric representation of a month (1 to 12)
                $currentYear = date('Y');
                if ($currentMonth >= 4) {
                    // If current month is April (4) or later, financial year starts this year
                    $fyStart = $currentYear;
                    $fyEnd = $currentYear + 1;
                } else {
                    // If current month is Jan to Mar, financial year started last year
                    $fyStart = $currentYear - 1;
                    $fyEnd = $currentYear;
                }
                return $fyStart;
            }
