public function get_userbyaaid($uid){
    $utype = $this->Menu_model->get_userbyid($uid);
    $utype = $utype[0]->type_id;

    $where = "status='active'"; // common condition

    switch($utype){
        case 4:
            $where .= " AND pst_co='$uid' AND (type_id=3 OR type_id=13)";
            break;
        case 2:
            $where .= " AND admin_id='$uid'";
            break;
        case 13:
            $where .= " AND aadmin='$uid' AND type_id IN (3,24)";
            break;
        case 15:
            $where .= " AND sales_co='$uid' AND (type_id IN (3,4,13))";
            break;
        case 3:
            $where .= " AND user_id='$uid' AND type_id=3";
            break;
        case 19:
            $where .= " AND ash_nae_co='$uid'";
            break;
        case 20:
            $where .= " AND ash_w_co='$uid'";
            break;
        case 21:
            $where .= " AND ash_s_co='$uid'";
            break;
        case 22:
            $where .= " AND rm_east_co='$uid'";
            break;
        case 23:
            $where .= " AND rm_north_co='$uid'";
            break;
        case 24:
            $where .= " AND acm_co='$uid' AND type_id=3";
            break;
        default:
            // fallback: return the user itself
            $where .= " AND user_id='$uid'";
            break;
    }

    $query = $this->db->query("SELECT * FROM user_details WHERE $where");
    return $query->result();
}





