    public function get_pendingt($uid,$tdate){
        $query = $this->db->query("
        SELECT *
        FROM tblcallevents
        WHERE user_id='$uid'
        AND appointmentdatetime >= '$tdate 00:00:00'
        AND appointmentdatetime <= '$tdate 23:59:59'
        AND nextCFID=0
        ");

        return $query->result();
    }

    

    public function get_totalpt($uid,$tdate){
        $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,(SELECT name from status WHERE id=cstatus) csname, (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus WHERE (user_id='$uid' OR assignedto_id='$uid') and cast(appointmentdatetime AS DATE)='$tdate' and nextCFID='0' and plan!='1'");
        return $query->result();
    }
    public function get_totalt($uid,$tdate){
        $utype          = $this->Menu_model->get_userbyid($uid);
        $utype          = $utype[0]->type_id;
        $leftJoin       = '';
        $checkapproved  = '';
        if($utype ==3 || $utype ==4 || $utype ==13 || $utype ==24){
            $apr_status = "AND tblcallevents.approved_status = 1";
            $leftJoin = "INNER JOIN planner_approved on planner_approved.user_id = '$uid' AND planner_approved.request_date = '$tdate' AND planner_approved.approved_status = 1";
            // $checkapproved = "AND planner_approved.approved_status = 1";
        }else{
            $apr_status = '';
        }
        // $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,(SELECT name from status WHERE id=cstatus) csname, (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus WHERE (user_id='$uid' OR assignedto_id='$uid') and cast(appointmentdatetime AS DATE)='$tdate' and nextCFID='0' $apr_status ");
        $query = $this->db->query("SELECT 
        tblcallevents.*,
        status.name,
        action.name AS aname,
        status.color,
        status.clr,
        init_call.cstatus AS cstatus,
        status_cstatus.name AS csname,
        init_call.cmpid_id,
        company_master.compname,
        company_master.id AS cid
    FROM tblcallevents
    LEFT JOIN action ON action.id = tblcallevents.actiontype_id
    LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
    LEFT JOIN status ON status.id = init_call.cstatus
    LEFT JOIN status AS status_cstatus ON status_cstatus.id = init_call.cstatus
    LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
    $leftJoin
    WHERE 
        (tblcallevents.user_id = '$uid' OR tblcallevents.assignedto_id = '$uid')
        -- AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate'
        AND tblcallevents.appointmentdatetime >= '$tdate 00:00:00'
        AND tblcallevents.appointmentdatetime < '$tdate 23:59:59'
        AND tblcallevents.nextCFID = '0'
        $apr_status
");
        return $query->result();
    }



    public function get_totaltdetails($uid,$tdate){

        // $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,(SELECT name from status WHERE id=cstatus) csname, (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus WHERE (user_id='$uid' OR assignedto_id='$uid') and cast(appointmentdatetime AS DATE)='$tdate' and nextCFID='0' and plan=1");



        $query = $this->db->query("
                SELECT 
                    tblcallevents.id,
                    tblcallevents.user_id,
                    tblcallevents.assignedto_id,
                    tblcallevents.appointmentdatetime,
                    tblcallevents.nextCFID,
                    tblcallevents.plan,
                    action.name AS aname,
                    status.name,
                    status.color,
                    status.clr,
                    init_call.cstatus,
                    status_cs.name AS csname,
                    init_call.cmpid_id,
                    company_master.compname,
                    company_master.id AS cid
                FROM tblcallevents
                LEFT JOIN action 
                    ON action.id = tblcallevents.actiontype_id
                LEFT JOIN init_call 
                    ON init_call.id = tblcallevents.cid_id
                LEFT JOIN status 
                    ON status.id = init_call.cstatus
                LEFT JOIN status AS status_cs
                    ON status_cs.id = init_call.cstatus
                LEFT JOIN company_master 
                    ON company_master.id = init_call.cmpid_id
                WHERE 
                    (tblcallevents.user_id = '$uid' 
                    OR tblcallevents.assignedto_id = '$uid')
                    AND tblcallevents.appointmentdatetime >= '$tdate 00:00:00'
                    AND tblcallevents.appointmentdatetime < '$tdate 23:59:59'
                    AND tblcallevents.nextCFID = 0
                    AND tblcallevents.plan = 1
                ");

        return $query->result();
    }



    public function getTotalUserTaskDetails($uid,$tdate){
        $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,(SELECT name from status WHERE id=cstatus) csname, (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus WHERE (user_id='$uid' OR assignedto_id='$uid') and cast(appointmentdatetime AS DATE)='$tdate' and plan=1");
