    public function getTotalUserTaskDetailsOnPlanner($uid,$tdate){

        $query=$this->db->query("SELECT 
        tblcallevents.*,
        status.name,action.name aname,
        status.color,status.clr,init_call.cstatus cstatus,
        u2.name as bdname,
        init_call.cmpid_id as company_master_id,
        (SELECT name from status WHERE id=cstatus) csname, 
        (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,
        (select company_master.compname from company_master WHERE id=cmpid_id) as compname, 
        (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents 

        left JOIN action ON action.id=tblcallevents.actiontype_id 
        left JOIN init_call ON init_call.id=tblcallevents.cid_id 
        left JOIN status ON status.id=init_call.cstatus 
        left JOIN user_details u2 ON u2.user_id =init_call.mainbd 

        
        
        WHERE (tblcallevents.user_id='$uid' OR tblcallevents.assignedto_id = '$uid') 
        and cast(appointmentdatetime AS DATE)='$tdate' 
        and tblcallevents.plan=1 and tblcallevents.autotask =0 
        ORDER BY tblcallevents.appointmentdatetime
        
        ");

        return $query->result();
    }
    
    public function getTaskDetailsOnPlannerGraphDatas($uid,$tdate){
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    $start_financial_date_year = new DateTime($start_financial_date);
    $year = $start_financial_date_year->format('Y');
        $query = $this->db->query("SELECT
            status.name,
            COUNT(tblcallevents.id) as task_count
        FROM
            tblcallevents
        LEFT JOIN action ON action.id = tblcallevents.actiontype_id
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        LEFT JOIN status ON status.id = tblcallevents.status_id
        WHERE
            (tblcallevents.user_id = '$uid' OR tblcallevents.assignedto_id = '$uid') 
            AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' 
            AND tblcallevents.plan = 1 
            AND tblcallevents.autotask = 0
            GROUP BY status.id");
            $statusTask =  $query->result();
        $query1 = $this->db->query("SELECT
            action.name,
            COUNT(tblcallevents.id) as task_count
        FROM
            tblcallevents
        LEFT JOIN action ON action.id = tblcallevents.actiontype_id
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        LEFT JOIN status ON status.id = tblcallevents.status_id
        WHERE
            (tblcallevents.user_id = '$uid' OR tblcallevents.assignedto_id = '$uid') 
            AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' 
            AND tblcallevents.plan = 1 
            AND tblcallevents.autotask = 0
            GROUP BY action.id");
        $actionTask =  $query1->result();
            $cfData = $this->Menu_model->getCurrentFinancialYearAndQuarter();
            $currentQuarter = "Q".$cfData['quarter'];
            $in_quarter_20_Closure_Funnel = "20 Closure Funnel in $currentQuarter";
            $in_quarter_Potential_Funnel = "Potential Funnel For $currentQuarter";
            $in_quarter_To_be_Nurtured = "To be Nurtured for $currentQuarter";
        $query2 = $this->db->query("SELECT
        COUNT(CASE WHEN init_call.potential = 'yes' THEN 1 END) AS Potential_client,
        COUNT(CASE WHEN init_call.topspender = 'yes' THEN 1 END) AS Top_Spender,
        COUNT(CASE WHEN init_call.upsell_client = 'yes' THEN 1 END) AS Upsell_Client,
        COUNT(CASE WHEN init_call.focus_funnel = 'yes' THEN 1 END) AS Focus_Funnel,
        COUNT(CASE WHEN init_call.keycompany = 'yes' THEN 1 END) AS Key_Client,
        COUNT(CASE WHEN init_call.pkclient   = 'yes' THEN 1 END) AS Positive_Key_Client,
        COUNT(CASE WHEN init_call.priorityc = 'yes' THEN 1 END) AS Priority_Calling,
        COUNT(CASE WHEN init_call.q1_twetenty_closure_funnel = '$year' THEN 1 END) AS in_q1_twetenty_closure_funnel,
        COUNT(CASE WHEN init_call.potential_funnel_for_fy = '$year' THEN 1 END) AS in_potential_funnel_for_fy,
        COUNT(CASE WHEN init_call.to_be_nurtured_for_fy = '$year' THEN 1 END) AS in_to_be_nurtured_for_fy,
        COUNT(CASE WHEN init_call.fifity_new_lead_funnel = '$year' THEN 1 END) AS in_fifity_new_lead_funnel,
        
        COUNT(CASE WHEN init_call.in_quarter = '$in_quarter_20_Closure_Funnel' THEN 1 END) AS in_quarter_20_Closure_Funnel,
        COUNT(CASE WHEN init_call.in_quarter = '$in_quarter_Potential_Funnel' THEN 1 END) AS in_quarter_Potential_Funnel,
        COUNT(CASE WHEN init_call.in_quarter = '$in_quarter_To_be_Nurtured' THEN 1 END) AS in_quarter_To_be_Nurtured
        
FROM
    tblcallevents
