    COUNT(CASE WHEN actiontype_id = 6 THEN 1 END) * 10 +
    COUNT(CASE WHEN actiontype_id = 7 THEN 1 END) * 15 +
    COUNT(CASE WHEN actiontype_id = 8 THEN 1 END) * 5 +
    COUNT(CASE WHEN actiontype_id = 9 THEN 1 END) * 5 +
    COUNT(CASE WHEN actiontype_id = 10 THEN 1 END) * 5 +
    COUNT(CASE WHEN actiontype_id = 11 THEN 1 END) * 2 +
