        public function GetTommrowReviewTaskBYActionID($actionid, $bduid){
            $query = $this->db->query("
                SELECT 
                    main_review.*, 
                    company_master.compname,
                    tce.actiontype_id
                FROM main_review
                LEFT JOIN tblcallevents AS tce ON tce.id = main_review.ntid
                LEFT JOIN init_call ON init_call.id = main_review.inid
                LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
                WHERE main_review.for_uid = '$bduid'
                    AND main_review.taskplan = 0
                    AND tce.nextCFID = 0
                    AND tce.actontaken = 'no'
                    AND tce.purpose_achieved = 'no'
                    AND tce.actiontype_id = '$actionid'
                    AND CAST(tce.appointmentdatetime AS DATE) = DATE_ADD(CURDATE(), INTERVAL 1 DAY)
            ");

            return $query->result();
        }



