    public function get_ttbytime($uid, $tdate, $t1, $t2){
    $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
    $leftJoin = '';
    $apr_status = '';

    if(in_array($utype, [3,4,13,24])){
        $apr_status = "AND planner_approved.approved_status = 1";
        $leftJoin = "INNER JOIN planner_approved 
                     ON planner_approved.user_id = '$uid' 
                     AND planner_approved.request_date = '$tdate' 
                     AND planner_approved.approved_status = 1";
    }

    // Build datetime range to avoid CAST on table column
    $start_datetime = "$tdate $t1";
    $end_datetime   = "$tdate $t2";

    $query = $this->db->query("
        SELECT
            tblcallevents.*,
            status.name,
            status.color,
            status.clr AS status_text_color,
            init_call.cmpid_id,
            company_master.compname,
            company_master.id AS cid,
            action.name AS task_name
        FROM tblcallevents
        LEFT JOIN status ON status.id = tblcallevents.status_id
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN action ON action.id = tblcallevents.actiontype_id
        $leftJoin
        WHERE
            tblcallevents.assignedto_id = '$uid'
            AND tblcallevents.autotask = 0
            AND tblcallevents.nextCFID = 0
            AND tblcallevents.plan = 1
            AND tblcallevents.appointmentdatetime BETWEEN '$start_datetime' AND '$end_datetime'
            $apr_status
        ORDER BY tblcallevents.appointmentdatetime ASC
    ");

    return $query->result();
}






