    public function get_ttbytimec($uid, $tdate, $t1, $t2){
        // Build datetime ranges for the query
        $start_datetime = "$tdate $t1";
        $end_datetime   = "$tdate $t2";

        $query = $this->db->query("
            SELECT 
                tblcallevents.*,
                status.name,
                status.color,
                init_call.cmpid_id,
                company_master.compname,
                company_master.id AS cid
            FROM tblcallevents
            JOIN status ON status.id = tblcallevents.status_id
            LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            WHERE 
                (
                    tblcallevents.assignedto_id = '$uid' AND tblcallevents.user_id = '$uid'
                ) 
                AND tblcallevents.updateddate >= '$start_datetime'
                AND tblcallevents.updateddate <= '$end_datetime'
                AND tblcallevents.nextCFID != 0
                AND tblcallevents.plan = 1
            ORDER BY tblcallevents.appointmentdatetime ASC
        ");

        return $query->result();
    }



