    public function get_ttbytimecAutotask1($uid, $tdate, $t1, $t2){
    // Build datetime range
    $start_datetime = "$tdate $t1";
    $end_datetime   = "$tdate $t2";

    $query = $this->db->query("
        SELECT 
            tb.*,
            status.name,
            status.color,
            init_call.cmpid_id,
            company_master.compname,
            company_master.id AS cid
        FROM tblcallevents tb
        JOIN status ON status.id = tb.status_id
        LEFT JOIN init_call ON init_call.id = tb.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        WHERE 
            tb.assignedto_id = '$uid'
            AND tb.updateddate >= '$start_datetime'
            AND tb.updateddate <= '$end_datetime'
            AND tb.nextCFID != 0
            AND tb.plan = 1
            AND tb.autotask = 1
            AND tb.appointmentdatetime != '0000-00-00 00:00:00'
        ORDER BY tb.appointmentdatetime ASC
    ");

    return $query->result();
}



