    public function get_ttbytimed($uid, $tdate, $t1, $t2){
    $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
    $leftJoin = '';
    $apr_status = '';

    if(in_array($utype, [3,4,13,24])){
        $apr_status = "AND planner_approved.approved_status = 1";
        $leftJoin = "INNER JOIN planner_approved 
                     ON planner_approved.user_id = '$uid' 
                     AND planner_approved.request_date = '$tdate' 
                     AND planner_approved.approved_status = 1";
    }

    // Build datetime range for the BETWEEN clause to avoid CAST
    $start_datetime = "$tdate $t1";
    $end_datetime   = "$tdate $t2";

    $query = $this->db->query("
        SELECT 
            COUNT(*) AS ab,
            COUNT(CASE WHEN actiontype_id = 1 THEN 1 END) AS a,
            COUNT(CASE WHEN actiontype_id = 2 THEN 1 END) AS b,
            COUNT(CASE WHEN actiontype_id = 3 THEN 1 END) AS c,
            COUNT(CASE WHEN actiontype_id = 4 THEN 1 END) AS d,
            COUNT(CASE WHEN actiontype_id = 5 THEN 1 END) AS e,
            COUNT(CASE WHEN actiontype_id = 6 THEN 1 END) AS f,
            COUNT(CASE WHEN actiontype_id = 7 THEN 1 END) AS g,
            COUNT(CASE WHEN actiontype_id = 8 THEN 1 END) AS h,
            COUNT(CASE WHEN actiontype_id = 9 THEN 1 END) AS i,
            COUNT(CASE WHEN actiontype_id = 10 THEN 1 END) AS j,
            COUNT(CASE WHEN actiontype_id = 11 THEN 1 END) AS k,
            COUNT(CASE WHEN actiontype_id = 12 THEN 1 END) AS l,
            COUNT(CASE WHEN actiontype_id = 13 THEN 1 END) AS m,
            COUNT(CASE WHEN actiontype_id = 22 THEN 1 END) AS vm
        FROM tblcallevents
        $leftJoin
        WHERE 
            tblcallevents.assignedto_id = '$uid'
            AND tblcallevents.nextCFID = 0
            AND tblcallevents.autotask = 0
            AND tblcallevents.plan = 1
            AND tblcallevents.appointmentdatetime BETWEEN '$start_datetime' AND '$end_datetime'
            $apr_status
    ");

    return $query->result();
}




    public function get_ttbytimedAutotask($uid,$tdate,$t1,$t2){
        // $utype = $this->Menu_model->get_userbyid($uid);
        // $utype = $utype[0]->type_id;
        // if($utype ==3){
        //     $apr_status = "and approved_status = 1";
        // }else{
        //     $apr_status = '';
        // }
        $query=$this->db->query("SELECT COUNT(*) AS ab, 
        COUNT(CASE WHEN actiontype_id = 1 THEN 1 END) AS a, 
        COUNT(CASE WHEN actiontype_id = 2 THEN 1 END) AS b, 
        COUNT(CASE WHEN actiontype_id = 3 THEN 1 END) AS c, 
        COUNT(CASE WHEN actiontype_id = 4 THEN 1 END) AS d, 
        COUNT(CASE WHEN actiontype_id = 5 THEN 1 END) AS e, 
        COUNT(CASE WHEN actiontype_id = 6 THEN 1 END) AS f, 
        COUNT(CASE WHEN actiontype_id = 7 THEN 1 END) AS g, 
        COUNT(CASE WHEN actiontype_id = 8 THEN 1 END) AS h, 
        COUNT(CASE WHEN actiontype_id = 9 THEN 1 END) AS i, 
        COUNT(CASE WHEN actiontype_id = 10 THEN 1 END) AS j, 
        COUNT(CASE WHEN actiontype_id = 11 THEN 1 END) AS k, 
        COUNT(CASE WHEN actiontype_id = 12 THEN 1 END) AS l, 
        COUNT(CASE WHEN actiontype_id = 13 THEN 1 END) AS m FROM tblcallevents WHERE CAST(appointmentdatetime AS DATE) = '$tdate' AND (assignedto_id ='$uid' || user_id ='$uid') AND autotask = 1 AND nextCFID = 0 AND plan = 1 AND CAST(appointmentdatetime AS TIME) BETWEEN '$t1' AND '$t2'");
        return $query->result();
    }
    public function get_ttbytimedAutotaskCount($uid){
        $query=$this->db->query("SELECT COUNT(*) AS ab, COUNT(CASE WHEN actiontype_id = 1 THEN 1 END) AS a, COUNT(CASE WHEN actiontype_id = 2 THEN 1 END) AS b, COUNT(CASE WHEN actiontype_id = 3 THEN 1 END) AS c, COUNT(CASE WHEN actiontype_id = 4 THEN 1 END) AS d, COUNT(CASE WHEN actiontype_id = 5 THEN 1 END) AS e, COUNT(CASE WHEN actiontype_id = 6 THEN 1 END) AS f, COUNT(CASE WHEN actiontype_id = 7 THEN 1 END) AS g, COUNT(CASE WHEN actiontype_id = 8 THEN 1 END) AS h, COUNT(CASE WHEN actiontype_id = 9 THEN 1 END) AS i, COUNT(CASE WHEN actiontype_id = 10 THEN 1 END) AS j, COUNT(CASE WHEN actiontype_id = 11 THEN 1 END) AS k, COUNT(CASE WHEN actiontype_id = 12 THEN 1 END) AS l, COUNT(CASE WHEN actiontype_id = 13 THEN 1 END) AS m FROM tblcallevents WHERE  autotask = 1 AND (assignedto_id ='$uid' || user_id ='$uid') AND nextCFID = 0 AND plan = 1 AND DATE(appointmentdatetime) < CURDATE() AND appointmentdatetime != '0000-00-00 00:00:00'");
        return $query->result();
    }
     public function get_ttbytimeAutotaskData($uid){
      //  $query=$this->db->query("SELECT tblcallevents.*,status.name,status.color,(select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents JOIN status ON status.id=tblcallevents.status_id WHERE assignedto_id='$uid' and autotask=1 and nextCFID=0 and plan=1 and DATE(appointmentdatetime) < CURDATE() AND appointmentdatetime != '0000-00-00 00:00:00'");
          $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,
    (SELECT name from status WHERE id=cstatus) csname,
    (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,
    (select company_master.compname from company_master WHERE id=cmpid_id) as compname,
    (select company_master.id from company_master WHERE id=cmpid_id) as cid 
   FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id
   left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus 
   WHERE nextCFID = 0 AND (assignedto_id='$uid' || user_id='$uid') AND autotask=1 and plan =1 AND DATE(appointmentdatetime) < CURDATE()
     AND appointmentdatetime != '0000-00-00 00:00:00'");
        return $query->result();
    }
