public function GetUserTotalPendingAutoTaskList($uid, $tdate, $t1, $t2){
    $start_datetime = "$tdate $t1";
    $end_datetime   = "$tdate $t2";

    $query = $this->db->query("
        SELECT
            tbcl.*,
            status.name,
            status.color,
            status.clr AS status_text_color,
            init_call.cmpid_id,
            company_master.compname,
            company_master.id AS cid,
            action.name AS task_name
        FROM tblcallevents tbcl
        LEFT JOIN status ON status.id = tbcl.status_id
        LEFT JOIN init_call ON init_call.id = tbcl.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN action ON action.id = tbcl.actiontype_id
        WHERE
            tbcl.user_id = '$uid'
            AND tbcl.nextCFID = 0
            AND tbcl.plan = 1
            AND tbcl.autotask = 1
            AND tbcl.appointmentdatetime != '0000-00-00 00:00:00'
            AND tbcl.appointmentdatetime BETWEEN '$start_datetime' AND '$end_datetime'
            AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)
            AND (tbcl.approved_status = 1 OR tbcl.approved_status = '')
        ORDER BY tbcl.appointmentdatetime ASC
    ");

    return $query->result();
}




    
    
