            COALESCE(SUM(actiontype_id = 9), 0) AS i,
            COALESCE(SUM(actiontype_id = 10), 0) AS j,
            COALESCE(SUM(actiontype_id = 11), 0) AS k,
            COALESCE(SUM(actiontype_id = 12), 0) AS l,
            COALESCE(SUM(actiontype_id = 13), 0) AS m,
