            COALESCE(SUM(actiontype_id = 24), 0) AS sv,
            COALESCE(SUM(actiontype_id = 25), 0) AS rns,
            COALESCE(SUM(actiontype_id = 26), 0) AS callons,

            COALESCE(SUM(actiontype_id IN (19, 20)), 0) AS n


        FROM tblcallevents
        $leftJoin
        WHERE tblcallevents.assignedto_id = '$uid'
          AND tblcallevents.appointmentdatetime >= '$tdate 00:00:00'
          AND tblcallevents.appointmentdatetime <  '$tdate 23:59:59'
          AND tblcallevents.nextCFID = 0
          AND tblcallevents.plan = 1
          $apr_status
    ");

    return $query->result();
}



