        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        
        $leftJoin = '';
        if($utype == 3){
            $apr_status = "AND tblcallevents.approved_status = 1";
            $leftJoin = "INNER JOIN planner_approved on planner_approved.user_id = '$uid' AND planner_approved.request_date = '$tdate' AND planner_approved.approved_status = 1";
        }else{
            $apr_status = '';
        }
        // $query=$this->db->query("SELECT COUNT(*) a,count(CASE WHEN nextCFID=0 THEN nextCFID end) b,count(CASE WHEN nextCFID!=0 THEN nextCFID end) c, count(CASE WHEN actiontype_id=1 THEN actiontype_id end) d,count(CASE WHEN actiontype_id=1 and nextCFID=0 THEN actiontype_id end) e,count(CASE WHEN actiontype_id=2 THEN actiontype_id end) f,count(CASE WHEN actiontype_id=2 and nextCFID=0 THEN actiontype_id end) g,count(CASE WHEN actiontype_id=3 THEN actiontype_id end) h,count(CASE WHEN actiontype_id=3 and nextCFID=0 THEN actiontype_id end) i,count(CASE WHEN actiontype_id=4 THEN actiontype_id end) j,count(CASE WHEN actiontype_id=4 and nextCFID=0 THEN actiontype_id end) k,count(CASE WHEN actiontype_id=5 THEN actiontype_id end) l,count(CASE WHEN actiontype_id=5 and nextCFID=0 THEN actiontype_id end) m,count(CASE WHEN actiontype_id=6 THEN actiontype_id end) n,count(CASE WHEN actiontype_id=6 and nextCFID=0 THEN actiontype_id end) o,count(CASE WHEN actiontype_id=7 THEN actiontype_id end) p,count(CASE WHEN actiontype_id=7 and nextCFID=0 THEN actiontype_id end) q,count(CASE WHEN actiontype_id=10 THEN actiontype_id end) na,count(CASE WHEN actiontype_id=10 and nextCFID=0 THEN actiontype_id end) nb,count(CASE WHEN actiontype_id=11 THEN actiontype_id end) nc,count(CASE WHEN actiontype_id=11 and nextCFID=0 THEN actiontype_id end) nd,count(CASE WHEN actiontype_id=12 THEN actiontype_id end) ne,count(CASE WHEN actiontype_id=12 and nextCFID=0 THEN actiontype_id end) nf,count(CASE WHEN actontaken='yes' and nextCFID!=0 THEN actiontype_id end) r,count(CASE WHEN actontaken='no' and nextCFID!=0 THEN actiontype_id end) s,count(CASE WHEN purpose_achieved='yes' and nextCFID!=0 THEN actiontype_id end) t,count(CASE WHEN purpose_achieved='no' and nextCFID!=0 THEN actiontype_id end) u FROM tblcallevents WHERE assignedto_id='$uid' and cast(appointmentdatetime AS DATE)='$tdate' and plan=1 $apr_status");
        $query=$this->db->query("SELECT 
    COUNT(*) AS a,
    -- NextCFID based
    COUNT(CASE WHEN nextCFID = 0 THEN nextCFID END) AS b,
    COUNT(CASE WHEN nextCFID != 0 THEN nextCFID END) AS c,
    
    -- Action Type Counts
    COUNT(CASE WHEN actiontype_id = 1 THEN actiontype_id END) AS d,
    COUNT(CASE WHEN actiontype_id = 1 AND nextCFID = 0 THEN actiontype_id END) AS e,
    
    COUNT(CASE WHEN actiontype_id = 2 THEN actiontype_id END) AS f,
    COUNT(CASE WHEN actiontype_id = 2 AND nextCFID = 0 THEN actiontype_id END) AS g,
    
    COUNT(CASE WHEN actiontype_id = 3 THEN actiontype_id END) AS h,
    COUNT(CASE WHEN actiontype_id = 3 AND nextCFID = 0 THEN actiontype_id END) AS i,
    
    COUNT(CASE WHEN actiontype_id = 4 THEN actiontype_id END) AS j,
    COUNT(CASE WHEN actiontype_id = 4 AND nextCFID = 0 THEN actiontype_id END) AS k,
    
    COUNT(CASE WHEN actiontype_id = 5 THEN actiontype_id END) AS l,
    COUNT(CASE WHEN actiontype_id = 5 AND nextCFID = 0 THEN actiontype_id END) AS m,
    
    COUNT(CASE WHEN actiontype_id = 6 THEN actiontype_id END) AS n,
    COUNT(CASE WHEN actiontype_id = 6 AND nextCFID = 0 THEN actiontype_id END) AS o,
    
    COUNT(CASE WHEN actiontype_id = 7 THEN actiontype_id END) AS p,
    COUNT(CASE WHEN actiontype_id = 7 AND nextCFID = 0 THEN actiontype_id END) AS q,
    
    COUNT(CASE WHEN actiontype_id = 10 THEN actiontype_id END) AS na,
    COUNT(CASE WHEN actiontype_id = 10 AND nextCFID = 0 THEN actiontype_id END) AS nb,
    
    COUNT(CASE WHEN actiontype_id = 11 THEN actiontype_id END) AS nc,
    COUNT(CASE WHEN actiontype_id = 11 AND nextCFID = 0 THEN actiontype_id END) AS nd,
    
    COUNT(CASE WHEN actiontype_id = 12 THEN actiontype_id END) AS ne,
    COUNT(CASE WHEN actiontype_id = 12 AND nextCFID = 0 THEN actiontype_id END) AS nf,
    -- Action Taken Flags
    COUNT(CASE WHEN actontaken = 'yes' AND nextCFID != 0 THEN actiontype_id END) AS r,
    COUNT(CASE WHEN actontaken = 'no'  AND nextCFID != 0 THEN actiontype_id END) AS s,
    -- Purpose Achieved Flags
    COUNT(CASE WHEN purpose_achieved = 'yes' AND nextCFID != 0 THEN actiontype_id END) AS t,
    COUNT(CASE WHEN purpose_achieved = 'no'  AND nextCFID != 0 THEN actiontype_id END) AS u
FROM 
    tblcallevents
    $leftJoin
WHERE 
    tblcallevents.assignedto_id = '$uid'
    AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate'
    AND tblcallevents.plan = 1
    $apr_status");
        return $query->result();
    }





