public function get_tbmeetdbyaid($uid, $tdate) {
    $utype = $this->Menu_model->get_userbyid($uid);
    $utype = $utype[0]->type_id;

    // Determine which users to filter
    switch ($utype) {
        case 1:
            $text = "user_details.sadmin_id='$uid' AND user_details.status='active'";
            break;
        case 2:
            $text = "user_details.admin_id='$uid' AND user_details.status='active'";
            break;
        case 3:
            $text = "user_details.user_id='$uid' AND user_details.status='active'";
            break;
        case 4:
            $text = "user_details.pst_co='$uid' AND user_details.status='active'";
            break;
        case 13:
            $text = "user_details.aadmin='$uid' AND user_details.user_id='$uid' AND user_details.status='active'";
            break;
        case 15:
            $text = "user_details.sales_co='$uid' AND user_details.status='active'";
            break;
        case 17:
            $text = "user_details.type_id='3' AND user_details.status='active'";
            break;
        case 19:
            $text = "user_details.ash_nae_co='$uid' AND user_details.status='active'";
            break;
        case 20:
            $text = "user_details.ash_w_co='$uid' AND user_details.status='active'";
            break;
        case 21:
            $text = "user_details.ash_s_co='$uid' AND user_details.status='active'";
            break;
        case 22:
            $text = "user_details.rm_east_co='$uid' AND user_details.status='active'";
            break;
        case 23:
            $text = "user_details.rm_north_co='$uid' AND user_details.status='active'";
            break;
        case 24:
            $text = "user_details.acm_co='$uid' AND user_details.user_id='$uid' AND user_details.status='active'";
            break;
        default:
            $text = "user_details.user_id='$uid' AND user_details.status='active'";
    }

    $apr_status = ($utype == 3) ? "AND barginmeeting.approved_status = 1" : "";

    $query = $this->db->query("
        SELECT 
            COUNT(*) AS ab,
            COUNT(CASE WHEN barginmeeting.status='Pending' THEN 1 END) AS a,
            COUNT(CASE WHEN barginmeeting.status='Start' THEN 1 END) AS b,
            COUNT(CASE WHEN barginmeeting.status='Close' THEN 1 END) AS c,
            COUNT(CASE WHEN tblcallevents.mtype IN ('RP','RPClose','Change RP') THEN 1 END) AS d,
            COUNT(CASE WHEN tblcallevents.mtype='NO RP' THEN 1 END) AS e,
            COUNT(CASE WHEN tblcallevents.priority='yes' THEN 1 END) AS f,
            COUNT(CASE WHEN tblcallevents.priority='no' THEN 1 END) AS g,
            COUNT(CASE WHEN barginmeeting.status='RPClose' THEN 1 END) AS h,
            COUNT(CASE WHEN barginmeeting.status!='Pending' THEN 1 END) AS i,
            COUNT(CASE WHEN tblcallevents.mtype='Only Got Detail' THEN 1 END) AS k
        FROM tblcallevents
        LEFT JOIN barginmeeting ON barginmeeting.tid = tblcallevents.id
        LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id
        WHERE $text
          AND CAST(barginmeeting.storedt AS DATE) = '$tdate'
          $apr_status
    ");

    return $query->result();
}





