        $query=$this->db->query("SELECT tblcallevents.*, barginmeeting.*, user_details.*, tblcallevents.id AS tid, tblcallevents.cid_id AS cid, ( SELECT COUNT(id) FROM tblcallevents WHERE tblcallevents.cid_id = cid AND id > tid AND mom != '' ) AS momc FROM tblcallevents LEFT JOIN barginmeeting ON barginmeeting.tid = tblcallevents.id LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id WHERE $text AND (tblcallevents.mtype = 'RP' OR tblcallevents.mtype = 'RPClose' OR tblcallevents.mtype = 'Change RP') AND CAST(barginmeeting.startm AS DATE) BETWEEN '$sdate' AND '$edate' AND nextCFID != '0' AND tblcallevents.cid_id IN ( SELECT cid_id FROM tblcallevents WHERE CAST(barginmeeting.startm AS DATE) BETWEEN '$sdate' AND '$edate' GROUP BY cid_id HAVING COUNT(*) > 1 )");
