    public function get_tteaamtd($uid, $tdate) {
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
    
        $common_select = "
            SELECT 
                COUNT(CASE WHEN tblcallevents.approved_status = 1 THEN 1 END) a,
                COUNT(CASE WHEN nextCFID=0 AND tblcallevents.approved_status = 1 THEN 1 END) b,
                COUNT(CASE WHEN nextCFID!=0 AND tblcallevents.approved_status = 1 THEN 1 END) c,
                COUNT(CASE WHEN actiontype_id=1 THEN 1 END) d,
                COUNT(CASE WHEN actiontype_id=1 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) e,
                COUNT(CASE WHEN actiontype_id=2 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) f,
                COUNT(CASE WHEN actiontype_id=2 AND nextCFID != 0 THEN 1 END) g,
                COUNT(CASE WHEN actiontype_id=3 THEN 1 END) h,
                COUNT(CASE WHEN actiontype_id=3 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) i,
                COUNT(CASE WHEN actiontype_id=4 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) j,
                COUNT(CASE WHEN actiontype_id=4 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) k,
                COUNT(CASE WHEN actiontype_id=5 THEN 1 END) l,
                COUNT(CASE WHEN actiontype_id=5 AND nextCFID != 0 AND tblcallevents.approved_status = 1 THEN 1 END) m,
                COUNT(CASE WHEN actiontype_id=6 THEN 1 END) n,
                COUNT(CASE WHEN actiontype_id=6 AND nextCFID != 0 THEN 1 END) o,
                COUNT(CASE WHEN actiontype_id=7 THEN 1 END) p,
                COUNT(CASE WHEN actiontype_id=7 AND nextCFID!=0 THEN 1 END) q,
                COUNT(CASE WHEN actontaken='yes' AND nextCFID!=0 THEN 1 END) r,
                COUNT(CASE WHEN actontaken='no' AND nextCFID!=0 THEN 1 END) s,
                COUNT(CASE WHEN purpose_achieved='yes' AND nextCFID!=0 AND tblcallevents.approved_status = 1 THEN 1 END) t,
                COUNT(CASE WHEN purpose_achieved='no' AND nextCFID!=0 AND tblcallevents.approved_status = 1 THEN 1 END) u
            FROM tblcallevents 
            LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id
            WHERE 
                CAST(appointmentdatetime AS DATE) = '$tdate' 
                AND plan = 1
                AND user_details.status = 'active'
        ";
    
        // Build dynamic condition
        $user_condition = "";
    
        if ($utype == 4) {
            $user_condition = "(user_details.pst_co='$uid' || user_details.user_id='$uid')";
        } elseif ($utype == 19) {
            $user_condition = "(user_details.ash_nae_co='$uid' OR user_details.user_id='$uid')";
        } elseif ($utype == 20) {
            $user_condition = "(user_details.ash_w_co='$uid' OR user_details.user_id='$uid')";
        } elseif ($utype == 21) {
            $user_condition = "(user_details.ash_s_co='$uid' OR user_details.user_id='$uid')";
        } elseif ($utype == 22) {
            $user_condition = "(user_details.rm_east_co='$uid' OR user_details.user_id='$uid')";
        } elseif ($utype == 23) {
            $user_condition = "(user_details.rm_north_co='$uid' OR user_details.user_id='$uid')";
        } elseif ($utype == 24) {
            $user_condition = "(user_details.acm_co='$uid' OR user_details.user_id='$uid')";
        }elseif ($utype == 2) {
            $user_condition = "(user_details.admin_id='$uid' OR user_details.user_id='$uid')";
        }elseif ($utype == 3) {
            $user_condition = "user_details.user_id='$uid'";
        }elseif ($utype == 15) {
            $user_condition = "(user_details.sales_co='$uid' OR user_details.user_id='$uid')";
        }elseif ($utype == 13) {
           $user_condition = "(user_details.aadmin='$uid' || user_details.user_id='$uid')";
        }else {
            $user_condition = "(user_details.user_id='$uid')";
        }
    
        // Final query
        $query = $this->db->query($common_select . " AND ($user_condition)");
        // echo $this->db->last_query();
    
        return $query->result();
    }
    
