    public function get_AllProposalDetailbyadmin($uid){
        $month = date('n'); // Current month as a number (1-12)
        $year = date('Y');  // Current year (4 digits)
        if ($month >= 4) {
            // If it's April or later, financial year starts from 1st April this year
            $financialYearStart = date('Y-04-01');
        } else {
            // If it's January, February, March, financial year started 1st April last year
            $financialYearStart = date('Y-04-01', strtotime('-1 year'));
        }
        $query=$this->db->query("SELECT
    *,
    company_master.id AS cid,
    company_master.compname,
    user_details.name as bdname,
    (
    SELECT
        COUNT(t2.id)
    FROM
        tblcallevents t2
    WHERE
        t2.nextCFID != '0' AND t2.cid_id = t1.cid_id AND t2.updateddate > '$financialYearStart'
) AS LOGS
FROM
    proposal
LEFT JOIN tblcallevents t1 ON t1.id = proposal.tid
LEFT JOIN user_details ON user_details.user_id = proposal.user_id
LEFT JOIN init_call ON init_call.id = t1.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
WHERE
    user_details.admin_id = '$uid'
ORDER BY
    `proposal`.`id`
DESC");
        
        
        return $query->result();
    }
