    public function in_dtime($tid){
        $initQuerys = $this->db->query("SELECT * FROM `tblcallevents` WHERE id = '$tid'");
        $tblDatas =  $initQuerys->result();
        if(sizeof($tblDatas) > 0){
            $initiateddt = $tblDatas[0]->initiateddt;   
            if ($initiateddt === null || $initiateddt === '') {
                $date = date('Y-m-d H:i:s');
                $query=$this->db->query("update tblcallevents set initiateddt='$date' WHERE id='$tid'");
            }
        }
    }
