    public function get_daydbyAadmins($uid, $tdate){
    $query = $this->db->query("
        SELECT 
            (SELECT COUNT(*) 
             FROM user_details 
             WHERE aadmin='$uid' AND status='active' AND type_id IN (3,24) AS a,
            COUNT(*) AS b,
            COUNT(CASE WHEN wffo=1 THEN 1 END) AS c,
            COUNT(CASE WHEN wffo=2 THEN 1 END) AS d,
            COUNT(CASE WHEN wffo=3 THEN 1 END) AS e
        FROM user_day
        LEFT JOIN user_details ON user_details.user_id = user_day.user_id
        WHERE CAST(ustart AS DATE) = '$tdate' 
          AND user_details.aadmin = '$uid'
    ");
    return $query->result();
}



