    public function check_days($rat1,$rat2,$rat3,$rat4,$sremark,$udid,$que){
        $q1 = $que[0].'('.$rat1.' Star)';
        $q2 = $que[1].'('.$rat2.' Star)';
        $q3 = $que[2].'('.$rat3.' Star)';
        $q4 = $que[3].'('.$rat4.' Star)';
        $queans=$q1.','.$q2.','.$q3.','.$q4;
        $this->db->query("update user_day set queans='$queans', scomment='$sremark' where user_id='$udid'");
    }
