    public function GetTodaysVirtualMeeting($uid, $tdate)
{
    $utype = $this->Menu_model->get_userbyid($uid);
    $utype = $utype[0]->type_id;

    $leftJoin = "";

    // planner approval only for selected roles
    if (in_array($utype, [3, 4, 13, 24])) {
        $leftJoin = "INNER JOIN planner_approved 
            ON planner_approved.user_id = '$uid'
            AND planner_approved.request_date = '$tdate'
            AND planner_approved.approved_status = 1";
    }

    $start = $tdate . " 00:00:00";
    $end   = $tdate . " 23:59:59";

    $query = $this->db->query("
        SELECT 
            barginmeeting.*,
            tblcallevents.delete_request
        FROM barginmeeting

        LEFT JOIN tblcallevents 
            ON tblcallevents.id = barginmeeting.tid

        $leftJoin

        WHERE 
            barginmeeting.user_id = '$uid'
            AND barginmeeting.storedt >= '$start'
            AND barginmeeting.storedt <= '$end'
            AND tblcallevents.actiontype_id = 22
            AND (tblcallevents.delete_request IS NULL OR tblcallevents.delete_request = '')
            AND barginmeeting.approved_status = 1

        ORDER BY barginmeeting.id DESC
    ");

    return $query->result();
}




