    public function submit_task($tid,$uid,$cmpid,$actontaken,$action_id,$status,$remark,$rpmmom,$purpose,$flink,$flink1,$flink2,$partner,$noofsc,$pbudgetme,$LinkedIn,$Facebook,$YouTube,$Instagram,$OtherSocial,$nadate,$no_of_school,$revenue,$attachment_flink){
        date_default_timezone_set("Asia/Kolkata");
        $date = date('Y-m-d H:i:s');
        $query=$this->db->query("SELECT cstatus,init_call.id inid ,init_call.cmpid_id as cmpid_id FROM tblcallevents left join init_call on init_call.id=tblcallevents.cid_id WHERE tblcallevents.id='$tid'");
        $data = $query->result();
        $cs = $data[0]->cstatus;
        $inid = $data[0]->inid;
        $cmpid_id   = $data[0]->cmpid_id;
        if($actontaken=='no'){
            $this->db->query("INSERT INTO tblcallevents (fwd_date,appointmentdatetime,actiontype_id,assignedto_id,cid_id,purpose_id,status_id,user_id,lastCFID,nextCFID) SELECT '$date','$date',actiontype_id,'$uid',cid_id,purpose_id,status_id,'$uid','0','0' FROM tblcallevents WHERE id='$tid'");
            $ntid =  $this->db->insert_id();
            $this->db->query("UPDATE tblcallevents SET remarks='$remark',nextCFID='$ntid',updateddate='$date',status_id='$cs',nstatus_id='$cs',actontaken='no',purpose_achieved='no',updation_data_type='update' WHERE id='$tid'");
            return $ntid;
        }
        else{
               if($purpose=='no'){
