      //  return ['error' => $error];
    }
    }




    public function uploadWorkOrderfile($fieldName, $uploadPath)

{
    // Check if uploaded field exists
    if (!isset($_FILES[$fieldName]) || empty($_FILES[$fieldName]['name'])) {
        return ['error' => 'No file uploaded'];
    }

    // Copy real file values into CI-friendly "file"
    $_FILES['file']['name']     = $_FILES[$fieldName]['name'];
    $_FILES['file']['type']     = $_FILES[$fieldName]['type'];
    $_FILES['file']['tmp_name'] = $_FILES[$fieldName]['tmp_name'];
    $_FILES['file']['error']    = $_FILES[$fieldName]['error'];
    $_FILES['file']['size']     = $_FILES[$fieldName]['size'];

    // Unique file name
    $extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);
    $uniqueFileName = date("Y-m-d") . time() . '_' . uniqid() . '.' . $extension;

    // Upload path
    $uploadPath = rtrim($uploadPath, '/') . '/';

    $config = [
        'upload_path'   => $uploadPath,
        'allowed_types' => '*',
        'file_name'     => $uniqueFileName,
    ];

    $this->load->library('upload');
    $this->upload->initialize($config);

    // Upload now
    if ($this->upload->do_upload('file')) {

        $uploadData = $this->upload->data();
        $filePath = $uploadPath . $uploadData['file_name'];

        // Compress only if image
        if (in_array(strtolower($extension), ['jpg','jpeg','png'])) {
            $this->CompressAndReUploadImageWhenIsExists($filePath, $uploadPath);
        }

        return $filePath;
    }

    // Upload failed
    return [
        'error' => $this->upload->display_errors('', '')
    ];
}









