    public function hand_Delete($aprid){

        $db3 = $this->load->database('db3', TRUE);

        $query=$db3->query("Delete FROM client_handover where id='$aprid'");
        $query=$db3->query("Delete FROM handover_account where handover_id='$aprid'");

        $bdrequestQuery         = $db3->query("SELECT * FROM `bdrequest` WHERE ch_id = '$aprid'");
        $bdrequestQueryDatas    =  $bdrequestQuery->result();
        if(sizeof($bdrequestQueryDatas) > 0){

            $bdrequestQueryDatasID  = $bdrequestQueryDatas[0]->id;
            $bdrLocationequestQuery = $db3->query("SELECT * FROM `bdrequest_location` WHERE bdr_id = '$bdrequestQueryDatasID'");
            $bdrequestLocationQueryDatas =  $bdrLocationequestQuery->result();

            if(sizeof($bdrequestLocationQueryDatas) > 0){
                foreach($bdrequestLocationQueryDatas as $bdrequestLocationQueryData){
                    $bdrequestLocationID = $bdrequestLocationQueryData->id;
                    $db3->query("Delete FROM bdrequest_location where id='$bdrequestLocationID'");
                }
            }

            $bdrRequestSchoolQuery = $db3->query("SELECT * FROM `spd_request` WHERE ch_id = '$aprid'");
            $bdrRequestSchoolDatas =  $bdrRequestSchoolQuery->result();

            $user           = $this->session->userdata('user');
            $uid            = $user['user_id'];
            $uname          = $user['name'];
            $current_date   = date("Y-m-d H:i:s");

            if(sizeof($bdrRequestSchoolDatas) > 0){
                foreach($bdrRequestSchoolDatas as $bdrRequestSchoolData){
                    $request_spd_id = $bdrRequestSchoolData->id;
                    $sname          = $bdrRequestSchoolData->sname;
                    $bdrid          = $bdrRequestSchoolData->bdrid;

                        $data = array(
                            'pi_id'         => 0,
                            'ins_id'        => 0,
                            'bd_id'         => 0,
                            'pro_id'        => 0,
                            'sales_co'      => 0,
                            'admin_id'      => 0,
                            'ch_id'         => 0,
                            'bdrid'         => 0,
                            'delete_remarks' => "Removed from handover mapping after rejection by $uname on $current_date"
                        );
                        $this->db->where('id', $request_spd_id);
                        $this->db->update('spd_request', $data);

                        if (strpos($sname, "Research New School") !== false) {
                            if($bdrequestQueryDatasID == $bdrid){
                               $db3->query("Delete FROM spd_request where id = '$request_spd_id'");     
                            }
                        }
                }
            }

        $bdrSchoolTaskQuery = $db3->query("SELECT * FROM `tblcallevents` WHERE bdrid = '$bdrequestQueryDatasID'");
        $bdrSchoolTaskDatas =  $bdrSchoolTaskQuery->result();
        if(sizeof($bdrSchoolTaskDatas) > 0){
                foreach($bdrSchoolTaskDatas as $bdrSchoolTaskData){
                    $request_task_id = $bdrSchoolTaskData->id;
                    $db3->query("Delete FROM tblcallevents where id = '$request_task_id'");
                }
            }

        $db3->query("Delete FROM bdrequest where id = '$bdrequestQueryDatasID'");

        }
    }




