    public function get_pstfannalstwise($uid){
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        if($utype == 2){
            $adminfilter = "user_details.admin_id = '$uid'";
        }elseif($utype == 4){
            $adminfilter = "user_details.user_id = '$uid'";
        }elseif($utype == 15){
            $adminfilter = "user_details.sales_co = '$uid'";
        }elseif($utype == 19){
            $adminfilter = " user_details.ash_nae_co = '$uid'";
        }else if($utype == 20){
            $adminfilter = "user_details.ash_w_co='$uid'";
        }else if($utype == 21){
            $adminfilter = "user_details.ash_s_co='$uid'";
        }else if($utype == 22){
            $adminfilter = "user_details.rm_east_co='$uid'";
        }else if($utype == 23){
            $adminfilter = "user_details.rm_north_co='$uid'";
        }else{
            $adminfilter = " user_details.admin_id = '$uid'";
        }
        if($utype==2 || $utype == 4 || $utype == 15 || $utype == 19 || $utype == 20 || $utype == 21 || $utype == 22 || $utype == 23){
            $query=$this->db->query("SELECT status.id stid,status.name stname, COUNT(*) cont FROM init_call LEFT join status ON status.id=init_call.cstatus LEFT JOIN user_details on user_details.user_id=init_call.apst  WHERE $adminfilter and user_details.status='active' GROUP BY status.name,status.id");
        }else{
            $query=$this->db->query("SELECT status.id stid,status.name stname, COUNT(*) cont FROM init_call LEFT JOIN status ON status.id=init_call.cstatus WHERE apst='$uid' GROUP BY status.name,status.id");
        }
        return $query->result();
    }
