public function get_cmpdbybd($stid,$bdid,$fdate){
    $leftjoin = '';
    $utype = $this->Menu_model->get_userbyid($bdid);
    $utype = $utype[0]->type_id;
    if($utype == 3){
        $txt = "init_call.mainbd='$bdid'";
    }elseif($utype == 13){
        $txt = "init_call.mainbd='$bdid'";
    }elseif($utype == 4){
        $txt = "init_call.apst='$bdid'";
    }else if($utype == 19){
        $txt = "init_call.ash_nae_co_id = '$bdid'";
    }else if($utype == 20){
        $txt = "init_call.ash_w_co_id = '$bdid'";
    }else if($utype == 21){
        $txt = "init_call.ash_s_co_id = '$bdid'";
    }else if($utype == 22){
        $txt = "init_call.rm_east_co_id = '$bdid'";
    }else if($utype == 23){
        $txt = "init_call.rm_north_co_id = '$bdid'";
    }else if($utype == 24){
         $txt = "(init_call.mainbd='$bdid')";
    }else{
        if($utype == 2){
            $txt = "(`init_call`.`mainbd` != '' AND `init_call`.`mainbd` != 0)";
            $leftjoin = "LEFT JOIN user_details ON user_details.user_id = init_call.mainbd 
                 AND user_details.admin_id = '$bdid' 
                 AND user_details.status = 'active'";
        }else{
            $txt = "`init_call`.`mainbd` = '$bdid'";
        }
    }
   
     $query = $this->db->query("SELECT *, init_call.id AS inid 
    FROM init_call
    LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
    $leftjoin
    WHERE $txt 
    AND init_call.cstatus = '$stid'");
    return $query->result();
}
