    public function convert_seconds($seconds){
        $days = floor($seconds / 86400);
$seconds %= 86400;
$hours = floor($seconds / 3600);
$seconds %= 3600;
$minutes = floor($seconds / 60);
$seconds %= 60;
return "Days: $days, Hours: $hours, Minutes: $minutes, Seconds: $seconds";
    }
