    public function GetReviewWhichNotSetTargetAchivmentSetting($uid = NULL, $reviewID = NULL) {
        // Base query
        $baseQuery = "
            SELECT
                u1.name,
                allreview.*
            FROM
                allreview
            LEFT JOIN
                user_details u1 ON u1.user_id = allreview.uid
            WHERE
                allreview.target_settings = 'no' 
                AND allreview.uid = allreview.bdid
                AND allreview.closet IS NOT NULL
                AND cast(closet as Date) >= '2025-05-06'
        ";
    
        // Parameters array
        $params = [];
    
        // Add uid condition if provided
        if (!is_null($uid)) {
            $baseQuery .= " AND allreview.uid = ?";
            $params[] = $uid;
        }
    
        // Add reviewID condition if provided
        if (!is_null($reviewID)) {
            $baseQuery .= " AND allreview.id = ?";
            $params[] = $reviewID;
        }
        // Add order by clause
        $baseQuery .= " ORDER BY allreview.id DESC";
        // Execute the query with prepared statements
        $query = $this->db->query($baseQuery, $params);
        return $query->result();
    }
    
    public function GetReviewWhichNotSetTargetAchivmentSettingInAdmin($uid) {
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        
        if($utype == 2){
            $text = " AND u1.admin_id ='$uid'";
        }else if($utype == 3){
            $text = "AND u1.user_id  = '$uid'";
        }else if($utype == 4){
            $text = " AND u1.user_id ='$uid' or u1.pst_co='$uid'";
        }else if($utype == 13){
            $text = " AND u1.user_id ='$uid' or u1.aadmin='$uid'";
        }else if($utype == 15){
            $text = "AND u1.sales_co='$uid'";
        }else if($utype == 19){
            $text = "AND u1.ash_nae_co_id='$uid'";
        }else if($utype == 20){
            $text = "AND u1.ash_w_co_id='$uid'";
        }else if($utype == 21){
            $text = "AND u1.ash_s_co_id='$uid'";
        }else if($utype == 22){
            $text = "AND u1.rm_east_co_id='$uid'";
        }else if($utype == 23){
            $text = "AND u1.rm_north_co_id='$uid'";
        }else if($utype == 24){
            $text = "AND u1.user_id ='$uid' OR u1.acm_co_id='$uid'";
        }else{
            $text = "AND u1.user_id  = '$uid'";
        }
        // Base query
        $baseQuery = "
            SELECT
                u1.name,
                allreview.*
            FROM
                allreview
            LEFT JOIN
                user_details u1 ON u1.user_id = allreview.uid
            WHERE
                allreview.target_settings = 'no'
                AND allreview.uid = allreview.bdid
                AND allreview.closet IS NOT NULL 
                $text AND cast(closet as Date) >= '2025-07-07'
                ORDER BY allreview.id DESC
        ";
    
        // Execute the query with prepared statements
        $query = $this->db->query($baseQuery);
        return $query->result();
    }
        
