    public function close_review($closetdate,$closeremark,$rrid){
        
        $query     =  $this->db->query("UPDATE allreview set closet='$closetdate',cremark='$closeremark' WHERE id='$rrid'");
        $pcdatetime = date("Y-m-d H:i:s");
        $pctime = date("H:i:s");
        
        $slct_rev_query =  $this->db->query("SELECT psdatetime FROM review_session  WHERE revew_id='$rrid' and main_review_on = 'ON'");
        $revData    = $slct_rev_query->result();
        $psdatetime = $revData[0]->psdatetime;
        $date1      = new DateTime($psdatetime);
        $date2      = new DateTime($pcdatetime);
        $interval   = $date1->diff($date2);
        $totaltime =  $interval->format('%H:%I:%S');
        $query     =  $this->db->query("UPDATE review_session set pcdatetime='$pcdatetime', pctime='$pctime',main_review_on='OFF',totaltime='$totaltime' WHERE revew_id='$rrid' and main_review_on = 'ON'");
        $this->db->query("UPDATE `review_session` SET`pctime`='$pctime',`pcdatetime`= '$pcdatetime',`totaltime`= '$totaltime',main_review_on='STOP' WHERE revew_id=$rrid and main_review_on='START'");
        $sel_query =  $this->db->query("SELECT uid,reviewtype FROM allreview WHERE id ='$rrid'");
        return $sel_query->result();
    }
