    public function get_statuscmp($sid, $uid) {
        $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
        // $fieldMap = [
        //     4  => 'apst', 
        //     13 => 'clm_id', 
        //     19 => 'ash_nae_co_id', 
        //     20 => 'ash_w_co_id', 
        //     21 => 'ash_s_co_id', 
        //     22 => 'rm_east_co_id', 
        //     23 => 'rm_north_co_id', 
        //     24 => 'acm_co_id'
        // ];
        // $field = $fieldMap[$utype] ?? 'mainbd';

        $userfilter2 = "";

        $cstatusCondition = ($sid == 'all') ? "cstatus!=''" : "cstatus='$sid'";

        if($sid == 'all'){
            $cstatusCondition = '';
        }else{
            $cstatusCondition = "AND init_call.cstatus = '$sid'";
        }


            if($utype == 4){
                $usesFilter = "init_call.apst = '$uid'";
                $usesFilter = "(init_call.apst = '$uid' OR u1.pst_co = '$uid')";
            }elseif($utype == 19){
                $usesFilter = "init_call.ash_nae_co_id = '$uid'";
            }elseif($utype == 20){
                $usesFilter = "init_call.ash_w_co_id = '$uid'";
            }elseif($utype == 21){
                $usesFilter = "init_call.ash_s_co_id = '$uid'";
            }elseif($utype == 22){
                $usesFilter = "init_call.rm_east_co_id = '$uid'";
            }elseif($utype == 23){
                $usesFilter = "init_call.rm_north_co_id = '$uid'";
            }elseif($utype == 24){
                $usesFilter = "((init_call.mainbd = '$uid' OR init_call.acm_co_id = '$uid') OR u1.acm_co = '$uid')";
            }elseif($utype == 3){
                $usesFilter = "init_call.mainbd = '$uid'";
            }elseif($utype == 13){
                $usesFilter = "((init_call.mainbd = '$uid' OR init_call.clm_id = '$uid') OR u1.aadmin = '$uid')";
            }elseif($utype == 1){
                $usesFilter = "(init_call.super_admin = '$uid')";
            }else{
                $usesFilter = "init_call.mainbd = '$uid'";
            }
        
        $query = $this->db->query("SELECT 
        init_call.id AS inid, 
        company_master.compname AS compname, 
        company_master.id as cid, 
        partner_master.name AS pname,
        status.name AS cstatus_name,
        u1.name AS main_bd_name
            FROM init_call
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
            LEFT JOIN status ON status.id = init_call.cstatus

            WHERE $usesFilter $cstatusCondition GROUP BY init_call.id ORDER BY company_master.compname ASC 
        ");
        
        return $query->result();
    }
    
    public function GetAllCompanyByUserID($uid){
        $udata = $this->Menu_model->get_userbyid($uid);
        $utype = $udata[0]->type_id;
        if($utype == 3){
           $text = "init_call.mainbd='$uid'";
        }else if($utype == 13){
            $text = "(init_call.mainbd='$uid' OR init_call.clm_id = '$uid')";
        }else if($utype == 4){
            $text = "init_call.apst='$uid'";
        }else if($utype == 19){
            $text = "init_call.ash_nae_co_id = '$uid'";
        }else if($utype == 20){
            $text = "init_call.ash_w_co_id = '$uid'";
        }else if($utype == 21){
            $text = "init_call.ash_s_co_id = '$uid'";
        }else if($utype == 22){
            $text = "init_call.rm_east_co_id = '$uid'";
        }else if($utype == 23){
            $text = "init_call.rm_north_co_id = '$uid'";
        }else if($utype == 24){
            $text = "(init_call.mainbd='$uid' OR init_call.acm_co_id = '$uid')";
        }else if($utype == 1){
            $text = "(init_call.super_admin='$uid')";
        }else if($utype == 16){
            $text = "(init_call.mainbd !='' AND init_call.cstatus IN (7,14))";
        }else{
            $text = "init_call.mainbd='$uid'";
        }
        $query=$this->db->query("SELECT 
        init_call.id inid,
        company_master.compname compname,
        company_master.id com_id,
        partner_master.name pname 
        FROM init_call 
        LEFT JOIN company_master ON company_master.id=init_call.cmpid_id 
        LEFT join partner_master ON partner_master.id=company_master.partnerType_id 
        WHERE $text and cstatus!=''");
     
        return $query->result();
    }
