    public function get_statuscmpnotplan($sid, $uid) {
        $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
        
        // $fieldMap = [
        //     4  => 'apst',
        //     19 => 'ash_nae_co_id',
        //     20 => 'ash_w_co_id',
        //     21 => 'ash_s_co_id',
        //     22 => 'rm_east_co_id',
        //     23 => 'rm_north_co_id',
        //     24 => 'acm_co_id'
        // ];
        
        // $field = $fieldMap[$utype] ?? 'mainbd'; // Default to 'mainbd' if not found
         if($utype == 4){
                $usesFilter = "init_call.apst = '$uid'";
            }elseif($utype == 19){
                $usesFilter = "init_call.ash_nae_co_id = '$uid'";
            }elseif($utype == 20){
                $usesFilter = "init_call.ash_w_co_id = '$uid'";
            }elseif($utype == 21){
                $usesFilter = "init_call.ash_s_co_id = '$uid'";
            }elseif($utype == 22){
                $usesFilter = "init_call.rm_east_co_id = '$uid'";
            }elseif($utype == 23){
                $usesFilter = "init_call.rm_north_co_id = '$uid'";
            }elseif($utype == 24){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.acm_co_id = '$uid')";
            }elseif($utype == 3){
                $usesFilter = "init_call.mainbd = '$uid'";
            }elseif($utype == 13){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.clm_id = '$uid')";
            }else{
                $usesFilter = "init_call.mainbd = '$uid'";
            }
        $whereSid = ($sid == 'all') ? "cstatus !=''" : "cstatus = '$sid'";
    
        $query = $this->db->query("
            SELECT init_call.id AS inid, company_master.compname, company_master.id as cid, partner_master.name AS pname
            FROM init_call
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN tblcallevents ON tblcallevents.cid_id != init_call.id
            WHERE $usesFilter
            AND $whereSid
            AND tblcallevents.assignedto_id = init_call.$field
            GROUP BY init_call.id
        ");
        
        return $query->result();
    }
    
    
