    public function createBargMeetingWithClusterId($uid,$bmdate,$select_cluster,$selectby){

        if($selectby == ''){
            $selectby = 'Task Action';
        }

        $cudetail            = $this->Menu_model->get_userbyid($uid);
        $current_user_cash   = $cudetail[0]->ucash;

        if($current_user_cash >= 500){
            $updated_cash = $current_user_cash - 500;

            $cashData = array(
                'ucash'  => $updated_cash
            );
            $this->db->where('user_id', $uid);
            $this->db->update('user_details', $cashData);

           
            $this->db->query("INSERT INTO company_master(compname, createddate,partnerType_id) VALUES ('Unknown', '$bmdate','1')");
            $cid = $this->db->insert_id();
        
            $this->db->query("INSERT INTO company_contact_master(contactperson, emailid, phoneno, designation, type, createddate, company_id) VALUES ('', '', '', '', 'primary', '$bmdate', '$cid')");
            $ccid = $this->db->insert_id();
            
            $this->db->query("INSERT INTO init_call(createDate, cmpid_id, creator_id,mainbd,cstatus,cluster_id) VALUES ('$bmdate','$cid','$uid','$uid','1','$select_cluster')");
            $inid = $this->db->insert_id();
        
            $this->db->query("INSERT INTO tblcallevents(lastCFID, nextCFID, purpose_achieved, fwd_date, actontaken, nextaction, mom_received, appointmentdatetime, actiontype_id, assignedto_id, cid_id, purpose_id, remarks, status_id, user_id, date, updateddate, updation_data_type,plan,selectby) VALUES ('0', '0','no', '$bmdate', 'no', 'Will Collect Data by RP Meeting', 'no','$bmdate','4','$uid','$inid','66','Will Collect Data by RP Meeting','1','$uid','$bmdate','$bmdate','updated',1,'$selectby')");
            $ntid = $this->db->insert_id();
        
            $this->db->query("INSERT INTO barginmeeting(storedt,user_id,cid,company_name) VALUES ('$bmdate','$uid','$cid','Unknown')");
            $bmid = $this->db->insert_id();
        
            $query = $this->db->query("update barginmeeting set cid='$cid',ccid='$ccid',inid='$inid',tid='$ntid' WHERE id='$bmid'");
            $query = $this->db->query("update init_call set new_lead='1', after_task='$ntid' WHERE id='$inid'");

            $cashAllotDatas = array(
                'cash_allot'  => 500
            );
            $this->db->where('id', $ntid);
            $this->db->update('tblcallevents', $cashAllotDatas);

            $cashlogdata = array(
                'uid'        => $uid,
                'cash'       => 500,
                'av_cash'    => $updated_cash,
                'type'       => "debit",
                'remarks'    => "Cash Deducted for Creating Barg in Meeting on $bmdate",
                'task_id'    => $ntid
            );
            $this->db->insert('cash_log', $cashlogdata);

        } else {
             $this->load->library('session');
            $this->session->set_flashdata('error_message',' ⚠️ Insufficient Cash Balance to Create Bargain Meeting. Please Contact Admin to Recharge Your Cash Balance.');
            $onlyDate  = date('Y-m-d', strtotime($bmdate));
            redirect('Menu/TaskPlanner2/'.$onlyDate);
        }

    }
