    public function get_cmp_samestatuslastdaysPartner($samestatus, $partnertype, $uid) {
        $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
    
        // Map user types to their respective field names
        // $fieldMap = [
        //     4  => 'apst',
        //     19 => 'ash_nae_co_id',
        //     20 => 'ash_w_co_id',
        //     21 => 'ash_s_co_id',
        //     22 => 'rm_east_co_id',
        //     23 => 'rm_north_co_id',
        //     24 => 'acm_co_id'
        // ];
        // $field = $fieldMap[$utype] ?? 'mainbd'; // Default to 'mainbd' if not found
         if($utype == 4){
                $usesFilter = "init_call.apst = '$uid'";
            }elseif($utype == 19){
                $usesFilter = "init_call.ash_nae_co_id = '$uid'";
            }elseif($utype == 20){
                $usesFilter = "init_call.ash_w_co_id = '$uid'";
            }elseif($utype == 21){
                $usesFilter = "init_call.ash_s_co_id = '$uid'";
            }elseif($utype == 22){
                $usesFilter = "init_call.rm_east_co_id = '$uid'";
            }elseif($utype == 23){
                $usesFilter = "init_call.rm_north_co_id = '$uid'";
            }elseif($utype == 24){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.acm_co_id = '$uid')";
            }elseif($utype == 3){
                $usesFilter = "init_call.mainbd = '$uid'";
            }elseif($utype == 13){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.clm_id = '$uid')";
            }else{
                $usesFilter = "init_call.mainbd = '$uid'";
            }
    
        // Build the WHERE condition for samestatus and partnertype
        if ($samestatus == 'all' || $partnertype == 'all') {
            $statusCondition = "(init_call.cstatus != '' AND tblcallevents.id IS NULL 
                                 OR tblcallevents.updateddate < NOW() - INTERVAL 365 DAY 
                                 AND tblcallevents.nstatus_id != '')";
        } else {
            $statusCondition = "(init_call.cstatus = '$samestatus' AND company_master.partnerType_id = '$partnertype' 
                                 AND tblcallevents.id IS NULL 
                                 OR tblcallevents.updateddate < NOW() - INTERVAL 365 DAY 
                                 AND tblcallevents.nstatus_id = '$samestatus')";
        }
    
        // Special: if samestatus or partnertype is 'all', ignore partnerType condition
        if ($partnertype != 'all') {
            $partnerCondition = "AND company_master.partnerType_id = '$partnertype'";
        } else {
            $partnerCondition = ""; // no condition
        }
    
        $query = $this->db->query("
            SELECT init_call.id AS inid, company_master.compname AS compname,  company_master.id AS cid, partner_master.name AS pname
            FROM init_call
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id
            WHERE $usesFilter
            $partnerCondition
            AND ($statusCondition)
        ");
    
        return $query->result();
    }
    
