    public function get_cmp_samestatuslastdaysPartnerdaysPurpose($samestatus, $partnertype, $daysfilter, $taskActioncard, $taskPurposecard, $uid) {
        $utype = $this->Menu_model->get_userbyid($uid)[0]->type_id;
    
        // Field mapping
        // $fieldMap = [
        //     4  => 'apst',
        //     19 => 'ash_nae_co_id',
        //     20 => 'ash_w_co_id',
        //     21 => 'ash_s_co_id',
        //     22 => 'rm_east_co_id',
        //     23 => 'rm_north_co_id',
        //     24 => 'acm_co_id'
        // ];
        // $field = $fieldMap[$utype] ?? 'mainbd'; // default fallback
            if($utype == 4){
                $usesFilter = "init_call.apst = '$uid'";
            }elseif($utype == 19){
                $usesFilter = "init_call.ash_nae_co_id = '$uid'";
            }elseif($utype == 20){
                $usesFilter = "init_call.ash_w_co_id = '$uid'";
            }elseif($utype == 21){
                $usesFilter = "init_call.ash_s_co_id = '$uid'";
            }elseif($utype == 22){
                $usesFilter = "init_call.rm_east_co_id = '$uid'";
            }elseif($utype == 23){
                $usesFilter = "init_call.rm_north_co_id = '$uid'";
            }elseif($utype == 24){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.acm_co_id = '$uid')";
            }elseif($utype == 3){
                $usesFilter = "init_call.mainbd = '$uid'";
            }elseif($utype == 13){
                $usesFilter = "(init_call.mainbd = '$uid' OR init_call.clm_id = '$uid')";
            }else{
                $usesFilter = "init_call.mainbd = '$uid'";
            }
    
        // Handling days filter
        $intervalDays = $this->getDaysFilter($daysfilter);
    
        // Base where conditions
        $where = $usesFilter;
    
        // Add partner type condition
        if ($partnertype != 'all') {
            $where .= " AND company_master.partnerType_id = '$partnertype'";
        }
    
        // Add task action condition
        $where .= " AND tblcallevents.actontaken = '$taskActioncard'";
    
        if($taskPurposecard !== ''){
        // Add purpose condition
        $where .= " AND tblcallevents.purpose_achieved = '$taskPurposecard'";
        }
      
    
        // Building status condition
        $statusCondition = $this->getStatusCondition($samestatus, $daysfilter, $intervalDays);
    
        // Final Query
        $query = $this->db->query("
            SELECT init_call.id AS inid, company_master.compname AS compname, partner_master.name AS pname
            FROM init_call
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id
            WHERE $where
            AND $statusCondition
        ");
    
        return $query->result();
    }
    
    // Helper for days filter
    private function getDaysFilter($daysfilter) {
        if ($daysfilter == 'more') {
            return 60;
        } elseif ($daysfilter == 'all') {
            return 365;
        } else {
            return (int)$daysfilter;
        }
    }
    
    // Helper for status condition
    private function getStatusCondition($samestatus, $daysfilter, $intervalDays) {
        if ($samestatus == 'all' || $daysfilter == 'all') {
            return "(init_call.cstatus != '' AND (tblcallevents.id IS NULL OR tblcallevents.updateddate < NOW() - INTERVAL $intervalDays DAY AND tblcallevents.nstatus_id != ''))";
        } else {
            return "(init_call.cstatus = '$samestatus' AND (tblcallevents.id IS NULL OR tblcallevents.updateddate < NOW() - INTERVAL $intervalDays DAY AND tblcallevents.nstatus_id = '$samestatus'))";
        }
    }
    
    
