    public function get_statuscmpwithtasktaction($sid,$uid,$tasktaction){
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        $query = $this->db->select('init_call.id AS inid, company_master.compname AS compname, company_master.id AS cid,
 partner_master.name AS pname, cast(tblcallevents.plandt as DATE) as pdate')
        ->from('init_call')
        ->join('tblcallevents', 'tblcallevents.cid_id = init_call.id','inner')
        ->join('company_master', 'company_master.id = init_call.cmpid_id')
        ->join('partner_master', 'partner_master.id = company_master.partnerType_id')
        ->where('tblcallevents.nextCFID !=', '0');
        
        if ($utype == 4) {
            $query->where('init_call.apst', $uid);
        }elseif($utype == 19){
            $query->where('init_call.ash_nae_co_id', $uid);
        }elseif($utype == 20){
            $query->where('init_call.ash_w_co_id', $uid);
        }elseif($utype == 21){
            $query->where('init_call.ash_s_co_id', $uid);
        }elseif($utype == 22){
            $query->where('init_call.rm_east_co_id', $uid);
        }elseif($utype == 23){
            $query->where('init_call.rm_north_co_id', $uid);
        }elseif($utype == 24){
            $query->where('init_call.acm_co_id', $uid);
        }else {
            $query->where('init_call.mainbd', $uid);
        }
    
        if($tasktaction == "all"){
            $query->where('tblcallevents.actiontype_id !=','');
        }else{
            $query->where('tblcallevents.actiontype_id =', $tasktaction);
        }
         
            if($sid != 0){
            $query->where('cstatus',$sid);
            }
            $query = $query->get();
            // $str = $this->db->last_query();
            return $query->result();
    }
