    public function get_cmpbynwpsta($uid){
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        if($utype == 4 || $utype == 19 || $utype == 20 || $utype == 21 || $utype == 22 || $utype == 23 || $utype == 24){
            if($utype == 4){
                $usesFilter = "init_call.apst = '$uid'";
            }elseif($utype == 19){
                $usesFilter = "init_call.ash_nae_co_id = '$uid'";
            }elseif($utype == 20){
                $usesFilter = "init_call.ash_w_co_id = '$uid'";
            }elseif($utype == 21){
                $usesFilter = "init_call.ash_s_co_id = '$uid'";
            }elseif($utype == 22){
                $usesFilter = "init_call.rm_east_co_id = '$uid'";
            }elseif($utype == 23){
                $usesFilter = "init_call.rm_north_co_id = '$uid'";
            }elseif($utype == 24){
                $usesFilter = "init_call.acm_co_id = '$uid'";
            }
            $query = $this->db->query("SELECT init_call.id AS inid,company_master.compname AS compname, company_master.id AS cid,partner_master.name AS pname FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN status s1 ON s1.id = init_call.cstatus LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd LEFT JOIN user_details u2 ON u2.user_id = init_call.apst WHERE $usesFilter
            AND init_call.mainbd IS NOT NULL AND init_call.id NOT IN (SELECT cid_id FROM tblcallevents WHERE cid_id IN (SELECT id FROM init_call WHERE apst = '$uid'AND mainbd IS NOT NULL) AND tblcallevents.nextCFID != '0' AND tblcallevents.updateddate > DATE_SUB(NOW(), INTERVAL 8 DAY))");
        }else{
            $query = $this->db->query("SELECT init_call.id AS inid,company_master.compname AS compname, company_master.id AS cid,partner_master.name AS pname FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
            LEFT JOIN status s1 ON s1.id = init_call.cstatus LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd LEFT JOIN user_details u2 ON u2.user_id = init_call.apst WHERE mainbd = '$uid'
            AND apst IS NOT NULL AND init_call.id NOT IN (SELECT cid_id FROM tblcallevents WHERE cid_id IN (SELECT id FROM init_call WHERE mainbd = '$uid'AND apst IS NOT NULL) AND nextCFID != '0' AND tblcallevents.updateddate > DATE_SUB(NOW(), INTERVAL 8 DAY))");
        }
        // echo $this->db->last_query(); exit;
        return $query->result();
    }
