    public function getClusterByUserId($uid){
            $udata = $this->Menu_model->get_userbyid($uid);
            $utype = $udata[0]->type_id;
            if($utype == 1){
                $text = " user_details.sadmin_id='$uid'";
            }else if($utype == 2){
                 $text = " user_details.sadmin_id='$uid'";
            }else if($utype == 3){
                $text = " cluster_mapping.user_id='$uid'";
            }else if($utype == 13){
                 $text = " (user_details.aadmin='$uid' || user_details.user_id='$uid')";
            }else if($utype == 4){
                 $text = " (user_details.pst_co='$uid' || user_details.user_id='$uid')";
            }else if($utype == 24){
                 $text = " (user_details.acm_co='$uid' || user_details.user_id='$uid')";
            }else if($utype == 15){
                $text = " (user_details.sales_co='$uid' || user_details.user_id='$uid')";
            }else if($utype == 19){
                $text = " (user_details.ash_nae_co = '$uid' || user_details.user_id='$uid')";
            }else if($utype == 20){
                $text = " (user_details.ash_w_co = '$uid' || user_details.user_id='$uid')";
            }else if($utype == 21){
                $text = " (user_details.ash_s_co = '$uid' || user_details.user_id='$uid')";
            }else if($utype == 22){
                $text = " (user_details.rm_east_co = '$uid' || user_details.user_id='$uid')";
            }else if($utype == 23){
                $text = " (user_details.rm_north_co = '$uid' || user_details.user_id='$uid')";
            }else if($utype == 24){
                $text = " (user_details.acm_co = '$uid' || user_details.user_id='$uid')";
            }else{
                 $text = " cluster_mapping.user_id='$uid'";
            }
        $query = $this->db->query("SELECT
            cluster.*,
            u1.name AS apr_by_user,
            user_details.name AS username,
            cluster_mapping.travel_type
        FROM
            `cluster`
            LEFT JOIN cluster_mapping on cluster_mapping.cluster_id = cluster.id
            LEFT JOIN user_details on user_details.user_id = cluster_mapping.user_id
            LEFT JOIN user_details u1 on u1.user_id = cluster.apr_by
        WHERE
            $text");
        return $query->result();
    }
