public function GetUserDetailsByUid($uid){
     $query = $this->db->query("SELECT
    ud.*,
    ut.name AS role_name,
    uz.name as zone_name,
    u1.name AS cluster_manager_name,
    u2.name AS admin_name,
    u3.name AS super_admin_name,
    u4.name AS pst_name,
    u5.name AS ash_nae_name,
    u6.name AS ash_w_name,
    u7.name AS ash_s_name,
    u8.name AS rm_east_name,
    u9.name AS rm_north_name,
    u10.name AS acm_name,
    u11.name AS sales_co_name
FROM user_details ud
LEFT JOIN user_type ut ON ut.id = ud.type_id
LEFT JOIN user_zone uz ON uz.id = ud.zone_id
LEFT JOIN user_details u1 ON u1.user_id = ud.aadmin 
LEFT JOIN user_details u2 ON u2.user_id = ud.admin_id
LEFT JOIN user_details u3 ON u3.user_id = ud.sadmin_id
LEFT JOIN user_details u4 ON u4.user_id = ud.pst_co
LEFT JOIN user_details u5 ON u5.user_id = ud.ash_nae_co 
LEFT JOIN user_details u6 ON u6.user_id = ud.ash_w_co 
LEFT JOIN user_details u7 ON u7.user_id = ud.ash_w_co
LEFT JOIN user_details u8 ON u8.user_id = ud.rm_east_co
LEFT JOIN user_details u9 ON u9.user_id = ud.rm_north_co
LEFT JOIN user_details u10 ON u10.user_id = ud.acm_co
LEFT JOIN user_details u11 ON u11.user_id = ud.sales_co
WHERE ud.user_id = '$uid'");
     return $query->result();
}
