public function getBdWiseCompList($uid,$sid){
   $main_query =  "SELECT ud.name as bdname, ud2.name as apst, cm.id as cid, cm.compname, count(tcs.id) as tblc_count, cm.state, cm.city, cm.draft, cm.budget, cm.address, cm.website, pm.name as partnername, ic.focus_funnel, ic.upsell_client, ic.keycompany, ccm.contactperson, ccm.phoneno, ccm.emailid, ccm.designation, ud1.name as creatorname, cm.createddate, s.name as status, tcs.remarks   
                FROM init_call as ic 
                LEFT JOIN user_details as ud on ud.user_id=ic.mainbd
                LEFT JOIN user_details as ud1 on ud1.user_id=ic.creator_id
                LEFT JOIN user_details as ud2 on ud2.user_id=ic.apst
                Left join company_master as cm on ic.cmpid_id = cm.id
                Left join partner_master as pm on cm.partnerType_id = pm.id
                Left join company_contact_master as ccm on ic.cmpid_id = ccm.company_id and ccm.type='primary'
                Left join status as s on ic.cstatus = s.id
                Left join tblcallevents as tcs on tcs.cid_id = ic.id and tcs.remarks is not null
                where ud.admin_id='$uid'
                and ud.status='active'
                and mainbd is not null "; 
    
    if($sid <=13)
    {
      
        if($sid == 0){
           $main_query .= " ";
        }
        else{
            if($sid != '8' && $sid != '1'){
                $main_query .=" AND ic.cstatus = '$sid' AND tcs.mom != '' AND ic.apst != '' ";
            }
            else{
                $main_query .= " AND ic.cstatus = $sid";
            }
        }
    }
    else
    {
         if($sid == 14){
            $main_query .= " AND focus_funnel = 'yes' ";
          }
         else if($sid == 15){
            $main_query .= " AND upsell_client = 'yes' ";
          }
         else if($sid == 16){
            $main_query .= " AND keycompany = 'yes' ";
         }
         else if($sid == 17){
            $main_query .= " AND pkclient = 'yes' ";
         }
         else if($sid == 18){
             $main_query .= " AND priorityc = 'yes' ";
         }
	 else if($sid == 27){
            $main_query .= " AND ic.upsell_client = 'yes' ";
         }
         else if($sid == 28){
           $main_query .= " AND ic.exbd is not null ";
         }
    }
   
        $main_query .= " group by ic.id ";
        $query       =  $this->db->query($main_query);
        return $query->result();
    }
