public function CreateTaskForMOMCheck($bdid,$bmdate,$selectcompanybyuser,$selectby){
    // $bmdate = date("Y-m-d");
    $date = new DateTime($bmdate);
    // $date->modify('+1 day');
    $bmdate = $date->format('Y-m-d H:i:s');
    if($selectby == ''){
        $selectby = 'Auto Assign';
    }
    $i=1;
    foreach($selectcompanybyuser as $mom_id){
        $query          = $this->db->query("SELECT * FROM `mom_data` WHERE mom_data.`id` = $mom_id AND `approved_status` IS NULL AND NOT EXISTS (SELECT 1 FROM `tblcallevents` WHERE `mom_data`.`id` = `tblcallevents`.`reviewtype`)");
        $mdata          =  $query->result();
        $mdata_initid   = $mdata[0]->init_cmpid;
        $user_id        = $mdata[0]->user_id;
        $mom_tid        = $mdata[0]->tid;
        $cmp_Data       = $this->Menu_model->get_initbyid($mdata_initid);
        $ntstatus       = $cmp_Data[0]->cstatus;
        if($i !==1){
            $dateTime = new DateTime($bmdate);
            $dateTime->modify('+5 minutes');
            $bmdate = $dateTime->format('Y-m-d H:i:s');
        }
        $data = array(
            'lastCFID' => $mom_tid,
            'nextCFID' => '0',
            'purpose_achieved' => 'no',
            'fwd_date' => $bmdate,
            'actontaken' => 'no',
            'nextaction' => '51',
            'mom_received' => 'no',
            'appointmentdatetime' => $bmdate,
            'actiontype_id' => '18',
            'assignedto_id' => $bdid,
            'cid_id' => $mdata_initid,
            'purpose_id' => '127',
            'remarks' => 'MOM Review Task After BD Submit',
            'status_id' =>$ntstatus,
            'user_id' => $bdid,
            'date' => $bmdate,
            'updateddate' => $bmdate,
            'updation_data_type' => 'update',
            'reviewtype' => $mom_id,
            'plan' => 1,
            'autotask' => 0,
            'auto_plan' => 1,
            'selectby' => $selectby,
            'aftertask'=>$mom_tid
        );
        // Insert data into the database
        $this->db->insert('tblcallevents', $data);
        $i++;
    }
}
public function get_tentative_comp($uid){
    $query = $this->db->query("SELECT count(DISTINCT(cmpid_id))  as count_comp_id FROM init_call 
                LEFT JOIN user_details ON user_details.user_id = init_call.mainbd 
                INNER JOIN tblcallevents ON tblcallevents.cid_id = init_call.id 
                INNER JOIN company_master ON company_master.id = init_call.cmpid_id
                WHERE user_details.admin_id = '$uid' 
                AND user_details.status = 'active' 
                AND mainbd != '' 
                AND mainbd IS NOT NULL 
                AND init_call.cstatus = 3 
                AND tblcallevents.mom != '' AND init_call.apst != '' ");
              return $query->result();
}
