public function get_userForTask($uid,$uyid){
    $this->db->select('user_id');
    $this->db->select('name');
    $this->db->from('user_details');
    if($uyid == 2){
        $this->db->where('admin_id',$uid);
    }elseif ($uyid == 15 ) {
        $this->db->where('sales_co',$uid);
    }elseif ($uyid == 13 ) {
        $this->db->where('aadmin',$uid);
    }elseif ($uyid == 4) {
        $this->db->where('pst_co',$uid);
    }elseif ($uyid == 9) {
        $this->db->where('aadmin',$uid);
    }else if($uyid == 19){
        $this->db->where('ash_nae_co',$uid);
    }else if($uyid == 20){
        $this->db->where('ash_w_co',$uid);
    }else if($uyid == 21){
        $this->db->where('ash_s_co',$uid);
    }else if($uyid == 22){
        $this->db->where('rm_east_co',$uid);
    }else if($uyid == 23){
        $this->db->where('rm_north_co',$uid);
    }else if($uyid == 24){
        $this->db->where('acm_co',$uid);
    }
    $this->db->where('status','active');
    $this->db->order_by('name','ASC');
    $query = $this->db->get();
    return $query->result();
}
public function getTasks($id,$date){
    $this->db->select('tce.id tid');
    $this->db->select('tce.actiontype_id actiontype_id');
