    $this->db->select('company_master.id cid');
    $this->db->select('tce.autotask autotask');
    $this->db->select('tce.initiateddt');
    $this->db->select('tce.lastCFID lastCFID');
    $this->db->select('tce.nextCFID nextCFID');
    $this->db->select('tce.mom short_mom');
    $this->db->select('tce.user_id user_id');
    $this->db->select('tce.actontaken actontaken');
    $this->db->select('tce.selectby selectby');
    $this->db->select('tce.filter_by filter_by');
    $this->db->select('tce.purpose_achieved purpose_achieved');
    $this->db->select('tce.late_remarks_message late_remarks_message');
    $this->db->select('bm.initiateTime');
    $this->db->select('s1.name old_status');
    $this->db->select('s2.name new_status');
    $this->db->select('company_master.id cmpid');
    $this->db->select('company_master.compname');
    $this->db->select('action_name.name action_name');
    $this->db->select('tce.appointmentdatetime plan_date');
    $this->db->select('(tce.initiateddt) start_time', FALSE);
    $this->db->select('(tce.updateddate) end_time', FALSE);
    $this->db->select('TIMEDIFF(tce.initiateddt, tce.appointmentdatetime) time_diff_updateVsInitiat', FALSE);
    $this->db->select('TIMEDIFF(tce.updateddate, tce.initiateddt) time_diff_InitiatVsClose', FALSE);
    $this->db->select('tce.remarks remarks');
    $this->db->select('tce.rremark remark');
    $this->db->select('tce.filter_by filter_used');
    $this->db->select('company_master.id company_id');
    $this->db->select('TIMEDIFF(bm.initiateTime, tce.appointmentdatetime) time_diff_meetingupdateVsInitiat', FALSE);
    $this->db->select('TIMEDIFF(tce.updateddate,bm.initiateTime) time_diff_InitiatVsCloseMeeting', FALSE);
    $this->db->from('tblcallevents tce');
    $this->db->join('init_call', 'init_call.id = tce.cid_id', 'left');
    $this->db->join('company_master', 'company_master.id = init_call.cmpid_id', 'left');
    $this->db->join('action action_name', 'action_name.id = tce.actiontype_id', 'left');
    $this->db->join('status s1', 's1.id = tce.status_id', 'left');
    $this->db->join('status s2', 's2.id = tce.nstatus_id', 'left');
    $this->db->join('barginmeeting bm','bm.tid = tce.id', 'left');
    $this->db->where('tce.user_id', $id);
    $this->db->where('tce.nextCFID !=', 0);
    $this->db->where('CAST(updateddate AS DATE) =', "'$date'", FALSE);
    // $this->db->where('rremark IS NULL', NULL, FALSE);
    $query = $this->db->get();
        // echo  $this->db->last_query(); die;
    return $query->result();
}
