        //     $text = "AND u1.pst_co  = '$uid'";
        // }elseif($utype == 15){
        //     $text = "AND u1.sales_co  = '$uid'";
        // }elseif($utype == 2){
        //     $text = "AND u1.admin_id  = '$uid'";
        // }else{
        //     $text = '';
        // }
        if($utype == 2){
            $text = "AND u1.admin_id  = '$uid'";
        }else if($utype == 3){
            $text = "AND u1.user_id  = '$uid'";
        }else if($utype == '4'){
            $text = "AND u1.pst_co='$uid'";
        }else if($utype == '19'){
            $text = "AND u1.ash_nae_co='$uid'";
        }else if($utype == '20'){
            $text = "AND u1.ash_w_co='$uid'";
        }else if($utype == '21'){
            $text = "AND u1.ash_s_co='$uid'";
        }else if($utype == '22'){
            $text = "AND u1.rm_east_co='$uid'";
        }else if($utype == '23'){
            $text = "AND u1.rm_north_co='$uid'";
        }else if($utype == '24'){
            $text = "AND u1.acm_co='$uid'";
        }else if($utype == '13'){
            $text = "AND u1.aadmin='$uid' ";
        }else if($utype == '15'){
            $text = "AND u1.sales_co='$uid'";
        }else{
            $text = "AND u1.admin_id = '$uid'";
        }
        $query = $this->db->query(
            "SELECT 
                u1.*,
                admin.name AS admin_name,
                sales.name AS sales_co_name,
                pst.name AS pst_co_name,
                aadmin.name AS aadmin_name,
                type.name AS type_name,
                zone.name AS zone_name
            FROM `user_details` u1
            LEFT JOIN `user_details` admin ON u1.admin_id = admin.user_id
            LEFT JOIN `user_details` sales ON u1.sales_co = sales.user_id
            LEFT JOIN `user_details` pst ON u1.pst_co = pst.user_id
            LEFT JOIN `user_details` aadmin ON u1.aadmin = aadmin.user_id
            LEFT JOIN `user_type` type ON u1.type_id = type.id
            LEFT JOIN `user_zone` zone ON u1.zone_id = zone.id
            WHERE 
            u1.status !='' $text
            ORDER BY u1.user_id DESC
        ");
        return $query->result();
    }
