    public function get_clusterWorkOnBDFunnel($uid, $tdate) {
        // Initialize the array to store column IDs
        $clm_ids = [];
    
        // Fetch CM IDs from the model
        $cmIDs = $this->Menu_model->get_CMFromAdminId($uid);
    
        // Flatten the array of CM IDs
        foreach ($cmIDs as $value) {
            foreach ($value as $value1) {
                $clm_ids[] = $value1;
            }
        }
    
        // Ensure $clm_ids is not empty to avoid SQL errors
        if (empty($clm_ids)) {
            return []; // Or handle this case as appropriate
        }
    
        // Construct the SQL query with query builder
        $this->db->select(
            "COUNT(*) AS a,
            COUNT(CASE WHEN nextCFID = 0 THEN nextCFID END) AS b,
            COUNT(CASE WHEN nextCFID != 0 THEN nextCFID END) AS c,
            COUNT(CASE WHEN actiontype_id = 1 THEN actiontype_id END) AS d,
            COUNT(CASE WHEN actiontype_id = 1 AND nextCFID = 0 THEN actiontype_id END) AS e,
            COUNT(CASE WHEN actiontype_id = 2 THEN actiontype_id END) AS f,
            COUNT(CASE WHEN actiontype_id = 2 AND nextCFID = 0 THEN actiontype_id END) AS g,
            COUNT(CASE WHEN actiontype_id = 3 THEN actiontype_id END) AS h,
            COUNT(CASE WHEN actiontype_id = 3 AND nextCFID = 0 THEN actiontype_id END) AS i,
            COUNT(CASE WHEN actiontype_id = 4 THEN actiontype_id END) AS j,
            COUNT(CASE WHEN actiontype_id = 4 AND nextCFID = 0 THEN actiontype_id END) AS k,
            COUNT(CASE WHEN actiontype_id = 5 THEN actiontype_id END) AS l,
            COUNT(CASE WHEN actiontype_id = 5 AND nextCFID = 0 THEN actiontype_id END) AS m,
            COUNT(CASE WHEN actiontype_id = 6 THEN actiontype_id END) AS n,
            COUNT(CASE WHEN actiontype_id = 6 AND nextCFID = 0 THEN actiontype_id END) AS o,
            COUNT(CASE WHEN actiontype_id = 7 THEN actiontype_id END) AS p,
            COUNT(CASE WHEN actiontype_id = 7 AND nextCFID = 0 THEN actiontype_id END) AS q,
            COUNT(CASE WHEN actontaken = 'yes' THEN actiontype_id END) AS r,
            COUNT(CASE WHEN actontaken = 'no' AND nextCFID = 0 THEN actiontype_id END) AS s,
            COUNT(CASE WHEN purpose_achieved = 'yes' THEN actiontype_id END) AS t,
            COUNT(CASE WHEN purpose_achieved = 'no' AND nextCFID = 0 THEN actiontype_id END) AS u
            ");
    
        // Join tables
        $this->db->from('tblcallevents');
        $this->db->join('init_call', 'init_call.id = tblcallevents.cid_id', 'left');
        $this->db->join('user_details', 'user_details.user_id = init_call.mainbd', 'left');
    
        // Add conditions
        $this->db->where_in('user_details.aadmin', $clm_ids); // Use query builder's where_in for security
        $this->db->where_not_in('init_call.mainbd', $clm_ids); // Use query builder's where_in for security
        //$this->db->where_not_in('user_details.user_id', $clm_ids); // Use query builder's where_in for security
        $this->db->where_in('tblcallevents.assignedto_id', $clm_ids); // Use query builder's where_in for security
        $this->db->where('CAST(appointmentdatetime AS DATE) =', $tdate); // Fix syntax here
        $this->db->where('plan', 1);
    
        // Execute the query
        $query = $this->db->get();
    
        // Debugging statement (Remove in production)
        //echo "Query",$this->db->last_query();
    
        return $query->result();
    }
    public function bdFunnelConversion($uid,$sd,$ed,$ab){
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        // if($utype==2){$text = "user_details.admin_id='$uid' and user_details.type_id='3' and user_details.status='active'";}
        // if($utype==17 || $utype==19){
        //     $text = "user_details.type_id='3' and user_details.status='active'";
        // }
        if($utype == 1){
            $text = "user_details.sadmin_id='$uid' and user_details.type_id='3' AND user_details.status='active'";
        }else if($utype == '2'){
            $text = "user_details.admin_id='$uid' AND user_details.type_id='3' AND user_details.status='active'";
        } else if($utype == '3'){
            $text = "user_details.user_id='$uid' and user_details.type_id='3' AND user_details.status='active'";
        }else if($utype == '4'){
            $text = "user_details.pst_co='$uid' AND user_details.type_id='3' and user_details.status='active'";
        }else if($utype == '19'){
            $text = "user_details.ash_nae_co='$uid' AND user_details.type_id='3'  and user_details.status='active'";
        }else if($utype == '20'){
            $text = "user_details.ash_w_co='$uid' AND user_details.type_id='3' and user_details.status='active'";
        }else if($utype == '21'){
            $text = "user_details.ash_s_co='$uid' AND user_details.type_id='3' and user_details.status='active'";
        }else if($utype == '22'){
            $text = "user_details.rm_east_co='$uid' AND user_details.type_id='3' AND user_details.type_id='13' and user_details.status='active'";
        }else if($utype == '23'){
            $text = "user_details.rm_north_co='$uid' AND user_details.type_id='3' and user_details.status='active'";
        }else if($utype == '17'){
            $text = "user_details.ea_co='$uid' AND user_details.type_id='3' and user_details.status='active'";
        }
        if($utype==4){$text = "user_details.user_id='$uid'";}
        $query=$this->db->query(
            "SELECT DISTINCT CONCAT(s1.name, ' -to- ', s2.name) scname 
            FROM tblcallevents 
            LEFT JOIN user_details ON user_details.user_id=tblcallevents.user_id 
            LEFT JOIN status s1 ON s1.id=tblcallevents.status_id 
            LEFT JOIN status s2 ON s2.id=tblcallevents.nstatus_id 
            WHERE $text and nextCFID!='0' 
            and cast(updateddate as DATE) BETWEEN '$sd' and '$ed' 
            and s1.name!=s2.name 
            and s1.name is not null 
            and s2.name is not null
            ");
        return $query->result();
    }
