    public function get_ComCompaniesSelectionWise($uid,$bdid,$commonwith,$commoncompanies){
        if($commoncompanies =='meetings'){
            if($commonwith =='bd'){
                $query=$this->db->query("SELECT cmpid_id FROM init_call WHERE mainbd != '' AND mainbd != '$bdid' AND clm_id = '$bdid'");
            }elseif($commonwith =='pst'){
                $query=$this->db->query("SELECT cmpid_id FROM init_call WHERE mainbd = '$bdid' AND apst !='' ");
            }elseif($commonwith =='both'){
                $query=$this->db->query("SELECT cmpid_id FROM init_call WHERE mainbd != '$bdid' AND clm_id = '$bdid' and apst !='' ");
            }
        }else if($commoncompanies =='topspender'){
            $query=$this->db->query("SELECT cmpid_id FROM init_call WHERE mainbd != '$bdid' AND clm_id = '$bdid' and topspender='$commonwith'");
        }
        return $query->result();
    }
