    public function get_clusterttswd($uid, $tdate, $ab) {
        // Fetch user type
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
    
        // Define conditions based on user type
        switch ($utype) {
            case 2:
                $text = "user_details.admin_id = ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 19:
                $text = "user_details.ash_nae_co = ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 20:
                $text = "user_details.ash_w_co= ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 21:
                $text = "user_details.ash_s_co= ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 22:
                $text = "user_details.rm_east_co = ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 23:
                $text = "user_details.rm_north_co = ? AND user_details.type_id = '13' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            case 4:
                $text = "user_details.user_id = ?";
                $params = [$uid];
                break;
            case 9:
                $text = "user_details.aadmin = ? AND user_details.type_id = '4' AND user_details.status = 'active'";
                $params = [$uid];
                break;
            default:
                $text = "1 = 1"; // Default condition, or handle other cases if needed
                $params = [];
                break;
        }
    
        // Prepare the query with parameterized inputs
        $query = $this->db->query(
            "SELECT
                COUNT(CASE WHEN status_id = 1 THEN status_id END) AS a,
                COUNT(CASE WHEN status_id = 8 THEN status_id END) AS b,
                COUNT(CASE WHEN status_id = 2 THEN status_id END) AS c,
                COUNT(CASE WHEN status_id = 3 THEN status_id END) AS d,
                COUNT(CASE WHEN status_id = 4 THEN status_id END) AS e,
                COUNT(CASE WHEN status_id = 5 THEN status_id END) AS f,
                COUNT(CASE WHEN status_id = 6 THEN status_id END) AS g,
                COUNT(CASE WHEN status_id = 7 THEN status_id END) AS h,
                COUNT(CASE WHEN status_id = 9 THEN status_id END) AS i,
                COUNT(CASE WHEN status_id = 10 THEN status_id END) AS j,
                COUNT(CASE WHEN status_id = 11 THEN status_id END) AS k,
                COUNT(CASE WHEN status_id = 12 THEN status_id END) AS l,
                COUNT(CASE WHEN status_id = 13 THEN status_id END) AS m
            FROM tblcallevents
            LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
            LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id
            WHERE $text
                AND CAST(updateddate AS DATE) = ?
                AND plan = '1'
                AND nextCFID != '0'",
            array_merge($params, [$tdate])
        );
    
        // Fetch and return result
        $result = $query->result();
        //echo"<pre>result ";print_r($result);exit;
    
        // Use proper logging for debugging
        // log_message('debug', print_r($result, true));
    
