    public function get_bdtofClusterf($uid,$tdate)
    {
        $query=$this->db->query(
            "SELECT COUNT(*) a,
            count(CASE WHEN nextCFID=0 THEN nextCFID end) b,
            count(CASE WHEN nextCFID!=0 THEN nextCFID end) c, 
            count(CASE WHEN actiontype_id=1 THEN actiontype_id end) d,
            count(CASE WHEN actiontype_id=1 and nextCFID=0 THEN actiontype_id end) e,
            count(CASE WHEN actiontype_id=2 THEN actiontype_id end) f,
            count(CASE WHEN actiontype_id=2 and nextCFID=0 THEN actiontype_id end) g,
            count(CASE WHEN actiontype_id=3 THEN actiontype_id end) h,
            count(CASE WHEN actiontype_id=3 and nextCFID=0 THEN actiontype_id end) i,
            count(CASE WHEN actiontype_id=4 THEN actiontype_id end) j,
            count(CASE WHEN actiontype_id=4 and nextCFID=0 THEN actiontype_id end) k,
            count(CASE WHEN actiontype_id=5 THEN actiontype_id end) l,
            count(CASE WHEN actiontype_id=5 and nextCFID=0 THEN actiontype_id end) m,
            count(CASE WHEN actiontype_id=6 THEN actiontype_id end) n,
            count(CASE WHEN actiontype_id=6 and nextCFID=0 THEN actiontype_id end) o,
            count(CASE WHEN actiontype_id=7 THEN actiontype_id end) p,
            count(CASE WHEN actiontype_id=7 and nextCFID=0 THEN actiontype_id end) q,
            count(CASE WHEN actontaken='yes' THEN actiontype_id end) r,
            count(CASE WHEN actontaken='no' and nextCFID=0 THEN actiontype_id end) s,
            count(CASE WHEN purpose_achieved='yes' THEN actiontype_id end) t,
            count(CASE WHEN purpose_achieved='no' and nextCFID=0 THEN actiontype_id end) u 
            FROM tblcallevents
            LEFT JOIN init_call on init_call.id=tblcallevents.cid_id 
            Left join user_details on user_details.admin_id='$uid'
            and cast(appointmentdatetime AS DATE)='$tdate' 
            and plan=1");
                
            $result = $query->result();
            //echo"<pre>result ";print_r($result);exit;
        return $result;
    }
    
    public function get_clusterFunnel($uid){
       
       
        $query=$this->db->query(
            "SELECT COUNT(*) AS a,
            COUNT(CASE WHEN cstatus=1 THEN cstatus END) b,
            COUNT(CASE WHEN cstatus=2 THEN cstatus END) c,
            COUNT(CASE WHEN cstatus=3 THEN cstatus END) d,
            COUNT(CASE WHEN cstatus=4 THEN cstatus END) e,
            COUNT(CASE WHEN cstatus=5 THEN cstatus END) f,
            COUNT(CASE WHEN cstatus=6 THEN cstatus END) g,
            COUNT(CASE WHEN cstatus=7 THEN cstatus END) h,
            COUNT(CASE WHEN cstatus=8 THEN cstatus END) i,
            COUNT(CASE WHEN cstatus=9 THEN cstatus END) j,
            COUNT(CASE WHEN cstatus=10 THEN cstatus END) k,
            COUNT(CASE WHEN cstatus=11 THEN cstatus END) l,
            COUNT(CASE WHEN focus_funnel='yes' THEN focus_funnel END) m,
            COUNT(CASE WHEN upsell_client='yes' THEN upsell_client END) n,
            COUNT(CASE WHEN cstatus=12 THEN cstatus END) o,
            COUNT(CASE WHEN cstatus=13 THEN cstatus END) p, 
            COUNT(CASE WHEN keycompany='yes' THEN keycompany END) q,
            COUNT(CASE WHEN  keycompany='yes' and clm_id is not null and pkclient='yes' THEN keycompany END) r,
            COUNT(CASE WHEN keycompany='yes' and clm_id is not null and priorityc='yes' THEN keycompany END) s,
            COUNT(CASE WHEN keycompany='yes' and clm_id is not null and priorityc='yes' and cstatus='3' THEN keycompany END) t,
            COUNT(CASE WHEN cstatus='12' THEN keycompany END) u,
            COUNT(CASE WHEN mainbd IN (100070,100144,100150,100182,100198) and clm_id='' THEN mainbd END) own,
            COUNT(CASE WHEN clm_id in (100070,100144,100150,100182,100198) and mainbd Not in (100070,100144,100150,100182,100198) THEN clm_id END) bd,
            COUNT(CASE WHEN cstatus='13' THEN keycompany END) v 
            FROM init_call 
            LEFT JOIN user_details ON user_details.user_id = init_call.mainbd
            WHERE user_details.admin_id = '$uid' 
            AND user_details.type_id IN (3,13)
            AND user_details.status = 'active' 
            AND init_call.mainbd != '' 
            AND init_call.mainbd IS NOT NULL
            ");
            //echo  $this->db->last_query();exit;
    $result = $query->result();
    
    return $result;
}
    
