    public function inActiveCompaniesCountAndStatus(){
        $query=$this->db->query(
            "SELECT count(tblcallevents.cid_id), init_call.*,S1.name as CurStatus,S2.name as LastStatus, tblcallevents.cid_id cid,tblcallevents.actontaken, tblcallevents.purpose_achieved,tblcallevents.remarks, tblcallevents.updateddate, company_master.compname AS compname, user_details.name AS bdname, partner_master.name AS pname,init_call.cstatus, DATEDIFF(CURDATE(), tblcallevents.appointmentdatetime) AS days, (SELECT max(t1.id) FROM tblcallevents t1 WHERE t1.cid_id=cid and t1.nextCFID!='0') ltid,company_master.id as cmp_id
            FROM init_call 
            LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
            LEFT JOIN status as S1 ON S1.id = init_call.cstatus
            LEFT JOIN status as S2 ON S2.id = init_call.lstatus
            LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id 
            LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id 
            LEFT JOIN user_details ON user_details.user_id = init_call.mainbd 
            WHERE (user_details.aadmin IN (select user_id from user_details where type_id=13 and status='active') OR user_details.pst_co IN (select user_id from user_details where type_id=4 and status='active'))
            AND user_details.status = 'active'
            AND user_details.type_id in (3,4,13)
            AND init_call.cstatus IN (1,2,8,3,6,9,12,13)
            AND tblcallevents.id IS NOT NULL 
            AND DATE(tblcallevents.appointmentdatetime) < CURDATE() 
            AND ( 
                    SELECT COUNT(*)
                    FROM tblcallevents WHERE DATE(tblcallevents.appointmentdatetime) < CURDATE() 
                    AND tblcallevents.cid_id = init_call.id 
                ) = 1 
            AND NOT EXISTS ( 
                                SELECT 1 FROM tblcallevents tce WHERE tce.cid_id = init_call.id 
                                AND DATE(tce.appointmentdatetime) = CURDATE()
                            )
            group by tblcallevents.cid_id                          
            having days > 8
            order by tblcallevents.updateddate ASC
            ");
            return $query->result();
    }
