    public function getMyTeamList($uid,$uyid,$columnname){
        
        
        if($uyid == 2){
            $query=$this->db->query("SELECT user_id FROM user_details where admin_id='$uid' AND type_id IN(3,4,10,15,16) and status='active'");
        }elseif($uyid == 19){
            $query=$this->db->query("SELECT user_id FROM user_details where ash_nae_co_id='$uid' and status='active'");
        }elseif($uyid == 20){
            $query=$this->db->query("SELECT user_id FROM user_details where ash_w_co_id='$uid'  and status='active'");
        }elseif($uyid == 21){
            $query=$this->db->query("SELECT user_id FROM user_details where ash_s_co_id='$uid' and status='active'");
        }elseif($uyid == 22){
            $query=$this->db->query("SELECT user_id FROM user_details where rm_east_co_id='$uid' and status='active'");
        }elseif($uyid == 23){
            $query=$this->db->query("SELECT user_id FROM user_details where rm_north_co_id='$uid' and status='active'");
        }elseif($uyid == 24){
            $query=$this->db->query("SELECT user_id FROM user_details where acm_co_id='$uid' and status='active'");
        }elseif($uyid == 13){
            $query=$this->db->query("SELECT user_id FROM user_details where aadmin='$uid' and status='active'");
        }elseif($uyid == 4){
            $query=$this->db->query("SELECT user_id FROM user_details where pst_co='$uid' and status='active'");
        }else{
            $query=$this->db->query("SELECT user_id FROM user_details where (aadmin='$uid' or badmin='$uid')  and status='active'");
        }
            
            // Extract user_id values into a single array
            $results = $query->result_array();
            $user_ids = array_column($results, 'user_id');
       
        return $user_ids;
    }


