public function geTodaysMOMCheckTask($uid, $tdate) {
    $query = $this->db->query("
        SELECT 
            tblcallevents.*,
            status.name AS status_name,
            status.color AS status_color,
            status.clr AS status_text_color,
            action.name AS aname,
            init_call.cstatus AS cstatus,
            cs.name AS csname,
            init_call.cmpid_id,
            company_master.compname,
            company_master.id AS cid
        FROM 
            tblcallevents
        LEFT JOIN action ON action.id = tblcallevents.actiontype_id
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN status ON status.id = init_call.cstatus
        LEFT JOIN status cs ON cs.id = init_call.cstatus
        WHERE 
            tblcallevents.user_id = '$uid'
            AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate'
            AND tblcallevents.nextCFID = 0
            AND tblcallevents.actiontype_id = 18
    ");

    return $query->result();
}




public function gePendingMOMCheckTask($uid,$tdate){
    $query=$this->db->query("SELECT tblcallevents.*,status.name,action.name aname,status.color,status.clr,init_call.cstatus cstatus,(SELECT name from status WHERE id=cstatus) csname, (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,(select company_master.compname from company_master WHERE id=cmpid_id) as compname, (select company_master.id from company_master WHERE id=cmpid_id) as cid FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id left JOIN init_call ON init_call.id=tblcallevents.cid_id left JOIN status ON status.id=init_call.cstatus WHERE user_id='$uid' and DATE(appointmentdatetime) < CURDATE() and nextCFID='0' and autotask =1 and plan=1 AND actiontype_id = 18");
    return $query->result();
}
