    // $user_data  = $this->session->userdata('user');
    // $user_id    = $user_data['user_id'];
    // $uyid       =  $user_data['type_id'];
    // if($uyid == 3){
    //     $text = "init_call.mainbd = '$uid'";
    // }else if($uyid == 13){
    //     $text = "init_call.mainbd = '$uid' or init_call.clm_id = '$uid'";
    // }else if($uyid == 4){
    //     $text = "init_call.apst = '$uid'";
    // }else{
    //     $text = "init_call.mainbd = '$uid'";
    // }
   // $query=$this->db->query("SELECT DISTINCT init_call.id AS inid, company_master.compname AS compname, partner_master.name AS pname,init_call.cstatus FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id WHERE init_call.mainbd = '$uid' AND init_call.cstatus IN ($status) AND ( tblcallevents.id IS NULL OR tblcallevents.appointmentdatetime < NOW() - INTERVAL $days DAY )");
   //$query=$this->db->query("SELECT DISTINCT init_call.id AS inid, company_master.compname AS compname, partner_master.name AS pname, init_call.cstatus, main_review.sdate AS main_review_date, DATEDIFF(NOW(), main_review.sdate) AS main_review_days, tblcallevents.id as tcallid, tblcallevents.appointmentdatetime as appointmentdatetime FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN main_review ON main_review.inid = init_call.id LEFT JOIN ( SELECT inid, MAX(sdate) AS latest_sdate FROM main_review GROUP BY inid ) AS latest_review ON latest_review.inid = main_review.inid AND latest_review.latest_sdate = main_review.sdate LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id AND tblcallevents.appointmentdatetime >= main_review.sdate AND tblcallevents.appointmentdatetime < DATE_ADD(main_review.sdate, INTERVAL $days DAY) WHERE init_call.mainbd = '$uid' AND init_call.cstatus IN ($status) AND main_review.sdate IS NOT NULL AND main_review.sdate < NOW() AND tblcallevents.id IS NULL");
   
$query = $this->db->query("SELECT DISTINCT
    init_call.id AS inid,
    company_master.compname AS compname,
    company_master.id AS cid,
    partner_master.name AS pname,
    init_call.cstatus,
    main_review.sdate AS main_review_date,
    DATEDIFF(NOW(), main_review.sdate) AS main_review_days,
    tblcallevents.id AS tcallid,
    tblcallevents.appointmentdatetime AS appointmentdatetime
FROM
    init_call
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
LEFT JOIN main_review ON main_review.inid = init_call.id
LEFT JOIN(
    SELECT
        inid,
        MAX(sdate) AS latest_sdate
    FROM
        main_review
    GROUP BY
        inid
) AS latest_review
ON latest_review.inid = main_review.inid AND latest_review.latest_sdate = main_review.sdate
LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id AND tblcallevents.appointmentdatetime >= main_review.sdate AND tblcallevents.appointmentdatetime < DATE_ADD(
        main_review.sdate,
        INTERVAL $days DAY
    )
WHERE
    init_call.mainbd = '$uid' AND init_call.cstatus IN($status) 
    AND main_review.sdate IS NOT NULL 
    AND main_review.sdate < NOW() 
    AND tblcallevents.id IS NULL 
    AND NOT EXISTS(
    SELECT
        1
    FROM
        tblcallevents te
    WHERE
        te.cid_id = init_call.id 
        AND te.appointmentdatetime <= DATE_ADD(CURDATE(), INTERVAL $days DAY))
        GROUP BY init_call.id
        ");
 return $query->result();
}
