public function NeedYourAttentions($days,$status){
    $user_data  = $this->session->userdata('user');
    $user_id    = $user_data['user_id'];
    $uyid       =  $user_data['type_id'];
    if($uyid == 3){
        $userfilter = "(user_details.user_id = '$user_id' OR user_details.user_id = '$user_id' )";
    }else if($uyid == 13){
        $userfilter = "(user_details.aadmin = '$user_id' OR user_details.user_id = '$user_id' )";
    }else if($uyid == 4){
        $userfilter = "(user_details.pst_co = '$user_id' OR user_details.user_id = '$user_id' )";
    }else{
