public function GetDayCloseRequestData($uid,$adate,$uyid){
    if($uyid ==13){
        $text = "user_details.aadmin = '$uid'";
    }else if($uyid ==4){
        $text = "user_details.pst_co = '$uid'";
    }else if($uyid ==15){
        $text = "user_details.sales_co = '$uid'";
    }else if($uyid ==2){
        $text = "user_details.admin_id = '$uid'";
    }else if($uyid ==19){
        $text = "user_details.ash_nae_co = '$uid'";
    }else if($uyid == 20){
        $text = "user_details.ash_w_co='$uid'";
    }else if($uyid == 21){
        $text = "user_details.ash_s_co='$uid'";
    }else if($uyid == 22){
        $text = "user_details.rm_east_co='$uid'";
    }else if($uyid == 23){
        $text = "user_details.rm_north_co='$uid'";
    }else if($uyid == 24){
        $text = "user_details.acm_co='$uid'";
    }else if($uyid == 1){
        $text = "user_details.sadmin_id='$uid'";
    }else{
        $text = "user_details.aadmin='$uid'";
    }
    $getreqData  =  $this->db->query("SELECT *,close_your_day_request.id FROM close_your_day_request LEFT JOIN user_details ON close_your_day_request.user_id = user_details.user_id WHERE $text and DATE(req_date) ='$adate'");
    $getreqData  =  $getreqData->result();
    return $getreqData;
}
public function getUserDayStartDetails($uid,$tdate){
    $query=$this->db->query("SELECT * FROM user_day WHERE user_id='$uid' and cast(sdatet as DATE)='$tdate'");
    return $query->result();
}
public function GetTodaysAutoTaskANDPlanningTime($uid,$tdate){
    $curdate = date("Y-m-d");
    $query  =  $this->db->query("SELECT * FROM `autotask_time` where user_id='$uid' AND date ='$curdate'");
    return $query->result();
}
public function GetTommarowPlanTask($uid){
        $curdate = date("Y-m-d");
        $tomorrow = date("Y-m-d", strtotime($curdate . ' +1 day'));
        $utype = $this->Menu_model->get_userbyid($uid);
        $utype = $utype[0]->type_id;
        if($utype   ==  3){
            $text = "`init_call`.`mainbd` = '$uid'";
        }elseif($utype == 13){
            $text = "(`init_call`.`mainbd` = '$uid')";
        }if($utype == 4){
            $text = "init_call.apst = '$uid'";
        }elseif($utype == 19){
            $text = "init_call.ash_nae_co_id = '$uid'";
        }elseif($utype == 20){
            $text = "init_call.ash_w_co_id = '$uid'";
        }elseif($utype == 21){
            $text = "init_call.ash_s_co_id = '$uid'";
        }elseif($utype == 22){
            $text = "init_call.rm_east_co_id = '$uid'";
        }elseif($utype == 23){
            $text = "init_call.rm_north_co_id = '$uid'";
        }elseif($utype == 24){
            // $text = "init_call.acm_co_id = '$uid'";
            $text = "(`init_call`.`mainbd` = '$uid')";
        }else{
            $text = "`init_call`.`mainbd` = '$uid'";
        }
         $query=$this->db->query("SELECT *, tblcallevents.id AS id, tblcallevents.cid_id AS cid, (SELECT max(t1.id) FROM tblcallevents t1 WHERE t1.cid_id = cid AND t1.nextCFID != '0') AS ltid FROM tblcallevents LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE init_call.mainbd = '$uid' AND tblcallevents.user_id != '$uid' AND tblcallevents.actontaken = 'no' AND tblcallevents.nextCFID = 0 AND (CAST(appointmentdatetime AS Date) = '$tomorrow' OR CAST(appointmentdatetime AS Date) = '$curdate')");
    return $query->result();
}
