public function GetTodaysOurReminder($uid){
    $today_start = date('Y-m-d 00:00:00');
    $today_end   = date('Y-m-d 23:59:59');

    $query = $this->db->query("
        SELECT *
        FROM reminder
        WHERE user_id = '$uid'
          AND created_at BETWEEN '$today_start' AND '$today_end'
        ORDER BY created_at ASC
    ");

    return $query->result();
}



