public function GetCompanyClusterWorkBecauseOf($uid,$stype){
    
    $mdata = $this->Menu_model->get_userbyaaid($uid);
    $udata      = $this->Menu_model->get_userbyid($uid);
    $pst_uid    = $udata[0]->pst_co;

    // echo $stype;
    // die;

    if($stype == 'On PST'){
         $query=$this->db->query("SELECT init_call.id AS inid, user_details.name, company_master.compname AS compname, company_master.id AS cid, partner_master.name AS pname FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN user_details ON user_details.user_id = init_call.apst WHERE init_call.apst = '$pst_uid' AND cstatus != '' ORDER BY company_master.compname ASC ");
    }else if($stype == 'On BD'){
        $users_id = '';
        foreach($mdata as $users){
            $users_id .= $users->user_id.',';
        }
        $users_id = rtrim($users_id, ',');

        // echo $users_id;

        $query=$this->db->query("SELECT 
        init_call.id AS inid, 
        user_details.name, 
        company_master.compname AS compname, 
        company_master.id AS cid, partner_master.name AS pname 
        FROM init_call 
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id 
        LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id 
        LEFT JOIN user_details ON user_details.user_id = init_call.mainbd 
        WHERE init_call.mainbd IN ($users_id) 
        AND cstatus != '' 
        ORDER BY company_master.compname ASC
        ");
      
    }else if($stype == 'both'){
        $users_id = '';
        foreach($mdata as $users){
            $users_id .= $users->user_id.',';
        }
        $users_id = rtrim($users_id, ',');
        $query=$this->db->query("SELECT init_call.id AS inid, user_details.name AS name, apst_details.name AS apst, company_master.compname AS compname, company_master.id AS cid, partner_master.name AS pname FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN user_details ON user_details.user_id = init_call.mainbd LEFT JOIN user_details AS apst_details ON apst_details.user_id = init_call.apst WHERE init_call.mainbd IN ($users_id) AND init_call.apst = '$pst_uid' AND cstatus != '' ORDER BY company_master.compname ASC");
    }else{
        $query=$this->db->query("SELECT 
        init_call.id inid,
        company_master.compname compname, 
        company_master.id AS cid, 
        partner_master.name pname 
        FROM init_call 
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id 
        LEFT join partner_master ON partner_master.id = company_master.partnerType_id 
        WHERE init_call.mainbd='$uid' 
        and cstatus!='' 
        ORDER BY company_master.compname ASC
        ");
    }
    return $query->result();
}
