            LEFT JOIN user_details ON user_details.user_id = init_call.mainbd
            LEFT JOIN barginmeeting ON barginmeeting.cid = init_call.cmpid_id 
            LEFT JOIN tblcallevents ON tblcallevents.id = barginmeeting.tid
            LEFT JOIN status ON status.id = init_call.cstatus
            WHERE init_call.mainbd IN ($users_id) 
            AND init_call.clm_id !='' 
            AND init_call.cstatus != ''
            AND DATE(barginmeeting.storedt) >= '2026-04-01' 
