        public function GetUserRequestForPendingTask($uid,$tdate){
    
            $tardate = date("Y-m-d");
            if($tdate == $tardate){
                $query = $this->db->query("SELECT * FROM `request_old_pend_task` WHERE user_id= '$uid' AND DATE(req_date) ='$tdate'");
            }else{
               
