        public function GetDayCloseRequest($uid,$tdate){
    $query = $this->db->query("SELECT * FROM `close_your_day_request` WHERE user_id= '$uid' AND DATE(req_date) ='$tdate'");
    $data = $query->result();
    return $data;
}
public function CreateCloseDayRequest($uid,$req_id,$req_answer,$message,$autotasktimeisset){
    $data = array(
        'user_id' => $uid,
        'req_id' => $req_id,
        'req_date' => date("Y-m-d H:i:s"),
        'why_did_you' => $req_answer,
        'req_remarks' => $message,
        'autotasktimeisset' => $autotasktimeisset
    );
    $this->db->insert('close_your_day_request', $data);
    $insert_id = $this->db->insert_id();
    
    return  $insert_id;
}
public function CreateCloseDayRequestWithAutoTaskTime($uid,$req_id,$req_answer,$message,$startautotasktime,$endautotasktime,$start_tttpft,$end_tttpft,$autotasktimeisset){
    $data = array(
        'user_id' => $uid,
        'req_id' => $req_id,
        'req_date' => date("Y-m-d H:i:s"),
        'why_did_you' => $req_answer,
        'req_remarks' => $message,
        'startautotasktime' => $startautotasktime,
        'endautotasktime' => $endautotasktime,
        'start_tttpft' => $start_tttpft,
        'end_tttpft' => $end_tttpft,
        'autotasktimeisset' => $autotasktimeisset
    );
  
    $this->db->insert('close_your_day_request', $data);
    $insert_id = $this->db->insert_id();
    $currentDate            = date("Y-m-d");
    $query1                 =  $this->db->query("SELECT * FROM `autotask_time` WHERE user_id =$uid and date='$currentDate'");
    $gecurAutoTaskTime      = $query1->result();
    $gecurAutoTaskTimecnt   = sizeof($gecurAutoTaskTime);
    if($gecurAutoTaskTimecnt == 0){
        $dataslct = array(
            'user_id'      => $uid,
            'date'         => $currentDate,
            'stime'        => $startautotasktime.":00",
            'etime'        => $endautotasktime.":00",
            'start_tttpft' => $start_tttpft,
            'end_tttpft'   => $end_tttpft
        );
        $this->db->insert('autotask_time', $dataslct);
    }
    return  $insert_id;
}
public function UpdateCloseYesterDay($flink,$user_id,$lat,$lng,$req_id){
    $tdate=date('Y-m-d H:i:s');
    $this->db->query("Update user_day set uclose='$tdate',ucimg='$flink',clatitude='$lat',clongitude='$lng' where id='$req_id'");
    $this->db->query("INSERT INTO notify(uid,type,sms) VALUES ('$user_id','1','You Are Closed Your Yesterday Day at $tdate')");
}
