public function CheckTodaysTaskAvilableTime($uid,$time1,$time2,$curDate){
    $query=$this->db->query("SELECT 
    actiontype_id, 
    appointmentdatetime, 
    CASE 
        WHEN actiontype_id = 1 THEN DATE_ADD(appointmentdatetime, INTERVAL 5 MINUTE)
        WHEN actiontype_id = 2 THEN DATE_ADD(appointmentdatetime, INTERVAL 10 MINUTE)
        WHEN actiontype_id IN (3, 4, 12, 17) THEN DATE_ADD(appointmentdatetime, INTERVAL 30 MINUTE)
        WHEN actiontype_id IN (5, 8, 9, 10, 15, 18) THEN DATE_ADD(appointmentdatetime, INTERVAL 5 MINUTE)
        WHEN actiontype_id IN (11, 13, 14) THEN DATE_ADD(appointmentdatetime, INTERVAL 2 MINUTE)
    END AS next_available_time
FROM 
    tblcallevents
WHERE 
    assignedto_id = '$uid'
    AND plan = 1
    AND Cast(appointmentdatetime AS DATE) = '$curDate'
    AND CAST(appointmentdatetime AS TIME) BETWEEN '$time1' AND '$time2'
ORDER BY 
    appointmentdatetime ASC");
    return $query->result();
}
public function GetBookedSlot($uid,$t1,$t2,$tdate){
    $query=$this->db->query("SELECT DISTINCT CAST(tblcallevents.appointmentdatetime AS DATETIME) as bookedtime FROM tblcallevents LEFT JOIN action ON action.id = tblcallevents.actiontype_id WHERE tblcallevents.user_id = '$uid' AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' AND tblcallevents.plan = 1 AND tblcallevents.nextCFID = 0 AND CAST(tblcallevents.appointmentdatetime AS TIME) BETWEEN '$t1' AND '$t2' ORDER BY appointmentdatetime ASC");
    return $query->result();
}
public function insert_visit($user_id, $page, $action) {
    $datetime = date('Y-m-d H:i:s');
    if($action == 'visit'){
        $data = array(
            'user_id' => $user_id,
            'page' => $page,
            'visit_time' => $datetime, // Current date and time
            'action' => $action,
        );
        // Insert data into user_visits table
        $this->db->insert('user_visits', $data);
    }
    if($action == 'leave'){
        $query=$this->db->query("UPDATE user_visits SET leave_time = '$datetime' WHERE user_id = '$user_id' AND page = '$page' ORDER BY created_at DESC LIMIT 1");
    }
  
}
