public function getReviewedCMPHalfYearly(){
    $year = date("Y");
    $month = 4;
    $day = 1;
    $date = new DateTime("$year-$month-$day");
    $formatted_date = $date->format('Y-m-d');
    $currentDate = new DateTime(); // Current date and time
    $currentDate->modify('-6 months'); // Subtract 6 months
    $sixMonthsAgo = $currentDate->format('Y-m-d'); // Format the date
     $query=$this->db->query("SELECT inid FROM `main_review` WHERE  DATE(sdate) > '$sixMonthsAgo' ");
    //  $query=$this->db->query("SELECT inid FROM `main_review` WHERE  DATE(sdate) > DATE_SUB(CURDATE(), INTERVAL 6 MONTH)");
    return $query->result();
}
