public function get_cmptd_new($inid,$fdate){
    $query=$this->db->query("SELECT tblcallevents.*, init_call.*, action.name AS actionname,user_details.type_id, user_details.name AS username, lstatus.name AS lstatusname, cstatus.name AS cstatusname FROM tblcallevents LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN action ON tblcallevents.actiontype_id = action.id LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id LEFT JOIN status AS lstatus ON lstatus.id = init_call.lstatus LEFT JOIN status AS cstatus ON cstatus.id = init_call.cstatus WHERE init_call.id = '$inid' AND CAST(updateddate AS DATE) BETWEEN '$fdate' AND CURRENT_DATE");
    return $query->result();
}
public function get_cmptd_taskdone_by($uadmid,$inid,$fdate){
    $query=$this->db->query("SELECT tblcallevents.*, init_call.*, action.name AS actionname, user_details.name AS username, lstatus.name AS lstatusname, cstatus.name AS cstatusname FROM tblcallevents LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN action ON tblcallevents.actiontype_id = action.id LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id LEFT JOIN status AS lstatus ON lstatus.id = init_call.lstatus LEFT JOIN status AS cstatus ON cstatus.id = init_call.cstatus WHERE init_call.id = '$inid' AND tblcallevents.assignedto_id = '$uadmid' AND CAST(updateddate AS DATE) > '$fdate'");
    return $query->result();
}
public function getCmpStatusChnageTaskDoneBy($uadmid,$inid,$fdate){
    $query=$this->db->query("SELECT tblcallevents.*, init_call.*, action.name AS actionname, user_details.name AS username, lstatus.name AS lstatusname, cstatus.name AS cstatusname FROM tblcallevents LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN action ON tblcallevents.actiontype_id = action.id LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id LEFT JOIN status AS lstatus ON lstatus.id = init_call.lstatus LEFT JOIN status AS cstatus ON cstatus.id = init_call.cstatus WHERE init_call.id = '$inid' AND tblcallevents.status_id != tblcallevents.nstatus_id AND tblcallevents.assignedto_id = '$uadmid' AND CAST(updateddate AS DATE) > '$fdate'");
    return $query->result();
}
public function getMainReviewBy_ALL($review,$bduid){
        $query=$this->db->query("SELECT mr.*, init_call.cstatus, company_master.compname, tblcallevents.actontaken, tblcallevents.purpose_achieved, lstatus.name AS lstatusname, cstatus.name AS cstatusname, exstatus.name AS exp_status, action.name, tblcallevents.appointmentdatetime, user_details.name AS username FROM `main_review` AS mr LEFT JOIN init_call ON mr.inid = init_call.id LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents ON tblcallevents.id = mr.ntid LEFT JOIN status AS lstatus ON lstatus.id = init_call.lstatus LEFT JOIN status AS cstatus ON cstatus.id = init_call.cstatus LEFT JOIN status AS exstatus ON exstatus.id = mr.exsid LEFT JOIN action ON action.id = tblcallevents.actiontype_id LEFT JOIN user_details ON user_details.user_id = tblcallevents.assignedto_id WHERE mr.rid ='$review' AND mr.for_uid = '$bduid'");
       
    return $query->result();
}
public function getMainReviewDate($review,$bduid){
    if($review == 'Self Half Yearly' || $review == 'Half Yearly'){
        $review ="'Self Half Yearly', 'Half Yearly'";
    }elseif($review == 'Self Weekly' || $review == 'Weekly'){
        $review ="'Self Weekly', 'Weekly'";
    }elseif($review == 'Self Fortnightly' || $review == 'Fortnightly'){
        $review ="'Self Fortnightly', 'Fortnightly'";
    }elseif($review == 'Self Monthly' || $review == 'Monthly'){
        $review ="'Self Monthly', 'Monthly'";
    }elseif($review == 'Self Quarterly' || $review == 'Querterly'){
        $review ="'Self Quarterly', 'Querterly'";
    }
    $query=$this->db->query("SELECT id, startt, closet FROM `allreview` WHERE reviewtype IN ($review) AND bdid = '$bduid' AND YEAR(startt) = YEAR(CURDATE()) ORDER BY ID DESC");
    return $query->result();
}
