public function GetTommrowReviewTask($bduid){
    $upquery = $this->db->query("SELECT main_review.*, company_master.compname, tce.actiontype_id, ( SELECT tce2.id FROM tblcallevents AS tce2 WHERE tce2.cid_id = main_review.inid AND tce2.actontaken = 'yes' AND tce2.nextCFID != 0 AND (tce2.status_id != tce2.nstatus_id) AND CAST(tce2.appointmentdatetime AS DATE) >= CURDATE() - INTERVAL 2 DAY LIMIT 1 ) AS updatetasktid FROM main_review LEFT JOIN tblcallevents AS tce ON tce.id = main_review.ntid LEFT JOIN init_call ON init_call.id = main_review.inid LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE main_review.for_uid = '100194' AND main_review.taskplan = 0 AND tce.nextCFID = 0 AND tce.actontaken = 'no' AND tce.purpose_achieved = 'no' AND CAST(tce.appointmentdatetime AS DATE) = CURDATE() + INTERVAL 1 DAY AND EXISTS ( SELECT 1 FROM tblcallevents AS tce2 WHERE tce2.cid_id = main_review.inid AND tce2.actontaken = 'yes' AND tce2.nextCFID != 0 AND (tce2.status_id != tce2.nstatus_id) AND CAST(tce2.appointmentdatetime AS DATE) >= CURDATE() - INTERVAL 2 DAY )");
    $upData = $upquery->result();
    if(sizeof($upData) > 0){
        foreach($upData as $row){
            $ntid = $row->ntid;
            $updatetasktid = $row->updatetasktid;
            $newtask = $this->db->query("SELECT * FROM `tblcallevents` WHERE `id` = $ntid");
            $newtaskData = $newtask->result();
            $newappointmentdatetime = $newtaskData[0]->appointmentdatetime;
            $appointmentdatetime = date("Y-m-d H:i:s");
            $remarks = "This is review task on date $newappointmentdatetime, Updated By System on date $appointmentdatetime, because of status change interval 2 DAY";
            $query=$this->db->query("UPDATE tblcallevents SET actontaken ='yes', purpose_achieved='yes', nextCFID ='$updatetasktid', remarks='$remarks',appointmentdatetime='$appointmentdatetime', updateddate = '$appointmentdatetime' WHERE id = '$ntid'");
        }
    }
    $query=$this->db->query("SELECT main_review.*, company_master.compname,tce.actiontype_id FROM `main_review` LEFT JOIN tblcallevents as tce ON tce.id = main_review.ntid LEFT JOIN init_call ON init_call.id = main_review.inid LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE main_review.for_uid = '$bduid' AND main_review.taskplan = 0 AND tce.nextCFID = 0 AND tce.actontaken = 'no' AND tce.purpose_achieved = 'no' AND CAST(tce.appointmentdatetime AS Date) = CURDATE() + INTERVAL 1 DAY");
    return $query->result();
}
