public function GetAddNewLeadComapny($uid)
{
    $utype = $this->Menu_model->get_userbyid($uid);
    $utype = $utype[0]->type_id;

    if ($uid == 1000360) {
        return [];
    }

    // User mapping filter
    if ($utype == 1) {
        $text = "AND u1.sadmin_id = '$uid'";
    } else if ($utype == 2) {
        $text = "AND u1.admin_id = '$uid'";
    } else if ($utype == 3) {
        $text = "AND u1.user_id = '$uid'";
    } else if ($utype == 13) {
        $text = "AND (u1.user_id = '$uid' OR u1.aadmin = '$uid') AND u1.type_id IN (3,24)";
    } else if ($utype == 4) {
        $text = "AND (u1.user_id = '$uid' OR u1.pst_co = '$uid')";
    } else if ($utype == 19) {
        $text = "AND u1.ash_nae_co = '$uid'";
    } else if ($utype == 20) {
        $text = "AND u1.ash_w_co = '$uid'";
    } else if ($utype == 21) {
        $text = "AND u1.ash_s_co = '$uid'";
    } else if ($utype == 22) {
        $text = "AND (u1.user_id = '$uid' OR u1.rm_east_co = '$uid') AND u1.type_id = 13";
    } else if ($utype == 23) {
        $text = "AND (u1.user_id = '$uid' OR u1.rm_north_co = '$uid')";
    } else if ($utype == 24) {
        $text = "AND (u1.user_id = '$uid' OR u1.acm_co = '$uid')";
    } else if ($utype == 15) {
        $text = "AND u1.sales_co = '$uid'";
    } else {
        $text = "AND u1.user_id = '$uid'";
    }

    $query = $this->db->query("
        SELECT
            ic.*,
            u1.name,
            tce.actiontype_id,
            tce.appointmentdatetime,
            tce.id AS taskid,
            cm.compname,
            u1.aadmin,
            ic.after_task AS create_after_task,
            u2.name AS reporting_manager

        FROM init_call ic

        LEFT JOIN tblcallevents tce 
            ON tce.id = ic.after_task

        LEFT JOIN company_master cm 
            ON cm.id = ic.cmpid_id

        LEFT JOIN user_details u1 
            ON u1.user_id = tce.user_id

        LEFT JOIN user_details u2 
            ON u2.user_id = (
                CASE 
                    WHEN u1.type_id = 3 THEN 
                        CASE 
                            WHEN u1.acm_co IS NOT NULL 
                                 AND u1.acm_co != '' 
                                THEN u1.acm_co

                            WHEN u1.aadmin IS NOT NULL 
                                 AND u1.aadmin != '' 
                                THEN u1.aadmin

                            ELSE u1.rm_east_co
                        END

                    WHEN u1.type_id = 13 THEN 
                        CASE 
                            WHEN u1.rm_east_co IS NOT NULL 
                                 AND u1.rm_east_co != '' 
                                THEN u1.rm_east_co

                            ELSE u1.aadmin
                        END

                    WHEN u1.type_id = 24 THEN u1.aadmin

                    WHEN u1.type_id = 22 THEN u1.sales_co
                END
            )

        WHERE 
            tce.nextCFID != 0
            AND ic.new_lead = 1
            AND ic.is_admin_approved = 0
            AND ic.mainbd != 0
            $text

        ORDER BY ic.id DESC
    ");

    return $query->result();
}




