public function updateLeaveStatus($status,$id,$uid,$rejectreamrk,$updateReason,$leaveEndRequest, $updatedBalance,$userId){
    if($status=='rejected' && $leaveEndRequest==0){
        $isUpdated=$this->db->query(
            "UPDATE leave_requests 
            SET status='$status',
                reject_reason='$rejectreamrk',
                rejected_by='$uid', 
                rejected_at=NOW()
            WHERE id=$id
            ");
    }elseif($status=='approved' && $leaveEndRequest==0){
        $isUpdated=$this->db->query(
            "UPDATE leave_requests 
            SET status='$status', 
                approved_by='$uid', 
                approved_at=NOW()
            WHERE id=$id
            ");
        $isUpdated=$this->db->query(
            "UPDATE user_details 
            SET leave_balance='$updatedBalance' where user_id=$userId
            ");
    }elseif($status=='pending' && $leaveEndRequest==1){
        $isUpdated=$this->db->query(
            "UPDATE leave_requests 
            SET update_status='$status',
            leave_end_request='$leaveEndRequest',
            update_reason='$updateReason'
            WHERE id=$id
            ");
    }elseif($status=='approved' && $leaveEndRequest==1){
        $isUpdated=$this->db->query(
            "UPDATE leave_requests 
            SET update_status='$status', 
                updated_by='$uid', 
                updated_at=NOW()
            WHERE id=$id
            ");
    }elseif($status=='rejected' && $leaveEndRequest==1){
        $isUpdated=$this->db->query(
            "UPDATE leave_requests 
            SET update_status='$status',
                update_reject_reason='$rejectreamrk',
                updated_by='$uid',
                updated_at=NOW()
            WHERE id=$id
            ");
    }
    //echo $str = $this->db->last_query();exit;
    return $isUpdated;
}
