            $slct_user = "`init_call`.`mainbd` = '$uid'";
        }
        if($taskActionbyuser == "all"){
            $actiontype_id_text      = "AND `tblcallevents`.`actiontype_id` != ''";
            $actontaken_text         = "`tblcallevents`.`actontaken` != ''"; 
            $purpose_achieved_text   = "`tblcallevents`.`purpose_achieved` != ''"; 
        }else{
            $actiontype_id_text      = "AND `tblcallevents`.`actiontype_id` = '$tasktaction'";
            $actontaken_text         = "`tblcallevents`.`actontaken` = '$taskActionbyuser'";
            $purpose_achieved_text   = "`tblcallevents`.`purpose_achieved` = '$taskPurposebyuser'";
        }
    }
        if($sid == 'all'){
            $status_text   = "`tblcallevents`.`status_id` != ''";
        }else{
            $status_text   = "`tblcallevents`.`status_id` = '$sid'";
        }
$query=$this->db->query("SELECT `init_call`.`id` AS `inid`, `company_master`.`compname` AS `compname`, `company_master`.`id` AS `cid`, `partner_master`.`name` AS `pname`, CAST(`tblcallevents`.`appointmentdatetime` AS DATE) AS `pdate`, DATEDIFF(CURDATE(), `tblcallevents`.`appointmentdatetime`) AS `days_difference` FROM `init_call` JOIN `tblcallevents` ON `tblcallevents`.`cid_id` = `init_call`.`id` JOIN `company_master` ON `company_master`.`id` = `init_call`.`cmpid_id` JOIN `partner_master` ON `partner_master`.`id` = `company_master`.`partnerType_id` WHERE `tblcallevents`.`nextCFID` != '0' AND $slct_user $actiontype_id_text AND $actontaken_text AND $purpose_achieved_text AND $status_text AND `tblcallevents`.`appointmentdatetime` BETWEEN DATE_SUB(CURDATE(), INTERVAL $second DAY) AND DATE_SUB(CURDATE(), INTERVAL $first DAY) GROUP BY `init_call`.`id`");
return $query->result();
}
