public function get_reviewdetail_New1($rid){
    $status = $this->get_status();
    $text = '';
    foreach($status as $s){
        if($s->id != 7 && $s->id != 14){
            $modifiedString = str_replace(' ', '_', $s->name.'_'.$s->id);
            $output  = preg_replace('/[^a-zA-Z0-9_]/', '', $modifiedString);
            $text   .= "SUM(CASE WHEN main_review.csid = $s->id THEN 1 ELSE 0 END) AS $output,";
        }
    }
    $texts = rtrim($text, ',');
    $query=$this->db->query("SELECT $texts FROM main_review WHERE main_review.rid = '$rid'");
            return $query->result();
        }
