/** To get planner report of the user - MM 21_11_@024*/
public function plannerReportDataModel($uid,$currdate){
$query = $this->db->query("SELECT action.name aname,status.name,init_call.cstatus cstatus,tblcallevents.remarks,
                            (SELECT name from status WHERE id=cstatus) csname,
                             (select init_call.cmpid_id from init_call WHERE id=tblcallevents.cid_id) as cmpid_id,
                             (select company_master.compname from company_master WHERE id=cmpid_id) as compname, 
                             (select company_master.id from company_master WHERE id=cmpid_id) as cid ,CASE WHEN tblcallevents.approved_status = 1 THEN 'Yes' ELSE 'No' END AS approved_status ,user_details.name as approved_by,tblcallevents.updated_at,
                             CASE WHEN tblcallevents.self_assign = 1 THEN 'Admin Requested' 
                                  WHEN tblcallevents.self_assign = 2 THEN 'Admin Created' 
                                  WHEN tblcallevents.self_assign =  3 THEN 'User Created'
                                  WHEN tblcallevents.self_assign = 4 THEN 'Task Approved By System'
                             Else ' ' 
                             END as Rejected
                             FROM tblcallevents left JOIN action ON action.id=tblcallevents.actiontype_id 
                             left JOIN init_call ON init_call.id=tblcallevents.cid_id 
                             left JOIN status ON status.id=init_call.cstatus 
                             LEFT JOIN user_details on user_details.user_id = tblcallevents.approved_by 
                             WHERE tblcallevents.user_id='$uid' and cast(appointmentdatetime AS DATE)='$currdate' and tblcallevents.plan=1 and tblcallevents.autotask =0 ORDER BY tblcallevents.appointmentdatetime");
    return $query->result_array();
}
