    company_master.compname,
    tblcallevents.id,
    init_call.id AS initid,
    tblcallevents.actiontype_id,
    tblcallevents.actontaken,
    tblcallevents.purpose_achieved,
    tblcallevents.appointmentdatetime,
    tblcallevents.targetdate,
    tblcallevents.targetstatus,
    tblcallevents.status_id,
    tblcallevents.assignedto_by
FROM
    tblcallevents
LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
WHERE
    tblcallevents.nextCFID = 0 
    AND tblcallevents.actontaken = 'no' 
    AND tblcallevents.purpose_achieved = 'no' 
    AND tblcallevents.assignedto_by != 0 
    AND tblcallevents.assignedto_id = $bduid 
    AND tblcallevents.selectby = 'Assign Task' 
    AND tblcallevents.user_id = $bduid 
    AND DATE(
        tblcallevents.appointmentdatetime
    ) = CURDATE() + INTERVAL 1 DAY");

    return $query->result();
}
public function GetTommrowAssignedTaskBYActionID($action,$bduid){
    $query=$this->db->query("SELECT company_master.compname,tblcallevents.id, init_call.id as initid, tblcallevents.actiontype_id, tblcallevents.actontaken, tblcallevents.purpose_achieved, tblcallevents.appointmentdatetime, tblcallevents.targetdate, tblcallevents.targetstatus, tblcallevents.status_id, tblcallevents.assignedto_by FROM tblcallevents 
    LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id 
