public function dayManagementReportModel($reportdate){
  $query = $this->db->query("SELECT sr.date,sr.periods,sr.question,sr.star,sr.remarks,ud.name report_for , ud1.name as report_by FROM `star_rating`  sr 
                    left join user_details ud on ud.user_id = sr.user_id 
