    $query = $this->db->query("SELECT barginmeeting.cid cmpid,tblcallevents.*,barginmeeting.*,user_details.*,init_call.cmpid_id,init_call.apst,init_call.potential,
                                tblcallevents.id tid, init_call.apst,init_call.potential,ud3.name as CM
                                FROM tblcallevents
                                LEFT JOIN user_details ON user_details.user_id=tblcallevents.user_id 
                                LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
                                LEFT JOIN barginmeeting ON barginmeeting.tid=tblcallevents.id 
                                LEFT JOIN mom_data ON mom_data.user_id = barginmeeting.user_id
                                LEFT JOIN user_details ud2 ON ud2.user_id = mom_data.user_id
                                LEFT JOIN user_details ud3 ON ud3.user_id = ud2.aadmin
                                WHERE user_details.admin_id = '".$uid."' AND tblcallevents.mtype IN ('RP', 'RPClose', 'Change RP') AND cast(appointmentdatetime as DATE)
