public function CreatePraposalCheckTask($uid,$new_datetime,$praposalid){
    $remarks            = 'Praposal Check';
    $praposal_query     =   $this->db->query("SELECT * FROM `proposal` WHERE id = '$praposalid' ORDER BY `id` DESC");
    $praposalData       = $praposal_query->result();
    $tid                = $praposalData[0]->tid;
    $callebents_query   =   $this->db->query("SELECT * FROM `tblcallevents` WHERE id = '$tid' ORDER BY `id` DESC");
    $callebentsData     = $callebents_query->result();
    $init_id            = $callebentsData[0]->cid_id;
    $cmp_Data           = $this->Menu_model->get_initbyid($init_id);
    $comp_cstatus       = $cmp_Data[0]->cstatus;
    $data1 = [
        'lastCFID' => 0,
        'nextCFID' => 0,
        'fwd_date' => $new_datetime,
        'appointmentdatetime' => $new_datetime,
        'actiontype_id' => 21,
        'auto_plan'=>1,
        'assignedto_id'=>$uid,
        'user_id'=>$uid,
        'purpose_id'=>140,
        'autotask' =>'0',
        'plan' =>'1',
        'remarks'=>$remarks,
        'selectby'=>'Auto Assign Task',
        // 'approved_status'=>1,
        // 'approved_by'=>'System',
        // 'self_assign'=>'4',
        'cid_id'=>$init_id,
        'status_id'=>$comp_cstatus,
        'aftertask'=>$tid
    ];
    $datainsert = $this->db->insert('tblcallevents',$data1);
    $ntid   =  $this->db->insert_id($datainsert);
    $query  =  $this->db->query("UPDATE `proposal` SET `taskplan`='$ntid',`taskplan_by`='$uid' WHERE id = $praposalid");
}
