    if($user_id !==''){
           $mom_query          = $this->db->query("SELECT * FROM `mom_data` WHERE mom_data.`user_id` IN ($user_id) AND `approved_status` IS NULL AND NOT EXISTS (SELECT 1 FROM `tblcallevents` WHERE `mom_data`.`id` = `tblcallevents`.`reviewtype`)");
            $mom_data           =  $mom_query->result();
            $pending_momdata    =  sizeof($mom_data);
                $proposal_query     =$this->db->query("SELECT proposal.*, tblcallevents.appointmentdatetime, user_details.name as username, company_master.compname as company_name,init_call.id as initid FROM `proposal` LEFT JOIN tblcallevents ON tblcallevents.id = proposal.tid LEFT JOIN user_details ON user_details.user_id = proposal.user_id LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE proposal.user_id IN($user_id) AND proposal.apr = 0 AND taskplan = 0 AND taskplan_by = 0 ORDER BY `id` DESC");
    $proposal_data      =  $proposal_query->result();
    $pending_praposal   =  sizeof($proposal_data);
    }else{
        $pending_momdata    =  0;
        $pending_praposal   =  0;
    }
 
    $call_data          = $this->getTaskAssignBySelf($uid);
    $call_data_count    =  sizeof($call_data);
    $alldata = [
        'Call Assign on Tentive Status'=> $call_data_count,
        'Mom Check'=>$pending_momdata,
        'Proposal Check'=>$pending_praposal
    ];
    
    return $alldata;
}
// Get Todays Plan review By user or Reporting Manager 
public function GetTodaysPlanReviews($uid,$tdate){
    $query = $this->db->query("SELECT allreview.*, from_user.name AS fromusername, to_user.name AS tousername FROM allreview LEFT JOIN user_details AS from_user ON from_user.user_id = allreview.uid LEFT JOIN user_details AS to_user ON to_user.user_id = allreview.bdid WHERE (allreview.uid = $uid OR allreview.bdid = $uid) AND NOW() >= allreview.plant AND DATE(allreview.plant) = '$tdate' AND (allreview.startt IS NULL OR allreview.closet IS NULL) AND allreview.reviewtype !='Select Review' ORDER BY `id` DESC");
    return $query->result();
}
public function CheckExistsReviewTime($uid,$pdate,$timeValue){
    $query = $this->db->query("SELECT allreview.*, from_user.name AS fromusername, to_user.name AS tousername FROM allreview LEFT JOIN user_details AS from_user ON from_user.user_id = allreview.uid LEFT JOIN user_details AS to_user ON to_user.user_id = allreview.bdid WHERE (allreview.uid = $uid OR allreview.bdid = $uid) AND DATE(allreview.plant) = '$pdate' AND (allreview.startt IS NULL OR allreview.closet IS NULL) AND TIME('$timeValue') BETWEEN TIME(allreview.plant) AND TIME(allreview.review_close_time) AND allreview.reviewtype !='Select Review' ORDER BY allreview.id DESC");
    return $query->result();
}
