    }else if($uyid == 20){
        $text = "init_call.ash_w_co_id = '$user_id'";
    }else if($uyid == 21){
        $text = "init_call.ash_s_co_id = '$user_id'";
    }else if($uyid == 22){
        $text = "init_call.rm_east_co_id = '$user_id'";
    }else if($uyid == 23){
