    }else{
        $text = "init_call.mainbd = '$user_id'";
    }


    $reset_date = $this->Menu_model->getMaxResetCompulisveNeedDate()[0]->max_reset_date;
   

        // $query=$this->db->query("SELECT DISTINCT init_call.id AS inid, company_master.compname AS compname, user_details.name AS bdname, partner_master.name AS pname, init_call.cstatus, DATEDIFF( main_review.sdate, MAX(tblcallevents.appointmentdatetime) ) AS days, MAX(tblcallevents.appointmentdatetime) AS appointmentdatetime, MAX(main_review.id) AS latest_review_id, MAX(main_review.sdate) AS latest_review_date, MAX(main_review.rtype) AS latest_review_type, DATEDIFF( CURDATE(), MAX(main_review.sdate) ) AS after_review_days, MAX(main_review.ntid) AS review_time_task, COUNT( CASE WHEN DATE(tblcallevents.appointmentdatetime) >= CURDATE() - INTERVAL $days DAY THEN 1 ELSE NULL END ) AS tasklogindays, revtimeaction.name AS revtimeactions, reviewtaskdata.appointmentdatetime as review_time_tasktime FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id LEFT JOIN user_details ON user_details.user_id = init_call.mainbd LEFT JOIN main_review ON init_call.id = main_review.inid LEFT JOIN tblcallevents AS reviewtaskdata ON reviewtaskdata.id = main_review.ntid LEFT JOIN action as revtimeaction ON revtimeaction.id = reviewtaskdata.actiontype_id WHERE ( user_details.user_id = '$user_id' OR user_details.user_id = '$user_id' ) AND user_details.status = 'active' AND init_call.cstatus IN ($status) AND tblcallevents.id IS NOT NULL AND DATE(tblcallevents.appointmentdatetime) < main_review.sdate AND ( SELECT COUNT(*) FROM tblcallevents WHERE DATE(tblcallevents.appointmentdatetime) < CURDATE() AND tblcallevents.cid_id = init_call.id ) = 1 AND NOT EXISTS ( SELECT 1 FROM tblcallevents tce WHERE tce.cid_id = init_call.id AND DATE(tce.appointmentdatetime) = CURDATE() ) GROUP BY init_call.id, company_master.compname, user_details.name, partner_master.name, init_call.cstatus, main_review.sdate HAVING days > $days AND after_review_days > $days");
        // $query=$this->db->query("SELECT init_call.id AS inid, cur_status.name as current_status, company_master.compname AS compname, partner_master.name AS pname, init_call.cstatus, user_details.name AS username, init_call.mainbd, init_call.apst, init_call.clm_id, MAX( DATEDIFF( '$date', tblcallevents.appointmentdatetime ) ) AS days, GREATEST( DATE(main_review.sdate), DATE(tblcallevents.updated_at) ) AS review_date, COUNT( CASE WHEN DATE(tblcallevents.appointmentdatetime) >= CURDATE() - INTERVAL $days DAY THEN tblcallevents.id END ) AS total_log_in_days, (SELECT tblcallevents.appointmentdatetime FROM tblcallevents WHERE tblcallevents.cid_id = init_call.id ORDER BY tblcallevents.id DESC LIMIT 1) AS last_task_update, DATEDIFF(CURDATE(), MAX(tblcallevents.appointmentdatetime)) AS last_task_days, (SELECT tblcallevents.id FROM tblcallevents WHERE tblcallevents.cid_id = init_call.id ORDER BY tblcallevents.id DESC LIMIT 1) AS last_task_id FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id LEFT JOIN main_review ON main_review.inid = init_call.id LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id LEFT JOIN status cur_status ON cur_status.id = init_call.cstatus WHERE ($text) AND init_call.cstatus IN($status) AND tblcallevents.id IS NOT NULL AND DATE(tblcallevents.appointmentdatetime) < '$date' AND ( SELECT COUNT(*) FROM tblcallevents WHERE DATE(tblcallevents.appointmentdatetime) < '$date' AND tblcallevents.cid_id = init_call.id ) >= 3 AND NOT EXISTS( SELECT 1 FROM tblcallevents tce WHERE tce.cid_id = init_call.id AND DATE(tce.appointmentdatetime) = '$date' ) AND ( CASE WHEN DATEDIFF(DATE(tblcallevents.updated_at), DATE(main_review.sdate)) > $days THEN CASE WHEN main_review.sdate > tblcallevents.updated_at THEN DATE(main_review.sdate) ELSE DATE(tblcallevents.updated_at) END ELSE CASE WHEN main_review.sdate > tblcallevents.updated_at THEN DATE(main_review.sdate) ELSE DATE(tblcallevents.updated_at) END END ) GROUP BY init_call.id, init_call.cstatus HAVING days > $days AND last_task_days > $days AND last_task_update < '$date' And last_task_update !='0000-00-00 00:00:00'");
 $query=$this->db->query("SELECT
    init_call.id AS inid,
    cur_status.name AS current_status,
    company_master.compname AS compname,
    partner_master.name AS pname,
    init_call.cstatus,
    user_details.name AS username,
    init_call.mainbd,
    init_call.apst,
    init_call.clm_id,
    main_review.sdate as main_review_date,
    main_review.rtype as main_review_rtype,
    MAX(
        DATEDIFF(
            '$date',
            tblcallevents.appointmentdatetime
        )
    ) AS days,

    -- GREATEST(
    --     DATE(main_review.sdate),
    --     DATE(tblcallevents.updated_at)
    -- ) AS review_date,

        GREATEST(
        DATE(tblcallevents.updated_at),
        GREATEST(DATE(main_review.sdate), DATE('$reset_date'))
        ) AS review_date,



    COUNT(
        CASE WHEN DATE(
            tblcallevents.appointmentdatetime
        ) >= CURDATE() - INTERVAL $days DAY THEN tblcallevents.id
        END) AS total_log_in_days,
    (
    SELECT
        tblcallevents.appointmentdatetime
    FROM
        tblcallevents
    WHERE
        tblcallevents.cid_id = init_call.id
    ORDER BY
        tblcallevents.id
    DESC
LIMIT 1
) AS last_task_update,
DATEDIFF(
    CURDATE(), MAX(
        tblcallevents.appointmentdatetime
    )) AS last_task_days,
    (
    SELECT
        tblcallevents.id
    FROM
        tblcallevents
    WHERE
        tblcallevents.cid_id = init_call.id
    ORDER BY
        tblcallevents.id
    DESC
LIMIT 1
) AS last_task_id
FROM
    init_call
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id
LEFT JOIN main_review ON main_review.inid = init_call.id
LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id
LEFT JOIN status cur_status ON
    cur_status.id = init_call.cstatus
WHERE
    ($text) AND init_call.cstatus IN($status) 
    AND tblcallevents.id IS NOT NULL AND DATE(
        tblcallevents.appointmentdatetime
    ) < '$date' 
    AND main_review.sdate IS NOT NULL
    AND(
    SELECT
        COUNT(*)
    FROM
        tblcallevents
    WHERE
        DATE(
            tblcallevents.appointmentdatetime
        ) < '$date' AND tblcallevents.cid_id = init_call.id
) >= 3 AND NOT EXISTS(
    SELECT
        1
    FROM
        tblcallevents tce
    WHERE
        tce.cid_id = init_call.id AND DATE(tce.appointmentdatetime) = '$date'
) AND(
    CASE WHEN DATEDIFF(
        DATE(tblcallevents.updated_at),
        DATE(main_review.sdate)
    ) > $days THEN CASE WHEN main_review.sdate > tblcallevents.updated_at THEN DATE(main_review.sdate) ELSE DATE(tblcallevents.updated_at)
END ELSE CASE WHEN main_review.sdate > tblcallevents.updated_at THEN DATE(main_review.sdate) ELSE DATE(tblcallevents.updated_at)
END
END
)
GROUP BY
    init_call.id,
    init_call.cstatus
HAVING
    days > $days AND last_task_days > $days 
    AND last_task_update < '$date' 
    AND last_task_update != '0000-00-00 00:00:00'
    AND review_date > main_review.sdate
    AND review_date > DATE('$reset_date')
    ");
    return $query->result();
}
