public function getProposalReportForAdmin($adminid,$sd){
    $this->db->SELECT('count(*) as totalrecs');
    $this->db->FROM('proposal p');
    $this->db->JOIN('user_details ud','ud.user_id=p.user_id');
    $this->db->JOIN('tblcallevents tbe','tbe.id=p.tid');
    $this->db->JOIN('init_call ic','ic.id=tbe.cid_id');
    $this->db->JOIN('company_master cm','cm.id=ic.cmpid_id');
    $this->db->WHERE('ud.status','active');
    $this->db->WHERE('ud.admin_id',$adminid);
    if(isset($sd)){
        $this->db->WHERE('p.sdatet =', $sd); 
    }
    $query = $this->db->get();
    return $query->row();
}
