public function getMeetingReportForAdmin($adminId,$yesterDay){
    $this->db->SELECT('count(tblcallevents.id) as totalRecords');
    $this->db->FROM('tblcallevents');
    $this->db->JOIN('barginmeeting','barginmeeting.tid = tblcallevents.id' ,'LEFT');
    $this->db->JOIN('mom_data','mom_data.tid = tblcallevents.id','LEFT');   
    $this->db->JOIN('init_call','init_call.id = tblcallevents.cid_id','LEFT');
    $this->db->JOIN('company_master','company_master.id = init_call.cmpid_id','LEFT');
    $this->db->JOIN('user_details','user_details.user_id = tblcallevents.assignedto_id','LEFT');
    $this->db->WHERE('CAST(appointmentdatetime as DATE) =',$yesterDay);
    $this->db->WHERE('user_details.admin_id',$adminId);
    $this->db->group_start(); // Opens a parenthesis for grouping conditions
    $this->db->where('actiontype_id', '3');
    $this->db->or_where('actiontype_id', '4');
    $this->db->group_end(); // Close the parenthesis
    $this->db->WHERE('plan','1');
    $query = $this->db->get();
    return $query->row();
}
public function getMeetingReportPerBD($bdid,$sdate,$edate){
  //  $sdate = '2024-11-29';    $edate = '2024-11-29';
    $this->db->SELECT('tblcallevents.*,tblcallevents.id as tid,tblcallevents.status_id,barginmeeting.*,company_master.id as CIN,company_master.compname as Company_Name,init_call.id as cid');
    $this->db->FROM('tblcallevents');
    $this->db->JOIN('barginmeeting','barginmeeting.tid = tblcallevents.id' ,'LEFT');
    $this->db->JOIN('mom_data','mom_data.tid = tblcallevents.id','LEFT');   
    $this->db->JOIN('init_call','init_call.id = tblcallevents.cid_id','LEFT');
    $this->db->JOIN('company_master','company_master.id = init_call.cmpid_id','LEFT');
    $this->db->WHERE('assignedto_id',$bdid);
    $this->db->WHERE('CAST(appointmentdatetime as DATE) >= ',$sdate);
    $this->db->WHERE('CAST(appointmentdatetime as DATE) <= ',$edate);
    $this->db->group_start(); // Opens a parenthesis for grouping conditions
    $this->db->where('actiontype_id', '3');
    $this->db->or_where('actiontype_id', '4');
    $this->db->group_end(); // Close the parenthesis
    $this->db->WHERE('plan','1');
    if(isset($meetingType) && !empty($meetingType)){
        $this->db->WHERE('actiontype_id',$meetingType);
    }
    if(isset($mtype) && !empty($mtype)){
        $this->db->WHERE('mtype',$mtype);
    }
    $query = $this->db->get();
    //echo $this->db->last_query();exit;
    return $query->result_array();
}
public function getMeetingSummaryData($bdid,$adate1,$adate2,$meetingType){
    //$sdate = '2024-11-29';    $edate = '2024-11-29';
    $this->db->SELECT('count(*) as Total');
    $this->db->FROM('tblcallevents');
    $this->db->JOIN('barginmeeting bm','bm.tid=tblcallevents.id','LEFT');
    $this->db->WHERE('assignedto_id',$bdid);
    $this->db->WHERE('CAST(appointmentdatetime as DATE) >= ',$adate1);
    $this->db->WHERE('CAST(appointmentdatetime as DATE) <= ',$adate2);
    $this->db->WHERE('plan','1');
   
     if(isset($meetingType)){
         if(is_numeric($meetingType)){
             if($meetingType == '0'){
                $this->db->group_start();
                 $this->db->where('actiontype_id', '3');
                $this->db->or_where('actiontype_id', '4');
                $this->db->group_end(); // Closes the parenthesis
             }else{
                 $this->db->WHERE_IN('actiontype_id',$meetingType);
             }
         }
         else{
            if($meetingType == 'Initiated'){
                $this->db->WHERE('bm.initiateTime !=','NULL');
            }
            else if($meetingType == 'Started'){
                $this->db->WHERE('bm.startm !=','NULL');
            }
            else if($meetingType == 'Completed'){
                $this->db->WHERE('bm.closem !=','NULL');
            }
            else{
                $this->db->WHERE_IN('mtype',$meetingType);
            }
         }
     }
    $query = $this->db->get();
    //echo $this->db->last_query();exit;
    $querydata = $query->row_array();
    if(isset($querydata['Total']) && !empty($querydata['Total']) && $querydata['Total'] != 0){
        return $querydata['Total'];
    }
    else{
        return false;
    }
}
