public function getProposalLogs($uid,$proposalid){
    $query  = $this->db->query("select proposal.id,(SELECT COUNT(t2.id) FROM tblcallevents t2 WHERE t2.nextCFID!='0' and t2.cid_id=t1.cid_id and t2.  updateddate>'2023-03-31') logs 
    FROM proposal LEFT JOIN tblcallevents t1 ON t1.id=proposal.tid 
    LEFT JOIN user_details ON user_details.user_id=proposal.user_id 
    WHERE user_details.user_id='$uid' AND proposal.id = ".$proposalid);
   
    return $query->row();
}
