public function getTotalCompanyCount($uid,$totalParam,$sd='',$ed=''){
    $db3            = $this->load->database('db3', TRUE);
    $condition1     = " ";
     if(isset($sd) && isset($ed)){
        $condition1 = " AND client_handover.sdatet BETWEEN ".$sd." AND ".$ed." ";
     }
     if($totalParam == 'client_name'){
        $query1       = "SELECT COUNT(DISTINCT client_name) AS totalcomp FROM client_handover WHERE bd_id = ".$uid." ".$condition1." ";
        $queryresult  =  $db3->query($query1);
     
        $result   = $queryresult->row_array();
        $totalSum = $result['totalcomp'];
        return $totalSum;
     }
     else if($totalParam == 'noofschool'){
        $this->db3->select("SUM(noofschool) AS totalSchoolCount");
        $this->db3->from("client_handover");
        $this->db3->where("bd_id",$uid);
        $query1       = "SELECT COUNT(DISTINCT client_name) AS totalcomp FROM client_handover WHERE bd_id = ".$uid;
        $queryresult  =  $db3->query($query1);
     
        $result   = $queryresult->row_array();
        $totalSum = $result['totalcomp'];
        return $totalSum;
        $query  = $this->db3->get();
        $result = $query->row_array();
        
        $totalSum = $result['totalSchoolCount'];
       return $totalSum;
     }
 
}
