public function GetMandatoryRestrictionforPlannerPageList($uid){
    $utype = $this->Menu_model->get_userbyid($uid);
    $utype = $utype[0]->type_id;
    if($utype == 2){
        $text = "";
    }elseif($utype == 13){
        $text = "WHERE user_details1.aadmin = $uid";
    }else if($utype == 4){
        $text = "WHERE user_details1.pst_co = $uid";
    }else if($utype == 15){
        $text = "WHERE user_details1.sales_co = $uid";
    }elseif($utype == 19){
        $text = "WHERE user_details1.ash_nae_co = '$uid'";
    }else if($utype == 20){
        $text = "WHERE user_details1.ash_w_co='$uid'";
    }else if($utype == 21){
        $text = "WHERE user_details1.ash_s_co='$uid'";
    }else if($utype == 22){
        $text = "WHERE user_details1.rm_east_co='$uid'";
    }else if($utype == 23){
        $text = "WHERE user_details1.rm_north_co='$uid'";
    }else if($utype == 24){
        $text = "WHERE user_details1.acm_co='$uid'";
    }else{
        $text = "WHERE user_details1.user_id = $uid";
    }
    $query=$this->db->query("SELECT mr.*, user_details1.name AS to_user, user_details2.name AS by_user FROM `mandatory_restriction` AS mr LEFT JOIN user_details user_details1 ON user_details1.user_id = mr.to_user_id LEFT JOIN user_details user_details2 ON user_details2.user_id = mr.by_user_id $text");
    // $query=$this->db->query("SELECT mr.*, user_details1.name AS to_user, user_details2.name AS by_user FROM `mandatory_restriction` AS mr LEFT JOIN user_details user_details1 ON user_details1.user_id = mr.to_user_id LEFT JOIN user_details user_details2 ON user_details2.user_id = mr.by_user_id");
