 }
 public function GetMandatoryRestrictionforPlannerPageListByUID($uid,$cdate){
    $query=$this->db->query("SELECT mr.*, user_details1.name AS to_user, user_details2.name AS by_user FROM `mandatory_restriction` AS mr LEFT JOIN user_details user_details1 ON user_details1.user_id = mr.to_user_id LEFT JOIN user_details user_details2 ON user_details2.user_id = mr.by_user_id WHERE mr.to_user_id = $uid AND '$cdate' BETWEEN mr.sdate AND mr.edate ORDER by mr.id DESC LIMIT 1");
    return $query->result();
 }
