public function AllMandatoryRestrictionCompanywithuid($userid,$cdate){
    $manData     =   $this->Menu_model->GetMandatoryRestrictionforPlannerPageListByUID($userid,$cdate);
    $manDatacnt  = sizeof($manData);
    if($manDatacnt > 0){
    
    $desiredKeys = ['an_pn_in_week', 'will_give_business', 'no_status_changes', 'review_target_achived','meetings_done'];
    $result = [];
    foreach ($manData as $item) {
        foreach ($desiredKeys as $key) {
            if (isset($item->$key) && $item->$key === "yes") {
                $result[$key] = $item->$key;
            }
        }
    }
    $category         = $manData[0]->category;
    $status_id        = $manData[0]->status_id;
    $week             = $manData[0]->week;
    $actions_id       = $manData[0]->actions_id;
    $pst_assign       = $manData[0]->pst_assign;
    $cluster_assign   = $manData[0]->cluster_assign;
    if($week == 0){
        $week    = 1;
    }
    
    if($actions_id == 0){
        $actions_id = '';
    }
    $company    = [];
    $i          = 0;
    $check_days = 4;
    foreach ($result as $key => $value) {
        if ($key == 'an_pn_in_week') {
            $companys               = $this->Menu_model->ManadotoryANPNInWeek($userid, $week);
            $companyscnt            = sizeof($companys);
            if($companyscnt > 0){
                foreach ($companys as $cmp) {
                    $init_id            = $cmp->cid_id;
                    $checked            = $this->Menu_model->CheckTaskPerforminLastDays($init_id,$check_days);
                    $checkedcnt         = sizeof($checked);
                    if($checkedcnt == 0){
                        $compname           = $cmp->compname;
                        $remarks2           = $cmp->remarks2;
                        $time_difference    = $cmp->time_difference;
                        $taskid1            = $cmp->taskid1;
                        $taskid2            = $cmp->taskid2;
                        $mainbd             = $cmp->mainbd;
                        $company[$init_id]['init_id']           = $init_id;
                        $company[$init_id]['compname']          = $compname;
                        $company[$init_id]['filter']            = 'AN PN Last Week';
                        $company[$init_id]['remarks']           = $remarks2;
                        $company[$init_id]['last_taskid']       = $taskid2;
                        $company[$init_id]['time_difference']   = $time_difference;
                        $company[$init_id]['mainbd']            = $mainbd;
                        $company[$init_id]['task_actions']      = $actions_id;
                    }
                }
            }
        } else if ($key == 'will_give_business') {
            $companys               = $this->Menu_model->GetCompListWillGiveBusiness($userid, $week);
            $companyscnt            = sizeof($companys);
            if($companyscnt > 0){
                foreach ($companys as $cmp) {
                    $init_id            = $cmp->id;
                    $checked            = $this->Menu_model->CheckTaskPerforminLastDays($init_id,$check_days);
                    $checkedcnt         = sizeof($checked);
                    if($checkedcnt == 0){
                        $compname           = $cmp->compname;
                        $time_difference    = $cmp->time_difference;
                        $remarks            = $cmp->remarks;
