public function CheckTaskPerforminLastDays($initid,$days){
    $query=$this->db->query("SELECT * FROM `tblcallevents` WHERE `cid_id` = $initid AND DATE(`appointmentdatetime`) BETWEEN DATE_SUB(CURDATE(), INTERVAL $days DAY) AND CURDATE() ORDER BY `id` DESC");
    return $query->result();
}
// Start Target vs Achievement
public function GetProposalBetweenDate($userid,$start,$end){
    $query=$this->db->query("SELECT 
    proposal.*, 
    user_details.name 
    FROM `proposal` 
    LEFT JOIN user_details on user_details.user_id = proposal.user_id 
    WHERE 
    proposal.user_id = $userid 
    AND DATE(`proposal`.`sdatet`) BETWEEN '$start' AND '$end' 
    AND proposal.apr = 1
    ORDER BY `proposal`.`id` DESC");
    return $query->result();
}
