public function GetMeetingBetweenDate($userid,$start,$end){
    $udetail = $this->Menu_model->get_userbyid($userid);
    $type_id = $udetail[0]->type_id;
    if($type_id == 2){
        $text = "user_details.admin_id = '$userid'";
    }else if($type_id == 3){
        $text = "user_details.user_id = '$userid'";
    }else if($type_id == 13){
        $text = "(user_details.aadmin = '$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 4){
        $text = "(user_details.pst_co = '$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 15){
        $text = "(user_details.sales_co = '$userid' || user_details.user_id = '$userid')";
    }elseif($type_id == 19){
        $text = "(user_details.ash_nae_co = '$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 20){
        $text = "(user_details.ash_w_co='$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 21){
        $text = "(user_details.ash_s_co='$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 22){
        $text = "(user_details.rm_east_co='$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 23){
        $text = "(user_details.rm_north_co='$userid' || user_details.user_id = '$userid')";
    }else if($type_id == 24){
        $text = "(user_details.acm_co='$userid' || user_details.user_id = '$userid')";
    }else{
        $text = "user_details.user_id = '$userid'";
    }
    $query=$this->db->query("SELECT
        barginmeeting.status as meeting_status,
        user_details.name as meeting_username,
        tblcallevents.nextCFID,
        tblcallevents.actontaken,
        tblcallevents.purpose_achieved,
        tblcallevents.actiontype_id,
        tblcallevents.appointmentdatetime,
        tblcallevents.mtype,
        barginmeeting.*,
        user_details.name,
        u1.name as mainbd_name,
        company_master.*,
        company_master.id as cid,
        init_call.cluster_id,
        init_call.upsell_client,
        init_call.focus_funnel,
        init_call.keycompany,
        init_call.pkclient,
        init_call.priorityc,
        init_call.topspender,
        init_call.q1_twetenty_closure_funnel,
        init_call.potential_funnel_for_fy,
        init_call.to_be_nurtured_for_fy,
        init_call.fifity_new_lead_funnel,
        init_call.anchor_clients,
        init_call.in_quarter,
        mom_data.id as mom_data_id,
        tbe1.id as mom_write_task_id,
        action.name as task_name,
        status.name as current_status,
        cluster.id as cluster_id,
        cluster.clustername as clustername,
        cluster_mapping.travel_type AS travelType
    FROM
        `barginmeeting`
    LEFT JOIN user_details ON user_details.user_id = barginmeeting.user_id
    LEFT JOIN company_master ON company_master.id = barginmeeting.cid
    LEFT JOIN init_call ON init_call.cmpid_id = company_master.id
    LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
    LEFT JOIN tblcallevents ON tblcallevents.id = barginmeeting.tid
    LEFT JOIN action ON action.id = tblcallevents.actiontype_id
    LEFT JOIN status ON status.id = init_call.cstatus
    LEFT JOIN cluster ON cluster.id = init_call.cluster_id
    LEFT JOIN cluster_mapping on cluster_mapping.cluster_id = cluster.id AND barginmeeting.user_id
    LEFT JOIN tblcallevents tbe1
        ON tbe1.aftertask = tblcallevents.id
        AND tbe1.actiontype_id = 6
    LEFT JOIN mom_data ON mom_data.tid = tbe1.id
    WHERE
        $text
        AND DATE(`barginmeeting`.`storedt`) BETWEEN '$start' AND '$end' 
        AND tblcallevents.nextCFID !=0
        AND tblcallevents.mtype IN ('RP', 'RPClose', 'Change RP')
        GROUP BY init_call.id 
    ORDER BY `barginmeeting`.`id` DESC");
    return $query->result();
}
public function GetNeewLeadBetweenDate($userid,$start,$end){
    $query=$this->db->query("SELECT
    init_call.*,
    user_details.name AS user_name,
    u1.name AS mainbd_name,
    company_master.*,
    company_master.id AS cid,
    action.name AS task_name,
    tblcallevents.nextCFID,
    tblcallevents.actontaken,
    tblcallevents.purpose_achieved,
    tblcallevents.actiontype_id,
    tblcallevents.appointmentdatetime,
    status.name as current_status
FROM
    init_call
LEFT JOIN  user_details ON user_details.user_id = init_call.creator_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN tblcallevents ON tblcallevents.id = init_call.after_task
LEFT JOIN action ON action.id = tblcallevents.actiontype_id
LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
LEFT JOIN status ON status.id = init_call.cstatus
WHERE
    init_call.creator_id = $userid
    AND DATE(init_call.created_at) BETWEEN '$start' AND '$end'
ORDER BY
    init_call.created_at DESC");
    return $query->result();
}
