// Start Manadatory Compulsive and Need Your Attentions Log 
public function GetAllCompulsiveAndNeedYourAttention($uid,$tdate,$cdate = 'NULL'){
    $udetail = $this->Menu_model->get_userbyid($uid);
       $uyid = $udetail[0]->type_id;
    if($uyid == 3){
        $text = " u3.user_id = '$uid'";
    }else if($uyid == 13){
        $text = " u1.aadmin = '$uid' || u1.user_id = '$uid'";
    }else if($uyid == 4){
        $text = " u1.pst_co = '$uid' || u1.user_id = '$uid'";
    }else if($uyid == 15){
        $text = " u1.sales_co = '$uid'";
    }else if($uyid == 19){
        $text = "u1.ash_nae_co = '$uid'";
    }else if($uyid == 20){
        $text = "u1.ash_w_co = '$uid'";
    }else if($uyid == 21){
        $text = "u1.ash_s_co = '$uid'";
    }else if($uyid == 22){
        $text = "u1.rm_east_co = '$uid'";
    }else if($uyid == 23){
        $text = "u1.rm_north_co = '$uid'";
    }else if($uyid == 24){
        $text = " u1.acm_co = '$uid' || u1.user_id = '$uid'";
    }else if($uyid == 1){
         $text = " u1.sadmin_id = '$uid'";
    }else{
        $text = " u1.admin_id = '$uid'";
    }
    if($cdate == 'NULL'){
        $cdate = $tdate;
     }
     // $query=$this->db->query("SELECT clt.*,MAX(clt.create_date) as last_log_date, COUNT(clt_sub.id) AS init_id_count, u1.name AS tag_username, u3.name AS mainbd_name, company_master.compname, tbc1.actiontype_id AS task_type, action.name AS last_task_name, u2.name AS last_task_byuser, tbc1.remarks AS last_task_remarks, init_call.cstatus FROM `compulsive_log_test` clt LEFT JOIN compulsive_log_test clt_sub ON clt_sub.init_id = clt.init_id AND clt_sub.create_date >= DATE_SUB('$tdate', INTERVAL 2 DAY) LEFT JOIN tblcallevents tbc1 ON tbc1.id = clt.last_task_id LEFT JOIN action ON action.id = tbc1.actiontype_id LEFT JOIN user_details u2 ON u2.user_id = tbc1.user_id LEFT JOIN user_details u1 ON u1.user_id = clt.user_id LEFT JOIN init_call ON init_call.id = clt.init_id LEFT JOIN user_details u3 ON u3.user_id = init_call.mainbd LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents tbc ON tbc.cid_id = clt.init_id AND tbc.appointmentdatetime >= DATE_SUB('$tdate', INTERVAL 2 DAY) WHERE clt.create_date >= DATE_SUB('$tdate', INTERVAL 2 DAY) AND tbc.cid_id IS NULL AND NOT EXISTS ( SELECT 1 FROM tblcallevents tbc2 WHERE tbc2.cid_id = clt.init_id AND tbc2.appointmentdatetime >= DATE_SUB('$tdate', INTERVAL 2 DAY) ) $text GROUP BY clt.init_id HAVING init_id_count >= 2 ORDER BY clt.id DESC");
    $query=$this->db->query("SELECT clt.*, company_master.compname,company_master.id as cid, tbc1.actiontype_id AS task_type, action.name AS last_task_name, u2.name AS last_task_byuser, tbc1.remarks AS last_task_remarks, u1.name AS tag_username, init_call.mainbd, u3.name AS mainbd_name,init_call.cstatus, ( SELECT COUNT(*) FROM compulsive_log_test clt_sub WHERE clt_sub.init_id = clt.init_id AND DATE(clt_sub.create_date) BETWEEN DATE_SUB('$tdate', INTERVAL 2 DAY) AND '$tdate' ) AS init_id_count FROM `compulsive_log_test` clt LEFT JOIN tblcallevents tbc1 ON tbc1.id = clt.last_task_id LEFT JOIN action ON action.id = tbc1.actiontype_id LEFT JOIN user_details u2 ON u2.user_id = tbc1.user_id LEFT JOIN user_details u1 ON u1.user_id = clt.user_id LEFT JOIN init_call ON init_call.id = clt.init_id LEFT JOIN user_details u3 ON u3.user_id = init_call.mainbd LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE $text AND DATE(clt.create_date) = '$tdate' AND NOT EXISTS ( SELECT 1 FROM tblcallevents tbc2 WHERE tbc2.cid_id = clt.init_id AND DATE(tbc2.fwd_date) BETWEEN DATE_SUB('$cdate', INTERVAL 8 DAY) AND '$cdate' ) GROUP BY clt.init_id HAVING init_id_count >= 2 ORDER BY clt.id DESC");
    return $query->result();
}
public function GetAllCompulsiveAndNeedYourAttentionByuid($uid,$tdate,$cdate = 'NULL'){
    // $query=$this->db->query("SELECT clt.*,MAX(clt.create_date) as last_log_date, COUNT(clt_sub.id) AS init_id_count, u1.name AS tag_username, u3.name AS mainbd_name, company_master.compname, tbc1.actiontype_id AS task_type, action.name AS last_task_name, u2.name AS last_task_byuser, tbc1.remarks AS last_task_remarks,init_call.cstatus FROM `compulsive_log_test` clt LEFT JOIN compulsive_log_test clt_sub ON clt_sub.init_id = clt.init_id AND clt_sub.create_date >= DATE_SUB('$tdate', INTERVAL 2 DAY) LEFT JOIN tblcallevents tbc1 ON tbc1.id = clt.last_task_id LEFT JOIN action ON action.id = tbc1.actiontype_id LEFT JOIN user_details u2 ON u2.user_id = tbc1.user_id LEFT JOIN user_details u1 ON u1.user_id = clt.user_id LEFT JOIN init_call ON init_call.id = clt.init_id LEFT JOIN user_details u3 ON u3.user_id = init_call.mainbd LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN tblcallevents tbc ON tbc.cid_id = clt.init_id AND tbc.appointmentdatetime >= DATE_SUB('$tdate', INTERVAL 2 DAY) WHERE clt.create_date >= DATE_SUB('$tdate', INTERVAL 2 DAY) AND tbc.cid_id IS NULL AND NOT EXISTS ( SELECT 1 FROM tblcallevents tbc2 WHERE tbc2.cid_id = clt.init_id AND tbc2.appointmentdatetime >= DATE_SUB('$tdate', INTERVAL 2 DAY) ) AND clt.user_id = '$uid' GROUP BY clt.init_id HAVING init_id_count >= 2 ORDER BY clt.id DESC");
   
    if($cdate == 'NULL'){
        $cdate = $tdate;
     }
    $query=$this->db->query("SELECT clt.*, company_master.compname,company_master.id as cid, tbc1.actiontype_id AS task_type, action.name AS last_task_name, u2.name AS last_task_byuser, tbc1.remarks AS last_task_remarks, u1.name AS tag_username, init_call.mainbd, u3.name AS mainbd_name,init_call.cstatus, ( SELECT COUNT(*) FROM compulsive_log_test clt_sub WHERE clt_sub.init_id = clt.init_id AND DATE(clt_sub.create_date) BETWEEN DATE_SUB('$tdate', INTERVAL 8 DAY) AND '$tdate' ) AS init_id_count FROM `compulsive_log_test` clt LEFT JOIN tblcallevents tbc1 ON tbc1.id = clt.last_task_id LEFT JOIN action ON action.id = tbc1.actiontype_id LEFT JOIN user_details u2 ON u2.user_id = tbc1.user_id LEFT JOIN user_details u1 ON u1.user_id = clt.user_id LEFT JOIN init_call ON init_call.id = clt.init_id LEFT JOIN user_details u3 ON u3.user_id = init_call.mainbd LEFT JOIN company_master ON company_master.id = init_call.cmpid_id WHERE clt.user_id = '$uid' AND DATE(clt.create_date) = '$tdate' AND NOT EXISTS ( SELECT 1 FROM tblcallevents tbc2 WHERE tbc2.cid_id = clt.init_id AND DATE(tbc2.fwd_date) BETWEEN DATE_SUB('$cdate', INTERVAL 8 DAY) AND '$cdate' ) GROUP BY clt.init_id HAVING init_id_count >= 2 ORDER BY clt.id DESC");
    return $query->result();
}
