        $text = " (u1.ash_nae_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 20){
        $text = " (u1.ash_w_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 21){
        $text = " (u1.ash_s_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 22){
        $text = " (u1.rm_east_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 23){
        $text = " (u1.rm_north_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 24){
        $text = " (u1.acm_co = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 1){
        $text = "  (u1.sadmin_id = '$uid' || u1.user_id = '$uid')";
    }else if($uyid == 2){
        $text = "  (u1.admin_id = '$uid' || u1.user_id = '$uid')";
    }else{
        $text = " u1.admin_id = '$uid'";
    }
    // $query=$this->db->query("SELECT plog.init_id, plog.task_id, company_master.id as cid, company_master.compname as company_name, plog.to_user, plog.task_id, tbc.actiontype_id, action.name as task_name, init_call.cstatus, init_call.mainbd, init_call.apst, init_call.clm_id, status.name, MIN(plog.org_task_date) AS org_task_date,plog.remarks, ( SELECT IFNULL(MAX(plog1.re_created_at), plog.re_created_at) FROM planner_log plog1 WHERE plog1.task_id = plog.task_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.re_created_at) ) AS last_create_date, ( SELECT COUNT(*) FROM planner_log plog3 WHERE plog3.task_id = plog.task_id ) AS duplicate_count, CONCAT( TIMESTAMPDIFF(DAY, MIN(plog.org_task_date), ( SELECT IFNULL(MAX(plog1.re_created_at), plog.re_created_at) FROM planner_log plog1 WHERE plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.re_created_at) ) ), ' days ', MOD(TIMESTAMPDIFF(HOUR, MIN(plog.org_task_date), ( SELECT IFNULL(MAX(plog1.re_created_at), plog.re_created_at) FROM planner_log plog1 WHERE plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.org_task_date) ) ), 24), ' hours ', MOD(TIMESTAMPDIFF(MINUTE, MIN(plog.org_task_date), ( SELECT IFNULL(MAX(plog1.re_created_at), plog.re_created_at) FROM planner_log plog1 WHERE plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.org_task_date) ) ), 60), ' minutes' ) AS time_difference, u1.name as to_user_name FROM planner_log plog LEFT JOIN tblcallevents tbc on tbc.id = plog.task_id LEFT JOIN action on action.id = tbc.actiontype_id LEFT JOIN user_details u1 on u1.user_id = plog.to_user LEFT JOIN init_call on init_call.id = plog.init_id LEFT JOIN company_master on company_master.id = init_call.cmpid_id LEFT JOIN status on status.id = init_call.cstatus WHERE Date(plog.re_created_at) <= '$tdate' AND tbc.nextCFID = 0 AND org_task_date != '0000-00-00 00:00:00' AND $text AND u1.status = 'active' GROUP BY plog.task_id HAVING duplicate_count >= 1");
    if($userWise == 'user_wise'){
          $text = " u1.user_id = '$uid'";
    }
    $query=$this->db->query("SELECT
    plog.init_id,
    plog.task_id,
    company_master.id AS cid,
    company_master.compname AS company_name,
    plog.to_user,
    plog.task_id,
    tbc.actiontype_id,
    action.name AS task_name,
    init_call.cstatus,
    init_call.mainbd,
    init_call.apst,
    init_call.clm_id,
status
    .name,
    MIN(plog.org_task_date) AS org_task_date,
    plog.remarks,
    (
    SELECT
        IFNULL(
            MAX(plog1.re_created_at),
            plog.re_created_at
        )
    FROM
        planner_log plog1
    WHERE
        plog1.task_id = plog.task_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.re_created_at)
) AS last_create_date,
(
    SELECT
        COUNT(*)
    FROM
        planner_log plog3
    WHERE
        plog3.task_id = plog.task_id
) AS duplicate_count,
CONCAT(
    TIMESTAMPDIFF(
        DAY,
        MIN(plog.org_task_date),
        (
        SELECT
            IFNULL(
                MAX(plog1.re_created_at),
                plog.re_created_at
            )
        FROM
            planner_log plog1
        WHERE
            plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.re_created_at)
    )
    ),
    ' days ',
    MOD(
        TIMESTAMPDIFF(
            HOUR,
            MIN(plog.org_task_date),
            (
            SELECT
                IFNULL(
                    MAX(plog1.re_created_at),
                    plog.re_created_at
                )
            FROM
                planner_log plog1
            WHERE
                plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.org_task_date)
        )
        ),
        24
    ),
    ' hours ',
    MOD(
        TIMESTAMPDIFF(
            MINUTE,
            MIN(plog.org_task_date),
            (
            SELECT
                IFNULL(
                    MAX(plog1.re_created_at),
                    plog.re_created_at
                )
            FROM
                planner_log plog1
            WHERE
                plog1.init_id = plog.init_id AND plog1.to_user = plog.to_user AND plog1.re_created_at > MIN(plog.org_task_date)
        )
        ),
        60
    ),
    ' minutes'
) AS time_difference,
u1.name AS to_user_name
FROM
    planner_log plog
LEFT JOIN tblcallevents tbc ON tbc.id = plog.task_id
LEFT JOIN action ON action.id = tbc.actiontype_id
LEFT JOIN user_details u1 ON u1.user_id = tbc.user_id
LEFT JOIN init_call ON init_call.id = plog.init_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN status ON status.id = init_call.cstatus
WHERE
    DATE(plog.re_created_at) <= '$tdate' 
    AND tbc.nextCFID = 0 
    AND org_task_date != '0000-00-00 00:00:00' 
    AND $text 
    AND u1.status = 'active'
    AND (tbc.delete_request = '' OR tbc.delete_request IS NULL)
GROUP BY
    plog.task_id
HAVING
    duplicate_count >= 1");
    return $query->result();
}
