public function GetAllPlannerLogByTaskID($taskid){
    $query=$this->db->query("SELECT plog.init_id, company_master.id AS cid, company_master.compname AS company_name, plog.to_user, plog.task_id, tbc.actiontype_id, action.name AS task_name, init_call.cstatus, init_call.mainbd, init_call.apst, init_call.clm_id, status.name, plog.remarks, plog.re_created_at, plog.org_task_date, ( SELECT COUNT(*) FROM planner_log plog3 WHERE plog3.task_id = plog.task_id AND plog3.re_created_at BETWEEN plog.org_task_date AND plog.re_created_at ) AS duplicate_count, CONCAT( TIMESTAMPDIFF(DAY, plog.org_task_date, plog.re_created_at), ' days ', MOD(TIMESTAMPDIFF(HOUR, plog.org_task_date, plog.re_created_at), 24), ' hours ', MOD(TIMESTAMPDIFF(MINUTE, plog.org_task_date, plog.re_created_at), 60), ' minutes' ) AS time_difference, u1.name AS to_user_name FROM planner_log plog LEFT JOIN tblcallevents tbc ON tbc.id = plog.task_id LEFT JOIN action ON action.id = tbc.actiontype_id LEFT JOIN user_details u1 ON u1.user_id = plog.to_user LEFT JOIN init_call ON init_call.id = plog.init_id LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN status ON status.id = init_call.cstatus WHERE org_task_date != '0000-00-00 00:00:00'  AND plog.task_id = '$taskid' ORDER BY plog.re_created_at ");
    return $query->result();
}
