  public function getLocationByLatlong($slat,$slong){
       // $query = "SELECT city_name,state_name FROM statelist WHERE latitude like %".$slat." AND longitude like %".$slong."";
        $query = "SELECT city_name,(6371 * acos(
                cos(radians(21.2308019)) * cos(radians(".$slat.")) * cos(radians(".$slong.") - radians(91.2667)) +
                sin(radians(21.2308019)) * sin(radians(".$slat.")) )) AS distance
                FROM statelist ORDER BY distance LIMIT 1";
        $query_result   = $this->db->query($query);
        $result         = $query_result->result();
        return $result;
    }
    public function getLocationsfromURL($lat,$long){
        // Nomina OpenStreetMap URL
if(isset($lat) && isset($long)){
      $url = "https://nominatim.openstreetmap.org/reverse?format=json&lat=".$lat."&lon=".$long."";
        // Initialize cURL
        $ch = curl_init();
        curl_setopt($ch, CURLOPT_URL, $url);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_setopt($ch, CURLOPT_USERAGENT, 'https://stemapp.in'); // Required by Nominatim API
        curl_setopt($ch, CURLOPT_TIMEOUT, 10); // Set a timeout
        // Execute the request
        $response = curl_exec($ch);
        curl_close($ch);
        // Parse the response
        $data = json_decode($response, true);
        // Check and display location details
        if (!empty($data['address'])){
            $location = $data['display_name'];
        }else 
    {
            $location = "Not Found";
        }
    }
 else {
            $location = "Not Found";
        }
    echo $location;
        return $location;
    }
    
    public function GetTaskDetailsByTid($tid){
        $query=$this->db->query("SELECT tblcallevents.*, company_master.id AS cid, company_master.compname, init_call.id AS init_id, init_call.cstatus, s1.name AS current_status_name, tblstatus.name AS tasktime_status, tblnstatus.name as tasktime_new_status, action.name AS task_name,u1.name as task_user_name, u2.name as task_approve_user_name FROM tblcallevents LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN status AS tblstatus ON tblstatus.id = tblcallevents.status_id LEFT JOIN status AS tblnstatus ON tblnstatus.id = tblcallevents.nstatus_id LEFT JOIN status AS s1 ON s1.id = init_call.cstatus LEFT JOIN action ON action.id = tblcallevents.actiontype_id LEFT JOIN user_details u1 ON u1.user_id = tblcallevents.user_id LEFT JOIN user_details u2 ON u2.user_id = tblcallevents.approved_by WHERE tblcallevents.id = '$tid'");
        return $query->result();
    }
