    public function Addexpensecash($uid,$meet,$expensecash,$bills,$expense_remark,$expense_string){
 
        
        $meetingsDatas = $this->Menu_model->getMeetingTaskonTableMId($meet);
        if(sizeof($meetingsDatas) > 0){

            $tbl_taskid    = $meetingsDatas[0]->tid;
            $tblTaskDatas  = $this->Menu_model->getTBLTaskBySingleID($tbl_taskid);
            $allreadyAddedData  = $this->Menu_model->get_cash_expense_by_meetid($meet);

            if(sizeof($tblTaskDatas) > 0){

                $tbl_task_user_id       = $tblTaskDatas[0]->user_id;
                $tbl_cash_allot         = !empty($tblTaskDatas[0]->cash_allot) ? $tblTaskDatas[0]->cash_allot : 0;

                $to_userDatas           = $this->Menu_model->get_userbyid($tbl_task_user_id);
                $touser_ucash           = $to_userDatas[0]->ucash;

                if(sizeof($allreadyAddedData) > 0){

                    if($expensecash > $touser_ucash){
                        $this->session->set_flashdata('error_message','* You do not have sufficient cash balance to record this expense . Please check your available cash balance.');
                        redirect("Menu/UpdateTodaysMeetingsDetails");
                    }else{
                        $touser_ucash = $touser_ucash - $expensecash;
                        $userDatas = array(
                            'ucash' => $touser_ucash
                        );
                        $this->db->where('user_id', $tbl_task_user_id);
                        $update = $this->db->update('user_details', $userDatas);
                        
                         $data = array(
                            'user_id'           => $tbl_task_user_id,
                            'meetid'            => $meet,
                            'expense'           => $expensecash,
                            'expense_remarks'   => $expense_remark,
                            'bills'             => $bills,
                            'expense_type'      => "$expense_string"
                        );
                        $this->db->insert('cash_expense', $data);

                        $cashlogdata = array(
                            'uid'        => $tbl_task_user_id,
                            'cash'       => $expensecash,
                            'av_cash'    => $touser_ucash,
                            'type'       => "Add",
                            'remarks'    => "Expense for Meeting ID: $meet. this meeting allready added by you. and this is expense for $expense_string",
                            'task_id'    => $tbl_taskid
                        );
                        $this->db->insert('cash_log', $cashlogdata);
                    }
                }else{

                    if($tbl_cash_allot >= $expensecash){
    
                        $new_cash_allot     = $tbl_cash_allot - $expensecash;

                        $new_user_cur_cash  = $touser_ucash + $new_cash_allot;
                        $userDatas = array(
                            'ucash' => $new_user_cur_cash
                        );
                        $this->db->where('user_id', $tbl_task_user_id);
                        $this->db->update('user_details', $userDatas);

                        $userTblCallDatas = array(
                            'cash_expense' => $expensecash,
                            'cash_refund' => $new_cash_allot
                        );
                        $this->db->where('id', $tbl_taskid);
                        $this->db->update('tblcallevents', $userTblCallDatas);

                        $cashlogdata = array(
                            'uid'        => $tbl_task_user_id,
                            'cash'       => $new_cash_allot,
                            'av_cash'    => $new_user_cur_cash,
                            'type'       => "Add",
                            'remarks'    => "Added Back for Meeting Expense Allocation. Great Job!",
                            'task_id'    => $tbl_taskid
                        );
                        $this->db->insert('cash_log', $cashlogdata);

                        $data = array(
                            'user_id'           => $uid,
                            'meetid'            => $meet,
                            'expense'           => $expensecash,
                            'expense_remarks'   => $expense_remark,
                            'bills'             => $bills,
                            'expense_type'      => "$expense_string"
                        );
                        $this->db->insert('cash_expense', $data);
                        $this->session->set_flashdata('success_message','* Expense Allocated Successfully from Task Cash Allotment for Meeting. *');

                    }else if($tbl_cash_allot < $expensecash){
                    
                        $new_cash_allot         = $expensecash - $tbl_cash_allot;
                        
                        if($touser_ucash >= $new_cash_allot){

                            $new_user_cur_cash  = $touser_ucash - $new_cash_allot;
                            $userDatas = array(
                                'ucash' => $new_user_cur_cash
                            );
                            $this->db->where('user_id', $tbl_task_user_id);
                            $this->db->update('user_details', $userDatas);

                            $userTblCallDatas = array(
                                'cash_expense'                  => $expensecash,
                                'extra_cash_diduct_from_wallet' => $new_cash_allot
                            );
                            $this->db->where('id', $tbl_taskid);
                            $this->db->update('tblcallevents', $userTblCallDatas);

                            $cashlogdata = array(
                                'uid'        => $tbl_task_user_id,
                                'cash'       => $new_cash_allot,
                                'av_cash'    => $new_user_cur_cash,
                                'type'       => "Deduct",
                                'remarks'    => "Deducted for Meeting Expense Allocation, Because Task Cash Allotment is Insufficient. $new_cash_allot Extra Cash Deducted From User Wallet.",
                                'task_id'    => $tbl_taskid
                            );
                            $this->db->insert('cash_log', $cashlogdata);

                            $data = array(
                                    'user_id'           => $uid,
                                    'meetid'            => $meet,
                                    'expense'           => $expensecash,
                                    'expense_remarks'   => $expense_remark,
                                    'bills'             => $bills,
                                    'expense_type'      => "$expense_string"
                                );
                            $this->db->insert('cash_expense', $data);
                            $this->session->set_flashdata('success_message','* Expense Allocated Successfully by Deducting User Cash Account for Meeting. *');
                        }else{
                            $this->session->set_flashdata('error_message','* Insufficient Cash in User Account to Allocate Expense Amount for Meeting. Please Recharge User Cash Account. *');
                        }
                    }

                }
            }   
        }
        // redirect("Menu/UpdateTodaysMeetingsDetails");

        // $data = array(
        //     'user_id'           => $uid,
        //     'meetid'            => $meet,
        //     'expense'           => $expensecash,
        //     'expense_remarks'   => $expense_remark,
        //     'bills'             => $bills,
        //     'expense_type'      => "$expense_string"
        // );
        // $this->db->insert('cash_expense', $data);

        // $tuser = $this->Menu_model->get_userbyid($uid);
        // $ucash = $tuser[0]->ucash;
        // $ucash = $ucash - $expensecash;
        
        // $this->db->query("UPDATE `user_details` SET `ucash`='$ucash' WHERE user_id = '$uid'");
    
}
