    $uyid = $udetail[0]->type_id;
    if($uyid == 3){
        $text = " u1.user_id = '$uid'";
    }else if($uyid == 13){
        $text = "( u1.aadmin = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 4){
        $text = "(u1.pst_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 15){
        $text = " u1.sales_co = '$uid'";
    }else if($uyid == 19){
        $text = "(u1.ash_nae_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 20){
        $text = "(u1.ash_w_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 21){
        $text = "(u1.ash_s_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 22){
        $text = "(u1.rm_east_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 23){
        $text = "(u1.rm_north_co = '$uid' OR u1.user_id = '$uid')";
    }else if($uyid == 24){
        $text = "(u1.acm_co = '$uid' OR u1.user_id = '$uid')";
    }elseif($uyid == 1){
        $text = "u1.sadmin_id = '$uid'";
    }elseif($uyid == 2){
        $text = "u1.admin_id = '$uid'";
    }else{
        $text = " u1.admin_id = '$uid'";
    }
    $ustatus = " AND u1.status = 'active'";
    $query=$this->db->query("SELECT u1.name,u1.ucash, ta.user_id, COUNT(*) AS total,COUNT(CASE WHEN ((ta.cluster_apr = '0' AND ta.admin_apr = '0' AND ta.account_apr = '0') || (ta.cluster_apr = '1' AND ta.admin_apr = '0' AND ta.account_apr = '0') || (ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '0')) THEN 1 END) AS total_pending,COUNT(CASE WHEN ((ta.cluster_apr = '2' AND ta.admin_apr = '0' AND ta.account_apr = '0') || (ta.cluster_apr = '1' AND ta.admin_apr = '2' AND ta.account_apr = '0') || (ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '2')) THEN 1 END) AS total_reject,COUNT(CASE WHEN ((ta.cluster_apr = '1' AND ta.admin_apr = '3' AND ta.account_apr = '0') || (ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '3') ) THEN 1 END) AS total_suspect, COUNT( CASE WHEN ta.cluster_apr = '0' THEN 1 END ) AS manager_pending, COUNT( CASE WHEN ta.cluster_apr = '1' THEN 1 END ) AS manager_approved, COUNT( CASE WHEN ta.cluster_apr = '2' THEN 1 END ) AS manager_reject, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '0' THEN 1 END ) AS admin_pending, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' THEN 1 END ) AS admin_approved, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '2' THEN 1 END ) AS admin_reject, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '3' THEN 1 END ) AS admin_suspected, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '0' THEN 1 END ) AS account_pending, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '1' THEN 1 END ) AS account_approved, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '2' THEN 1 END ) AS account_reject, COUNT( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' AND ta.account_apr = '3' THEN 1 END ) AS account_suspect, SUM(ta.cash) AS total_cash_request, SUM( CASE WHEN ta.cluster_apr = '1' THEN ta.cash ELSE 0 END ) AS total_approved_cash_form_manager, SUM( CASE WHEN ta.cluster_apr = '2' THEN ta.cash ELSE 0 END ) AS total_reject_cash_form_manager, SUM( CASE WHEN ta.cluster_apr = '3' THEN ta.cash ELSE 0 END ) AS total_suspect_cash_form_manager, SUM( CASE WHEN ta.cluster_apr = '0' THEN ta.cash ELSE 0 END ) AS total_pending_cash_form_manager, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1' THEN ta.cash ELSE 0 END ) AS total_approved_cash_form_admin, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '2' THEN ta.cash ELSE 0 END ) AS total_reject_cash_form_admin, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '3' THEN ta.cash ELSE 0 END ) AS total_suspect_cash_form_admin, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '0' THEN ta.cash ELSE 0 END ) AS total_pending_cash_form_admin, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1'  AND ta.account_apr = '1' THEN ta.cash ELSE 0 END ) AS total_approved_cash_form_account, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1'  AND ta.account_apr = '2' THEN ta.cash ELSE 0 END ) AS total_reject_cash_form_account, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1'  AND ta.account_apr = '3' THEN ta.cash ELSE 0 END ) AS total_suspect_cash_form_account, SUM( CASE WHEN ta.cluster_apr = '1' AND ta.admin_apr = '1'  AND ta.account_apr = '0' THEN ta.cash ELSE 0 END ) AS total_pending_cash_form_account  FROM `travel_advance` ta LEFT JOIN user_details u1 ON u1.user_id = ta.user_id WHERE u1.name IS NOT NULL AND $text $ustatus AND cast(ta.date as DATE) BETWEEN '$sdate' and '$edate' GROUP BY ta.user_id");
    return $query->result();
}
