        $text = " u1.admin_id = '$uid'";
    }
    $ustatus = " AND u1.status = 'active'";
   $query=$this->db->query("SELECT u1.name,u1.ucash, ce.user_id, COUNT(*) AS total,COUNT( CASE WHEN( ( ce.verify = '0' AND ce.admin_apr = '0' AND ce.account_apr = '0' ) ||( ce.verify = '1' AND ce.admin_apr = '0' AND ce.account_apr = '0' ) ||( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '0' ) ) THEN 1 END ) AS total_pending, COUNT( CASE WHEN( ( ce.verify = '2' AND ce.admin_apr = '0' AND ce.account_apr = '0' ) ||( ce.verify = '1' AND ce.admin_apr = '2' AND ce.account_apr = '0' ) ||( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '2' ) ) THEN 1 END ) AS total_reject, COUNT( CASE WHEN( ( ce.verify = '1' AND ce.admin_apr = '3' AND ce.account_apr = '0' ) ||( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '3' )) THEN 1 END ) AS total_suspect, COUNT( CASE WHEN ce.verify = '0' THEN 1 END ) AS manager_pending, COUNT( CASE WHEN ce.verify = '1' THEN 1 END ) AS manager_approved, COUNT( CASE WHEN ce.verify = '2' THEN 1 END ) AS manager_reject, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '0' ) THEN 1 END ) AS admin_pending, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '1' ) THEN 1 END ) AS admin_approved, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '2' ) THEN 1 END ) AS admin_reject, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '3' ) THEN 1 END ) AS admin_suspected, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '0' ) THEN 1 END ) AS account_pending, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '1' ) THEN 1 END ) AS account_approved, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '2' ) THEN 1 END ) AS account_reject, COUNT( CASE WHEN( ce.verify = '1' AND ce.admin_apr = '1' AND ce.account_apr = '3' ) THEN 1 END ) AS account_suspected,SUM(ce.expense) AS total_cash_expense, SUM( CASE WHEN ce.verify = '1' THEN ce.expense ELSE 0 END ) AS total_approved_cash_form_manager, SUM( CASE WHEN ce.verify = '2' THEN ce.expense ELSE 0 END ) AS total_reject_cash_form_manager, SUM( CASE WHEN ce.verify = '3' THEN ce.expense ELSE 0 END ) AS total_suspect_cash_form_manager, SUM( CASE WHEN ce.verify = '0' THEN ce.expense ELSE 0 END ) AS total_pending_cash_form_manager, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '1' THEN ce.expense ELSE 0 END ) AS total_approved_cash_form_admin, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '2' THEN ce.expense ELSE 0 END ) AS total_reject_cash_form_admin, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '3' THEN ce.expense ELSE 0 END ) AS total_suspect_cash_form_admin, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '0' THEN ce.expense ELSE 0 END ) AS total_pending_cash_form_admin, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '1'  AND ce.account_apr = '1' THEN ce.expense ELSE 0 END ) AS total_approved_cash_form_account, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '1'  AND ce.account_apr = '2' THEN ce.expense ELSE 0 END ) AS total_reject_cash_form_account, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '1'  AND ce.account_apr = '3' THEN ce.expense ELSE 0 END ) AS total_suspect_cash_form_account, SUM( CASE WHEN ce.verify = '1' AND ce.admin_apr = '1'  AND ce.account_apr = '0' THEN ce.expense ELSE 0 END ) AS total_pending_cash_form_account FROM `cash_expense` ce LEFT JOIN user_details u1 ON u1.user_id = ce.user_id WHERE u1.name IS NOT NULL AND $text $ustatus AND cast(ce.created_at as DATE) BETWEEN '$sdate' and '$edate' GROUP BY ce.user_id");
    return $query->result();
}
public function GetAllTravelAdvancedByCode($code,$uid,$sdate,$edate){
   
    $text = "user_details.user_id = '$uid'";
    $textfilter = "AND travel_advance.user_id = '$uid'";
    if($code ==1){
        $filter = '';
    }else if($code ==2){
        $filter = "AND travel_advance.cluster_apr = '1'";
    }else if($code ==3){
        $filter = "AND travel_advance.cluster_apr = '0'";
    }else if($code ==4){
        $filter = "AND travel_advance.cluster_apr = '2'";
    }else if($code ==5){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1'";
    }else if($code ==6){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '0'";
    }else if($code ==7){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '2'";
    }else if($code ==8){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '1'";
    }else if($code ==9){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '0'";
    }else if($code ==10){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '2'";
    }else if($code ==11){
        $filter = "AND travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '3'";
    }else if($code ==12){
        $filter = "AND ((travel_advance.cluster_apr = '0' AND travel_advance.admin_apr = '0' AND travel_advance.account_apr = '0') || (travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '0' AND travel_advance.account_apr = '0') || (travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '0') $textfilter )";
    }else if($code ==13){
        $filter = "AND ((travel_advance.cluster_apr = '2' AND travel_advance.admin_apr = '0' AND travel_advance.account_apr = '0') || (travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '2' AND travel_advance.account_apr = '0') || (travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '2') $textfilter )";
    }else if($code ==14){
        $filter = "AND ((travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '3' AND travel_advance.account_apr = '0') || (travel_advance.cluster_apr = '1' AND travel_advance.admin_apr = '1' AND travel_advance.account_apr = '3') $textfilter )";
    }

    if($sdate == 'all' && $edate == 'all'){
       $dateFilter = '';
    }else{
       $dateFilter = "AND CAST(travel_advance.date AS DATE) BETWEEN '$sdate' AND '$edate'";
    }

    $query=$this->db->query("SELECT
    travel_advance.*,
    user_details.name,
    u1.name as cluster_by_name,
    u2.name as admin_by_name
FROM
    travel_advance
LEFT JOIN user_details ON user_details.user_id = travel_advance.user_id
LEFT JOIN user_details u1 ON u1.user_id = travel_advance.cluster_by
LEFT JOIN user_details u2 ON u2.user_id = travel_advance.admin_by
WHERE
    $text $dateFilter
    $filter $textfilter
ORDER BY
    travel_advance.id
DESC
    ");
    return $query->result();
}




