public function GetSCTaskDayTypesWithGroupANDUid($uid,$adate){
    $query=$this->db->query("SELECT sc_task.type_of_task, COUNT(CASE WHEN NOT EXISTS ( SELECT 1 FROM sc_task_events WHERE sc_task_events.sc_task_id = sc_task.id AND sc_task_events.by_user_id = '$uid' AND Cast(appointment_datetime AS Date) = '$adate' ) THEN 1 ELSE NULL END) AS count_of_null_events FROM sc_task WHERE sc_task.status = 1 GROUP BY sc_task.type_of_task");
    return $query->result();
}
public function GetSCTaskDayTypesWithGroupAndDUidDWA($uid,$adate){
    $daystask = $this->Menu_model->day_wise_task_type();
    $daystasktext = '';
    foreach($daystask as $dts){
        if($dts->task_type !== 'Daily'){
            $daystasktext .= "OR(sc_task.type_of_task = '$dts->task_type' AND CAST(sc_task_events.appointment_datetime AS DATE) > DATE_SUB('$adate', INTERVAL $dts->days DAY))";
        }
    }
    $query=$this->db->query("SELECT sc_task.type_of_task, COUNT( CASE WHEN sc_task_events.sc_task_id IS NULL THEN 1 ELSE NULL END ) AS count_of_null_events FROM sc_task LEFT JOIN sc_task_events ON sc_task_events.sc_task_id = sc_task.id AND sc_task_events.by_user_id = '$uid' AND( ( sc_task.type_of_task = 'Daily' AND CAST( sc_task_events.fwd_date AS DATE ) = '$adate' ) $daystasktext ) WHERE sc_task.status = 1 GROUP BY sc_task.type_of_task");
    return $query->result();
}
public function GetSCTaskDayTypesWithGroupAndDUidDWA_New($uid,$adate,$timezone){
    $daystask = $this->Menu_model->day_wise_task_type();
    $daystasktext = '';
    foreach($daystask as $dts){
        if($dts->task_type !== 'Daily'){
            $daystasktext .= "OR(sc_task.type_of_task = '$dts->task_type' AND CAST(sc_task_events.appointment_datetime AS DATE) > DATE_SUB('$adate', INTERVAL $dts->days DAY))";
        }
    }
    $query=$this->db->query("SELECT * FROM sc_task WHERE sc_task.status = 1 AND sc_task.type_of_task = '$timezone' AND NOT EXISTS( SELECT 1 FROM sc_task_events WHERE sc_task_events.sc_task_id = sc_task.id AND sc_task_events.by_user_id = '$uid' AND( ( sc_task.type_of_task = 'Daily' AND CAST( sc_task_events.fwd_date AS DATE ) = '$adate' ) $daystasktext ) )");
    return $query->result();
}
