nt(CASE WHEN tblcallevents.actiontype_id=6 THEN actiontype_id end) write_mom, count(CASE WHEN tblcallevents.actiontype_id=7 THEN actiontype_id end) write_proposal, count(CASE WHEN tblcallevents.actiontype_id=10 THEN actiontype_id end) research_task, count(CASE WHEN tblcallevents.actiontype_id=12 THEN actiontype_id end) documentation_task, count(CASE WHEN tblcallevents.actiontype_id=13 THEN actiontype_id end) social_networking_task, count(CASE WHEN tblcallevents.actiontype_id=14 THEN actiontype_id end) social_activity_task, count(CASE WHEN tblcallevents.actiontype_id=15 THEN actiontype_id end) annual_review_target_task, count(CASE WHEN tblcallevents.actiontype_id=17 THEN actiontype_id end) join_meeting_task, count(CASE WHEN tblcallevents.actiontype_id=18 THEN actiontype_id end) mom_check_task, count(CASE WHEN tblcallevents.actiontype_id=19 THEN actiontype_id end) create_bd_request_task, count(CASE WHEN tblcallevents.actiontype_id=20 THEN actiontype_id end) submit_handover_task, count(CASE WHEN tblcallevents.actiontype_id=21 THEN actiontype_id end) praposal_check_task FROM tblcallevents LEFT JOIN user_details u1 ON u1.user_id = tblcallevents.user_id LEFT JOIN user_type ut ON ut.id = u1.type_id LEFT JOIN user_day ud ON ud.user_id = u1.user_id LEFT JOIN userworkfrom ON userworkfrom.id = ud.wffo WHERE CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' AND CAST(ud.ustart AS DATE) = '$tdate' $text GROUP BY u1.name, u1.user_id");
