public function MultipleUploadFiles($fileInputName, $uploadPath)
{
    $uploadedFiles = []; // Array to store paths of uploaded files
    // Loop through each uploaded file
    foreach ($_FILES[$fileInputName]['name'] as $key => $value) {
        if (!empty($_FILES[$fileInputName]['name'][$key])) {
            // Prepare the file data for each file
            $_FILES['file']['name']     = $_FILES[$fileInputName]['name'][$key];
            $_FILES['file']['type']     = $_FILES[$fileInputName]['type'][$key];
            $_FILES['file']['tmp_name'] = $_FILES[$fileInputName]['tmp_name'][$key];
            $_FILES['file']['error']    = $_FILES[$fileInputName]['error'][$key];
            $_FILES['file']['size']     = $_FILES[$fileInputName]['size'][$key];
            // Generate a unique file name for each file
            $extension = pathinfo($_FILES['file']['name'], PATHINFO_EXTENSION);
            $uniqueFileName = date("Y-m-d") . time() . '_' . uniqid() . '.' . $extension;
            // Configure upload settings
            $config['upload_path']   = $uploadPath;
            $config['allowed_types'] = '*';
            $config['file_name']     = $uniqueFileName;
            // Load the upload library for each file
            $this->load->library('upload', $config);
            if ($this->upload->do_upload('file')) {
                $uploadData = $this->upload->data();
                $filename = $uploadData['file_name'];
                $uploadedFiles[] = $uploadPath . $filename; // Add the full path of the uploaded file
            } else {
                $error = $this->upload->display_errors();
                log_message('error', "File upload error: $error");
                // Optionally handle errors (e.g., add to a log or error array)
            }
        }
    }
    // Return the array of uploaded file paths
    return $uploadedFiles;
}
