public function CheckNoStatusChangeBetweenDaysByuid($uid,$days){
    // $query=$this->db->query("SELECT init_call.id AS inid, company_master.compname AS compname, partner_master.name AS pname, init_call.cstatus, s1.name AS current_status, s2.name AS last_status, init_call.lstatus, MAX(tblcallevents.id) AS last_task_id, action.name AS last_task_name, MAX(tblcallevents.appointmentdatetime) AS last_task_date, COUNT(tblcallevents.id) AS task_count_last_days, IF( MAX(tblcallevents.status_id) = init_call.cstatus, CONCAT( TIMESTAMPDIFF(DAY, MAX(tblcallevents.updateddate), NOW()), ' days ', TIMESTAMPDIFF(HOUR, MAX(tblcallevents.updateddate), NOW()) % 24, ' hours ', TIMESTAMPDIFF(MINUTE, MAX(tblcallevents.updateddate), NOW()) % 60, ' minutes' ), NULL ) AS time_difference FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id LEFT JOIN status s1 ON s1.id = init_call.cstatus LEFT JOIN status s2 ON s2.id = init_call.lstatus LEFT JOIN action ON action.id = tblcallevents.actiontype_id WHERE init_call.mainbd = '$uid' AND tblcallevents.nextCFID != 0 AND tblcallevents.appointmentdatetime >= DATE_SUB(CURDATE(), INTERVAL $days DAY) GROUP BY init_call.id");
    $query=$this->db->query("SELECT init_call.id AS inid, company_master.compname AS compname, partner_master.name AS pname, init_call.cstatus, s1.name AS current_status, s2.name AS last_status, init_call.lstatus, MAX(tblcallevents.id) AS last_task_id, action.name AS last_task_name, MAX(tblcallevents.appointmentdatetime) AS last_task_date, COUNT(tblcallevents.id) AS task_count_last_days, IF( MAX(tblcallevents.status_id) = init_call.cstatus, CONCAT( TIMESTAMPDIFF(DAY, MAX(tblcallevents.updateddate), NOW()), ' days ', TIMESTAMPDIFF(HOUR, MAX(tblcallevents.updateddate), NOW()) % 24, ' hours ', TIMESTAMPDIFF(MINUTE, MAX(tblcallevents.updateddate), NOW()) % 60, ' minutes' ), NULL ) AS time_difference FROM init_call LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id LEFT JOIN tblcallevents ON tblcallevents.cid_id = init_call.id LEFT JOIN status s1 ON s1.id = init_call.cstatus LEFT JOIN status s2 ON s2.id = init_call.lstatus LEFT JOIN action ON action.id = tblcallevents.actiontype_id WHERE (init_call.mainbd = '$uid') AND tblcallevents.nextCFID != 0 AND tblcallevents.appointmentdatetime >= DATE_SUB(CURDATE(), INTERVAL $days DAY) GROUP BY init_call.id HAVING time_difference IS NOT NULL AND TIMESTAMPDIFF(DAY, MAX(tblcallevents.updateddate), NOW()) >= $days");
    return $query->result();
}
