}
public function GetAllTypeRequestCreateByUserWithPlannerHours($uid,$tdate){
    $text = "AND u1.user_id  = '$uid'";
    $query=$this->db->query("SELECT ufo.TYPE AS planning_time_user_work_from, ( SUM( CASE WHEN tblcallevents.actiontype_id = 1 THEN 5 WHEN tblcallevents.actiontype_id = 2 THEN 10 WHEN tblcallevents.actiontype_id = 3 THEN 60 WHEN tblcallevents.actiontype_id = 4 THEN 60 WHEN tblcallevents.actiontype_id = 5 THEN 5 WHEN tblcallevents.actiontype_id = 6 THEN 10 WHEN tblcallevents.actiontype_id = 7 THEN 15 WHEN tblcallevents.actiontype_id = 8 THEN 5 WHEN tblcallevents.actiontype_id = 9 THEN 5 WHEN tblcallevents.actiontype_id = 10 THEN 5 WHEN tblcallevents.actiontype_id = 11 THEN 2 WHEN tblcallevents.actiontype_id = 12 THEN 30 WHEN tblcallevents.actiontype_id = 13 THEN 2 WHEN tblcallevents.actiontype_id = 14 THEN 2 WHEN tblcallevents.actiontype_id = 17 THEN 60 WHEN tblcallevents.actiontype_id = 19 THEN 10 ELSE 0 END ) ) AS total_task_time, ( SUM( CASE WHEN tblcallevents.autotask = 0 THEN CASE WHEN tblcallevents.actiontype_id = 1 THEN 5 WHEN tblcallevents.actiontype_id = 2 THEN 10 WHEN tblcallevents.actiontype_id = 3 THEN 60 WHEN tblcallevents.actiontype_id = 4 THEN 60 WHEN tblcallevents.actiontype_id = 5 THEN 5 WHEN tblcallevents.actiontype_id = 6 THEN 10 WHEN tblcallevents.actiontype_id = 7 THEN 15 WHEN tblcallevents.actiontype_id = 8 THEN 5 WHEN tblcallevents.actiontype_id = 9 THEN 5 WHEN tblcallevents.actiontype_id = 10 THEN 5 WHEN tblcallevents.actiontype_id = 11 THEN 2 WHEN tblcallevents.actiontype_id = 12 THEN 30 WHEN tblcallevents.actiontype_id = 13 THEN 2 WHEN tblcallevents.actiontype_id = 14 THEN 2 WHEN tblcallevents.actiontype_id = 17 THEN 60 WHEN tblcallevents.actiontype_id = 19 THEN 10 ELSE 0 END ELSE 0 END ) ) AS total_plan_time_on_planner, ( SUM( CASE WHEN tblcallevents.autotask = 1 THEN CASE WHEN tblcallevents.actiontype_id = 1 THEN 5 WHEN tblcallevents.actiontype_id = 2 THEN 10 WHEN tblcallevents.actiontype_id = 3 THEN 60 WHEN tblcallevents.actiontype_id = 4 THEN 60 WHEN tblcallevents.actiontype_id = 5 THEN 5 WHEN tblcallevents.actiontype_id = 6 THEN 10 WHEN tblcallevents.actiontype_id = 7 THEN 15 WHEN tblcallevents.actiontype_id = 8 THEN 5 WHEN tblcallevents.actiontype_id = 9 THEN 5 WHEN tblcallevents.actiontype_id = 10 THEN 5 WHEN tblcallevents.actiontype_id = 11 THEN 2 WHEN tblcallevents.actiontype_id = 12 THEN 30 WHEN tblcallevents.actiontype_id = 13 THEN 2 WHEN tblcallevents.actiontype_id = 14 THEN 2 WHEN tblcallevents.actiontype_id = 17 THEN 60 WHEN tblcallevents.actiontype_id = 19 THEN 10 ELSE 0 END ELSE 0 END ) ) AS total_plan_time_with_autotask, CASE WHEN EXISTS ( SELECT 1 FROM task_plan_for_today WHERE user_id = u1.user_id AND DATE = '$tdate' ) THEN 'Yes' ELSE 'No' END AS task_plan_for_today_request, CASE WHEN EXISTS ( SELECT 1 FROM special_request_for_leave WHERE user_id = u1.user_id AND DATE = '$tdate' ) THEN 'Yes' ELSE 'No' END AS user_create_special_request_for_leave, CASE WHEN EXISTS ( SELECT 1 FROM reminder WHERE user_id = u1.user_id AND DATE(created_at) = '$tdate' ) THEN 'Yes' ELSE 'No' END AS user_request_any_reminder, CASE WHEN EXISTS ( SELECT 1 FROM create_planner_request WHERE request_user_id = u1.user_id AND DATE(created_at) = '$tdate' ) THEN 'Yes' ELSE 'No' END AS pending_task_planner_request, ( SELECT COUNT(*) FROM session_plan_time WHERE user_id = u1.user_id AND DATE(created_at) = '$tdate' ) AS session_count FROM tblcallevents LEFT JOIN user_details u1 ON u1.user_id = tblcallevents.user_id LEFT JOIN user_type ut ON ut.id = u1.type_id LEFT JOIN user_day ud ON ud.user_id = u1.user_id LEFT JOIN autotask_time ON autotask_time.user_id = u1.user_id AND autotask_time.date = '$tdate' LEFT JOIN userworkfrom ON userworkfrom.id = ud.wffo LEFT JOIN userworkfrom ufo ON ufo.id = autotask_time.userworkfrom AND autotask_time.date = '$tdate' WHERE CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' AND CAST(ud.ustart AS DATE) = '$tdate' $text GROUP BY u1.user_id, u1.name, ut.name, userworkfrom.TYPE, ufo.TYPE");
    return $query->result();
}
public function CompressAndReUploadImageWhenIsExists($file_path, $upload_path) {
                    // Check if the file exists
                if (!file_exists($file_path)) {
                    return "File does not exist.";
                }
                // Get image info
                $image_info = getimagesize($file_path);
                $mime = $image_info['mime'];
                // Load the image based on its MIME type
                switch ($mime) {
                    case 'image/jpeg':
                        $image = imagecreatefromjpeg($file_path);
                        break;
                    case 'image/png':
                        $image = imagecreatefrompng($file_path);
                        break;
                    case 'image/gif':
                        $image = imagecreatefromgif($file_path);
                        break;
                    default:
                        return "Unsupported image type.";
                }
                // Set compression quality (0 - 100 for JPEG, 0 - 9 for PNG)
                $quality = 50; // Adjust as needed
                // Delete the existing file
                if (file_exists($file_path)) {
                    unlink($file_path); // Deletes the file
                }
                // Save the compressed image with the same filename
                $output_path = $upload_path . basename($file_path);
                switch ($mime) {
                    case 'image/jpeg':
                        imagejpeg($image, $output_path, $quality);
                        break;
                    case 'image/png':
                        // Convert quality to 0-9 range for PNG
                        $png_quality = (int)((100 - $quality) / 10);
                        imagepng($image, $output_path, $png_quality);
                        break;
                    case 'image/gif':
                        // GIFs do not support quality adjustment
                        imagegif($image, $output_path);
                        break;
                }
                // Free up memory
                imagedestroy($image);
                return "Image compressed, existing file deleted, and uploaded successfully to: " . $output_path;
}
