    $query=$this->db->query("SELECT init_call.id AS init_id, company_master.id AS cid, company_master.compname, init_call.cstatus, s1.name AS cstatus_name, u1.name AS mainbd_name, u2.name AS clm_name, u3.name AS pst_name, u4.name AS apr_by_name, init_call.apr_date, init_call.created_at, a1.name as action_name FROM `init_call` LEFT JOIN company_master ON company_master.id = init_call.cmpid_id LEFT JOIN status s1 ON s1.id = init_call.cstatus LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd LEFT JOIN user_details u2 ON u2.user_id = init_call.clm_id LEFT JOIN user_details u3 ON u3.user_id = init_call.apst LEFT JOIN user_details u4 ON u4.user_id = init_call.apr_by LEFT JOIN tblcallevents tce ON tce.id = init_call.after_task LEFT JOIN action a1 ON a1.id = tce.actiontype_id WHERE DATE($filterDate) > '$tdate' $text AND init_call.mainbd IS NOT NULL $is_admin_approvedfilter $taskfilter $bystatusFilter");
    return $query->result();
