    }else if($utype == '22'){
        $text = "AND (u1.user_id  = '$uid' || u1.rm_east_co='$uid')";
    }else if($utype == '23'){
        $text = "AND (u1.user_id  = '$uid' || u1.rm_north_co='$uid')";
    }else if($utype == '24'){
        $text = "AND (u1.user_id  = '$uid' || u1.acm_co='$uid')";
    }else if($utype == '15'){
        $text = "AND u1.sales_co='$uid'";
    }else{
         $text = "AND u1.user_id  = '$uid' ";
    }
    // $query=$this->db->query("SELECT u1.name AS user_name,u1.user_id as tar_user_id, ut.name as type_name, COUNT(ic.id) AS total_create_company, COUNT( CASE WHEN ic.is_admin_approved = 1 THEN ic.id END ) AS total_approved, COUNT( CASE WHEN ic.is_admin_approved = 0 THEN ic.id END ) AS pending_for_approved, COUNT( CASE WHEN ic.is_admin_approved = 2 THEN ic.id END ) AS need_to_update, COUNT( CASE WHEN tce.actiontype_id = 4 THEN ic.id END ) AS form_barg_in_meeting, COUNT( CASE WHEN tce.actiontype_id = 10 THEN ic.id END ) AS form_research, u2.name AS admin_name FROM user_details u1 LEFT JOIN init_call ic ON ic.mainbd = u1.user_id LEFT JOIN user_details u2 ON ( (u1.type_id = 3 AND u2.user_id = u1.aadmin) OR (u1.type_id = 13 AND u2.user_id = u1.pst_co) ) LEFT JOIN user_type ut ON ut.id = u1.type_id LEFT JOIN tblcallevents tce ON tce.id = ic.after_task WHERE u1.type_id IN (3,13) AND ic.created_at BETWEEN '$sd' AND '$ed' AND ic.mainbd IS NOT NULL AND ic.new_lead = 1 AND ic.after_task !=0 AND tce.nextCFID != 0 AND  u1.admin_id = $uid GROUP BY u1.user_id, u1.name, u2.name HAVING total_create_company != 0");
    $query = $this->db->query("SELECT 
    u1.name AS user_name,
    u1.user_id AS tar_user_id,
    ut.name AS type_name,
    COUNT(ic.id) AS total_create_company,
    COUNT(
        CASE WHEN ic.is_admin_approved = 1 THEN ic.id END
    ) AS total_approved,
    COUNT(
        CASE WHEN ic.is_admin_approved = 0 THEN ic.id END
    ) AS pending_for_approved,
    COUNT(
        CASE WHEN ic.is_admin_approved = 2 THEN ic.id END
    ) AS need_to_update,
    COUNT(
        CASE WHEN tce.actiontype_id = 4 THEN ic.id END
    ) AS form_barg_in_meeting,
    COUNT(
        CASE WHEN tce.actiontype_id = 10 THEN ic.id END
    ) AS form_research,
    u2.name AS admin_name
FROM user_details u1
LEFT JOIN init_call ic ON ic.mainbd = u1.user_id
LEFT JOIN user_details u2 
    ON u2.user_id = (
        CASE 
            WHEN u1.type_id = 3 THEN 
                CASE 
                    WHEN u1.acm_co IS NOT NULL AND u1.acm_co != '' 
                        THEN u1.acm_co
                    WHEN u1.aadmin IS NOT NULL AND u1.aadmin != '' 
                        THEN u1.aadmin
                    ELSE u1.rm_east_co
                END

            WHEN u1.type_id = 13 THEN 
                CASE 
                    WHEN u1.rm_east_co IS NOT NULL AND u1.rm_east_co != '' 
                        THEN u1.rm_east_co
                    ELSE u1.aadmin
                END

            WHEN u1.type_id = 24 THEN u1.aadmin

            WHEN u1.type_id = 22 THEN u1.sales_co
        END
    )
LEFT JOIN user_type ut ON ut.id = u1.type_id
LEFT JOIN tblcallevents tce ON tce.id = ic.after_task
WHERE 
  ic.created_at BETWEEN '$sd' AND '$ed'
  AND ic.mainbd IS NOT NULL
  AND ic.new_lead = 1
  AND ic.after_task != 0
  AND tce.nextCFID != 0
--   AND u1.status = 'active'
 $text
GROUP BY 
    u1.user_id,
    u1.name,
    u2.name
HAVING total_create_company != 0;
");
    return $query->result();
}
public function GetCompanyDetailsAfterAdd($sd,$ed,$types,$uid,$targetuid){
   
    $udata = $this->Menu_model->get_userbyid($uid);
    $utype = $udata[0]->type_id;
    if($utype == 1){
        $text = "AND u1.sadmin_id  = '$uid'";
    }else if($utype == 2){
        $text = "AND u1.admin_id  = '$uid'";
    }else if($utype == 3){
        $text = "AND u1.user_id  = '$uid' ";
    }else if($utype == 13){
        $text = "AND (u1.user_id  = '$uid' || u1.aadmin  = '$uid')";
    }else if($utype == 4){
        $text = "AND (u1.user_id  = '$uid' || u1.pst_co  = '$uid')";
    }else if($utype == '19'){
        $text = "AND u1.ash_nae_co='$uid'";
    }else if($utype == '20'){
        $text = "AND u1.ash_w_co='$uid'";
    }else if($utype == '21'){
        $text = "AND u1.ash_s_co='$uid'";
    }else if($utype == '22'){
        $text = "AND (u1.user_id  = '$uid' || u1.rm_east_co='$uid')";
    }else if($utype == '23'){
        $text = "AND (u1.user_id  = '$uid' || u1.rm_north_co='$uid')";
    }else if($utype == '24'){
        $text = "AND (u1.user_id  = '$uid' || u1.acm_co='$uid')";
    }else if($utype == '15'){
        $text = "AND u1.sales_co='$uid'";
    }else{
         $text = "AND u1.user_id  = '$uid' ";
    }
    if($types == 'total_create_company'){
        $applyfilter = '';
    }else if($types == 'total_approved'){
        $applyfilter = 'AND ic.is_admin_approved = 1';
    }else if($types == 'pending_for_approved'){
        $applyfilter = "AND ic.is_admin_approved =0";
    }else if($types == 'need_to_update'){
        $applyfilter = "AND ic.is_admin_approved =2";
    }else if($types == 'form_barg_in_meeting'){
        $applyfilter = "AND tce.actiontype_id =4";
    }else if($types == 'form_research'){
        $applyfilter = "AND tce.actiontype_id =10";
    }
    if($targetuid !=0){
        $applyuserfilter = "AND u1.user_id = $targetuid";
    }else{
        $applyuserfilter = "";
    }
    $query=$this->db->query("SELECT
    u1.name AS user_name,
    ut.name AS type_name,
    u2.name AS checkbyname,
    ic.id AS init_id,
    ic.created_at,
    ic.is_admin_approved,
    ic.apr_by,
    ic.apr_date,
    cm.id AS cid,
    u4.name AS approved_by_name,
    cm.compname,
    action.name AS by_task_name,
    tce.mtype,
    tce.id as task_id
FROM
    init_call ic
LEFT JOIN user_details u1 ON
    u1.user_id = ic.mainbd
LEFT JOIN user_details u2 ON
    (
        (
            u1.type_id = 3 AND u2.user_id = u1.aadmin
        ) OR(
            u1.type_id = 13 AND u2.user_id = u1.pst_co
        )
    )
LEFT JOIN user_type ut ON ut.id = u1.type_id
LEFT JOIN tblcallevents tce ON tce.id = ic.after_task
LEFT JOIN company_master cm ON cm.id = ic.cmpid_id
LEFT JOIN action ON action.id = tce.actiontype_id
LEFT JOIN user_details u4 ON u4.user_id = ic.apr_by
WHERE
     ic.created_at BETWEEN '$sd' AND '$ed' 
    AND ic.mainbd IS NOT NULL 
    AND ic.new_lead = 1 
    AND ic.after_task != 0 
    AND tce.nextCFID != 0 
      $text
    $applyfilter $applyuserfilter");
    return $query->result();
}
