public function GetOurReminderMessageonTask($uid, $date){
    $start = $date . ' 00:00:00';
    $end   = $date . ' 23:59:59';

    $query = $this->db->query("
        SELECT
            reminder_comments.*,
            user_details.name,
            company_master.compname,
            u1.name AS reminder_by_name,
            action.name AS task_name
        FROM
            reminder_comments
        LEFT JOIN tblcallevents ON tblcallevents.id = reminder_comments.task_id
        LEFT JOIN user_details ON user_details.user_id = tblcallevents.user_id
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN user_details u1 ON u1.user_id = reminder_comments.reminderby
        LEFT JOIN action ON action.id = tblcallevents.actiontype_id
        WHERE
            user_details.user_id = '$uid'
            AND reminder_comments.created_at BETWEEN '$start' AND '$end'
            AND (tblcallevents.delete_request IS NULL OR tblcallevents.delete_request = '')
    ");

    return $query->result();
}




