public function getCurrentFinancialYear() {
    $currentMonth = date('n'); // 'n' returns the month without leading zeros
    $currentYear = date('Y');
    if ($currentMonth >= 4) {
        // If the current month is April or later, the financial year starts this year
        $startYear = $currentYear;
        $endYear = $currentYear + 1;
    } else {
        // If the current month is before April, the financial year started last year
        $startYear = $currentYear - 1;
        $endYear = $currentYear;
    }
    return $startYear . '-' . substr($endYear, 2); // Format as "YYYY-YY"
}
public function getCurrentFinancialYearStart() {
    $currentMonth = date('n'); // 'n' returns the month without leading zeros
    $currentYear = date('Y');
    if ($currentMonth >= 4) {
        // If the current month is April or later, the financial year starts this year
        $startYear = $currentYear;
    } else {
        // If the current month is before April, the financial year started last year
        $startYear = $currentYear - 1;
    }
    return $startYear;
}




public function getCurrentFinancialYearStartAndEND() {
    $currentMonth = date('n'); // Numeric month without leading zeros (1-12)
    $currentYear = date('Y');
    
    if ($currentMonth >= 4) {
        // Financial year starts this year (April 1 of current year)
        $startYear = $currentYear;
        $endYear = $currentYear + 1;
    } else {
        // Financial year started last year
        $startYear = $currentYear - 1;
        $endYear = $currentYear;
    }

    $financialYear = [
        'start_date' => $startYear . '-04-01',
        'end_date'   => $endYear . '-03-31',
        'label'      => $startYear . '-' . $endYear
    ];

    return $financialYear;
}









