    COUNT(CASE WHEN init_call.focus_funnel = 'yes' THEN 1 END) v,
    COUNT(CASE WHEN init_call.potentialp = 'yes' AND init_call.apst IS NULL THEN 1 END) w,
    COUNT(CASE WHEN init_call.potentialp = 'no' AND init_call.apst IS NULL THEN 1 END) X,
    COUNT(CASE WHEN init_call.potentialp IS NULL AND init_call.apst IS NULL THEN 1 END) Y,
    COUNT(CASE WHEN init_call.mainbd = u1.user_id AND init_call.apst IS NULL THEN 1 END) z,
    COUNT(CASE WHEN init_call.mainbd = u1.user_id AND init_call.potentialppst = 'yes' THEN 1 END) za,
    COUNT(CASE WHEN init_call.mainbd = u1.user_id AND init_call.potentialppst = 'no' THEN 1 END) zb,
    COUNT(CASE WHEN init_call.mainbd = u1.user_id AND init_call.apst IS NOT NULL AND init_call.potentialppst IS NULL THEN 1 END) zc,
    COUNT(CASE WHEN init_call.mainbd = u1.user_id AND init_call.apst IS NOT NULL THEN 1 END) zd
FROM
    init_call
LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd 
WHERE
    $userfilter $filter AND u1.status = 'active'
GROUP BY
    u1.user_id ORDER BY u1.name ASC");
    return $query->result();
}
