public function getFinancialYearRange($date = 'today') {
    $currentDate = new DateTime($date);
    $year = $currentDate->format('Y');
    $month = $currentDate->format('m');
    if ($month < 4) {
        // If before April, financial year is the previous year
        $startYear = $year - 1;
        $endYear = $year;
    } else {
        // If April or later, financial year is the current year
        $startYear = $year;
        $endYear = $year + 1;
    }
    $startDate = new DateTime("$startYear-04-01");
    $endDate = new DateTime("$endYear-03-31");
    return [
        'start_date' => $startDate->format('Y-m-d'),
        'end_date'   => $endDate->format('Y-m-d')
    ];
}


public function getLastFinancialYearRange($date = 'today') {
    $currentDate = new DateTime($date);
    $year = $currentDate->format('Y');
    $month = $currentDate->format('m');

    if ($month < 4) {
        // Current FY: (year-1) to year
        // Last FY: (year-2) to (year-1)
        $startYear = $year - 2;
        $endYear = $year - 1;
    } else {
        // Current FY: year to (year+1)
        // Last FY: (year-1) to year
        $startYear = $year - 1;
        $endYear = $year;
    }

    $startDate = new DateTime("$startYear-04-01");
    $endDate = new DateTime("$endYear-03-31");

    return [
        'start_date' => $startDate->format('Y-m-d'),
        'end_date'   => $endDate->format('Y-m-d')
    ];
}









