public function StorAnnualReviewSessionStart($uid, $psdatetime, $pstime, $review_id, $main_review_session,$rid) {
    $start_date = $this->getFinancialYearRange(); 
    
    if (!$start_date || !isset($start_date['start_date'])) {
        return false; // Return false if function fails
    }
    
    $year = (new DateTime($start_date['start_date']))->format('Y');
    $data = array(
        'user_id'        => $uid,
        'revew_year'     => $year,
        'revew_id'       => $rid,
        'psdatetime'     => $psdatetime,
        'pstime'         => $pstime,
        'main_review_on' => $main_review_session
    );
    return $this->db->insert('annual_review_session', $data);
}
public function StorAnnualReviewSessionClose($uid, $pcdatetime, $pctime, $totaltime, $review_id, $main_review_session) {
    $start_date = $this->getFinancialYearRange(); 
    if (!$start_date || !isset($start_date['start_date'])) {
        return false; // Return false if function fails
    }
    $year = (new DateTime($start_date['start_date']))->format('Y');
    $data = array(
        'pctime'         => $pctime,
        'pcdatetime'     => $pcdatetime,
        'totaltime'      => $totaltime,
        'revew_id'       => $review_id,
        'main_review_on' => $main_review_session
    );
    $this->db->where('user_id', $uid);
    $this->db->where('revew_year', $year);
    $this->db->where('main_review_on', 'START');
    return $this->db->update('annual_review_session', $data);
}
public function GetCopmanyLogFrequencyInThisFinancialYear($init_id){
    $financial_Year_date = $this->getFinancialYearRange(); 
    $start_date = $financial_Year_date['start_date'];
    $end_date   = $financial_Year_date['end_date'];
    
    $query=$this->db->query("SELECT 
    tblc1.id AS task_id,
    tblc1.appointmentdatetime,
    CASE 
        WHEN @prev_appointmentdatetime IS NOT NULL THEN
            CONCAT(
                CASE 
                    WHEN TIMESTAMPDIFF(DAY, @prev_appointmentdatetime, tblc1.appointmentdatetime) > 0 
                    THEN CONCAT(TIMESTAMPDIFF(DAY, @prev_appointmentdatetime, tblc1.appointmentdatetime), ' days ') 
                    ELSE ''
                END,
                CASE 
                    WHEN TIMESTAMPDIFF(HOUR, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 24 > 0
                    THEN CONCAT(TIMESTAMPDIFF(HOUR, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 24, ' hours ') 
                    ELSE ''
                END,
                CASE 
                    WHEN TIMESTAMPDIFF(MINUTE, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 60 > 0 
                    THEN CONCAT(TIMESTAMPDIFF(MINUTE, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 60, ' minutes ') 
                    ELSE ''
                END,
                CASE 
                    WHEN TIMESTAMPDIFF(SECOND, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 60 > 0 
                    THEN CONCAT(TIMESTAMPDIFF(SECOND, @prev_appointmentdatetime, tblc1.appointmentdatetime) % 60, ' seconds') 
                    ELSE ''
                END
            )
        ELSE NULL 
    END AS frequency_between_plan,
    @prev_appointmentdatetime := tblc1.appointmentdatetime AS temp_var, -- Update variable for next row
    user_details.name AS task_by_name, -- Assuming you want to show the user name from user_details
    user_details.user_id as task_user_id,
    action.name AS action_name,
    user_type.name as user_type_name,
    CASE 
        WHEN tblc1.nextCFID = 0 THEN 'Pending'
        ELSE 'Complete'
    END AS task_status -- Adding task status based on nextCFID
FROM (
    SELECT id, user_id, appointmentdatetime, actiontype_id, nextCFID
    FROM tblcallevents 
    WHERE cid_id = '$init_id' 
    AND CAST(appointmentdatetime AS DATE) >= '$start_date' 
    AND CAST(appointmentdatetime AS DATE) < '$end_date'
    ORDER BY appointmentdatetime ASC
) tblc1
LEFT JOIN user_details ON user_details.user_id = tblc1.user_id
LEFT JOIN action ON action.id = tblc1.actiontype_id
LEFT JOIN user_type ON user_type.id = user_details.type_id,
(SELECT @prev_appointmentdatetime := NULL) AS init");
   
   return $query->result();
}
