    $query=$this->db->query("SELECT 
            COUNT(CASE 
                    WHEN ((status_id = 8 AND nstatus_id = 1) 
                        OR (status_id = 2 AND nstatus_id = 8) 
                        OR (status_id = 12 AND nstatus_id = 3) 
                        OR (status_id = 13 AND nstatus_id = 6) 
                        OR (status_id = 7 AND nstatus_id = 9) 
                        OR (status_id = 3 AND nstatus_id = 4) 
                        OR (status_id = 12 AND nstatus_id = 4) 
                        OR (status_id = 6 AND nstatus_id = 4) 
                        OR (status_id = 13 AND nstatus_id = 4) 
                        OR (status_id = 9 AND nstatus_id = 4) 
                        OR (status_id = 7 AND nstatus_id = 4) 
                        OR (status_id = 3 AND nstatus_id = 11) 
                        OR (status_id = 12 AND nstatus_id = 11) 
                        OR (status_id = 12 AND nstatus_id = 6) 
                        OR (status_id = 6 AND nstatus_id = 11)) 
                    THEN 1 ELSE NULL END) AS negative_conversion,
            COUNT(CASE 
                    WHEN ((status_id = 1 AND nstatus_id = 8) 
                        OR (status_id = 8 AND nstatus_id = 2) 
                        OR (status_id = 2 AND nstatus_id = 3) 
                        OR (status_id = 3 AND nstatus_id = 12) 
                        OR (status_id = 12 AND nstatus_id = 6) 
                        OR (status_id = 6 AND nstatus_id = 13) 
                        OR (status_id = 13 AND nstatus_id = 9) 
                        OR (status_id = 9 AND nstatus_id = 7) 
                        OR (status_id = 4 AND nstatus_id = 2)) 
                    THEN 1 ELSE NULL END) AS positive_conversion
        FROM tblcallevents
        WHERE cid_id = '$inid' AND CAST(appointmentdatetime AS DATE) >= '$start_date' 
    AND CAST(appointmentdatetime AS DATE) < '$end_date'");
    return $query->result();
}
