public function GetBDAnnualReviewData($adminid,$cfyear){
    $utype = $this->Menu_model->get_userbyid($adminid);
    $utype = $utype[0]->type_id;
    

    if($utype == 1){
        $adminfilter = " AND u2.sadmin_id = '$adminid'";
    }else if($utype == 2){
        $adminfilter = " AND u2.admin_id = '$adminid'";
    }elseif($utype == 3){
        $adminfilter = " AND u2.user_id = '$adminid'";
    }elseif($utype == 4){
        $adminfilter = " AND u2.pst_co = '$adminid'";
    }elseif($utype == 13){
        $adminfilter = " AND u2.aadmin = '$adminid'";
    }elseif($utype == 15){
        $adminfilter = " AND u2.sales_co = '$adminid'";
    }elseif($utype == 19){
        $adminfilter = " AND u2.ash_nae_co = '$adminid'";
    }else if($utype == 19){
        $adminfilter = "AND u2.ash_nae_co='$adminid'";
    }else if($utype == 20){
        $adminfilter = "AND u2.ash_w_co='$adminid'";
    }else if($utype == 21){
        $adminfilter = "AND u2.ash_s_co='$adminid'";
    }else if($utype == 22){
        $adminfilter = "AND u2.rm_east_co='$adminid'";
    }else if($utype == 23){
        $adminfilter = "AND u2.rm_north_co='$adminid'";
    }else if($utype == 24){
        $adminfilter = "AND u2.acm_co='$adminid'";
    }else{
        $adminfilter = " AND u2.admin_id = '$adminid'";
    }

    $ustype = $this->Menu_model->get_userbyid($adminid);
    $cu_admin_id = $ustype[0]->admin_id;
    if($cu_admin_id == 45 || $adminid == 45){
        $status_filter = '1,3,4,5,8';
      }else {
        $status_filter = '1,4,5,8';
      }

    $query=$this->db->query("SELECT 
    u2.user_id,
    u2.name AS username,
    COUNT(
        CASE 
            WHEN init_call.cstatus IN ($status_filter) 
                AND init_call.mainbd = u2.user_id 
            THEN 1 
        END
    ) AS total_count,
    COUNT(
        CASE 
            WHEN amr.inid IS NOT NULL 
                AND init_call.cstatus IN ($status_filter) 
                AND init_call.mainbd = u2.user_id 
            THEN 1 
        END
    ) AS complete_review,
    COUNT(
        CASE 
            WHEN amr.inid IS NULL 
                AND init_call.cstatus IN ($status_filter) 
                AND init_call.mainbd = u2.user_id 
            THEN 1 
        END
    ) AS pending_review,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.current_year_focus_funnel = 'Yes' THEN 1 END) AS bd_marked_current_year_focus_funnel,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.q1_closure = 'Yes' THEN 1 END) AS bd_marked_q1_closure,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.to_be_Nurture_in_q1 = 'Yes' THEN 1 END) AS bd_marked_to_be_Nurture_in_q1,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.keep_company = 'yes' THEN 1 END) AS keep_company_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.keep_company = 'no' THEN 1 END) AS keep_company_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 0 THEN 1 END) AS pending_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 1 THEN 1 END) AS complete_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 2 THEN 1 END) AS reject_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'yes' THEN 1 END) AS vmeeting_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'no' THEN 1 END) AS vmeeting_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'yes' THEN 1 END) AS annaul_focuspositive_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'no' THEN 1 END) AS annaul_focuspositive_no,
    
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'yes' THEN 1 END) AS annaul_topspender_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'no' THEN 1 END) AS annaul_topspender_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'yes' THEN 1 END) AS annaul_upsell_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'no' THEN 1 END) AS annaul_upsell_no,
	SUM(CASE  WHEN amr.inid IS NOT NULL AND amr.by_uid = u2.user_id THEN amr.annaul_revenue ELSE 0 END) AS total_annaul_revenue,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.transfer_the_funnel = 'yes' THEN 1 END) AS total_transfer_the_funnel_yes
FROM init_call
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details u2 ON u2.user_id = init_call.mainbd AND u2.type_id = 3
LEFT JOIN annual_main_review amr ON amr.inid = init_call.id AND amr.by_uid = u2.user_id AND amr.financial_year = '$cfyear'
LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd AND u1.status = 'active' AND u1.admin_id = '2'
WHERE 
    init_call.cstatus IN ($status_filter) 
    AND init_call.mainbd IS NOT NULL
   $adminfilter
GROUP BY u2.user_id, u2.name");
    return $query->result();
}







// Start DATABASE LOGIC FOR ANNUAL REVIEW
public function GetNewBDAnnualReviewData($adminid, $cfyear,$target_types){

    $utype      = $this->Menu_model->get_userbyid($adminid);
    $type_id    = $utype[0]->type_id;
    $uid        = $adminid; // FIXED

    $financial_Year_date    = $this->getCustmizeFinancialYear('current');
    $start_date             = $financial_Year_date['start_date'];
    $end_date               = $financial_Year_date['end_date'];

    if($type_id == 3){
        $userFilter = " AND u2.user_id = '$uid'";
    }else if($type_id == 13){
        $userFilter = " AND (u2.aadmin = '$uid' OR u2.user_id = '$uid')";
    }else if($type_id == 4){ // FIXED typo
        $userFilter = " AND (u2.pst_co = '$uid' OR u2.user_id = '$uid')";
    }else if($type_id == 15){
        $userFilter = " AND u2.sales_co = '$uid'";
    }else if($type_id == 19){
        $userFilter = " AND u2.ash_nae_co = '$uid'";
    }else if($type_id == 20){
        $userFilter = " AND u2.ash_w_co = '$uid'";
    }else if($type_id == 21){
        $userFilter = " AND u2.ash_s_co = '$uid'";
    }else if($type_id == 22){
        $userFilter = " AND u2.rm_east_co = '$uid'";
    }else if($type_id == 23){
        $userFilter = " AND u2.rm_north_co = '$uid'";
    }else if($type_id == 24){
        $userFilter = " AND (u2.acm_co = '$uid' OR u2.user_id = '$uid')";
    }else if($type_id == 1){
        $userFilter = " AND u2.sadmin_id = '$uid'";
    }else{
        $userFilter = " AND u2.admin_id = '$uid'";
    }


    $ststusFilter = "AND ic.cstatus != 0";                

    $teamLeftJoinFilter = '';
    $teamWhereFilter = '';

    if($target_types == 1){
        $teamLeftJoinFilter = 'u2.sadmin_id = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (1)';
    }else if($target_types == 2){
        
        $teamLeftJoinFilter = 'u2.admin_id = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (2)';

    }else if($target_types == 3){

        $teamLeftJoinFilter = 'u2.user_id = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (3)';
        $ststusFilter       = " AND ic.cstatus IN (1, 2, 8, 10, 11)";                          
    }else if($target_types == 4){
        
        $teamLeftJoinFilter = 'u2.pst_co = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (4)';

        $ststusFilter       = "AND ic.cstatus IN (3, 6, 7, 12, 13, 4,5,9)"; 

    }else if($target_types == 13){

        $teamLeftJoinFilter = 'u2.aadmin = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (13)';

        $ststusFilter       = "AND ic.cstatus IN (3, 6, 7, 12, 13, 4,5,9)"; 

    }else if($target_types == 15){

        $teamLeftJoinFilter = 'u2.sales_co = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (15)';

    }else if($target_types == 17){

        $teamLeftJoinFilter = 'u2.ea_co = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (17)';

    }else if($target_types == 22){

        $teamLeftJoinFilter = 'u2.rm_east_co = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (22)';
        $ststusFilter       = "AND ic.cstatus IN (3, 6, 7, 12, 13, 4,5,9)"; 

    }else if($target_types == 24){

        $teamLeftJoinFilter = 'u2.acm_co = u1.user_id';
        $teamWhereFilter    = 'u1.type_id IN (24)';
        $ststusFilter       = "AND ic.cstatus IN (3, 6, 7, 12, 13, 4,5,9)"; 
    }

    


    $query = $this->db->query("SELECT 
    u1.user_id, 
    u1.name AS username, 

    COUNT(DISTINCT ic.id) AS total_count,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL THEN amr.inid 
    END) AS complete_review,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NULL THEN ic.id 
    END) AS pending_review,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.current_year_focus_funnel = 'Yes' 
        THEN amr.inid 
    END) AS bd_marked_current_year_focus_funnel,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.q1_closure = 'Yes' 
        THEN amr.inid 
    END) AS bd_marked_q1_closure,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.to_be_Nurture_in_q1 = 'Yes' 
        THEN amr.inid 
    END) AS bd_marked_to_be_Nurture_in_q1,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.keep_company = 'yes' 
        THEN amr.inid 
    END) AS keep_company_yes,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.keep_company = 'no' 
        THEN amr.inid 
    END) AS keep_company_no,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 0 
        THEN amr.inid 
    END) AS pending_for_check,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 1 
        THEN amr.inid 
    END) AS complete_for_check,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 2 
        THEN amr.inid 
    END) AS reject_for_check,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'yes' 
        THEN amr.inid 
    END) AS vmeeting_yes,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'no' 
        THEN amr.inid 
    END) AS vmeeting_no,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'yes' 
        THEN amr.inid 
    END) AS annaul_focuspositive_yes,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'no' 
        THEN amr.inid 
    END) AS annaul_focuspositive_no,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'yes' 
        THEN amr.inid 
    END) AS annaul_topspender_yes,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'no' 
        THEN amr.inid 
    END) AS annaul_topspender_no,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'yes' 
        THEN amr.inid 
    END) AS annaul_upsell_yes,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'no' 
        THEN amr.inid 
    END) AS annaul_upsell_no,

    SUM(CASE 
        WHEN amr.inid IS NOT NULL AND amr.by_uid = u1.user_id 
        THEN amr.annaul_revenue 
        ELSE 0 
    END) AS total_annaul_revenue,

    COUNT(DISTINCT CASE 
        WHEN amr.inid IS NOT NULL AND amr.transfer_the_funnel = 'yes' 
        THEN amr.inid 
    END) AS total_transfer_the_funnel_yes

FROM user_details u1

LEFT JOIN user_details u2 ON $teamLeftJoinFilter

LEFT JOIN init_call ic 
    ON ic.cstatus IS NOT NULL 
    AND ic.cstatus NOT IN ('', '0')
    AND (ic.mainbd = u1.user_id OR ic.mainbd = u2.user_id)

LEFT JOIN annual_main_review amr 
    ON amr.inid = ic.id 
    AND amr.by_uid = u1.user_id 
    AND amr.financial_year = '2025'

WHERE $teamWhereFilter
AND u1.status = 'active'
AND u2.status = 'active'
AND cast(ic.created_at as Date) <= '$end_date'
$userFilter 
$ststusFilter
GROUP BY u1.user_id");

    return $query->result();
}



public function GetCMAnnualReviewData($adminid,$cfyear){
    $utype = $this->Menu_model->get_userbyid($adminid);
    $utype = $utype[0]->type_id;
    if($utype == 1){
        $adminfilter = " u1.sadmin_id = '$adminid'";
    }else if($utype == 2){
        $adminfilter = " u1.admin_id = '$adminid'";
    }elseif($utype == 15){
        $adminfilter = " u1.sales_co = '$adminid'";
    }elseif($utype == 19){
        $adminfilter = " u1.ash_nae_co = '$adminid'";
    }else if($utype == 20){
        $adminfilter = "u1.ash_w_co='$adminid'";
    }else if($utype == 21){
        $adminfilter = "u1.ash_s_co='$adminid'";
    }else if($utype == 22){
        $adminfilter = "u1.rm_east_co='$adminid'";
    }else if($utype == 23){
        $adminfilter = "u1.rm_north_co='$adminid'";
    }else if($utype == 24){
        $adminfilter = "u1.acm_co='$adminid'";
    }elseif($utype == 4){
        $adminfilter = " u1.pst_co = '$adminid'";
    }elseif($utype == 13){
        $adminfilter = " u1.user_id = '$adminid'";
    }elseif($utype == 3){
        $adminfilter = " u1.aadmin = '$adminid'";
    }else{
        $adminfilter = " u1.admin_id = '$adminid'";
    }
    $ustype = $this->Menu_model->get_userbyid($adminid);
    $cu_admin_id = $ustype[0]->admin_id;
    if($cu_admin_id == 45 || $adminid == 45){
        $status_filter = '1,2,8,4,5,10,11,6,9,12,13';
      }else {
        $status_filter = '1,2,8,4,5,10,11';
      }
    $query=$this->db->query("SELECT
    u1.user_id,
    u1.name AS username,
        COUNT(
        CASE 
            WHEN init_call.cstatus IS NOT NULL 
                AND init_call.cstatus != '' 
                AND (
                    (init_call.cstatus IN ('1', '8', '4', '5') AND init_call.mainbd = u2.user_id)
                    OR
                    (init_call.cstatus IN ('2', '10', '11','6','9','12','13') 
                        AND (init_call.mainbd = u2.user_id OR init_call.clm_id = u2.user_id)
                    )
                )
                AND u1.status = 'active' 
            THEN 1 
        END
    ) AS total_count,
   COUNT(
        CASE 
            WHEN amr.inid IS NOT NULL 
                AND init_call.cstatus IS NOT NULL 
                AND init_call.cstatus != '' 
                AND (
                    (init_call.cstatus IN ('1', '8', '4', '5') AND init_call.mainbd = u2.user_id)
                    OR
                    (init_call.cstatus IN ('2', '10', '11','6','9','12','13') 
                        AND (init_call.mainbd = u2.user_id OR init_call.clm_id = u2.user_id)
                    )
                )
                AND u1.status = 'active' 
            THEN 1 
        END
    ) AS complete_review,
    COUNT(
        CASE 
            WHEN amr.inid IS NULL 
                AND init_call.cstatus IS NOT NULL 
                AND init_call.cstatus != '' 
                AND (
                    (init_call.cstatus IN ('1', '8', '4', '5') AND init_call.mainbd = u2.user_id)
                    OR
                    (init_call.cstatus IN ('2', '10', '11','6','9','12','13') 
                        AND (init_call.mainbd = u2.user_id OR init_call.clm_id = u2.user_id)
                    )
                )
                AND u1.status = 'active' 
            THEN 1 
        END
    ) AS pending_review,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.current_year_focus_funnel = 'Yes' THEN 1 END) AS bd_marked_current_year_focus_funnel,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.q1_closure = 'Yes' AND amr.by_uid = u2.user_id THEN 1 END) AS bd_marked_q1_closure,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.to_be_Nurture_in_q1 = 'Yes' THEN 1 END) AS bd_marked_to_be_Nurture_in_q1,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.keep_company = 'yes' THEN 1 END) AS keep_company_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.keep_company = 'no' THEN 1 END) AS keep_company_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 0 THEN 1 END) AS pending_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 1 THEN 1 END) AS complete_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.review_apr_status = 2 THEN 1 END) AS reject_for_check,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'yes' THEN 1 END) AS vmeeting_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.vmeeting = 'no' THEN 1 END) AS vmeeting_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'yes' THEN 1 END) AS annaul_focuspositive_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'no' THEN 1 END) AS annaul_focuspositive_no,
    
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'yes' THEN 1 END) AS annaul_topspender_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_topspender = 'no' THEN 1 END) AS annaul_topspender_no,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'yes' THEN 1 END) AS annaul_upsell_yes,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.annaul_upsell = 'no' THEN 1 END) AS annaul_upsell_no,
	SUM(CASE  WHEN amr.inid IS NOT NULL AND amr.by_uid = u2.user_id THEN amr.annaul_revenue ELSE 0 END) AS total_annaul_revenue,
    COUNT(CASE WHEN amr.inid IS NOT NULL AND amr.transfer_the_funnel = 'yes' THEN 1 END) AS total_transfer_the_funnel_yes
    FROM
        init_call
    LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
    LEFT JOIN user_details u2 ON u2.type_id = 13
    LEFT JOIN user_details u1 ON u1.user_id = u2.user_id
    LEFT JOIN annual_main_review amr ON amr.inid = init_call.id AND amr.by_uid = u2.user_id AND amr.financial_year = '$cfyear'
    WHERE $adminfilter AND init_call.mainbd != 0
    GROUP BY u1.user_id");
    return $query->result();
}




