    }else if($type == 'total_annaul_revenue'){
        $filter = " AND amr.inid IS NOT NULL AND amr.annaul_revenue != ''";
    }else{
        $filter = '';
    }
  
        $query = $this->db->query("SELECT 
   
            ic.id,
            u5.name AS mainbdname,
            u4.name as review_done_by,
            company_master.compname,
            company_master.id AS cid,
            s1.name AS current_status,
            CASE 
                WHEN amr.id IS NULL THEN 'pending' 
                ELSE 'complete' 
            END AS amr_status,
            amr.id as amr_id,
            amr.review_time_status,
            amr.sdate,
            amr.by_uid,
            amr.remarks,
            amr.rtype,
            amr.current_year_focus_funnel,
            amr.q1_closure,
            amr.to_be_Nurture_in_q1,
            amr.financial_year,
            amr.keep_company,
            amr.keepremark,
            amr.vmeeting,
            amr.annaul_focuspositive,
            amr.annaul_topspender,
            amr.annaul_upsell,
            amr.annaul_revenue,
            amr.transfer_the_funnel,
            amr.transfer_location,
            amr.review_apr_status,
            amr.review_apr_by,
            u3.name as review_apr_by_name,
            amr.review_apr_remarks,
            amr.created_at,
            amr.updated_at,
            s2.name as review_time_status_name,
            CASE 
                WHEN amr.id IS NOT NULL AND amr.review_apr_status = 1 THEN 'Agree' 
                WHEN amr.id IS NOT NULL AND amr.review_apr_status = 2 THEN 'Disagree' 
                ELSE 'Pending' 
            END AS sc_agree_or_not


            FROM user_details u1

            LEFT JOIN user_details u2 ON $teamLeftJoinFilter

            LEFT JOIN init_call ic 
                ON ic.cstatus IS NOT NULL 
                AND ic.cstatus NOT IN ('', '0')
                AND (ic.mainbd = u1.user_id OR ic.mainbd = u2.user_id)

            LEFT JOIN annual_main_review amr 
                ON amr.inid = ic.id 
                AND amr.by_uid = u1.user_id 
                AND amr.financial_year = '2025'

            LEFT JOIN company_master ON company_master.id = ic.cmpid_id
            LEFT JOIN user_details u5 ON u5.user_id = ic.mainbd
            LEFT JOIN status s1 ON s1.id = ic.cstatus
            LEFT JOIN status s2 ON s2.id = amr.review_time_status
            LEFT JOIN user_details u3 ON u3.user_id = amr.review_apr_by
            LEFT JOIN user_details u4 ON u4.user_id = amr.by_uid

            WHERE $teamWhereFilter
            AND u1.status = 'active'
            AND u2.status = 'active'
            AND cast(ic.created_at as Date) <= '$end_date'
            $userFilter 
            $ststusFilter
            $filter
            GROUP BY ic.id
            ");

    return $query->result();

}









