    LEFT JOIN barginmeeting ON barginmeeting.inid = init_call.id
    LEFT JOIN status s1 ON
        s1.id = init_call.cstatus
    LEFT JOIN status s2 ON
        s2.id = amr.review_time_status
    LEFT JOIN user_details u3 ON
        u3.user_id = amr.review_apr_by
    LEFT JOIN user_details u4 ON
        u4.user_id = amr.by_uid
    WHERE
        $rstatus_filter
        $status_filter
        AND barginmeeting.inid IS NOT NULL 
        AND CAST(barginmeeting.storedt AS DATE) BETWEEN '$start_date' AND '$end_date' 
        AND u1.status = 'active' 
        AND u1.ea_co = '$tar_uid'
        $filter 
    GROUP BY init_call.id;");
    
    return $query->result();
}
