// Start Planner Redictions after planning start and before 6 hours planning complete
public function CheckUserPlannerStartOrNot($uid,$date){
    $query = $this->db->query("SELECT * FROM `autotask_time` WHERE user_id = '$uid'  AND cast(created_at as Date) = '$date' AND next_days_planner_start = 'On' ORDER BY id DESC LIMIT 1");
    $data = $query->result();
    $upsoncnt = sizeof($data);
    if($upsoncnt > 0){
    $planner_date = $data[0]->date;
    $currentPath = $_SERVER['REQUEST_URI']; // Get the URL path
    $targetPath = "Menu/TaskPlanner2/$planner_date";
        if (strpos($currentPath, $targetPath) === false) {
            $totalttaskdata         = $this->getUserTotalTaskTimeForTodays($uid,$planner_date);
            $totalttasktime         = $totalttaskdata[0]->ttime;
            $totalttasktimeplanned  = $totalttasktime;
            $lunchtime              = 30;                                   // Lunch Time 45 Miniute
            $autoTasktime           = 90;                                   // 90 Minutes For Auto Task
            $topp                   = 60;                                   // 60 Minutes For Tommorow Planner Planning
            $expense_time           = $lunchtime + $autoTasktime + $topp;   // totol expense time
            $nine_hours_planning    = 540;
            $totalttasktime         = $expense_time + $totalttasktime;
            $hours = floor($totalttasktime / 60);
            $remainingMinutes = $totalttasktime % 60;
            $totaluserplantime =  "$hours hours and $remainingMinutes minutes";
            if($totalttasktime >= $nine_hours_planning){
                $this->session->set_flashdata('success_message',"* You have successfully scheduled your plan for $planner_date on $totaluserplantime including Lunch Time, Auto Task Time AND Next Days Planner Planning Time");
            }else{
                $remainingMinutesonplanner = $nine_hours_planning - $totalttasktime;
                $hours = floor($remainingMinutesonplanner / 60);
                $remainingMinutes = $remainingMinutesonplanner % 60;
                $totaluserplantime1 =  "$hours hours and $remainingMinutes minutes";
                if($totalttasktimeplanned == 0){
                    $totaluserplantime =  "0 hours and 0 minutes";
                    $this->session->set_flashdata('error_message_plan',"You have successfully scheduled your plan for $planner_date for $totaluserplantime. * Please complete your remaining $totaluserplantime1 of planning.");
                }else{
                    $this->session->set_flashdata('error_message_plan',"You have successfully scheduled your plan for $planner_date for $totaluserplantime. * Please complete your remaining $totaluserplantime1 of planning.");
                }
               
                redirect('Menu/TaskPlanner2/'.$planner_date);
            }
        }
    }
}
