// Start - New Annual Review Report With Last Year Meetings Details Database logic
    public function GetBDAnnualReviewCompanyDataWithLastYearMeetingDetails($fyear,$tar_uid,$type){
        if($type == 'total_count'){
            $filter = '';
        }else if($type == 'complete_review'){
            $filter = " AND amr.inid IS NOT NULL";
        }else if($type == 'pending_review'){
            $filter = " AND amr.inid IS NULL";
        }else if($type == 'bd_marked_current_year_focus_funnel'){
            $filter = " AND amr.inid IS NOT NULL AND amr.current_year_focus_funnel = 'yes'";
        }else if($type == 'bd_marked_q1_closure'){
            $filter = " AND amr.inid IS NOT NULL AND amr.q1_closure = 'yes'";
        }else if($type == 'bd_marked_to_be_Nurture_in_q1'){
            $filter = " AND amr.inid IS NOT NULL AND amr.to_be_Nurture_in_q1 = 'yes'";
        }else if($type == 'keep_company_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.keep_company = 'yes'";
        }else if($type == 'keep_company_no'){
            $filter = " AND amr.inid IS NOT NULL AND amr.keep_company = 'no'";
        }else if($type == 'vmeeting_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.vmeeting = 'yes'";
        }else if($type == 'vmeeting_no'){
            $filter = " AND amr.inid IS NOT NULL AND amr.vmeeting = 'no'";
        }else if($type == 'annaul_focuspositive_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'yes'";
        }else if($type == 'annaul_focuspositive_no'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_focuspositive = 'no'";
        }else if($type == 'annaul_topspender_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_topspender = 'yes'";
        }else if($type == 'annaul_topspender_no'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_topspender = 'no'";
        }else if($type == 'annaul_upsell_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_upsell = 'yes'";
        }else if($type == 'annaul_upsell_no'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_upsell = 'no'";
        }else if($type == 'total_transfer_the_funnel_yes'){
            $filter = " AND amr.inid IS NOT NULL AND amr.transfer_the_funnel = 'yes'";
        }else if($type == 'pending_for_check'){
            $filter = " AND amr.inid IS NOT NULL AND amr.review_apr_status = '0'";
        }else if($type == 'complete_for_check'){
            $filter = " AND amr.inid IS NOT NULL AND amr.review_apr_status = '1'";
        }else if($type == 'reject_for_check'){
            $filter = " AND amr.inid IS NOT NULL AND amr.review_apr_status = '2'";
        }else if($type == 'pending_review'){
            $filter = " AND amr.inid IS NULL";
        }else if($type == 'total_annaul_revenue'){
            $filter = " AND amr.inid IS NOT NULL AND amr.annaul_revenue != ''";
        }else{
            $filter = '';
        }
      
    
        $query=$this->db->query("SELECT 
        init_call.id,
        u2.name AS mainbdname,
        u4.name as review_done_by,
        company_master.compname,
        company_master.id AS cid,
        s1.name AS current_status,
        CASE 
            WHEN amr.id IS NULL THEN 'pending' 
            ELSE 'complete' 
        END AS amr_status,
        amr.id as amr_id,
        amr.review_time_status,
        amr.sdate,
        amr.by_uid,
        amr.remarks,
        amr.rtype,
        amr.current_year_focus_funnel,
        amr.q1_closure,
        amr.to_be_Nurture_in_q1,
        amr.financial_year,
        amr.keep_company,
        amr.keepremark,
        amr.vmeeting,
        amr.annaul_focuspositive,
        amr.annaul_topspender,
        amr.annaul_upsell,
        amr.annaul_revenue,
        amr.transfer_the_funnel,
        amr.transfer_location,
        amr.review_apr_status,
        amr.review_apr_by,
        u3.name as review_apr_by_name,
        amr.review_apr_remarks,
        amr.created_at,
        amr.updated_at,
        s2.name as review_time_status_name,
         CASE 
            WHEN amr.id IS NOT NULL AND amr.review_apr_status = 1 THEN 'Agree' 
            WHEN amr.id IS NOT NULL AND amr.review_apr_status = 2 THEN 'Disagree' 
            ELSE 'Pending' 
        END AS sc_agree_or_not,
        (
        SELECT COUNT(*) 
        FROM barginmeeting 
        JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
        WHERE barginmeeting.inid = init_call.id 
          AND YEAR(barginmeeting.storedt) = '$fyear'
          AND barginmeeting.user_id = '$tar_uid'
    ) AS total_barginmeeting_plan_count,
  
    (
        SELECT COUNT(*) 
        FROM barginmeeting 
        JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
        WHERE barginmeeting.inid = init_call.id 
          AND YEAR(barginmeeting.storedt) = '$fyear'
          AND (barginmeeting.status = 'Close' OR barginmeeting.status = 'RPClose' OR barginmeeting.startm IS NOT NULL)
          AND barginmeeting.user_id = '$tar_uid'
    ) AS total_complete_barginmeeting_count,
    (
        SELECT COUNT(*) 
        FROM barginmeeting 
        JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
        WHERE barginmeeting.inid = init_call.id 
          AND YEAR(barginmeeting.storedt) = '$fyear'
          AND barginmeeting.status = 'Pending'
          AND barginmeeting.user_id = '$tar_uid'
    ) AS total_pending_barginmeeting_count,
         (
        SELECT COUNT(*) 
        FROM barginmeeting 
        JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
        WHERE barginmeeting.inid = init_call.id 
          AND YEAR(barginmeeting.storedt) = '$fyear'
          AND barginmeeting.status = 'Start' AND barginmeeting.startm IS NOT NULL
          AND barginmeeting.user_id = '$tar_uid'
    ) AS total_barginmeeting_start_count
        FROM init_call
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN user_details u2 ON u2.user_id = init_call.mainbd AND u2.type_id = 3
        LEFT JOIN annual_main_review amr ON amr.inid = init_call.id AND amr.by_uid = u2.user_id AND amr.financial_year = '$fyear'
        LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd AND u1.status = 'active' 
        LEFT JOIN status s1 ON s1.id = init_call.cstatus
        LEFT JOIN status s2 ON s2.id = amr.review_time_status
        LEFT JOIN user_details u3 ON u3.user_id = amr.review_apr_by
        LEFT JOIN user_details u4 ON u4.user_id = amr.by_uid
        WHERE 
            init_call.cstatus IN (1, 4, 5, 8) 
            AND init_call.mainbd IS NOT NULL
            $filter
            AND u2.user_id = '$tar_uid'");
        
        return $query->result();
    }
    
    public function GetLastYearMeetingsDetailsUsinginitID($init_id,$tar_uid,$fyear,$mtype){
           if($mtype == 'total_barginmeeting_plan_count'){
                $meeting_filter = '';
            }
            if($mtype == 'total_complete_barginmeeting_count'){
                $meeting_filter  = "AND (barginmeeting.status = 'Close' OR barginmeeting.status = 'RPClose')";
            }
            if($mtype == 'total_pending_barginmeeting_count'){
                $meeting_filter  = "AND barginmeeting.status = 'Pending'";
            }
            if($mtype == 'total_barginmeeting_start_count'){
                $meeting_filter  = "AND barginmeeting.status = 'Start'";
            }  
            $tar_utype = $this->Menu_model->get_userbyid($tar_uid);
            $tar_utype = $tar_utype[0]->type_id;
            if($tar_utype == 17){
                $user_filter = "";
            }else{
                $user_filter = " AND barginmeeting.user_id = '$tar_uid'";
            }
        $query = $this->db->query("SELECT
	init_call.id as init_call_id,
	u1.name as main_bd_name,
    u2.name as clm_name,
    u3.name as pst_name,
    u4.name as task_done_by,
    company_master.id AS cid,
    company_master.compname,
    barginmeeting.id AS barginmeeting_id,
    barginmeeting.storedt,
    barginmeeting.tid,  -- Added missing comma here
    barginmeeting.startm,
    barginmeeting.closem,
    barginmeeting.status as meeting_status,
    s1.name AS current_status,
    s2.name AS last_status,
    s3.name AS task_plan_time_status,
    action.name as task_name,
    tblcallevents.appointmentdatetime,
    tblcallevents.updateddate,
    tblcallevents.nextCFID,
    tblcallevents.fwd_date,
    tblcallevents.actontaken,
    tblcallevents.purpose_achieved,
    tblcallevents.approved_status,
    tblcallevents.approved_by,
    tblcallevents.remarks,
    tblcallevents.mom,
    tblcallevents.mom_remarks,
    mom_data.id as mom_id,
    tblcallevents.id as task_id,
    tblc1.id AS mom_task_id
FROM
    barginmeeting
JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
LEFT JOIN init_call ON init_call.id = 32253
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN status s1 ON s1.id = init_call.cstatus
LEFT JOIN status s2 ON s2.id = init_call.lstatus
LEFT JOIN status s3 ON s3.id = tblcallevents.status_id
LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
LEFT JOIN user_details u2 ON u2.user_id = init_call.clm_id
LEFT JOIN user_details u3 ON u3.user_id = init_call.apst
LEFT JOIN user_details u4 ON u4.user_id = tblcallevents.user_id
LEFT JOIN action ON action.id = tblcallevents.actiontype_id
LEFT JOIN tblcallevents AS tblc1 ON tblc1.aftertask = tblcallevents.id AND tblc1.actiontype_id = 6
LEFT JOIN mom_data ON mom_data.tid = tblc1.id
WHERE
    barginmeeting.inid = '$init_id'
    AND YEAR(barginmeeting.storedt) = '$fyear'
    $meeting_filter
   $user_filter");
        return $data = $query->result();
    }
