        amr.sdate,
        amr.by_uid,
        amr.remarks,
        amr.rtype,
        amr.current_year_focus_funnel,
        amr.q1_closure,
        amr.to_be_Nurture_in_q1,
        amr.financial_year,
        amr.keep_company,
        amr.keepremark,
        amr.vmeeting,
        amr.annaul_focuspositive,
        amr.annaul_topspender,
        amr.annaul_upsell,
        amr.annaul_revenue,
        amr.transfer_the_funnel,
