        ) AS total_barginmeeting_plan_count,
      
        (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND (barginmeeting.status = 'Close' OR barginmeeting.status = 'RPClose' OR barginmeeting.startm IS NOT NULL)
              AND barginmeeting.user_id = '$tar_uid'
        ) AS total_complete_barginmeeting_count,
        (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND barginmeeting.status = 'Pending'
              AND barginmeeting.user_id = '$tar_uid'
        ) AS total_pending_barginmeeting_count,
             (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND barginmeeting.status = 'Start' AND barginmeeting.startm IS NOT NULL
              AND barginmeeting.user_id = '$tar_uid'
        ) AS total_barginmeeting_start_count
    
        FROM
            init_call
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
        LEFT JOIN annual_main_review amr ON amr.inid = init_call.id AND amr.by_uid = '$tar_uid' AND amr.financial_year = '$fyear'
        LEFT JOIN user_details u3 ON u3.user_id = amr.review_apr_by
        LEFT JOIN user_details u4 ON u4.user_id = amr.by_uid
        LEFT JOIN status s1 ON s1.id = init_call.cstatus
        LEFT JOIN status s2 ON s2.id = amr.review_time_status
    
        WHERE
            init_call.cstatus IS NOT NULL AND init_call.cstatus != '' 
            $status_filter
            $rstatus_filter
            $filter
            AND u1.status = 'active'");
        
        return $query->result();
    }
