        s2.name AS review_time_status_name,
        CASE WHEN amr.id IS NOT NULL AND amr.review_apr_status = 1 THEN 'Agree' WHEN amr.id IS NOT NULL AND amr.review_apr_status = 2 THEN 'Disagree' ELSE 'Pending'
        END AS sc_agree_or_not,
        (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
        ) AS total_barginmeeting_plan_count,
      
        (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND (barginmeeting.status = 'Close' OR barginmeeting.status = 'RPClose' OR barginmeeting.startm IS NOT NULL)
        ) AS total_complete_barginmeeting_count,
        (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND barginmeeting.status = 'Pending'
        ) AS total_pending_barginmeeting_count,
             (
            SELECT COUNT(*) 
            FROM barginmeeting 
            JOIN tblcallevents ON barginmeeting.tid = tblcallevents.id
            WHERE barginmeeting.inid = init_call.id 
              AND YEAR(barginmeeting.storedt) = '$fyear'
              AND barginmeeting.status = 'Start' AND barginmeeting.startm IS NOT NULL
        ) AS total_barginmeeting_start_count
        FROM
            init_call
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN user_details u1 ON
            u1.user_id = init_call.mainbd
        LEFT JOIN annual_main_review amr ON amr.inid = init_call.id AND amr.by_uid = '$tar_uid' AND amr.financial_year = '$fyear'
        LEFT JOIN barginmeeting ON barginmeeting.inid = init_call.id
        LEFT JOIN status s1 ON
            s1.id = init_call.cstatus
        LEFT JOIN status s2 ON
            s2.id = amr.review_time_status
        LEFT JOIN user_details u3 ON
            u3.user_id = amr.review_apr_by
        LEFT JOIN user_details u4 ON
            u4.user_id = amr.by_uid
        WHERE
            $rstatus_filter
            $status_filter
            AND barginmeeting.inid IS NOT NULL 
            AND CAST(barginmeeting.storedt AS DATE) BETWEEN '$start_date' AND '$end_date' 
            AND u1.status = 'active' 
            AND u1.ea_co = '$tar_uid'
            $filter 
        GROUP BY init_call.id;");
        
        return $query->result();
    }
