public function CheckYesterdayPlannerStartOrNot($uid,$tdate){
    $query=$this->db->query("SELECT * FROM `autotask_time` WHERE date != DATE(created_at) AND date = '$tdate' AND user_id = '$uid' AND DATE(created_at) < date ORDER BY `id` DESC;");
    return $query->result();
