public function GetNextFollowupHaveDate($uid,$tdate){
    $query=$this->db->query("SELECT
    nfhd.id AS followup_id,
    company_master.id AS cid,
    init_call.id AS init_id,
    company_master.compname,
    action.name as task_name,
    action.id as action_id,
    status.name as status_name,
    nfhd.next_folloup_have_date,
    nfhd.next_folloup_date,
    nfhd.remarks,
    nfhd.followup_plan,
    nfhd.followup_done,
    nfhd.created_at
FROM
    `next_folloup_have_date` AS nfhd
LEFT JOIN tblcallevents tbl ON tbl.id = nfhd.tid
LEFT JOIN init_call ON init_call.id = tbl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN action ON action.id = tbl.actiontype_id
LEFT JOIN status ON status.id = init_call.cstatus
WHERE
    nfhd.next_folloup_have_date = 'yes'
    AND nfhd.user_id = '$uid'
    AND DATE(nfhd.next_folloup_date) = '$tdate'
    AND nfhd.followup_plan = 'no'");
    return $query->result();
}
