SELECT
    u2.name,
    u2.user_id AS planner_user_id,
    -- Task/Review ID and Type
    ar.id AS action_id,
    CONCAT(ar.reviewtype, ' Review') AS tasktype,
    -- Task time estimate or NULL for reviews
    NULL AS yest,
    -- Count of tasks
    COUNT(ar.id) AS task_count,
    -- Total planned task count for the user
    (
        SELECT COUNT(*)
        FROM tblcallevents tce
        WHERE tce.actiontype_id != ''
          AND tce.plan = 1
          AND DATE(tce.appointmentdatetime) = '$planner_date'
          AND tce.user_id = u2.user_id
          AND tce.autotask = 0
          AND tce.appointmentdatetime != '0000-00-00 00:00:00'
    ) + (
        SELECT COUNT(*)
        FROM allreview ar_inner
        WHERE ar_inner.uid = u2.user_id
          AND DATE(ar_inner.plant) = '$planner_date'
    ) AS total_task_count,
    -- Total time of all planned tasks
    NULL AS total_plan_task_time,
    -- Total time spent on reviews (in hours and minutes)
    CASE
        WHEN SUM(
            CASE
                WHEN ar.plant IS NOT NULL AND ar.review_close_time IS NOT NULL THEN
                    TIME_TO_SEC(TIMEDIFF(ar.review_close_time, ar.plant)) / 60
                ELSE 0
            END
        ) < 0 THEN '0 hours and 0 minutes'
        ELSE CONCAT(
            FLOOR(SUM(
                CASE
                    WHEN ar.plant IS NOT NULL AND ar.review_close_time IS NOT NULL THEN
                        TIME_TO_SEC(TIMEDIFF(ar.review_close_time, ar.plant)) / 60
                    ELSE 0
                END
            ) / 60),
            ' hours ',
            FLOOR(SUM(
                CASE
                    WHEN ar.plant IS NOT NULL AND ar.review_close_time IS NOT NULL THEN
                        TIME_TO_SEC(TIMEDIFF(ar.review_close_time, ar.plant)) / 60
                    ELSE 0
                END
            ) % 60),
            ' minutes'
        )
    END AS total_review_plan_time
FROM
    allreview ar
JOIN user_details u2 ON u2.user_id = ar.uid
WHERE
    DATE(ar.plant) = '$planner_date'
    $userfilter1
GROUP BY
    u2.user_id, ar.id
ORDER BY
    task_count DESC");
    return $query->result();
}
