public function GetUserMappingQuery($uid,$and = ''){
    
    $utype      = $this->Menu_model->get_userbyid($uid);
    $user_type_id      = $utype[0]->type_id;
    if($user_type_id == 3){
        $userfilter = "$and u1.user_id = '$uid'";
    }elseif($user_type_id == 13){
        $userfilter = "$and (u1.user_id = '$uid' || u1.aadmin = '$uid' ) AND u1.type_id IN (3,13)";
    }else if($user_type_id == 4){
        $userfilter = "$and u1.pst_co = '$uid' AND u1.type_id IN (3,13,4)";
    }else if($user_type_id == 15){
        $userfilter = "$and u1.sales_co = '$uid' AND u1.type_id IN (3,13,4)";
    }elseif($user_type_id == 2){
        $userfilter = "$and u1.admin_id = '$uid' AND u1.type_id IN (3,13,4,15)";
    }else{
        $userfilter = "$and u1.admin_id = '$uid' AND u1.type_id IN (3,13,4)";
    }
    return $userfilter;
}
public function GetUserPlannedTravelMeetingsByUid($uid,$tdate=NULL){
    $query=$this->db->query(" SELECT
    tblcallevents.actiontype_id,
    cluster.travelType,
    COUNT(tblcallevents.id) AS total_actions
FROM
    tblcallevents
    LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
    LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
    LEFT JOIN user_details u1 ON u1.user_id = tblcallevents.user_id
    LEFT JOIN cluster ON cluster.id = init_call.cluster_id AND cluster.user_id = tblcallevents.user_id
WHERE
    CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate'
    AND tblcallevents.user_id = '$uid'
    AND tblcallevents.actiontype_id IN (3, 4)
    AND cluster.travelType IS NOT NULL
GROUP BY
    tblcallevents.actiontype_id,
    cluster.travelType");
    return $query->result();
}
