    MIN(user_activity.event_time) AS event_start_time,
    MAX(CASE
        WHEN closed_event_time IS NOT NULL THEN closed_event_time
        ELSE leave_time
    END) AS event_close_time,
    CONCAT(
        FLOOR(SUM(TIMESTAMPDIFF(SECOND, user_activity.event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )) / 3600), ' hours ',
        FLOOR(MOD(SUM(TIMESTAMPDIFF(SECOND, user_activity.event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )) / 60, 60)), ' minutes and ',
        MOD(SUM(TIMESTAMPDIFF(SECOND, user_activity.event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )), 60), ' seconds'
    ) AS total_time_formatted
FROM
    user_activity
LEFT JOIN
    user_details ON user_details.user_id = user_activity.user_id
WHERE
    (closed_event_time IS NOT NULL OR (closed_event_time IS NULL AND leave_time IS NOT NULL))
    AND $text
    AND CAST(user_activity.event_time AS DATE) = '$tdate'
GROUP BY
    user_details.user_id,
    user_details.name,
    CAST(user_activity.event_time AS DATE),
    user_activity.url_path
ORDER BY
    event_date,
    user_details.user_id,
    user_activity.url_path");
    return $query->result();
}
public function GetTodaysUserTotalTimeSpentByUrlPath($userid,$tdate){
    $udetail = $this->Menu_model->get_userbyid($userid);
    $type_id = $udetail[0]->type_id;
    
   if($type_id == 1){
        $text = "user_details.sadmin_id = $userid";
    }else if($type_id == 2){
        $text = "user_details.admin_id = $userid";
    }else if($type_id == 3){
        $text = "user_details.user_id = $userid";
    }else if($type_id == 13){
        $text = "user_details.aadmin = $userid";
    }else if($type_id == 4){
        $text = "user_details.pst_co = $userid";
    }else if($type_id == 15){
        $text = "user_details.sales_co = $userid";
    }elseif($type_id == 19){
        $text = "user_details.ash_nae_co = '$userid'";
    }else if($type_id == 20){
        $text = "user_details.ash_w_co='$userid'";
    }else if($type_id == 21){
        $text = "user_details.ash_s_co='$userid'";
    }else if($type_id == 22){
        $text = "user_details.rm_east_co='$userid'";
    }else if($type_id == 23){
        $text = "user_details.rm_north_co='$userid'";
    }else if($type_id == 24){
        $text = "user_details.acm_co='$userid'";
    }else{
        $text = "user_details.admin_id = $userid";
    }
    $query=$this->db->query("SELECT
    user_details.user_id,
    user_details.name AS name,
    CAST(user_activity.event_time AS DATE) AS event_date,
    user_activity.url_path,
    user_activity.event_time AS event_start_time,
    CASE
        WHEN closed_event_time IS NOT NULL THEN closed_event_time
        ELSE leave_time
    END AS event_close_time,
    CONCAT(
        FLOOR(SUM(TIMESTAMPDIFF(SECOND, event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )) / 3600), ' hours ',
        FLOOR(MOD(SUM(TIMESTAMPDIFF(SECOND, event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )) / 60, 60)), ' minutes and ',
        MOD(SUM(TIMESTAMPDIFF(SECOND, event_time,
            CASE
                WHEN closed_event_time IS NOT NULL THEN closed_event_time
                ELSE leave_time
            END
        )), 60), ' seconds'
    ) AS total_time_formatted
FROM
    user_activity
LEFT JOIN
    user_details ON user_details.user_id = user_activity.user_id
WHERE
    (closed_event_time IS NOT NULL OR (closed_event_time IS NULL AND leave_time IS NOT NULL))
    AND $text
    AND CAST(user_activity.event_time AS DATE) = '$tdate'
GROUP BY
    user_details.user_id,
    user_details.name,
    CAST(user_activity.event_time AS DATE),
    user_activity.url_path,
    user_activity.event_time,
    CASE
        WHEN closed_event_time IS NOT NULL THEN closed_event_time
        ELSE leave_time
    END
ORDER BY
    event_date");
    return $query->result();
}
public function getCompanyContactDetailsByTask($taskId){
     $query= $this->db->query(" SELECT * FROM company_contact_master ccm 
                                  LEFT JOIN init_call ic ON ic.cmpid_id = ccm.company_id
                                  LEFT JOIN tblcallevents tbe ON tbe.cid_id= ic.id 
                                  WHERE tbe.id ='".$taskId."' AND ccm.type = 'primary' ");
      
      return $query->result();           
}
