    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 4 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_will_do_later,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 5 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_not_interested,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 6 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_positive,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND (tbcl.status_id = 7 || init_call.upsell_client = 'yes') AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_closure,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 8 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_open_rpem,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 9 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_very_positive,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 10 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_ttd_reachout,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 11 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_wno_reachout,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 12 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_positive_nap,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 13 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_very_positive_nap,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND tbcl.status_id = 14 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) AS total_OGD_in_on_boarded,
    -- Closed Only Got Detail Meeting By Planned Status
    -- meeting on other funnel
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_meetings,
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_complete_meetings,
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND tbcl.nextCFID = 0 AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_pending_meetings,
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'RP' || tbcl.mtype = 'RPClose' || tbcl.mtype = 'Change RP') AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_RP_meetings,
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'NO RP') AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_NO_RP_meetings,
    COUNT(CASE WHEN tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND tbcl.mtype = 'Only Got Detail' AND init_call.mainbd != user_details.user_id THEN 1 END) AS total_other_funnel_Only_Got_Detail_meetings,
    -- meeting on other funnel
    -- Start New Company Meetings
    COUNT(CASE WHEN (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_complete,
    COUNT(CASE WHEN tbcl.nextCFID = 0 AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_pending,
    COUNT(CASE WHEN ((tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose' OR tbcl.mtype = 'Change RP') AND tbcl.nextCFID != 0) AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_RP_meetings,
    COUNT(CASE WHEN ((tbcl.mtype = 'NO RP') AND tbcl.nextCFID != 0) AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_NO_RP_meetings,
    COUNT(CASE WHEN (tbcl.mtype = 'Only Got Detail' AND tbcl.nextCFID != 0) AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate') AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_Only_Got_details_meetings,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND init_call.potential  = 'yes' AND (tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose' OR tbcl.mtype = 'Change RP') AND CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate' AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_potential_rp_meetings,
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND init_call.potential  = 'no' AND (tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose' OR tbcl.mtype = 'Change RP') AND CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate' AND tbcl.actiontype_id IN (4) THEN 1 END) AS total_new_company_non_rp_potential_meetings,
    -- Closed New Company Meetings
    ROUND(
    COUNT(CASE WHEN tbcl.nextCFID != 0 THEN 1 END) 
    / (DATEDIFF('$edate', '$sdate') + 1),
    1
) AS task_frequency_per_day,
 ROUND(
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND (tbcl.mtype = 'RP' || tbcl.mtype = 'RPClose' || tbcl.mtype = 'Change RP') THEN 1 END) 
    / (DATEDIFF('$edate', '$sdate') + 1),
    1
) AS task_RP_frequency_per_day,
 ROUND(
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND (tbcl.mtype = 'NO RP') THEN 1 END) 
    / (DATEDIFF('$edate', '$sdate') + 1),
    1
) AS task_NO_RP_frequency_per_day,
 ROUND(
    COUNT(CASE WHEN tbcl.nextCFID != 0 AND (tbcl.mtype = 'Only Got Detail') THEN 1 END) 
    / (DATEDIFF('$edate', '$sdate') + 1),
    1
) AS task_OGD_frequency_per_day
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
WHERE
    cast(tbcl.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'
    $taskactionFilter
    AND (tbcl.approved_status = '1' OR tbcl.approved_status = '')
    AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)
    AND user_details.status ='active'
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR
        (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR
        (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
        OR
        (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
        OR
        (user_details.type_id = 22 AND init_call.rm_east_co_id = user_details.user_id)
    )
    -- GROUP BY tbcl.id
	AND $text");
    return $query->result(); 
}
