        $taskactionFilter = "AND tbcl.actiontype_id IN (4)";
    }else if ($mtypes == 'total_new_company_RP_meetings') {
        $filter = " AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose' OR tbcl.mtype = 'Change RP') AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate')";
        $taskactionFilter = "AND tbcl.actiontype_id IN (4)";
    }else if ($mtypes == 'total_new_company_NO_RP_meetings') {
        $filter = " AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'NO RP') AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate')";
        $taskactionFilter = "AND tbcl.actiontype_id IN (4)";
    }else if ($mtypes == 'total_new_company_Only_Got_details_meetings') {
         $filter = " AND tbcl.nextCFID != 0 AND tbcl.mtype = 'Only Got Detail' AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate')";
    }else if ($mtypes == 'total_new_company_potential_rp_meetings') {
        $filter = " AND (tbcl.nextCFID != 0 AND tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose') AND init_call.potential  = 'yes' AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate')";
        $taskactionFilter = "AND tbcl.actiontype_id IN (4)";
    }else if ($mtypes == 'total_new_company_non_rp_potential_meetings') {
        $filter = " AND tbcl.nextCFID != 0 AND init_call.potential  = 'no' AND (tbcl.mtype = 'RP' OR tbcl.mtype = 'RPClose' OR tbcl.mtype = 'Change RP') AND (CAST(init_call.createDate AS DATE) BETWEEN '$sdate' AND '$edate')";
        $taskactionFilter = "AND tbcl.actiontype_id IN (4)";
    }else if ($mtypes == 'total_other_funnel_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND init_call.mainbd != user_details.user_id";
    }else if ($mtypes == 'total_other_funnel_complete_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0  AND init_call.mainbd != user_details.user_id";
    }else if ($mtypes == 'total_other_funnel_pending_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND tbcl.nextCFID = 0  AND init_call.mainbd != user_details.user_id";
    }else if ($mtypes == 'total_other_funnel_RP_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'RP' || tbcl.mtype = 'RPClose' || tbcl.mtype = 'Change RP') AND init_call.mainbd != user_details.user_id";
    }else if ($mtypes == 'total_other_funnel_NO_RP_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND (tbcl.mtype = 'NO RP') AND init_call.mainbd != user_details.user_id";
    }else if ($mtypes == 'total_other_funnel_Only_Got_Detail_meetings'){
        $filter = "AND tbcl.actiontype_id != 0 AND tbcl.nextCFID != 0 AND tbcl.mtype = 'Only Got Detail' AND init_call.mainbd != user_details.user_id";
    }
    else if($mtypes == 'total_anchor_clients_meetings'){
        $filter = ' AND init_call.anchor_clients = "yes"';
    }
    else if($mtypes == 'total_complete_anchor_clients_meetings'){
        $filter = ' AND tbcl.nextCFID != 0 AND init_call.anchor_clients = "yes"';
    }
    else if($mtypes == 'total_pending_anchor_clients_meetings'){
        $filter = ' AND tbcl.nextCFID = 0 AND init_call.anchor_clients = "yes"';
    }
    $query= $this->db->query("SELECT
     user_details.user_id as task_user_id,
     user_details.name as task_username,
     company_master.compname,
     company_master.id as cid,
     tbcl.id as task_id,
     tbcl.nextCFID,
     tbcl.fwd_date,
     tbcl.appointmentdatetime,
     tbcl.actontaken,
     tbcl.purpose_achieved,
     tbcl.meeting_type,
     tbcl.actiontype_id,
     tbcl.assignedto_id,
     tbcl.cid_id,
     tbcl.remarks,
     tbcl.mom as mom_remarks,
     tbcl.mtype,
     tbcl.selectby,
     tbcl.filter_by,
     tbcl.approved_status as task_approved_status,
     tbcl.approved_by as task_approved_by,
     tbcl.assignedto_by as task_assignedto_by,
     tbcl.assignedto_by as task_aftertask,
     tbcl.norp_by as norp_by_admin,
     action.name as task_name,
     status.name as current_status,
     tbcl.plan_count as plan_count,
     barginmeeting.startm,
     barginmeeting.closem,
     barginmeeting.company_as,
     barginmeeting.proposalStatus,
     barginmeeting.company_descri,
     barginmeeting.status as meetings_status,
     barginmeeting.initphoto,
     barginmeeting.cphoto,
     barginmeeting.potentional_client as business_potentional_client,
     init_call.potential,
     init_call.topspender,
     init_call.upsell_client,
     init_call.focus_funnel,
     init_call.keycompany,
     init_call.pkclient,
     init_call.priorityc,
     init_call.anchor_clients,
     init_call.createDate as company_createDate,
     s1.name as meetings_time_status,
     init_call.q1_twetenty_closure_funnel,
     init_call.potential_funnel_for_fy,
     init_call.to_be_nurtured_for_fy,
     init_call.fifity_new_lead_funnel,
     u2.name as mainbd_name,
     partner_master.name as partner_name,
     cluster.id as cluster_id,
     cluster.clustername as cluster_name,
     cluster.travelType as cluster_travelType,
     u4.name as inside_sales_name
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
LEFT JOIN user_details u2 ON u2.user_id = init_call.mainbd
LEFT JOIN user_details u4 ON u4.user_id = init_call.insidebd
LEFT JOIN action ON action.id = tbcl.actiontype_id
LEFT JOIN status ON status.id = init_call.cstatus
LEFT JOIN status s1 ON s1.id = tbcl.status_id
LEFT JOIN cluster ON cluster.id = init_call.cluster_id
WHERE
    $taskDateFilter
    $taskactionFilter
    $approval_filter
    $deleteRequest 
    $checkUserStatus
    $userMainBDRolesFilter
	AND $text $filter $groupbyFilter");
    return $query->result(); 
}
