                }else if($type_id == 2){
                    $text = "user_details.admin_id = '$userid'";
                }else if($type_id == 3){
                    $text = "user_details.user_id = '$userid'";
                }else if($type_id == 4){
                    $text = "(user_details.pst_co = '$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 13){
                    $text = "(user_details.aadmin = '$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 15){
                    $text = "user_details.sales_co = '$userid'";
                }elseif($type_id == 19){
                    $text = "(user_details.ash_nae_co = '$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 20){
                    $text = "(user_details.ash_w_co='$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 21){
                    $text = "(user_details.ash_s_co='$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 22){
                    $text = "(user_details.rm_east_co='$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 23){
                    $text = "(user_details.rm_north_co='$userid' || user_details.user_id = '$userid')";
                }else if($type_id == 24){
                    $text = "(user_details.acm_co = $userid || user_details.user_id = '$userid')";
                }else{
                    $text = "user_details.admin_id = $userid";
                }
        }
    }
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    $start_financial_date = '2026-04-01';
    
    $query= $this->db->query("SELECT
    user_details.user_id,
    user_details.name as username,
    -- COUNT(CASE 
    --     WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) BETWEEN 0 AND 15 
    --     THEN 1 END) AS one_to_fifteen,
    COUNT(
        CASE
            WHEN TIMESTAMPDIFF(SECOND, barginmeeting.startm, barginmeeting.closem) BETWEEN 0 AND 59
            THEN 1
        END
    ) AS one_to_fifty_nine_seconds,
     COUNT(
        CASE
            WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) BETWEEN 0 AND 15
            THEN 1
        END
    ) AS one_to_fifteen,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 15 
             AND TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) <= 30 
        THEN 1 END) AS fifteen_to_thirteen,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 30 
             AND TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) <= 50 
        THEN 1 END) AS thirteen_to_fifty,
    
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 30 
             AND TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) <= 60 
        THEN 1 END) AS thirteen_to_sixty,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 60 
        THEN 1 END) AS gretter_than_sixty,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 50 
             AND TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) <= 90 
        THEN 1 END) AS fifty_to_ninety,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 90 
             AND TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) <= 120 
        THEN 1 END) AS ninety_to_one_twenty,
    COUNT(CASE 
        WHEN TIMESTAMPDIFF(MINUTE, barginmeeting.startm, barginmeeting.closem) > 120 
        THEN 1 END) AS gretter_than_one_twenty
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
WHERE
    CAST(tbcl.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'
    AND tbcl.actiontype_id IN (3,4,17,22) 
    AND tbcl.nextCFID != 0 
    AND (tbcl.approved_status = 1 || tbcl.approved_status = '')
    AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)
    AND user_details.status = 'active'
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR
        (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR
        (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
        OR
        (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
        OR 
        (user_details.type_id = 22 AND init_call.rm_east_co_id = user_details.user_id)
    )
    AND $text
GROUP BY
    user_details.user_id");
    return $query->result(); 
}
