    COUNT(DISTINCT CASE WHEN init_call.to_be_nurtured_for_fy = '$year' THEN init_call.id END) AS total_company_in_to_be_nurtured_for_fy,
    COUNT(DISTINCT CASE WHEN init_call.fifity_new_lead_funnel = '$year' THEN init_call.id END) AS total_company_in_fifity_new_lead_funnel,
    -- These counts still depend on tbcl join
    COUNT(CASE WHEN init_call.q1_twetenty_closure_funnel = '$year' AND tbcl.id IS NOT NULL AND tbcl.nextCFID != 0 AND tbcl.user_id = user_details.user_id THEN 1 END) AS total_in_q1_twetenty_closure_funnel,
