FROM init_call
LEFT JOIN tblcallevents tbcl 
    ON tbcl.cid_id = init_call.id
    AND DATE(tbcl.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
    AND tbcl.actiontype_id IN (3, 4, 17)
    AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)
    AND (tbcl.approved_status = 1 OR tbcl.approved_status = '')
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details ON user_details.user_id = init_call.mainbd
WHERE user_details.status = 'active'
  AND (
         (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
         OR
         (user_details.type_id = 13 AND init_call.mainbd = user_details.user_id)
         OR
         (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
         OR
         (user_details.type_id = 24 AND init_call.mainbd = user_details.user_id)
         OR 
        (user_details.type_id = 22 AND init_call.rm_east_co_id = user_details.user_id)
     )
  AND $text
GROUP BY user_details.user_id");
    return $query->result(); 
