    $year = $start_financial_date_year->format('Y');
    
    $query= $this->db->query("SELECT
    user_details.user_id,
    user_details.name as username,
    COUNT(CASE WHEN tbcl.status_id = 1 THEN 1 END) AS total_open,
    COUNT(CASE WHEN tbcl.status_id = 2 THEN 1 END) AS total_reachout,
    COUNT(CASE WHEN tbcl.status_id = 3 THEN 1 END) AS total_tentative,
    COUNT(CASE WHEN tbcl.status_id = 4 THEN 1 END) AS total_will_do_later,
    COUNT(CASE WHEN tbcl.status_id = 5 THEN 1 END) AS total_not_interested,
    COUNT(CASE WHEN tbcl.status_id = 6 THEN 1 END) AS total_positive,
    COUNT(CASE WHEN (tbcl.status_id = 7 || init_call.upsell_client = 'yes') THEN 1 END) AS total_closure,
    COUNT(CASE WHEN tbcl.status_id = 8 THEN 1 END) AS total_open_rpem,
    COUNT(CASE WHEN tbcl.status_id = 9 THEN 1 END) AS total_very_positive,
    COUNT(CASE WHEN tbcl.status_id = 10 THEN 1 END) AS total_ttd_reachout,
    COUNT(CASE WHEN tbcl.status_id = 11 THEN 1 END) AS total_wno_reachout,
    COUNT(CASE WHEN tbcl.status_id = 12 THEN 1 END) AS total_positive_nap,
    COUNT(CASE WHEN tbcl.status_id = 13 THEN 1 END) AS total_very_positive_nap,
    COUNT(CASE WHEN tbcl.status_id = 14 THEN 1 END) AS total_on_boarded
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
WHERE
    CAST(tbcl.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'
    AND tbcl.actiontype_id IN (3,4,17,22) 
    AND tbcl.nextCFID != 0 
    AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)
    AND (tbcl.approved_status = 1 || tbcl.approved_status = '')
    AND user_details.status = 'active'
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR
        (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR
        (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
        OR
        (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
        OR 
        (user_details.type_id = 22 AND init_call.rm_east_co_id = user_details.user_id)
    )
    AND $text
	AND user_details.status = 'active'
GROUP BY
    user_details.user_id");
    return $query->result(); 
}
