public function GetMeetingDetailsByTaskID($taskid){
    $query = $this->db->query("SELECT
     user_details.user_id as task_user_id,
     user_details.name as task_username,
     company_master.compname,
     company_master.id as cid,
     tbcl.id as task_id,
