    }
    
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    $sdate = '2026-04-01';
    $edate = date('Y-m-d', strtotime('-1 day'));
    $query = $this->db->query("SELECT
	user_details.user_id,
	user_details.name as user_name,
	u3.name as task_user_name,
    company_master.compname as company_name,
    company_master.id as cid,
    barginmeeting.id as meeting_id,
    barginmeeting.tid as task_id,
    barginmeeting.storedt,
    barginmeeting.startm,
    barginmeeting.closem,
    barginmeeting.cid,
    barginmeeting.status AS meeting_status,
    tblcallevents.id as tbl_task_id,
    tblcallevents.mtype,
    tblcallevents.nextCFID,
    check_mom_exists_in_tblc.id AS write_mom_id,
    tblcallevents.approved_status as task_approved_status,
    u2.name as task_approved_by,
    action.name as task_name,
    s1.name as task_plan_time_status,
    s2.name as task_complete_time_new_status,
    s3.name as current_status
FROM
    barginmeeting
LEFT JOIN tblcallevents ON tblcallevents.id = barginmeeting.tid
LEFT JOIN tblcallevents AS check_mom_exists_in_tblc ON check_mom_exists_in_tblc.aftertask = barginmeeting.tid AND check_mom_exists_in_tblc.actiontype_id = 6
LEFT JOIN user_details ON user_details.user_id = barginmeeting.user_id
LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN user_details u2 ON u2.user_id = tblcallevents.approved_by
LEFT JOIN user_details u3 ON u3.user_id = tblcallevents.user_id
LEFT JOIN action ON action.id = tblcallevents.actiontype_id
LEFT JOIN status s1 ON s1.id = tblcallevents.status_id
LEFT JOIN status s2 ON s2.id = tblcallevents.nstatus_id
LEFT JOIN status s3 ON s3.id = init_call.cstatus
WHERE
    check_mom_exists_in_tblc.id IS NULL
	AND tblcallevents.mtype IN ('RP', 'RPClose', 'Change RP')
    -- AND cast(tblcallevents.appointmentdatetime as Date) >= '2026-04-01' 
    AND cast(tblcallevents.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'
    AND tblcallevents.nextCFID != 0
    $text AND user_details.status = 'active'
	AND tblcallevents.actiontype_id IN (3,4,17) 
    AND tblcallevents.approved_status = 1
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR
        (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR
        (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
    )
ORDER BY
    barginmeeting.id ASC");
    return $query->result();
  }
