    COUNT(CASE 
        WHEN tblc.nextCFID !=0 AND init_call.mainbd != u1.user_id AND (tblc.actontaken = 'no' AND  tblc.purpose_achieved = 'yes')
        THEN 1 
    END) AS total_team_anpy_funnel_complete_task
    
FROM tblcallevents AS tblc
LEFT JOIN user_details AS u1 ON u1.user_id = tblc.user_id
LEFT JOIN init_call ON init_call.id = tblc.cid_id
WHERE 
 
    --  DATE(tblc.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
    tblc.appointmentdatetime >= '{$sdate} 00:00:00'
    AND tblc.appointmentdatetime <= '{$edate} 23:59:59'
     $task_action_filter
    AND u1.status = 'active'
    $text");
    return $query->result();
}
