             LEFT JOIN cluster_mapping on cluster_mapping.cluster_id = cluster.id
             LEFT JOIN user_details on user_details.user_id = cluster_mapping.user_id
             LEFT JOIN user_details u1 on u1.user_id = cluster.apr_by
        WHERE
            user_details.status = 'active'
            AND $text
            ");
        $totalCluster =  $query1->result();
        $query2 = $this->db->query("SELECT
        user_details.user_id,
        user_details.name as username,
        COUNT(CASE WHEN cluster.id THEN 1 END) AS total_cluster,
        COUNT(CASE WHEN cluster.apr_status = 1 THEN 1 END) AS approved_cluster,
        COUNT(CASE WHEN cluster.apr_status = 0 THEN 1 END) AS pending_for_approved_cluster,
        COUNT(CASE WHEN cluster.apr_status = 2 THEN 1 END) AS rejected_cluster,
        COUNT(CASE WHEN cluster_mapping.travel_type = 'base' THEN 1 END) AS total_base_station_cluster,
        COUNT(CASE WHEN cluster_mapping.travel_type = 'outStation' THEN 1 END) AS total_out_station_cluster,
        COUNT(CASE WHEN cluster_mapping.travel_type = 'base' AND cluster.apr_status = 1 THEN 1 END) AS total_base_station_approved_cluster,
        COUNT(CASE WHEN cluster_mapping.travel_type = 'outStation' AND cluster.apr_status = 1 THEN 1 END) AS total_out_station_approved_cluster
        FROM
            `cluster`
             LEFT JOIN cluster_mapping on cluster_mapping.cluster_id = cluster.id
             LEFT JOIN user_details on user_details.user_id = cluster_mapping.user_id
             LEFT JOIN user_details u1 on u1.user_id = cluster.apr_by
        WHERE
            user_details.status = 'active'
            AND $text
            GROUP BY user_details.user_id");
        $totalClusterData =  $query2->result();
        // echo $this->db->last_query();
        // die;
        $result = [
            'totalCluster'      => $totalCluster,
            'totalClusterData'  => $totalClusterData
        ];
        return $result;
    }
