public function GetAllReviewDatasOnCompanyByCID($cid) {
  
    $query = $this->db->query("SELECT
    main_review.id as review_id,
    company_master.compname,
    user_details.name as review_by_name,
    action.name as review_time_task,
    tblc.nextCFID,
    tblc.appointmentdatetime,
    s1.name as review_time_compnay_status,
    s2.name as review_time_expected_status,
    s3.name as current_status,
    main_review.exdate as expected_date,
    main_review.*
FROM
    `main_review`
    LEFT JOIN init_call ON init_call.id = main_review.inid
    LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
    LEFT JOIN user_details ON user_details.user_id = main_review.by_uid
    LEFT JOIN tblcallevents tblc on tblc.id = main_review.ntid
    LEFT JOIN action ON action.id = tblc.actiontype_id
    LEFT JOIN status s1 ON s1.id = main_review.csid
    LEFT JOIN status s2 ON s2.id = main_review.exsid 
    LEFT JOIN status s3 ON s3.id = init_call.cstatus
    WHERE init_call.cmpid_id = '$cid'");
    return $query->result();
}
