            tbcl.initiateddt,
            tbcl.updated_at,
            tbcl.updateddate as task_updateddate,
            CONCAT(
                FLOOR(TIMESTAMPDIFF(SECOND, COALESCE(tbcl.initiateddt, tbcl.appointmentdatetime), tbcl.updateddate) / 3600), ' hours ',
                FLOOR(MOD(TIMESTAMPDIFF(SECOND, COALESCE(tbcl.initiateddt, tbcl.appointmentdatetime), tbcl.updateddate), 3600) / 60), ' minutes and ',
                MOD(TIMESTAMPDIFF(SECOND, COALESCE(tbcl.initiateddt, tbcl.appointmentdatetime), tbcl.updateddate), 60), ' seconds'
            ) AS total_time_taken,
            tbcl.late_remarks_message,
            tbcl.actontaken,
            tbcl.purpose_achieved,
            tbcl.meeting_type,
            tbcl.actiontype_id,
            tbcl.assignedto_id,
            tbcl.cid_id,
            tbcl.remarks,
            tbcl.mom AS mom_remarks,
            tbcl.mtype,
            tbcl.selectby,
            tbcl.special_remarks,
            tbcl.filter_by,
            tbcl.delete_request,
            tbcl.reminder_remarks,
            tbcl.aftertask as tbl_aftertask,
            tbcl.reviewtype as tbl_reviewtype,
            tbcl.approved_status AS task_approved_status,
            tbcl.approved_date AS task_approved_date,
            -- tbcl.approved_by AS task_approved_by,
            tbcl.assignedto_by AS task_assignedto_by,
            tbcl.assignedto_by AS task_aftertask,
            tbcl.delete_request,
            action.name AS task_name,
            status.name AS current_status,
            tbcl.plan_count AS plan_count,
            init_call.potential,
            init_call.topspender,
            init_call.upsell_client,
            init_call.focus_funnel,
            init_call.keycompany,
            init_call.pkclient,
            init_call.priorityc,
            init_call.q1_twetenty_closure_funnel,
            init_call.potential_funnel_for_fy,
            init_call.to_be_nurtured_for_fy,
            init_call.fifity_new_lead_funnel,
            init_call.anchor_clients,
            init_call.in_quarter,
            u1.name AS main_bd_name,
            u2.name AS main_bd_manager_name,
            s1.name AS task_time_status,
            s2.name AS task_time_new_status,
            s3.name as ccurrent_status,
            partner_master.name AS partner_name,
            COALESCE(u3.name, tbcl.approved_by) AS task_approved_by,
            u10.name AS pst_name,
            init_call.createDate as company_createDate,
            tbcl.mom as mom_remarks
            $selectFilert
        FROM
            tblcallevents AS tbcl
        LEFT JOIN init_call ON init_call.id = tbcl.cid_id
        LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
        LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
        LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
        LEFT JOIN action ON action.id = tbcl.actiontype_id
        LEFT JOIN status ON status.id = init_call.cstatus
        LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd
        LEFT JOIN user_details u2 ON u2.user_id = init_call.clm_id
        LEFT JOIN user_details u3 ON u3.user_id = tbcl.approved_by
        LEFT JOIN status s1 ON s1.id = tbcl.status_id
        LEFT JOIN status s2 ON s2.id = tbcl.nstatus_id
        LEFT JOIN status s3 ON s3.id = init_call.cstatus
        LEFT JOIN user_details u10 ON u10.user_id = init_call.apst
        $leftjoin
        WHERE
        $text AND Cast(tbcl.appointmentdatetime as Date) = '$cdate'
        AND $taskactionFilter ORDER BY tbcl.appointmentdatetime ASC
    ");
    return $query->result();
}
    // Closed Live Meeting Task Tracking BY Rolles
 public function GetMeetingDoneProposalDoneOrNot($userid,$sdate,$edate){
        $udetail = $this->Menu_model->get_userbyid($userid); 
        $type_id = $udetail[0]->type_id;
            
        if($type_id == 2){
            $text = "user_details.admin_id = $userid";
        }else if($type_id == 13){
            $text = "(user_details.aadmin='$userid' || user_details.user_id='$userid')";
        }else if($type_id == 4){
            $text = "(user_details.pst_co='$userid' || user_details.user_id='$userid')";
        }else if($type_id == 15){
            $text = "user_details.sales_co = $userid";
        }elseif($type_id == 19){
            $text = "user_details.ash_nae_co = '$userid'";
        }else if($type_id == 20){
            $text = "user_details.ash_w_co='$userid'";
        }else if($type_id == 21){
            $text = "(user_details.ash_s_co='$userid')";
        }else if($type_id == 22){
            $text = "(user_details.rm_east_co='$userid' || user_details.user_id='$userid')";
        }else if($type_id == 23){
            $text = "(user_details.rm_north_co='$userid' || user_details.user_id='$userid')";
        }else if($type_id == 24){
            $text = "(user_details.acm_co='$userid' || user_details.user_id='$userid')";
        }else{
            $text = "user_details.user_id='$userid'";
        }
        $query=$this->db->query("SELECT
  -- Unique total task count
COUNT(DISTINCT tblcallevents.id) AS total_task,
-- Unique count of Scheduled Meetings
COUNT(DISTINCT CASE WHEN tblcallevents.actiontype_id = 3 THEN tblcallevents.id ELSE NULL END) AS total_scheduled_meeting,
-- Unique count of Bargaining Meetings
COUNT(DISTINCT CASE WHEN tblcallevents.actiontype_id = 4 THEN tblcallevents.id ELSE NULL END) AS total_barg_meeting,
    -- Count Proposal Sent (approved)
    COUNT(DISTINCT CASE 
        WHEN tblcallevents1.id IS NOT NULL 
             AND proposal.id IS NOT NULL 
             AND proposal.apr = 1 
        THEN tblcallevents.id
        ELSE NULL
    END) AS proposal_sent,
    -- Count Proposal Not Sent
    COUNT(DISTINCT CASE 
        WHEN (
            tblcallevents1.id IS NULL OR 
            proposal.id IS NULL OR 
            proposal.apr IN (0, 2)
        )
        THEN tblcallevents.id
        ELSE NULL
    END) AS proposal_not_sent,
    -- Scheduled Meeting + Proposal Sent
    COUNT(DISTINCT CASE 
        WHEN tblcallevents.actiontype_id = 3
             AND tblcallevents1.id IS NOT NULL
             AND proposal.id IS NOT NULL
             AND proposal.apr = 1
        THEN tblcallevents.id
        ELSE NULL
    END) AS shedulded_meeting_proposal_sent,
    -- Scheduled Meeting + Proposal Not Sent
    COUNT(DISTINCT CASE 
        WHEN tblcallevents.actiontype_id = 3
             AND (
                 tblcallevents1.id IS NULL OR
                 proposal.id IS NULL OR
                 proposal.apr IN (0, 2)
             )
        THEN tblcallevents.id
        ELSE NULL
    END) AS shedulded_meeting_proposal_not_sent,
    -- Bargaining + Proposal Sent
    COUNT(DISTINCT CASE 
        WHEN tblcallevents.actiontype_id = 4
             AND tblcallevents1.id IS NOT NULL
             AND proposal.id IS NOT NULL
             AND proposal.apr = 1
        THEN tblcallevents.id
        ELSE NULL
    END) AS shedulded_barg_proposal_sent,
    -- Bargaining + Proposal Not Sent
    COUNT(DISTINCT CASE 
        WHEN tblcallevents.actiontype_id = 4
             AND (
                 tblcallevents1.id IS NULL OR
                 proposal.id IS NULL OR
                 proposal.apr IN (0, 2)
             )
        THEN tblcallevents.id
        ELSE NULL
    END) AS shedulded_barg_proposal_not_sent,
      -- Proposal sent but closer not done (cstatus != 7)
    COUNT(DISTINCT CASE 
        WHEN tblcallevents1.id IS NOT NULL 
             AND proposal.id IS NOT NULL 
             AND proposal.apr = 1
             AND init_call.cstatus != 7
        THEN tblcallevents.id
        ELSE NULL
    END) AS proposal_sent_closer_not_done
FROM
    tblcallevents
-- Join user info
LEFT JOIN user_details 
    ON user_details.user_id = tblcallevents.user_id
-- Join call info
LEFT JOIN init_call 
    ON init_call.id = tblcallevents.cid_id
-- Related task (actiontype_id = 7)
LEFT JOIN tblcallevents AS tblcallevents1
    ON tblcallevents1.cid_id = tblcallevents.cid_id
    AND tblcallevents1.actiontype_id = 7
    AND DATE(tblcallevents1.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
-- Proposal info
LEFT JOIN proposal
    ON proposal.tid = tblcallevents1.id
WHERE
    tblcallevents.actiontype_id IN (3, 4)
    AND tblcallevents.nextCFID != 0
    AND $text
    AND DATE(tblcallevents.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
    AND tblcallevents.mtype IN ('RP', 'RPClose', 'Change RP')");
        return $query->result();
    }
