    COUNT(DISTINCT init_call.id) AS total_meetings,
    -- Proposal sent (approved or pending)
    COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1)
        THEN init_call.id
    END) AS proposal_sent,
    -- Proposal not sent (no proposal or rejected)
  COUNT(DISTINCT CASE
        WHEN (proposal.id IS NULL OR proposal.apr = 2)
        AND NOT EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$sdate' AND '$edate'
        )
        THEN init_call.id
    END) AS proposal_not_sent,
      COUNT(DISTINCT CASE
        WHEN (proposal.id IS NULL OR proposal.apr = 2)
        AND barginmeeting.potentional_client = 'yes'
        AND NOT EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$sdate' AND '$edate'
        )
        THEN init_call.id
    END) AS bd_potentional_client_proposal_not_sent,
    -- Proposal sent but closure not done
    COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1) AND init_call.cstatus != 7
        THEN init_call.id
    END) AS proposal_sent_but_closure_not_done,
    -- Proposal sent but closure not done
    COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1) AND init_call.cstatus = 7
        THEN init_call.id
    END) AS proposal_sent_but_closure_done
FROM init_call
-- Only include callevents that match RP/RPClose and are approved
JOIN tblcallevents ON tblcallevents.cid_id = init_call.id
    AND tblcallevents.nextCFID != 0
    AND tblcallevents.mtype IN ('RP', 'RPClose','Change RP')
    AND tblcallevents.actiontype_id IN (3, 4,17,22)
    AND (tblcallevents.approved_status = '1' OR tblcallevents.approved_status = '')
    AND (tblcallevents.delete_request = '' OR tblcallevents.delete_request IS NULL)
LEFT JOIN barginmeeting on barginmeeting.tid = tblcallevents.id
JOIN user_details ON user_details.user_id = tblcallevents.user_id
    AND user_details.status = 'active'
-- LEFT JOIN proposals — may or may not exist
LEFT JOIN proposal ON proposal.init_id = init_call.id AND DATE(proposal.sdatet) BETWEEN '$sdate' AND '$edate'
LEFT JOIN user_details u1 ON u1.user_id = proposal.user_id AND u1.status = 'active'
WHERE
    DATE(tblcallevents.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
        OR (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
    )
    AND $text");
        return $query->result();
