                    $text = "user_details.user_id = $userid";
                }else if($type_id == 4){
                    $text = "(user_details.pst_co = $userid || user_details.user_id = $userid)";
                }else if($type_id == 13){
                    $text = "(user_details.aadmin = $userid || user_details.user_id = $userid)";
                }else if($type_id == 15){
                    $text = "user_details.sales_co = $userid";
                }elseif($type_id == 19){
                    $text = "user_details.ash_nae_co = '$userid'";
                }else if($type_id == 20){
                    $text = "user_details.ash_w_co='$userid'";
                }else if($type_id == 21){
                    $text = "user_details.ash_s_co='$userid'";
                }else if($type_id == 22){
                    $text = "user_details.rm_east_co='$userid'";
                }else if($type_id == 23){
                    $text = "user_details.rm_north_co='$userid'";
                }else if($type_id == 24){
                    $text = "(user_details.acm_co = $userid || user_details.user_id = $userid)";
                }else{
                    $text = "user_details.admin_id = $userid";
                }
        }
    }
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    
    $start_financial_date_year = new DateTime($start_financial_date);
    $fyear = $start_financial_date_year->format('Y');
    $start_financial_date = '2026-04-01';
    $taskactionFilter = "AND tbcl.actiontype_id IN (3,4,17,22)";
$query = $this->db->query("SELECT
  
    -- Proposal sent (approved or pending)
     COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1)
         AND EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$check_review_start_date' AND '$edate'
        )
         AND NOT EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$sdate' AND '$check_review_start_date'
        )
        THEN init_call.id
    END) AS proposal_sent_after_review,
      COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1)
        AND barginmeeting.potentional_client = 'yes'
        AND EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$check_review_start_date' AND '$edate'
        )
        AND NOT EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$sdate' AND '$check_review_start_date'
        )
        THEN init_call.id
    END) AS bd_potentional_client_proposal_sent_after_review,
    -- Proposal sent but closure not done
    COUNT(DISTINCT CASE
        WHEN proposal.id IS NOT NULL AND proposal.apr IN (0, 1) 
        AND EXISTS (
            SELECT 1
            FROM proposal p
            WHERE p.init_id = init_call.id
            AND p.apr IN (0, 1)
            AND DATE(p.sdatet) BETWEEN '$check_review_start_date' AND '$edate'
        )
        AND init_call.cstatus = 7
        THEN init_call.id
    END) AS proposal_sent_closure_done_after_review
FROM init_call
-- Only include callevents that match RP/RPClose and are approved
JOIN tblcallevents ON tblcallevents.cid_id = init_call.id
    AND tblcallevents.nextCFID != 0
    AND tblcallevents.mtype IN ('RP', 'RPClose','Change RP')
    AND tblcallevents.actiontype_id IN (3, 4)
    AND (tblcallevents.approved_status = '1' OR tblcallevents.approved_status = '')
    AND (tblcallevents.delete_request = '' OR tblcallevents.delete_request IS NULL)
LEFT JOIN barginmeeting on barginmeeting.tid = tblcallevents.id
JOIN user_details ON user_details.user_id = tblcallevents.user_id
    AND user_details.status = 'active'
-- LEFT JOIN proposals — may or may not exist
LEFT JOIN proposal ON proposal.init_id = init_call.id AND DATE(proposal.sdatet) BETWEEN '$sdate' AND '$edate'
LEFT JOIN user_details u1 ON u1.user_id = proposal.user_id AND u1.status = 'active'
WHERE
    DATE(tblcallevents.appointmentdatetime) BETWEEN '$sdate' AND '$edate'
    AND (
        (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
        OR (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
        OR (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
        OR (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
    )
    AND $text");
        return $query->result();
    }
