            if($userwise =='userwise'){
                $text = "user_details.user_id = $userid";
            }else{
                $text = "(user_details.pst_co = $userid || user_details.user_id = $userid)";
            }
        }else if($type_id == 13){
            if($userwise =='userwise'){
                $text = "user_details.user_id = $userid";
            }else{
                $text = "(user_details.aadmin = $userid || user_details.user_id = $userid)"; 
            }
        }else if($type_id == 24){
            if($userwise =='userwise'){
                $text = "user_details.user_id = $userid";
            }else{
                $text = "(user_details.acm_co = $userid || user_details.user_id = $userid)"; 
            }
        }else{
             $text = "user_details.user_id = $userid";
        }
    }
    }
   
    
   
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    $start_financial_date   = '2026-04-01';
    $start_financial_date_year  = new DateTime($start_financial_date);
    $fyear                       = $start_financial_date_year->format('Y');
    $taskactionFilter       = "AND  tbcl.actiontype_id IN (3,4,17,22) AND tbcl.mtype IN ('RP', 'RPClose','Change RP') AND tbcl.nextCFID != 0 ";
    $approval_filter        = " AND (tbcl.approved_status = '1' OR tbcl.approved_status = '')";
    $groupbyFilter          = '';
    $userMainBDRolesFilter  = "AND (
    (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
    OR
    (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
    OR
    (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
    OR
    (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
    )";
$deleteRequest = "AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)";
$checkUserStatus = "AND user_details.status ='active'";
$taskDateFilter = " cast(tbcl.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'";
    if($mtypes == 'proposal_sent'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN (0, 1)';
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'proposal_not_sent'){
         $filter = "AND (proposal.id IS NULL OR proposal.apr = 2) AND NOT EXISTS (
                SELECT 1
                FROM proposal p
                WHERE p.init_id = init_call.id
                AND p.apr IN (0, 1)
                AND DATE(p.sdatet) BETWEEN '$sdate' AND '$edate'
            )";
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'bd_potentional_client_proposal_not_sent'){
         $filter = "AND (proposal.id IS NULL OR proposal.apr = 2) 
            AND barginmeeting.potentional_client = 'yes'
            AND NOT EXISTS (
                SELECT 1
                FROM proposal p
                WHERE p.init_id = init_call.id
                AND p.apr IN (0, 1)
                AND DATE(p.sdatet) BETWEEN '$sdate' AND '$edate'
            )";
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'proposal_sent_but_closure_not_done'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN(0,1) AND init_call.cstatus !=7';
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'proposal_sent_but_closure_done'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN(0,1) AND init_call.cstatus =7';
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }
    $query= $this->db->query("SELECT
     user_details.user_id as task_user_id,
     user_details.name as task_username,
     company_master.compname,
     company_master.id as cid,
    CONCAT_WS(' | ',
        CONCAT('<b>Name :</b>', ccm.contactperson),
        CONCAT('<b>Email : </b>', ccm.emailid),
        CONCAT('<b>Phone : </b>', ccm.phoneno),
        CONCAT('<b>Type : </b>', ccm.type)
    ) AS contact_details,
     tbcl.id as task_id,
     tbcl.nextCFID,
     tbcl.fwd_date,
     tbcl.appointmentdatetime,
     tbcl.actontaken,
     tbcl.purpose_achieved,
     tbcl.meeting_type,
     tbcl.actiontype_id,
     tbcl.assignedto_id,
     tbcl.cid_id,
     tbcl.remarks,
     tbcl.mom as mom_remarks,
     tbcl.mtype,
     tbcl.selectby,
     tbcl.filter_by,
     tbcl.approved_status as task_approved_status,
     tbcl.approved_by as task_approved_by,
     tbcl.assignedto_by as task_assignedto_by,
     tbcl.assignedto_by as task_aftertask,
     action.name as task_name,
     status.name as current_status,
     tbcl.plan_count as plan_count,
     barginmeeting.startm,
     barginmeeting.closem,
     barginmeeting.company_as,
     barginmeeting.company_descri,
     barginmeeting.status as meetings_status,
     barginmeeting.initphoto, 
     barginmeeting.potentional_client AS bd_potentional_client, 
     barginmeeting.cphoto,
     init_call.super_admin,
     init_call.potential,
     init_call.topspender,
     init_call.upsell_client,
     init_call.focus_funnel,
     init_call.keycompany,
     init_call.pkclient,
     init_call.priorityc,
     init_call.createDate as company_createDate,
     s1.name as meetings_time_status,
     init_call.q1_twetenty_closure_funnel,
     init_call.potential_funnel_for_fy,
     init_call.to_be_nurtured_for_fy,
     init_call.fifity_new_lead_funnel,
     u2.name as mainbd_name,
     partner_master.name as partner_name,
     proposal.id AS proposal_id,
     proposal.proattach AS proposal_attach,
     proposal.sdatet AS proposal_sdatet,
     proposal.apr AS proposal_apr,
     proposal.aprdatet AS proposal_aprdatet,
     proposal.remark AS proposal_remark,
     u3.name as super_admin_name
     
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN company_contact_master ccm ON ccm.company_id = company_master.id  AND ccm.type = 'primary'
LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
LEFT JOIN user_details u3 ON u3.user_id = init_call.super_admin
LEFT JOIN user_details u2 ON u2.user_id = init_call.mainbd
LEFT JOIN action ON action.id = tbcl.actiontype_id
LEFT JOIN status ON status.id = init_call.cstatus
LEFT JOIN status s1 ON s1.id = tbcl.status_id
LEFT JOIN proposal ON proposal.init_id = tbcl.cid_id  AND DATE(proposal.sdatet) BETWEEN '$sdate' AND '$edate'
WHERE
    $taskDateFilter
    $taskactionFilter
    $approval_filter
    $deleteRequest 
    $checkUserStatus
    $userMainBDRolesFilter
	AND $text $filter $groupbyFilter");
    return $query->result(); 
}






