public function getSaturdaysInCurrentQuarterAfter($afterDate) {
    $currentMonth = (int)date('n');
    $currentYear = (int)date('Y');
    $afterTimestamp = strtotime($afterDate);
    // Determine current quarter
    $quarter = ceil($currentMonth / 3);
    $startMonth = ($quarter - 1) * 3 + 1;
    $endMonth = $startMonth + 2;
    $saturdays = [];
    for ($month = $startMonth; $month <= $endMonth; $month++) {
        $firstDay = strtotime("$currentYear-$month-01");
        $lastDay = strtotime(date("Y-m-t", $firstDay));
        for ($day = $firstDay; $day <= $lastDay; $day = strtotime("+1 day", $day)) {
            if ($day > $afterTimestamp && date('N', $day) == 6) {
                $monthName = date('F', $day);
                $saturdays[$monthName][] = date('Y-m-d', $day);
            }
        }
    }
    return $saturdays;
}
function getSaturdaysInCurrentMonthAfterDate($afterDate) {
    $currentYear = (int)date('Y');
    $currentMonth = (int)date('n');
    $afterTimestamp = strtotime($afterDate);
    $saturdays = [];
    $firstDay = strtotime("$currentYear-$currentMonth-01");
    $lastDay = strtotime(date("Y-m-t", $firstDay)); // End of current month
    for ($day = $firstDay; $day <= $lastDay; $day = strtotime("+1 day", $day)) {
        if ($day > $afterTimestamp && date('N', $day) == 6) { // Saturday
            $monthName = date('F', $day);
            $saturdays[$monthName][] = date('Y-m-d', $day);
        }
    }
    return $saturdays;
}
public function getPendingReviewsByMonth($baseDate) {
    $baseTimestamp = strtotime($baseDate);
    $currentMonth = (int)date('n', $baseTimestamp);
    $currentYear = (int)date('Y', $baseTimestamp);
    // Calculate current quarter
    $quarter = ceil($currentMonth / 3);
    $startMonth = ($quarter - 1) * 3 + 1;
    $endMonth = $startMonth + 2;
    $result = [];
    for ($month = $startMonth; $month <= $endMonth; $month++) {
        $firstDay = strtotime("$currentYear-$month-01");
        $lastDay = strtotime(date("Y-m-t", $firstDay));
        $saturdays = [];
        // Collect all Saturdays of the month
        for ($day = $firstDay; $day <= $lastDay; $day = strtotime('+1 day', $day)) {
            if (date('N', $day) == 6) { // 6 = Saturday
                $saturdays[] = $day;
            }
        }
        $monthName = date('F', $firstDay);
        $result[$monthName] = [];
        // first_weekly
        if (isset($saturdays[0]) && $saturdays[0] > $baseTimestamp) {
            $result[$monthName]['first_weekly'] = date('Y-m-d', $saturdays[0]);
        }
        // second_weekly
        if (isset($saturdays[1]) && $saturdays[1] > $baseTimestamp) {
            $result[$monthName]['second_weekly'] = date('Y-m-d', $saturdays[1]);
        }
        // fortnightly = 3rd Saturday
        if (isset($saturdays[2]) && $saturdays[2] > $baseTimestamp) {
            $result[$monthName]['fortnightly'] = date('Y-m-d', $saturdays[2]);
        }
        // monthly = last Saturday
        if (!empty($saturdays)) {
            $lastSaturday = end($saturdays);
            if ($lastSaturday > $baseTimestamp) {
                $result[$monthName]['monthly'] = date('Y-m-d', $lastSaturday);
            }
        }
        // Clean month if all reviews were already completed
        if (empty($result[$monthName])) {
            unset($result[$monthName]);
        }
    }
    return $result;
}
public function getPendingReviewsByMonthFriday($baseDate) {
    $baseTimestamp = strtotime($baseDate);
    $currentMonth = (int)date('n', $baseTimestamp);
    $currentYear = (int)date('Y', $baseTimestamp);
    // Calculate current quarter
    $quarter = ceil($currentMonth / 3);
    $startMonth = ($quarter - 1) * 3 + 1;
    $endMonth = $startMonth + 2;
    $result = [];
    for ($month = $startMonth; $month <= $endMonth; $month++) {
        $firstDay = strtotime("$currentYear-$month-01");
        $lastDay = strtotime(date("Y-m-t", $firstDay));
        $fridays = [];
        // Collect all Fridays of the month
        for ($day = $firstDay; $day <= $lastDay; $day = strtotime('+1 day', $day)) {
            if (date('N', $day) == 5) { // 5 = Friday
                $fridays[] = $day;
            }
        }
        $monthName = date('F', $firstDay);
        $result[$monthName] = [];
        // first_weekly
        if (isset($fridays[0]) && $fridays[0] > $baseTimestamp) {
            $result[$monthName]['first_weekly'] = date('Y-m-d', $fridays[0]);
        }
        // second_weekly
        if (isset($fridays[1]) && $fridays[1] > $baseTimestamp) {
            $result[$monthName]['second_weekly'] = date('Y-m-d', $fridays[1]);
        }
        // fortnightly = 3rd Friday
        if (isset($fridays[2]) && $fridays[2] > $baseTimestamp) {
            $result[$monthName]['fortnightly'] = date('Y-m-d', $fridays[2]);
        }
        // monthly = last Friday
        if (!empty($fridays)) {
            $lastFriday = end($fridays);
            if ($lastFriday > $baseTimestamp) {
                $result[$monthName]['monthly'] = date('Y-m-d', $lastFriday);
            }
        }
        // Clean month if all reviews were already completed
        if (empty($result[$monthName])) {
            unset($result[$monthName]);
        }
    }
    return $result;
}
