public function getPreviousQuarterStartDate(): string {
    $currentMonth = date('n'); // Numeric representation of a month (1 to 12)
    $currentYear = date('Y');
    // Determine current quarter
    $currentQuarter = ceil($currentMonth / 3);
    // Calculate previous quarter and year
    if ($currentQuarter == 1) {
        $prevQuarter = 4;
        $year = $currentYear - 1;
    } else {
        $prevQuarter = $currentQuarter - 1;
        $year = $currentYear;
    }
    // Map quarter to start month
    $startMonth = ($prevQuarter - 1) * 3 + 1;
    // Format start date
    return date('Y-m-d', strtotime("$year-$startMonth-01"));
}
