public function GetTravelClusterCreatedByUserid($uid) {
    $this->db->select('
        cluster.*,
        ud.user_id,
        ud.name AS username,
        u1.name AS apr_by_user,
        cluster_mapping.id AS cluster_mapping_id,
        cluster_mapping.travel_type AS cluster_mapping_travel_type
    ');
    $this->db->from('cluster');
    $this->db->join('user_details ud', 'ud.user_id = cluster.add_by', 'left');
    $this->db->join('user_details u1', 'u1.user_id = cluster.apr_by', 'left');
