public function getPastQuarterStartDate($date = null) {
    // Use current date if not provided
    $timestamp = $date ? strtotime($date) : time();
    $month = date('n', $timestamp);
    $year = date('Y', $timestamp);
    $currentQuarter = ceil($month / 3);
    $pastQuarter = $currentQuarter - 1;
    if ($pastQuarter == 0) {
        $pastQuarter = 4;
        $year -= 1;
    }
    // Quarter start months: 1, 4, 7, 10
    $startMonth = (($pastQuarter - 1) * 3) + 1;
    return date('Y-m-d', strtotime("$year-$startMonth-01"));
}
function getDateRangeByFilter(string $filter): array {
    $currentYear = date('Y');
    $currentMonth = date('n');
    // Adjust FY if current month is Jan–Mar (belongs to previous FY)
    if ($currentMonth < 4) {
        $fyStartYear = $currentYear - 1;
    } else {
        $fyStartYear = $currentYear;
    }
    switch ($filter) {
        case 'FY':
            $start = "$fyStartYear-04-01";
            $end = ($fyStartYear + 1) . "-03-31";
            break;
        case 'Q1': // Apr–Jun
            $start = "$fyStartYear-04-01";
            $end = "$fyStartYear-06-30";
            break;
        case 'Q2': // Jul–Sep
            $start = "$fyStartYear-07-01";
            $end = "$fyStartYear-09-30";
            break;
        case 'Q3': // Oct–Dec
            $start = "$fyStartYear-10-01";
            $end = "$fyStartYear-12-31";
            break;
        case 'Q4': // Jan–Mar (next calendar year)
            $start = ($fyStartYear + 1) . "-01-01";
            $end = ($fyStartYear + 1) . "-03-31";
            break;
        default:
            $start = $end = null;
    }
    return ['start' => $start, 'end' => $end];
}
