                $text = "(acm_co = '$userid' || user_id = '$userid') AND type_id IN(3,24)";
            }else{
                $text = "admin_id = '$userid'";
            }
        $status = 'status = "active"';
        $query=$this->db->query("SELECT * FROM `user_details` WHERE $text AND $status ");
        return $query->result();
    }
    public function get_ttbytimed_category($uid, $tdate, $t1, $t2){
        $query = $this->db->query("SELECT 
            Count(Case When ic.upsell_client='yes' Then 1 End) AS upsell_client,
            Count(Case When ic.focus_funnel='yes' Then 1 End) AS focus_funnel,
            Count(Case When ic.keycompany='yes' Then 1 End) AS key_client,
            Count(Case When ic.pkclient='yes' Then 1 End) AS positive_key_client,
            Count(Case When ic.priorityc='yes' Then 1 End) AS priority_calling,
            Count(Case When ic.topspender='yes' Then 1 End) AS top_spender,
            Count(Case When ic.anchor_clients='yes' Then 1 End) AS anchor_clients,
            Count(Case When ic.in_quarter='yes' Then 1 End) AS in_quarter
            FROM tblcallevents 
            LEFT JOIN init_call ic ON ic.id = tblcallevents.cid_id 
            LEFT JOIN company_master cm ON cm.id = ic.cmpid_id 
            LEFT JOIN partner_master ON partner_master.id = cm.partnerType_id 
            WHERE 
                tblcallevents.user_id = '$uid' 
                AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate' 
                AND tblcallevents.plan = 1 
                AND tblcallevents.autotask = 0 
                AND CAST(tblcallevents.appointmentdatetime AS TIME) BETWEEN '$t1' AND '$t2' 
        ");
        $result = $query->row_array();
        // Filter out keys with 0 values
        $filtered = array_filter($result, function($value) {
            return $value > 0;
        });
        return $filtered;
    }
