public function TotalMeetingProposalDetailsDatasonPlanner($userid,$mtypes){
    
  
         $udetail = $this->Menu_model->get_userbyid($userid); 
        $utid = $udetail[0]->type_id;
    
            if($utid == 4){
                $text = "init_call.apst = '$userid'";
            }elseif($utid == 19){
                $text = "init_call.ash_nae_co_id = '$userid'";
            }elseif($utid == 20){
                $text = "init_call.ash_w_co_id = '$userid'";
            }elseif($utid == 21){
                $text = "init_call.ash_s_co_id = '$userid'";
            }elseif($utid == 22){
                $text = "init_call.rm_east_co_id = '$userid'";
            }elseif($utid == 23){
                $text = "init_call.rm_north_co_id = '$userid'";
            }elseif($utid == 24){
                $text = "(init_call.mainbd = '$userid' OR init_call.acm_co_id = '$userid')";
            }elseif($utid == 3){
                $text = "init_call.mainbd = '$userid'";
            }elseif($utid == 13){
                $text = "(init_call.mainbd = '$userid' OR init_call.clm_id = '$userid')";
            }elseif($utid == 1){
                $text = "(init_call.super_admin = '$userid')";
            }else{
                $text = "init_call.mainbd = '$userid'";
            }
   
    $curFinancialDate       = $this->Menu_model->getFinancialYearRange();
    $start_financial_date   = $curFinancialDate['start_date'];
    $end_financial_date     = $curFinancialDate['end_date'];
    $start_financial_date   = '2026-04-01';
    $start_financial_date_year  = new DateTime($start_financial_date);
    $fyear                       = $start_financial_date_year->format('Y');
    $taskactionFilter       = "  tbcl.actiontype_id IN (3,4,17,22) AND tbcl.mtype IN ('RP', 'RPClose','Change RP') AND tbcl.nextCFID != 0 ";
    $approval_filter        = " AND (tbcl.approved_status = '1' OR tbcl.approved_status = '')";
    $groupbyFilter          = '';
    $userMainBDRolesFilter  = "AND (
    (user_details.type_id = 3 AND init_call.mainbd = user_details.user_id)
    OR
    (user_details.type_id = 13 AND (init_call.mainbd = user_details.user_id OR init_call.clm_id = user_details.user_id))
    OR
    (user_details.type_id = 4 AND init_call.apst = user_details.user_id)
    OR
    (user_details.type_id = 24 AND (init_call.mainbd = user_details.user_id OR init_call.acm_co_id = user_details.user_id))
    )";
$deleteRequest = "AND (tbcl.delete_request = '' OR tbcl.delete_request IS NULL)";
$checkUserStatus = "AND user_details.status ='active'";
// $taskDateFilter = " cast(tbcl.appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'";
$taskDateFilter = " ";
    if($mtypes == 'proposal_sent'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN (0, 1)';
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'proposal_not_sent'){
         $filter = "AND (proposal.id IS NULL OR proposal.apr = 2) AND NOT EXISTS (
                SELECT 1
                FROM proposal p
                WHERE p.init_id = init_call.id
                AND p.apr IN (0, 1)
            )";
        $groupbyFilter          = 'GROUP BY tbcl.cid_id';
    }else if($mtypes == 'bd_potentional_client_proposal_not_sent'){
         $filter = "AND (proposal.id IS NULL OR proposal.apr = 2) 
            AND barginmeeting.potentional_client = 'yes'
            AND NOT EXISTS (
                SELECT 1
                FROM proposal p
                WHERE p.init_id = init_call.id
                AND p.apr IN (0, 1)
            )";
    }else if($mtypes == 'proposal_sent_but_closure_not_done'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN(0,1) AND init_call.cstatus !=7';
    }else if($mtypes == 'proposal_sent_but_closure_done'){
        $filter = 'AND proposal.id IS NOT NULL AND proposal.apr IN(0,1) AND init_call.cstatus =7';
    }else if($mtypes == 'meetings_on_company'){
       $filter = ' AND tbcl.nextCFID != 0 AND (tbcl.mtype = "RP" || tbcl.mtype = "RPClose" || tbcl.mtype = "Change RP")';
    }
    $groupbyFilter          = 'GROUP BY init_call.id';
    $query= $this->db->query("SELECT
     company_master.compname,
     company_master.id as cid,
     status.name as current_status,
     s1.name as meetings_time_status,
     init_call.id as init_id,
     init_call.q1_twetenty_closure_funnel,
     init_call.potential_funnel_for_fy,
     init_call.to_be_nurtured_for_fy,
     init_call.fifity_new_lead_funnel,
     u3.name as super_admin_name
     
FROM
    tblcallevents AS tbcl
LEFT JOIN barginmeeting ON barginmeeting.tid = tbcl.id
LEFT JOIN init_call ON init_call.id = tbcl.cid_id
LEFT JOIN company_master ON company_master.id = init_call.cmpid_id
LEFT JOIN partner_master ON partner_master.id = company_master.partnerType_id
LEFT JOIN user_details ON user_details.user_id = tbcl.user_id
LEFT JOIN user_details u3 ON u3.user_id = init_call.super_admin
LEFT JOIN user_details u2 ON u2.user_id = init_call.mainbd
LEFT JOIN action ON action.id = tbcl.actiontype_id
LEFT JOIN status ON status.id = init_call.cstatus
LEFT JOIN status s1 ON s1.id = tbcl.status_id
LEFT JOIN proposal ON proposal.init_id = tbcl.cid_id  
WHERE
    $taskDateFilter
    $taskactionFilter
    $approval_filter
    $deleteRequest 
    $checkUserStatus
    $userMainBDRolesFilter
	AND $text $filter $groupbyFilter");
    return $query->result(); 
}
public function GetFreeTimeSlotByUser($uid,$adate,$startTime,$endTime,$task=''){
    if($task ==''){
        $task = '';
    }else{
        $task = " AND a.id = $task";
    }
    $query= $this->db->query("SELECT 
    a.id,
    a.name,
    ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) AS slot_time,
    CASE 
        WHEN t.id IS NULL THEN 'Available'
        ELSE 'Booked'
    END AS status
FROM 
    (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9
        UNION ALL SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14
        UNION ALL SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19
        UNION ALL SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24
        UNION ALL SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29
        UNION ALL SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34
        UNION ALL SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39
        UNION ALL SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44
        UNION ALL SELECT 45 UNION ALL SELECT 46 UNION ALL SELECT 47 UNION ALL SELECT 48 UNION ALL SELECT 49
        UNION ALL SELECT 50 UNION ALL SELECT 51 UNION ALL SELECT 52 UNION ALL SELECT 53 UNION ALL SELECT 54
        UNION ALL SELECT 55 UNION ALL SELECT 56 UNION ALL SELECT 57 UNION ALL SELECT 58 UNION ALL SELECT 59
        UNION ALL SELECT 60 UNION ALL SELECT 61 UNION ALL SELECT 62 UNION ALL SELECT 63 UNION ALL SELECT 64
        UNION ALL SELECT 65 UNION ALL SELECT 66 UNION ALL SELECT 67 UNION ALL SELECT 68 UNION ALL SELECT 69
        UNION ALL SELECT 70 UNION ALL SELECT 71 UNION ALL SELECT 72
    ) n
JOIN action a ON a.action_status = 1
LEFT JOIN tblcallevents t 
    ON DATE(t.appointmentdatetime) = '$adate'
    AND TIME(t.appointmentdatetime) = ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60))
    AND t.user_id = '$uid'
WHERE 
    ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) <= '$endTime'
    $task
ORDER BY 
    a.id, slot_time");
    return $query->result(); 
}
public function GetFreeTimeSlotByUserIDTaskID($uid,$adate,$startTime,$endTime,$task=''){
    $query= $this->db->query("SELECT
    base.action_id,
    base.action_name,
    base.slot_time,
    base.booked_for_task,
    base.status,
    CASE
        WHEN base.status = 'Booked' THEN 0
        ELSE COUNT(next.slot_time)
    END AS task
FROM (
    SELECT
        a.id AS action_id,
        a.name AS action_name,
        n.n,
        a.yest,
        DATE_FORMAT(ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)), '%H:%i') AS slot_time,
        (
            SELECT a2.name
            FROM tblcallevents t
            JOIN action a2 ON a2.id = t.actiontype_id
            WHERE
                t.user_id = $uid
                AND DATE(t.appointmentdatetime) = '$adate'
                AND ADDTIME('$adate $startTime', SEC_TO_TIME(n.n * a.yest * 60)) < ADDTIME(t.appointmentdatetime, SEC_TO_TIME(a2.yest * 60))
                AND ADDTIME('$adate $startTime', SEC_TO_TIME((n.n + 1) * a.yest * 60)) > t.appointmentdatetime
            LIMIT 1
        ) AS booked_for_task,
        CASE
            WHEN EXISTS (
                SELECT 1
                FROM tblcallevents t
                JOIN action a2 ON a2.id = t.actiontype_id
                WHERE
                    t.user_id = $uid
                    AND DATE(t.appointmentdatetime) = '$adate'
                    AND ADDTIME('$adate $startTime', SEC_TO_TIME(n.n * a.yest * 60)) < ADDTIME(t.appointmentdatetime, SEC_TO_TIME(a2.yest * 60))
                    AND ADDTIME('$adate $startTime', SEC_TO_TIME((n.n + 1) * a.yest * 60)) > t.appointmentdatetime
            ) THEN 'Booked'
            ELSE 'Available'
        END AS status
    FROM (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL
            SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL
            SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14 UNION ALL
            SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19 UNION ALL
            SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24 UNION ALL
            SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29 UNION ALL
            SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34 UNION ALL
            SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39 UNION ALL
            SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44 UNION ALL
            SELECT 45 UNION ALL SELECT 46 UNION ALL SELECT 47 UNION ALL SELECT 48 UNION ALL SELECT 49 UNION ALL
            SELECT 50 UNION ALL SELECT 51 UNION ALL SELECT 52 UNION ALL SELECT 53 UNION ALL SELECT 54 UNION ALL
            SELECT 55 UNION ALL SELECT 56 UNION ALL SELECT 57 UNION ALL SELECT 58 UNION ALL SELECT 59 UNION ALL
            SELECT 60 UNION ALL SELECT 61 UNION ALL SELECT 62 UNION ALL SELECT 63 UNION ALL SELECT 64 UNION ALL
            SELECT 65 UNION ALL SELECT 66 UNION ALL SELECT 67 UNION ALL SELECT 68 UNION ALL SELECT 69 UNION ALL
            SELECT 70 UNION ALL SELECT 71 UNION ALL SELECT 72
    ) n
    JOIN action a ON a.id = $task AND a.action_status = 1
    WHERE ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) >= '$startTime'
      AND ADDTIME('$startTime', SEC_TO_TIME((n.n + 1) * a.yest * 60)) <= '$endTime'
) base
LEFT JOIN (
    SELECT
        a.id AS action_id,
        n.n,
        a.yest,
        DATE_FORMAT(ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)), '%H:%i') AS slot_time,
        CASE
            WHEN EXISTS (
                SELECT 1
                FROM tblcallevents t
                JOIN action a2 ON a2.id = t.actiontype_id
                WHERE
                    t.user_id = $uid
                    AND DATE(t.appointmentdatetime) = '$adate'
                    AND ADDTIME('$adate $startTime', SEC_TO_TIME(n.n * a.yest * 60)) < ADDTIME(t.appointmentdatetime, SEC_TO_TIME(a2.yest * 60))
                    AND ADDTIME('$adate $startTime', SEC_TO_TIME((n.n + 1) * a.yest * 60)) > t.appointmentdatetime
            ) THEN 'Booked'
            ELSE 'Available'
        END AS status
    FROM (
       SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL
            SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL
            SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14 UNION ALL
            SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19 UNION ALL
            SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24 UNION ALL
            SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29 UNION ALL
            SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34 UNION ALL
            SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39 UNION ALL
            SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44 UNION ALL
            SELECT 45 UNION ALL SELECT 46 UNION ALL SELECT 47 UNION ALL SELECT 48 UNION ALL SELECT 49 UNION ALL
            SELECT 50 UNION ALL SELECT 51 UNION ALL SELECT 52 UNION ALL SELECT 53 UNION ALL SELECT 54 UNION ALL
            SELECT 55 UNION ALL SELECT 56 UNION ALL SELECT 57 UNION ALL SELECT 58 UNION ALL SELECT 59 UNION ALL
            SELECT 60 UNION ALL SELECT 61 UNION ALL SELECT 62 UNION ALL SELECT 63 UNION ALL SELECT 64 UNION ALL
            SELECT 65 UNION ALL SELECT 66 UNION ALL SELECT 67 UNION ALL SELECT 68 UNION ALL SELECT 69 UNION ALL
            SELECT 70 UNION ALL SELECT 71 UNION ALL SELECT 72
    ) n
    JOIN action a ON a.id = $task AND a.action_status = 1
    WHERE ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) >= '$startTime'
      AND ADDTIME('$startTime', SEC_TO_TIME((n.n + 1) * a.yest * 60)) <= '$endTime'
) next
  ON next.n >= base.n
 AND next.status = 'Available'
 AND NOT EXISTS (
    SELECT 1
    FROM (
        SELECT b.n,
               CASE
                 WHEN EXISTS (
                     SELECT 1
                     FROM tblcallevents t
                     JOIN action a4 ON a4.id = t.actiontype_id
                     WHERE
                         t.user_id = $uid
                         AND DATE(t.appointmentdatetime) = '$adate'
                         AND ADDTIME('$adate $startTime', SEC_TO_TIME(b.n * a3.yest * 60)) < ADDTIME(t.appointmentdatetime, SEC_TO_TIME(a4.yest * 60))
                         AND ADDTIME('$adate $startTime', SEC_TO_TIME((b.n + 1) * a3.yest * 60)) > t.appointmentdatetime
                 ) THEN 'Booked'
                 ELSE 'Available'
               END AS status
        FROM (
            SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 UNION ALL
            SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9 UNION ALL
            SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14 UNION ALL
            SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19 UNION ALL
            SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24 UNION ALL
            SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29 UNION ALL
            SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34 UNION ALL
            SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39 UNION ALL
            SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44 UNION ALL
            SELECT 45 UNION ALL SELECT 46 UNION ALL SELECT 47 UNION ALL SELECT 48 UNION ALL SELECT 49 UNION ALL
            SELECT 50 UNION ALL SELECT 51 UNION ALL SELECT 52 UNION ALL SELECT 53 UNION ALL SELECT 54 UNION ALL
            SELECT 55 UNION ALL SELECT 56 UNION ALL SELECT 57 UNION ALL SELECT 58 UNION ALL SELECT 59 UNION ALL
            SELECT 60 UNION ALL SELECT 61 UNION ALL SELECT 62 UNION ALL SELECT 63 UNION ALL SELECT 64 UNION ALL
            SELECT 65 UNION ALL SELECT 66 UNION ALL SELECT 67 UNION ALL SELECT 68 UNION ALL SELECT 69 UNION ALL
            SELECT 70 UNION ALL SELECT 71 UNION ALL SELECT 72
        ) b
        JOIN action a3 ON a3.id = $task
    ) booked_gap
    WHERE booked_gap.n > base.n AND booked_gap.n < next.n
      AND booked_gap.status = 'Booked'
)
GROUP BY base.action_id, base.action_name, base.slot_time, base.booked_for_task, base.status
ORDER BY base.slot_time");
    return $query->result(); 
}
public function GetFreeTimeSlotByUserID($uid,$adate,$startTime,$endTime,$task=''){
    if($task ==''){
        $task = '';
    }else{
        $task = " AND a.id = $task";
    }
    $query= $this->db->query("SELECT 
    base.id,
    base.name,
    base.slot_time,
    (
        SELECT a2.name
        FROM tblcallevents t
        JOIN action a2 ON a2.id = t.actiontype_id
        WHERE 
            t.user_id = '$uid'
            AND DATE(t.appointmentdatetime) = '$adate'
            AND TIME(base.slot_time) >= TIME(t.appointmentdatetime)
            AND TIME(base.slot_time) < ADDTIME(TIME(t.appointmentdatetime), SEC_TO_TIME(a2.yest * 60))
        LIMIT 1
    ) AS booked_for_task,
    CASE 
        WHEN EXISTS (
            SELECT 1
            FROM tblcallevents t
            JOIN action a2 ON a2.id = t.actiontype_id
            WHERE 
                t.user_id = '$uid'
                AND DATE(t.appointmentdatetime) = '$adate'
                AND TIME(base.slot_time) >= TIME(t.appointmentdatetime)
                AND TIME(base.slot_time) < ADDTIME(TIME(t.appointmentdatetime), SEC_TO_TIME(a2.yest * 60))
        ) THEN 'Booked'
        ELSE 'Available'
    END AS status
FROM (
    SELECT 
        a.id,
        a.name,
        -- ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) AS slot_time
        DATE_FORMAT(ADDTIME('10:00:00', SEC_TO_TIME(n.n * a.yest * 60)), '%H:%i') AS slot_time
    FROM (
        SELECT 0 AS n UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4
        UNION ALL SELECT 5 UNION ALL SELECT 6 UNION ALL SELECT 7 UNION ALL SELECT 8 UNION ALL SELECT 9
        UNION ALL SELECT 10 UNION ALL SELECT 11 UNION ALL SELECT 12 UNION ALL SELECT 13 UNION ALL SELECT 14
        UNION ALL SELECT 15 UNION ALL SELECT 16 UNION ALL SELECT 17 UNION ALL SELECT 18 UNION ALL SELECT 19
        UNION ALL SELECT 20 UNION ALL SELECT 21 UNION ALL SELECT 22 UNION ALL SELECT 23 UNION ALL SELECT 24
        UNION ALL SELECT 25 UNION ALL SELECT 26 UNION ALL SELECT 27 UNION ALL SELECT 28 UNION ALL SELECT 29
        UNION ALL SELECT 30 UNION ALL SELECT 31 UNION ALL SELECT 32 UNION ALL SELECT 33 UNION ALL SELECT 34
        UNION ALL SELECT 35 UNION ALL SELECT 36 UNION ALL SELECT 37 UNION ALL SELECT 38 UNION ALL SELECT 39
        UNION ALL SELECT 40 UNION ALL SELECT 41 UNION ALL SELECT 42 UNION ALL SELECT 43 UNION ALL SELECT 44
        UNION ALL SELECT 45 UNION ALL SELECT 46 UNION ALL SELECT 47 UNION ALL SELECT 48 UNION ALL SELECT 49
        UNION ALL SELECT 50 UNION ALL SELECT 51 UNION ALL SELECT 52 UNION ALL SELECT 53 UNION ALL SELECT 54
        UNION ALL SELECT 55 UNION ALL SELECT 56 UNION ALL SELECT 57 UNION ALL SELECT 58 UNION ALL SELECT 59
        UNION ALL SELECT 60 UNION ALL SELECT 61 UNION ALL SELECT 62 UNION ALL SELECT 63 UNION ALL SELECT 64
        UNION ALL SELECT 65 UNION ALL SELECT 66 UNION ALL SELECT 67 UNION ALL SELECT 68 UNION ALL SELECT 69
        UNION ALL SELECT 70 UNION ALL SELECT 71 UNION ALL SELECT 72
    ) n
    JOIN action a ON a.action_status = 1
    WHERE 
        ADDTIME('$startTime', SEC_TO_TIME(n.n * a.yest * 60)) <= '$endTime' 
     $task
) base
ORDER BY 
    base.slot_time, base.id");
    return $query->result(); 
}
public function GetOurSelfAssignRequestByUser($uid,$date){
    $query = $this->db->query("SELECT
        tblcallevents.id as task_id,
        tblcallevents.approved_status,
        u1.name as self_assign_request_by,
        cm.id as cid,
        cm.compname,
        action.name as task_name
    FROM
        tblcallevents
        LEFT JOIN user_details u1 on u1.user_id = tblcallevents.approved_by
