public function GetTeamRejectedTaskButNotAssign($uid,$date){
    $query = $this->db->query("SELECT
            tblcallevents.id as task_id,
            tblcallevents.approved_status,
            u1.name as self_assign_request_by,
            u2.name as task_planned_by,
            cm.id as cid,
            cm.compname,
            action.name as task_name
        FROM
            tblcallevents
            LEFT JOIN user_details u1 on u1.user_id = tblcallevents.approved_by
            LEFT JOIN action on action.id = tblcallevents.actiontype_id
            LEFT JOIN user_details u2 on u2.user_id = tblcallevents.user_id
            LEFT JOIN init_call on init_call.id = tblcallevents.cid_id
            LEFT JOIN company_master cm on cm.id = init_call.cmpid_id
            
        WHERE
            tblcallevents.approved_by = '$uid' 
            AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$date'
            AND tblcallevents.approved_status = 0 AND TRIM(self_assign) = ''");
        $notAssignAfterReject =  $query->result();
    $notAssignAfterRejectCount = count($notAssignAfterReject);
 
    if($notAssignAfterRejectCount > 0){
        
        $plannedByCount = [];
        foreach ($notAssignAfterReject as $task) {
            $name = $task->task_planned_by;
            if (!isset($plannedByCount[$name])) {
                $plannedByCount[$name] = 0;
            }
            $plannedByCount[$name]++;
        }
        // Format as "Name (count)"
        $formatted = [];
        foreach ($plannedByCount as $name => $count) {
            $formatted[] = "$name ($count)";
        }
        $notAssignAfterRejectCounttext = implode(' | ', $formatted);
        $rejectassignMessage = " * You have rejected $notAssignAfterRejectCounttext task(s). Please assign a new task yourself or create a request for BD to assign one. Unassigned tasks may impact your performance tracking.";
        $this->load->library('session');
        $this->session->set_flashdata('error_message',$rejectassignMessage);
        redirect('Menu/PlannerTaskApprovelPageTestData');
            
    }
    }
    public function getCurrentUrl() {
        $protocol = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off') ? "https://" : "http://";
        $host     = $_SERVER['HTTP_HOST'];
        $uri      = $_SERVER['REQUEST_URI'];
        return $protocol . $host . $uri;
    }
