    public function CheckOwnFunnelTaskAndTeamFunnelTask($uid,$tdate){
            $query = $this->db->query("SELECT 
            Count(Case When tblcallevents.actiontype_id != '' Then 1 End) AS total_task,
            Count(Case When init_call.mainbd = '$uid' Then 1 End) AS own_funnel_task,
            Count(Case When init_call.mainbd != '$uid' Then 1 End) AS team_funnel_task
        FROM 
            tblcallevents
        LEFT JOIN init_call ON init_call.id = tblcallevents.cid_id
        WHERE 
            (tblcallevents.user_id = '$uid' OR tblcallevents.assignedto_id = '$uid')
            AND CAST(tblcallevents.appointmentdatetime AS DATE) = '$tdate'
            AND tblcallevents.plan = 1
            AND tblcallevents.autotask = 0
        ORDER BY 
            tblcallevents.appointmentdatetime
        ");
        return $query->result();
    }
    public function CheckYesterDayPlannerSetOrNot($uid,$tdate){
        $query=$this->db->query("SELECT
    -- COUNT(tce.id) AS total,
    COUNT(CASE WHEN tce.nextCFID = 0 THEN tce.id END) AS total,
    COUNT(CASE WHEN tce.nextCFID = 0 THEN tce.id END) AS pending,
    COUNT(CASE WHEN tce.nextCFID != 0 THEN tce.id END) AS complete,
    MAX(tce.updateddate) AS last_task_update,
    (
        SELECT t1.actiontype_id
        FROM tblcallevents t1
        WHERE 
            t1.user_id = '$uid'
            AND DATE(t1.updateddate) = (
                SELECT MAX(DATE(updateddate))
                FROM tblcallevents
                WHERE 
                    user_id = '$uid'
                    AND DATE(updateddate) < CURDATE()
                    AND (approved_status = 1 OR approved_status = '')
            )
            AND (t1.approved_status = 1 OR t1.approved_status = '')
            AND (t1.delete_request = '' OR t1.delete_request IS NULL)
            AND t1.nextCFID !=0
            AND t1.updateddate < CURDATE()
        ORDER BY t1.updateddate DESC
        LIMIT 1
    ) AS last_actiontype_id,
    CASE 
        WHEN COUNT(CASE WHEN tce.nextCFID = 0 THEN tce.id END) = 0 THEN 'Yes'
        ELSE 'No'
    END AS achieve,
    aut.id AS aut_id
    -- aut.date AS aut_date (uncomment if needed)
FROM
    tblcallevents tce
    LEFT JOIN user_details u1 ON u1.user_id = tce.user_id
    LEFT JOIN (
        SELECT user_id, id, date, created_at
        FROM autotask_time
    ) aut ON aut.user_id = tce.user_id 
        AND DATE(aut.created_at) = (
            SELECT Date(MAX(updateddate))
            FROM tblcallevents
            WHERE 
                user_id = '$uid'
                AND DATE(updateddate) < CURDATE()
                AND (approved_status = 1 OR approved_status = '')
            	AND nextCFID != 0 
        )
        AND aut.date = '$tdate'
WHERE
    tce.user_id = '$uid'
    AND DATE(tce.appointmentdatetime) = (
        SELECT MAX(DATE(updateddate))
        FROM tblcallevents
        WHERE 
            user_id = '$uid'
            AND DATE(updateddate) < CURDATE()
            AND (approved_status = 1 OR approved_status = '')
    )
    AND ((tce.approved_status = 1 OR tce.approved_status = '') 
    AND (tce.delete_request = '' OR tce.delete_request IS NULL))
    AND tce.appointmentdatetime < CURDATE()
    AND tce.appointmentdatetime < CURDATE()
    -- AND tce.autotask = 0
GROUP BY u1.user_id");
        return $query->result();
    }



