public function CheckTodaysPlannerTaskStatus($uid, $tdate){
    $start = $tdate . ' 00:00:00';
    $end   = $tdate . ' 23:59:59';

    $query = $this->db->query("
        SELECT
            COUNT(id) AS total,
            COUNT(CASE WHEN nextCFID = 0 THEN id END) AS pending,
            COUNT(CASE WHEN nextCFID != 0 THEN id END) AS complete,
            MAX(CASE 
                    WHEN nextCFID != 0 AND appointmentdatetime BETWEEN '$start' AND '$end'
                    THEN updateddate 
                END) AS last_task_update,
            (
                SELECT actiontype_id
                FROM tblcallevents t2
                WHERE
                    t2.user_id = '$uid'
                    AND ((t2.approved_status = 1 OR t2.approved_status = '') 
                        AND (t2.delete_request IS NULL OR t2.delete_request = ''))
                    AND t2.appointmentdatetime BETWEEN '$start' AND '$end'
                    AND t2.nextCFID != 0
                ORDER BY t2.updateddate DESC
                LIMIT 1
            ) AS last_updated_actiontype_id
        FROM
            tblcallevents
        WHERE
            user_id = '$uid'
            AND ((approved_status = 1 OR approved_status = '') 
                AND (delete_request IS NULL OR delete_request = ''))
            AND appointmentdatetime BETWEEN '$start' AND '$end'
    ");
    return $query->result();
}







