    CONCAT(s1.id, '_', s2.id) AS status_change_id
FROM
    tblcallevents
    LEFT JOIN init_call ON init_call.id = tblcallevents.	cid_id
    LEFT JOIN user_details u1 ON u1.user_id = tblcallevents.user_id
    LEFT JOIN status s1 ON s1.id = tblcallevents.status_id
    LEFT JOIN status s2 ON s2.id = tblcallevents.nstatus_id
WHERE 
    status_id != nstatus_id 
    AND CAST(appointmentdatetime AS DATE) BETWEEN '$sdate' AND '$edate'
    AND nextCFID != 0 
    AND nstatus_id IS NOT NULL 
    AND nstatus_id != 0
    AND init_call.cmpid_id = '$cid'
GROUP BY CONCAT(s1.name, ' → ', s2.name)
ORDER BY tblcallevents.appointmentdatetime ASC ");
    return $query->result();
}
