public function findSpecialDate($currentDate = null) {
    // If no date is given, use today
    $currentDate = $currentDate ? new DateTime($currentDate) : new DateTime();
    // Get previous date
    $prevDate = clone $currentDate;
    $prevDate->modify('-1 day');
    $dayOfWeek = $prevDate->format('w'); // 0 = Sunday, 1 = Monday, ..., 6 = Saturday
    // Case 1: Previous date is Sunday
    if ($dayOfWeek == 0) {
        $dayOfMonth = (int)$prevDate->format('j');
        $weekOfMonth = ceil($dayOfMonth / 7);
        if ($weekOfMonth == 2 || $weekOfMonth == 4) {
            // 2nd or 4th Sunday → return that Friday
            $friday = clone $prevDate;
            $friday->modify('-2 days'); // Friday before Sunday
            return $friday->format('Y-m-d');
        } else {
            // Sunday but not 2nd or 4th → return Saturday
            $saturday = clone $prevDate;
            $saturday->modify('-1 day');
            return $saturday->format('Y-m-d');
        }
    } else {
        // Case 2: Previous date is not Sunday → return yesterday
        return $prevDate->format('Y-m-d');
    }
}







public function findNextSpecialDate_bkp($currentDate = null) {
    // If no date is given, use today
    $currentDate = $currentDate ? new DateTime($currentDate) : new DateTime();

    // Get next date
    $nextDate = clone $currentDate;
    $nextDate->modify('+1 day'); // move forward

    $dayOfWeek = $nextDate->format('w'); // 0 = Sunday, 1 = Monday, ..., 6 = Saturday

    // Case 1: Next date is Saturday
    if ($dayOfWeek == 6) {
        $dayOfMonth = (int)$nextDate->format('j');
        $weekOfMonth = ceil($dayOfMonth / 7);

        if ($weekOfMonth == 2 || $weekOfMonth == 4) {
            // 2nd or 4th Saturday → +2 days (Monday)
            $result = clone $nextDate;
            $result->modify('+2 days');
            return $result->format('Y-m-d');
        } elseif ($weekOfMonth == 1 || $weekOfMonth == 3) {
            // 1st or 3rd Saturday → +1 day (Sunday)
            $result = clone $nextDate;
            $result->modify('+1 day');
            return $result->format('Y-m-d');
        }
    }

    // Case 2: Any other day → just +1 day
    return $nextDate->format('Y-m-d');
}


public function findNextSpecialDate($currentDate = null) {
  
    // If no date is given, use today
    $currentDate = $currentDate ? new DateTime($currentDate) : new DateTime();

    // Get next date
    $nextDate = clone $currentDate;
    $nextDate->modify('+1 day'); // move forward

    $dayOfWeek = $nextDate->format('w'); // 0 = Sunday, 1 = Monday, ..., 6 = Saturday

    // Case 1: Next date is Saturday
    if ($dayOfWeek == 6) {
        $dayOfMonth = (int)$nextDate->format('j');
        $weekOfMonth = ceil($dayOfMonth / 7);

        if ($weekOfMonth == 2 || $weekOfMonth == 4) {
            // 2nd or 4th Saturday → +2 days (Monday)
            $result = clone $nextDate;
            $result->modify('+2 days');
        } elseif ($weekOfMonth == 1 || $weekOfMonth == 3) {
            // 1st or 3rd Saturday → +1 day (Sunday)
            $result = clone $nextDate;
            $result->modify('+1 day');
        } else {
            $result = clone $nextDate;
        }
    } else {
        // Case 2: Any other day → just +1 day
        $result = clone $nextDate;
    
    }

    // ✅ Skip Sundays — move to Monday
    if ($result->format('w') == 0) {
        $result->modify('+1 day');
    }

    return $result->format('Y-m-d');
}


