            LPAD(MOD(TIMESTAMPDIFF(HOUR, allreview.plant, NOW()), 24), 2, '0'), ' hours ',
            LPAD(MOD(TIMESTAMPDIFF(MINUTE, allreview.plant, NOW()), 60), 2, '0'), ' minutes ',
            LPAD(MOD(TIMESTAMPDIFF(SECOND, allreview.plant, NOW()), 60), 2, '0'), ' seconds'
        )
        ELSE NULL
    END AS plan_and_start_and_not_close_till_date,
    CASE 
        WHEN allreview.startt IS NULL 
             AND allreview.closet IS NULL
        THEN CONCAT(
            TIMESTAMPDIFF(DAY, allreview.plant, NOW()), ' days ',
            LPAD(MOD(TIMESTAMPDIFF(HOUR, allreview.plant, NOW()), 24), 2, '0'), ' hours ',
            LPAD(MOD(TIMESTAMPDIFF(MINUTE, allreview.plant, NOW()), 60), 2, '0'), ' minutes ',
            LPAD(MOD(TIMESTAMPDIFF(SECOND, allreview.plant, NOW()), 60), 2, '0'), ' seconds'
        )
        ELSE NULL
    END AS plan_and_not_start_till_date
FROM
    `allreview`
    LEFT JOIN user_details u1 ON u1.user_id = allreview.uid
    LEFT JOIN user_details u2 ON u2.user_id = allreview.bdid
    LEFT JOIN user_type ON user_type.id = u1.type_id
WHERE
    $text
    AND allreview.closet IS NULL
AND cast(allreview.plant AS Date) <= CURRENT_DATE() ORDER BY allreview.startt DESC ");
    return $query->result();
}
