public function add_bdHandover_New($filtereNewSchoolData,$filtereOldSchoolData,$bdid, $client_name, $mediator, $noofschool, $location, $city, $state, $spd_identify_by, $infrastructure, $filname, $count, $contact_person, $cp_mno, $acontact_person, $acp_mno, $language, $expected_installation_date, $project_tenure, $project_type, $comments, $sid, $remark, $fttptype,$company_id) {
    
    // Handle file uploads
    $flink = "";
    if ($count > 0) {
        $uploadPath = 'uploads/logo/';
        $this->load->library('upload');
        
        for ($i = 0; $i < $count; $i++) {
            $_FILES['file']['name']     = $_FILES['filname']['name'][$i];
            $_FILES['file']['type']     = $_FILES['filname']['type'][$i];
            $_FILES['file']['tmp_name'] = $_FILES['filname']['tmp_name'][$i];
            $_FILES['file']['error']    = $_FILES['filname']['error'][$i];
            $_FILES['file']['size']     = $_FILES['filname']['size'][$i];

            $config['upload_path']   = $uploadPath;
            $config['allowed_types'] = '*';
            $config['file_name']     = $_FILES['file']['name'];

            $this->upload->initialize($config);
            if ($this->upload->do_upload('file')) {
                $uploadData = $this->upload->data();
                $filename = $uploadData['file_name'];
                $flink .= ($i == 0) ? $uploadPath . $filename : ',' . $uploadPath . $filename;
            }
        }
    }

    // Calculate Financial Year
    $currentMonth = date('n');
    $currentYear  = date('Y');
    $financialYearStart = ($currentMonth < 4) ? ($currentYear - 1) : $currentYear;
    $financialYearEnd   = ($currentMonth < 4) ? $currentYear : ($currentYear + 1);
    $financialYear      = $financialYearStart . '-' . $financialYearEnd;

    // Database connection
    $db3 = $this->load->database('db3', TRUE);

    // Start transaction

   //  Insert into client_handover table

    $handoverData = [
        'bd_id'                     => $bdid,
        'client_name'               => $client_name,
        'client_id'                 => $company_id,
        'mediator'                  => $mediator,
        'noofschool'                => $noofschool,
        'location'                  => $location,
        'city'                      => $city,
        'state'                     => $state,
        'spd_identify_by'           => $spd_identify_by,
        'infrastructure'            => $infrastructure,
        'logo'                      => $flink,
        'contact_person'            => $contact_person,
        'cp_mno'                    => $cp_mno,
        'acontact_person'           => $acontact_person,
        'acp_mno'                   => $acp_mno,
        'language'                  => $language,
        'expected_installation_date' => $expected_installation_date,
        'project_tenure'            => $project_tenure,
        'project_type'              => $project_type,
        'comments'                  => $comments,
        'remark'                    => $remark,
        'fttptype'                  => $fttptype,
        'project_year'              => $financialYear,
        'sales_cid'                 => $company_id
    ];
    
    $db3->insert('client_handover', $handoverData);
    $cid = $db3->insert_id();


    // Update spd table

    // if (!empty($sid)) {
    //     foreach ($sid as $spd_id) {
    //         $db3->where('id', $spd_id);
    //         $db3->update('spd', ['idebypi' => 'pi_id', 'cid' => $cid, 'pi_id' => NULL]);
    //     }
    // }


    $filtereNewSchoolData_cnt = sizeof($filtereNewSchoolData);
    if($filtereNewSchoolData_cnt > 0){

        // Insert New School Data into spd and spd_contact tables
            foreach($filtereNewSchoolData as $filterNewSchool){
                $schoolName_New         = $filterNewSchool['sname'];
                $schoolState_New        = $filterNewSchool['sstate'];
                $schoolDistrict_New     = $filterNewSchool['sdistrict'];
                $schoolCity_New         = $filterNewSchool['scity'];
                $schoolAddress_New      = $filterNewSchool['saddress'];
                $call_visit             = $filterNewSchool['call_visit'];

                $newStateData           = $this->getInStateById($schoolState_New);
                if(sizeof($newStateData) > 0){
                    $schoolState_New = $newStateData[0]->state_title;
                }
                $newDistrictData           = $this->getInDistricById($schoolDistrict_New);
                if(sizeof($newDistrictData) > 0){
                    $schoolDistrict_New = $newDistrictData[0]->district_title;
                }
             
                $schoolContact_New      = $filterNewSchool['scontact'];
                $schoolDesignation_New  = $filterNewSchool['sdegignation'];
                $schoolNumber_New       = $filterNewSchool['snumber'];

                $spdNewData = [
                            'sname'     => $schoolName_New,
                            'clientname'=> $client_name,
                            'sstate'    => $schoolState_New,
                            'sdistrict' => $schoolDistrict_New,
                            'tehshil'   => $schoolCity_New,
                            'saddress'  => $schoolAddress_New,
                            'ch_id'     => $cid,
                            'sales_cid' => $company_id,
                            'sayear'    => $financialYear,
                            'sdate'     => date("Y-m-d H:i:s"),
                            'call_visit'=> $call_visit,
                            'status'    => 1
                            ];
                $db3->insert('spd_request', $spdNewData);
                $new_ssid = $db3->insert_id();

                $spdNewContactData = [
                            'contact_name' => $schoolContact_New,
                            'designation'  => $schoolDesignation_New,
                            'contact_no'   => $schoolNumber_New,
                            'main'         => 1,
                            'rsid'         => $new_ssid
                            ];
                $db3->insert('spd_contact_request', $spdNewContactData);
            }
    }

    $filtereOldSchoolData_cnt = sizeof($filtereOldSchoolData);
    if($filtereOldSchoolData_cnt > 0){

        // Update School Data into spd and spd_contact tables
            foreach($filtereOldSchoolData as $filterOldSchool){
                $schoolID_old           = $filterOldSchool['sid'];
                $schoolName_old         = $filterOldSchool['sname'];
                $schoolState_old        = $filterOldSchool['sstate'];
                $schoolDistrict_old     = $filterOldSchool['sdistrict'];
                $schoolCity_old         = $filterOldSchool['scity'];
                $schoolAddress_old      = $filterOldSchool['saddress'];

                $schoolContact_old      = $filterOldSchool['scontact'];
                $schoolDesignation_old  = $filterOldSchool['sdegignation'];
                $schoolNumber_old       = $filterOldSchool['snumber'];

                $db3->where('id', $schoolID_old);
                $db3->update('spd_request', ['sales_cid'=>$company_id,'ch_id'=>$cid,'pi_id' => NULL]);

                $spdOldData = [
                            'sname'     => $schoolName_old,
                            'sstate'    => $schoolState_old,
                            'sdistrict' => $schoolDistrict_old,
                            'scity'     => $schoolCity_old,
                            'saddress'  => $schoolAddress_old,
                            'sales_cid' => $company_id
                            ];

                $db3->where('id',$schoolID_old);
                $db3->update('spd_request', $spdOldData);

                $spdOldContactData = [
                            'contact_name' => $schoolContact_old,
                            'designation'  => $schoolDesignation_old,
                            'contact_no'   => $schoolNumber_old,
                            'rsid'         => $schoolID_old,
                            'main'         => 1
                            ];
                $db3->insert('spd_contact_request', $spdOldContactData);
                // $db3->where('sid',$schoolID_old);
                // $db3->update('spd_contact_request', $spdOldContactData);
            }
    }

    // Insert into handoverlog table
    $handoverLogData = [
        'cid'       => $cid,
        'sales_cid' => $company_id,
        'taskby'    => 1,
        'remark'    => 'Handover From BD to Program Manager'
    ];
    $db3->insert('handoverlog', $handoverLogData);

    // Commit transaction
    // $db3->trans_complete();

    // if ($db3->trans_status() === FALSE) {
    //     return FALSE;
    // } else {
    //     return $cid;
    // }
    return $cid;
}













