public function SubmitBDRequestSchoolIdentification($ctype, $uid, $targetd, $request_type, $remark, $cname, $tyschool, $noschool, $location_count,$single_or_multi_location, $idetype, $ngoletter, $school_request_draft_path, $dm_deo_draft_path, $sletter, $dmletter, $sales_cid,$verify_handover_id,$school_letter_remarks,$dm_deo_letter_remarks) {
    // Map request types to abbreviations
    $request_map = [
        'School Identification'         => 'SSCHOOLID',
        'Report'                        => 'Report',
        'New client school visit'       => 'NCSV',
        'Inauguration'                  => 'Inauguration',
        'Demo'                          => 'Demo',
        'OnBoardVisit'                  => 'OnBoardVisit',
        'School Maintenance'            => 'SMaintenance',
        'New Client Report'             => 'NCR',
        'On Board Client School Visit'  => 'OnBoardClientVisit',
        'DIY'                           => 'DIY',
        'Employee Engagement'           => 'EmployeeEngagement',
        'RTTP'                          => 'RTTP'
    ];

    // Get the mapped request type or use an empty string if not found
    $rysn = isset($request_map[$request_type]) ? $request_map[$request_type] : '';
   
    // Fetch user details
    $data = $this->Menu_model->get_userbyid($uid);
    if (empty($data)) {
        return false; // Prevent errors if no user data is found
    }
    $bdname = $data[0]->name;

    // Load database connection
    $db3 = $this->load->database('db3', TRUE);

    // Insert data into bdrequest table
    $insert_data = [
        'targetd'       => $targetd,    /* Target Date */
        'bd_id'         => $uid,
        'bd_name'       => $bdname,
        'request_type'  => $request_type,
        'remark'        => $remark,
        'cname'         => $cname,
        'vlocation'     => '',
        'schooltype'    => $tyschool,
        'noofschool'    => $noschool,
        'assignto'      => '0',
        'rysn'          => $rysn,
        'onnew'         => $ctype,
        'ctype'         => $ctype,
        'idetype'       => $idetype,
        'ngoletter'     => $ngoletter,
        'school_request_draft'      => $school_request_draft_path,
        'dm_deo_draft'              => $dm_deo_draft_path,
        'sletter'                   => $sletter,
        'dmletter'                  => $dmletter,
        'sales_cid'                 => $sales_cid,
        'ch_id'                     => $verify_handover_id,
        'school_letter_remarks'     => $school_letter_remarks,
        'dm_deo_letter_remarks'     => $dm_deo_letter_remarks,
        'single_or_multi_location'  => $single_or_multi_location,
        'location_count'            => $location_count
    ];
    


    $db3->insert('bdrequest', $insert_data);
    $tid = $db3->insert_id();

    // Insert log entry
    $log_data = [
        'tid'       => $tid,
        'tby'       => $bdname,
        'remark'    => $remark,
        'detail'    => "$request_type Task Created By $bdname"
    ];
    $db3->insert('bdrequestlog', $log_data);

    return $tid;
}

