public function GetAllHandoverDetailsLists($cur_userid){

    $utype      = $this->Menu_model->get_userbyid($cur_userid);
    $userTypeid = $utype[0]->type_id;
    
    if($userTypeid ==1){
        $filter  = " (sadmin_id = '$cur_userid' OR user_id = '$cur_userid')";
    }else if($userTypeid ==2){
        $filter  = " (admin_id = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid == 3){
        $filter  = " (user_id = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid == 4){
        $filter  = " (pst_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid == 13){
        $filter  = " (aadmin = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==15){
        $filter  = " (sales_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==19){
        $filter  = " (ash_nae_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==20){
        $filter  = " (ash_w_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==21){
        $filter  = " (ash_s_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==22){
        $filter  = " (rm_east_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==23){
        $filter  = " (rm_north_co = '$cur_userid' OR user_id = '$cur_userid')";
    }elseif($userTypeid ==24){
        $filter  = " (acm_co = '$cur_userid' OR user_id = '$cur_userid')";
    }else{
         $filter  = " user_id = '$cur_userid' OR user_id = '$cur_userid')";
    }

    $queryUser   = $this->db->query("SELECT user_id,name FROM `user_details` WHERE $filter");
    $userDatas   = $queryUser->result();

    $userIds = array_map(function($u) {
        return $u->user_id;
    }, array_filter($userDatas, function($u) {
        return !empty($u->user_id) && $u->user_id != 0;
    }));

    $user_id_list =  implode(",", $userIds);

    $db3 = $this->load->database('db3', TRUE);

    $query          = $db3->query("SELECT * FROM `client_handover` WHERE bd_id IN ($user_id_list) ORDER BY id DESC");
    $queryDatas     = $query->result();

    return $queryDatas;
}


