    public function GetQuaterStrategyCountsDatas($cur_userid,$cq_start,$cq_end,$cquarter,$fyear){


    $utype      = $this->Menu_model->get_userbyid($cur_userid);
    $userTypeid = $utype[0]->type_id;
    
    if($userTypeid ==1){
        $filter  = " u3.sadmin_id = '$cur_userid'";
    }else if($userTypeid ==2){
        $filter  = " u3.admin_id = '$cur_userid'";
    }elseif($userTypeid == 4){
        $filter  = " u3.pst_co = '$cur_userid'";
    }elseif($userTypeid == 13){
        $filter  = " u3.aadmin = '$cur_userid'";
    }elseif($userTypeid ==15){
        $filter  = " u3.sales_co = '$cur_userid'";
    }elseif($userTypeid ==19){
        $filter  = " u3.ash_nae_co = '$cur_userid'";
    }elseif($userTypeid ==20){
        $filter  = " u3.ash_w_co = '$cur_userid'";
    }elseif($userTypeid ==21){
        $filter  = " u3.ash_s_co = '$cur_userid'";
    }elseif($userTypeid ==22){
        $filter  = " u3.rm_east_co = '$cur_userid'";
    }elseif($userTypeid ==23){
        $filter  = " u3.rm_north_co = '$cur_userid'";
    }elseif($userTypeid ==24){
        $filter  = " (u3.acm_co = '$cur_userid' OR u3.user_id = '$cur_userid')";
    }elseif($userTypeid ==25){
        $filter  = " u3.user_id = '$cur_userid' ";
    }else{
         $filter  = " u3.user_id = '$cur_userid'";
    }


        $query = $this->db->query("SELECT
    u1.name AS main_bd_name,
    u1.user_id AS main_bd_id,
    quater_strategy.fyear as quater_strategy_fyear,
    quater_strategy.in_quater as quater_strategy_in_quater,

   COUNT(CASE 
        WHEN init_call.id IS NOT NULL THEN init_call.id 
    END) AS total_bd_funnel,


    COUNT(DISTINCT quater_strategy.id) AS total,
    
    COUNT(DISTINCT CASE 
        WHEN quater_strategy.prospecting_funnel = 'Yes' THEN quater_strategy.id 
    END) AS total_prospecting_funnel,

    COUNT(DISTINCT CASE 
        WHEN quater_strategy.proposal_to_be_sent_review = 'Yes' THEN quater_strategy.id 
    END) AS total_proposal_to_be_sent_review,
    
    COUNT(DISTINCT CASE 
        WHEN quater_strategy.proposal_to_be_sent_target = 'Yes' THEN quater_strategy.id 
    END) AS total_proposal_to_be_sent_target,

    COUNT(DISTINCT CASE 
        WHEN quater_strategy.closure_pipeline_october = 'Yes' THEN quater_strategy.id 
    END) AS total_closure_pipeline_october,

    -- RP/RPClose meetings done
    COUNT(DISTINCT CASE 
        WHEN tblc1.id IS NOT NULL THEN quater_strategy.id 
    END) AS total_rp_meeting_done,
    
    -- Pending meetings = total - RP/RPClose meetings
    COUNT(DISTINCT quater_strategy.id) - COUNT(DISTINCT CASE 
        WHEN tblc1.id IS NOT NULL THEN quater_strategy.id 
    END) AS pending_for_meeting,
    
    -- Proposals sent
    COUNT(DISTINCT CASE 
        WHEN proposal.id IS NOT NULL THEN quater_strategy.id 
    END) AS proposal_sent,
    
    -- Pending proposals = total - proposals sent
    COUNT(DISTINCT quater_strategy.id) - COUNT(DISTINCT CASE 
        WHEN proposal.id IS NOT NULL THEN quater_strategy.id 
    END) AS pending_proposal_sent,

	COUNT(DISTINCT CASE 
        WHEN init_call.cstatus IN (7,14) THEN quater_strategy.id 
    END) AS total_closure,

COUNT(DISTINCT CASE 
        WHEN init_call.cstatus NOT IN (7,14) THEN quater_strategy.id 
    END) AS total_pending_closure


FROM quater_strategy
LEFT JOIN init_call ON init_call.cmpid_id = quater_strategy.cid
LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd

-- RP/RPClose meetings
LEFT JOIN tblcallevents tblc1 ON tblc1.cid_id = init_call.id AND tblc1.actiontype_id IN (3,4,22) AND tblc1.mtype IN ('RP','RPClose','Change RP')
    AND CAST(tblc1.appointmentdatetime AS DATE) BETWEEN '$cq_start' AND '$cq_end'

-- Proposals
LEFT JOIN tblcallevents tblc3 ON tblc3.cid_id = init_call.id AND tblc3.nextCFID != 0
LEFT JOIN proposal ON proposal.tid = tblc3.id AND proposal.apr IN (0,1)
    AND  CAST(tblc3.appointmentdatetime AS DATE) BETWEEN '$cq_start' AND '$cq_end'

LEFT JOIN user_details u3 ON u3.user_id = quater_strategy.main_bd

    WHERE 
    quater_strategy.fyear = '$fyear'
   AND quater_strategy.in_quater = '$cquarter'
   AND $filter
GROUP BY u3.user_id
ORDER BY u3.name");

        return $query->result();
    }



