}else if ($rtype == 'total_rp_meeting_done') {
    $filter = " AND tblc1.mtype IN ('RP','RPClose','Change RP')";
}else if ($rtype == 'pending_for_meeting') {
    $having = " HAVING 
        COUNT(DISTINCT quater_strategy.id) - 
        COUNT(DISTINCT CASE WHEN tblc1.id IS NOT NULL THEN quater_strategy.cid END) > 0";
}else if ($rtype == 'proposal_sent') {
    $filter = " AND proposal.id IS NOT NULL";
}else if ($rtype == 'pending_proposal_sent') {
    $having = " HAVING 
        COUNT(DISTINCT quater_strategy.id) - 
        COUNT(DISTINCT CASE WHEN proposal.id IS NOT NULL THEN quater_strategy.id END) > 0";
}else if ($rtype == 'total_closure') {
    $filter = " AND init_call.cstatus IN (7,14)";
}else if ($rtype == 'total_pending_closure') {
    $filter = " AND init_call.cstatus NOT IN (7,14)";
}else if ($rtype == 'total_prospecting_funnel') {
    $filter = " AND quater_strategy.prospecting_funnel = 'Yes'";
}else if ($rtype == 'total_proposal_to_be_sent_review') {
    $filter = " AND quater_strategy.proposal_to_be_sent_review = 'Yes'";
}else if ($rtype == 'total_proposal_to_be_sent_target') {
    $filter = " AND quater_strategy.proposal_to_be_sent_target = 'Yes'";
}else if ($rtype == 'total_closure_pipeline_october') {
    $filter = " AND quater_strategy.closure_pipeline_october = 'Yes'";
}


// $mainBDFilter = "AND quater_strategy.main_bd = '$uid'";
$mainBDFilter = '';

$query = $this->db->query("SELECT
        u1.name AS main_bd_name,
        u1.user_id AS main_bd_id,
        quater_strategy.fyear AS quater_strategy_fyear,
        quater_strategy.in_quater AS quater_strategy_in_quater,
        u3.name AS given_main_bd_name,
        company_master.compname,
        company_master.id AS cid,
        tblc1.id AS tblc1_id,
        quater_strategy.prospecting_funnel,
        quater_strategy.proposal_to_be_sent_review,
        quater_strategy.proposal_to_be_sent_target,
        quater_strategy.closure_pipeline_october,
        init_call.id as init_call_id,

        -- ✅ RP/RPClose meeting done
        CASE 
            WHEN COUNT(DISTINCT CASE WHEN tblc1.id IS NOT NULL THEN quater_strategy.cid END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS total_rp_meeting_done,

        -- ✅ Pending meetings
        CASE 
            WHEN COUNT(DISTINCT quater_strategy.id) - COUNT(DISTINCT CASE WHEN tblc1.id IS NOT NULL THEN quater_strategy.cid END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS pending_for_meeting,

        -- ✅ Proposal sent
        CASE 
            WHEN COUNT(DISTINCT CASE WHEN proposal.id IS NOT NULL THEN quater_strategy.id END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS proposal_sent,

        -- ✅ Pending proposal sent
        CASE 
            WHEN COUNT(DISTINCT quater_strategy.id) - COUNT(DISTINCT CASE WHEN proposal.id IS NOT NULL THEN quater_strategy.id END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS pending_proposal_sent,

        -- ✅ Total closure
        CASE 
            WHEN COUNT(DISTINCT CASE WHEN init_call.cstatus IN (7,14) THEN quater_strategy.id END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS total_closure,

        -- ✅ Pending closure
        CASE 
            WHEN COUNT(DISTINCT CASE WHEN init_call.cstatus NOT IN (7,14) THEN quater_strategy.id END) > 0 
            THEN 'Yes' ELSE 'No' 
        END AS total_pending_closure,

        s1.name AS current_status_name

    FROM quater_strategy

    LEFT JOIN init_call ON init_call.cmpid_id = quater_strategy.cid

    LEFT JOIN user_details u1 ON u1.user_id = init_call.mainbd

    LEFT JOIN company_master 
        ON company_master.id = init_call.cmpid_id

    LEFT JOIN tblcallevents tblc1 
        ON tblc1.cid_id = init_call.id 
        AND tblc1.actiontype_id IN (3,4,22) 
        AND tblc1.mtype IN ('RP','RPClose','Change RP')
        AND DATE(tblc1.appointmentdatetime) BETWEEN '$cq_start' AND '$cq_end'

    LEFT JOIN tblcallevents tblc3 
        ON tblc3.cid_id = init_call.id 
        AND tblc3.nextCFID != 0 
        -- AND tblc3.actiontype_id = 6

    LEFT JOIN proposal 
        ON proposal.tid = tblc3.id  
        AND proposal.apr IN (0,1)
        AND DATE(tblc3.appointmentdatetime) BETWEEN '$cq_start' AND '$cq_end'

    LEFT JOIN user_details u3 
        ON u3.user_id = quater_strategy.main_bd

    LEFT JOIN status s1 
        ON s1.id = init_call.cstatus

    WHERE 
        quater_strategy.fyear = '$fyear'
        AND quater_strategy.in_quater = '$cquarter'
        $mainBDFilter
        $userfilter
        $filter

    GROUP BY 
        quater_strategy.cid, company_master.compname
    $having
");

        return $query->result();
    }



