    public function getAllCurrentFinancialYearAndQuarter($fyear = null) {
    $month = date('n');
    $year  = date('Y');

    // Determine financial year if not provided
    if (!$fyear) {
        if ($month >= 4) {
            $fyear = $year . '-' . ($year + 1);
        } else {
            $fyear = ($year - 1) . '-' . $year;
        }
    }

    // Split financial year into start and end years
    [$startYear, $endYear] = explode('-', $fyear);

    // Define quarter date ranges
    $quarters = [
        'Q1' => [
            'start' => "$startYear-04-01",
            'end'   => "$startYear-06-30"
        ],
        'Q2' => [
            'start' => "$startYear-07-01",
            'end'   => "$startYear-09-30"
        ],
        'Q3' => [
            'start' => "$startYear-10-01",
            'end'   => "$startYear-12-31"
        ],
        'Q4' => [
            'start' => "$endYear-01-01",
            'end'   => "$endYear-03-31"
        ]
    ];

    // Determine current quarter based on current month
    if ($month >= 4 && $month <= 6) {
        $currentQuarter = 'Q1';
    } elseif ($month >= 7 && $month <= 9) {
        $currentQuarter = 'Q2';
    } elseif ($month >= 10 && $month <= 12) {
        $currentQuarter = 'Q3';
    } else {
        $currentQuarter = 'Q4';
    }

    return [
        'financial_year' => $fyear,
        'current_quarter' => $currentQuarter,
        'current_quarter_start' => $quarters[$currentQuarter]['start'],
        'current_quarter_end'   => $quarters[$currentQuarter]['end'],
        'all_quarters' => $quarters
    ];
}



