public function GetAllInitCallinCurrentQuarter($mainBD,$quarter){

    $query = $this->db->query("SELECT 
    COUNT(DISTINCT CASE WHEN init_call.prospecting_funnel = '$quarter' THEN init_call.id END) AS total_prospecting_funnel,
    COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_review = '$quarter' THEN init_call.id END) AS total_proposal_to_be_sent_review,
    COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_target = '$quarter' THEN init_call.id END) AS total_proposal_to_be_sent_target,
    COUNT(DISTINCT CASE WHEN init_call.closure_pipeline = '$quarter' THEN init_call.id END) AS total_closure_pipeline
FROM 
