public function GetAllCompleteTargetinCurrentQuarter($mainBD,$quarter,$review_start_date,$tend_date){

    $query = $this->db->query("SELECT 
     COUNT(DISTINCT CASE WHEN init_call.prospecting_funnel = '$quarter' THEN init_call.id END) AS total_complete_prospecting_funnel,
     COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_review = '$quarter' THEN init_call.id END) AS total_complete_proposal_to_be_sent_review,
     COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_target = '$quarter' THEN init_call.id END) AS total_complete_proposal_to_be_sent_target,
     COUNT(DISTINCT CASE WHEN init_call.closure_pipeline = '$quarter' THEN init_call.id END) AS total_complete_closure_pipeline
FROM 
    `init_call`
WHERE 
    init_call.mainbd = '$mainBD'
    AND EXISTS (
        SELECT 1 
        FROM tblcallevents AS sub_tbcl 
        WHERE (sub_tbcl.mtype = 'RP' OR sub_tbcl.mtype = 'RPClose' OR sub_tbcl.mtype  = 'Change RP')
 		AND DATE(sub_tbcl.appointmentdatetime) BETWEEN '$review_start_date' AND '$tend_date'
          AND sub_tbcl.cid_id = init_call.id
    )");
    return $query->result();

    }
public function GetAllCompletePraposalTargetinCurrentQuarter($mainBD,$quarter,$review_start_date,$tend_date){

    $query = $this->db->query("SELECT 
     COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_review = '$quarter' THEN init_call.id END) AS total_complete_proposal_to_be_sent_review,
     COUNT(DISTINCT CASE WHEN init_call.proposal_to_be_sent_target = '$quarter' THEN init_call.id END) AS total_complete_proposal_to_be_sent_target
FROM 
    `init_call`
WHERE 
    init_call.mainbd = '$mainBD'
    AND EXISTS (
        SELECT 1
        FROM proposal p
        WHERE p.init_id = init_call.id
        AND p.apr IN (0, 1)
        AND DATE(p.sdatet) BETWEEN '$review_start_date' AND '$tend_date'
        )");
    return $query->result();

    }

public function GetAllCompleteCloserPipelineTargetinCurrentQuarter($mainBD,$quarter,$review_start_date,$tend_date){

    $query = $this->db->query("SELECT 
     COUNT(DISTINCT CASE WHEN init_call.closure_pipeline = '$quarter' THEN init_call.id END) AS total_complete_closure_pipeline
FROM 
    `init_call`
WHERE 
    init_call.mainbd = '$mainBD' 
    AND init_call.cstatus = 7
    ");
    return $query->result();

    }




