LEFT JOIN user_details u3 ON u3.user_id = tblc.approved_by
LEFT JOIN status s1 ON s1.id = tblc.status_id
LEFT JOIN status s3 ON s3.id = init_call.cstatus

WHERE
    tblc.id = '$tid'");
