    public function GetNextStepConfirmationMessage($init_id,$sdate,$edate){
        $query = $this->db->query("SELECT
    nscm.*,
    action.name as task_name,
    company_master.id as cid,
    company_master.compname,
    u1.name as confirmation_by,
    tblc.actontaken,
    tblc.purpose_achieved,
    tblc.appointmentdatetime,
    tblc.remarks,
    tblc.special_remarks,
    s1.name as planned_on_status,
    s2.name as updated_at_on_status

FROM
    `next_step_confirmation_message` nscm
    LEFT JOIN tblcallevents tblc on tblc.id = nscm.next_step_confirmation_task_id
    LEFT JOIN action on action.id = tblc.actiontype_id
    LEFT JOIN status s1 on s1.id = tblc.status_id
    LEFT JOIN status s2 on s2.id = tblc.nstatus_id
    LEFT JOIN init_call on init_call.id = tblc.cid_id
    LEFT JOIN company_master on company_master.id = init_call.cmpid_id
    LEFT JOIN user_details u1 on u1.user_id = tblc.user_id
    
   WHERE 
   init_call.id = '$init_id'
   AND cast(nscm.created_at AS Date) BETWEEN '$sdate' AND '$edate'
   ORDER BY nscm.id DESC
   ");
        return $query->result();
    }
