        public function getQuestionnaireByTask($task_id) {
            $this->db->where('task_id', $task_id);
            $query = $this->db->get('school_call_questionnaires');
            
            if($query->num_rows() > 0) {
                $result = $query->row();
                
                // Decode JSON data
                if(isset($result->questionnaire_data)) {
                    $result->questionnaire_data = json_decode($result->questionnaire_data, true);
                }
                
                return $result;
            }
            
            return false;
        }

        public function getQuestionnairesBySchool($school_id) {
            $this->db->where('school_id', $school_id)
                    ->order_by('submitted_at', 'DESC');
            $query = $this->db->get('school_call_questionnaires');
            
            $results = $query->result();
            
            // Decode JSON data for all results
            foreach($results as $result) {
                if(isset($result->questionnaire_data)) {
                    $result->questionnaire_data = json_decode($result->questionnaire_data, true);
                }
            }
            
            return $results;
        }






