    public function BuyVendorRequestBYAdminExcutive($uid){

    $db3    = $this->load->database('db3', TRUE);
    $query  = $db3->query("SELECT
                buy_requests.*,
                buy_requests.id as buy_requests_id,
                tblcallevents.project_code,
                u1.fullname as task_username,
                ta.tasktype,
                ta.taskname,
                tblcallevents.sid,
                tblcallevents.rsid,
                COALESCE(spdr.sname, spd.sname) AS sname,
                u2.fullname as admin_manager_name,
                tblcallevents.user_id as request_user_id,

                vendors.vendor_name,
                vendors.vendor_state,
                vendors.vendor_district,
                vendors.vendor_city,
                vendors.contact_person,
                vendors.email as vendor_email,
                vendors.phone as vendor_phone,
                vendors.address as vendor_address
            FROM
                buy_requests
            LEFT JOIN tblcallevents ON tblcallevents.id = buy_requests.task_id
            LEFT JOIN vendors ON vendors.vendor_id  = buy_requests.is_best_vendor_id
            LEFT JOIN task_action ta on ta.id = tblcallevents.task_action
            LEFT JOIN user_detail u1 on u1.id = tblcallevents.user_id
            LEFT JOIN user_detail u2 on u2.id = buy_requests.am_approved_by
            LEFT JOIN spd ON spd.id = tblcallevents.sid
            LEFT JOIN spd_request spdr ON spdr.id = tblcallevents.rsid
            WHERE 
            (
            (buy_requests.am_approved_status IS NOT NULL)
                AND (buy_requests.am_approved_status = 1 OR buy_requests.admin_approved_status IS NULL)
            )
            ");
            
        return $query->result();
}

    public function BuyVendorRequestBYAdminExcutiveByRequestID($request_id){

        $db3    = $this->load->database('db3', TRUE);

        $query = $db3->query("SELECT
                buy_requests.*,
                vendor_requests.id as vendor_buy_requests_id,
                vendor_requests.is_best as s_is_best_vendor,
                vendor_requests.price as s_vendor_price,
                vendor_requests.remarks as s_vendor_remarks,
                vendor_requests.invoice_file_path as vendor_invoice_file_path,

                tblcallevents.project_code,
                u1.fullname as task_username,
                ta.tasktype,
                ta.taskname,
                tblcallevents.sid,
                tblcallevents.rsid,
                COALESCE(spdr.sname, spd.sname) AS sname,
                u2.fullname as admin_manager_name,
                tblcallevents.user_id as request_user_id,
                vendors.vendor_name,
                vendors.vendor_state,
                vendors.vendor_district,
                vendors.vendor_city,
                vendors.contact_person,
                vendors.email as vendor_email,
                vendors.phone as vendor_phone,
                vendors.address as vendor_address
            FROM
                buy_requests
            LEFT JOIN vendor_requests ON vendor_requests.request_id = buy_requests.id
            LEFT JOIN tblcallevents ON tblcallevents.id = buy_requests.task_id
            LEFT JOIN vendors ON vendors.vendor_id  = vendor_requests.vendor_id
            LEFT JOIN task_action ta on ta.id = tblcallevents.task_action
            LEFT JOIN user_detail u1 on u1.id = tblcallevents.user_id
            LEFT JOIN user_detail u2 on u2.id = buy_requests.am_approved_by
            LEFT JOIN spd ON spd.id = tblcallevents.sid
            LEFT JOIN spd_request spdr ON spdr.id = tblcallevents.rsid
            WHERE 
            buy_requests.id = '$request_id'
            ");
            
        return $query->result();
}

