    spdr.sname,
    ta.tasktype,
    spd.id as spd_id,
    spdr.id as spdr_id,
    vd.*
FROM
    vendor_details vd
    LEFT JOIN user_detail u1 ON u1.id = vd.add_by
    LEFT JOIN tblcallevents AS tblc on tblc.id = vd.tbl_task_id
    LEFT JOIN task_action ta on ta.id = tblc.task_action
    LEFT JOIN spd on spd.id = tblc.sid
    LEFT JOIN spd_request spdr on spdr.id = tblc.rsid
    LEFT JOIN user_detail u2 on u2.id = tblc.assigned_by
WHERE
    vd.tbl_task_id IS NOT NULL AND vd.best_vendor != 'yes' AND vd.tbl_task_id = '$task_id'");

    return $query->result();
}





public function ChangeAnnualReviewsDate() {
    
    $fydate     = $this->getLastFinancialYearRange(date("Y-m-d"));
    $start_date = $fydate['start_date'];
    $end_date   = $fydate['end_date'];

    // $start_date = date("Y").'-04-01';
    $start_date = (date('m') >= 4 ? date('Y') - 1 : date('Y') - 2) . '-04-01';

