}


public function search_cities_by_name($search) {
    $this->db->select('id, name');
    $this->db->from('in_city');
    $this->db->like('name', $search, 'both'); // %search%
    $this->db->limit(20);
    $query = $this->db->get();
    return $query->result();
}

public function search_states_by_name($search) {
    $this->db->select('state_id, state_title');
    $this->db->from('in_state');
    $this->db->like('state_title', $search, 'both'); // %search%
    $this->db->limit(20);
    $query = $this->db->get();
    return $query->result();
}

// getFinancialYear('current');
// getFinancialYear('last');

public function getCustmizeFinancialYear($type = 'current', $date = 'today') {
    $currentDate = new DateTime($date);
    $year = (int)$currentDate->format('Y');
    $month = (int)$currentDate->format('m');

    $type = 'last';

    // Determine current FY start year
    if ($month < 4) {
        $startYear = $year - 1;
    } else {
        $startYear = $year;
    }

    // Adjust based on type
    if ($type === 'last') {
        $startYear -= 1;
    }

    $endYear = $startYear + 1;

    return [
        'start_date' => "$startYear-04-01",
        'end_date'   => "$endYear-03-31"
    ];
}


