        public function AddexpensecashonVisit($tbl_user_id,$task_id,$expensecash,$bills,$expense_remark,$expense_string){

          
                $to_userDatas           = $this->Menu_model->get_userbyid($tbl_user_id);
                $touser_ucash           = $to_userDatas[0]->ucash;
            
                if($touser_ucash >= $expensecash){
 
                    $new_user_cur_cash   = $touser_ucash - $expensecash;

                    $userDatas = array(
                        'ucash' => $new_user_cur_cash
                    );
                    $this->db->where('user_id', $tbl_user_id);
                    $this->db->update('user_details', $userDatas);

                    $userTblCallDatas = array(
                        'cash_expense'  => $expensecash,
                        'cash_refund'   => 0
                    );
                    $this->db->where('id', $task_id);
                    $this->db->update('tblcallevents', $userTblCallDatas);

                    $data = array(
                        'user_id'           => $tbl_user_id,
                        'tbl_task_id'       => $task_id,
                        'expense'           => $expensecash,
                        'expense_remarks'   => $expense_remark,
                        'bills'             => $bills,
                        'expense_type'      => "$expense_string"
                    );
                    $this->db->insert('cash_expense', $data);
                    $insert_id = $this->db->insert_id();

                    $visitCashLogData = array(
                        'uid'        => $tbl_user_id,
                        'cash'       => $expensecash,
                        'av_cash'    => $new_user_cur_cash,
                        'type'       => "expense",
                        'remarks'    => "Expense Allocated from Task Cash Allotment for Visit",
                        'task_id'    => $task_id
                    );
                    $this->db->insert('cash_log', $visitCashLogData);

                    return $insert_id;

                }
              
    }


