public function getActionWiseCounts($uid, $tdate)
{
    $startDate = $tdate . " 00:00:00";
    $endDate   = date('Y-m-d', strtotime($tdate . ' +1 day')) . " 00:00:00";

     $query   = $this->db->query("  SELECT 
    action.id AS actions_id,
    action.name,
    LOWER(REPLACE(action.name, ' ', '_')) AS action_name_small,
    COUNT(tblcallevents.id) AS total_count
FROM action
LEFT JOIN tblcallevents 
    ON tblcallevents.actiontype_id = action.id
    AND tblcallevents.assignedto_id = '1000301'
    AND tblcallevents.appointmentdatetime >= '2026-05-25 00:00:00'
    AND tblcallevents.appointmentdatetime <  '2026-05-26 00:00:00'
    AND tblcallevents.plan = 1
    AND tblcallevents.approved_status = 1
    AND action.action_status = 1
GROUP BY action.id, action.name");
        $result =  $query->result();
        return $result;

}
