    public function CheckSalesCompnayNameBYCid($cid_in,$type_id,$uid){

        $filter     = '';

        if($type_id == 3){
            $filter     = " AND (u1.user_id = '$uid')";
        }else if($type_id == 24){
            $filter     = " AND (u1.acm_co = '$uid' || u1.user_id = '$uid')";
        }else if($type_id == 13){
            $filter       = " AND (u1.aadmin='$userid' || u1.user_id = '$uid')";
        }else if($type_id == 4){
            $filter       = "AND (u1.pst_co='$userid' || u1.user_id = '$uid')";
        }else if($type_id == 15){
            $filter       = "AND (u1.sales_co = $userid || u1.user_id = '$uid')";
        }elseif($type_id == 19){
            $filter       = "AND (u1.ash_nae_co = '$userid' || u1.user_id = '$uid')";
        }else if($type_id == 20){
            $filter       = "AND (u1.ash_w_co='$userid' || u1.user_id = '$uid')";
        }else if($type_id == 21){
            $filter       = "AND (u1.ash_s_co='$userid' || u1.user_id = '$uid')";
        }else if($type_id == 22){
            $filter       = "AND (u1.rm_east_co='$userid' || u1.user_id = '$uid')";
        }

        $query = $this->db->query("SELECT
                cm.id as cid
            FROM
                `init_call`
                LEFT JOIN company_master cm on cm.id = init_call.cmpid_id
                LEFT JOIN user_details u1 on u1.user_id = init_call.mainbd
                LEFT JOIN status s1 on s1.id = init_call.cstatus
            WHERE
                init_call.cmpid_id IN ($cid_in) $filter");

        return $query->result();
        
    }

   

